import { useState, useEffect, useRef, useCallback } from 'react';
import { supabase, getSupabaseConfig } from './lib/supabase';
import { AuthUI } from './components/AuthUI';
import { RootLayout } from './layouts/RootLayout';
import { OnboardingModal } from './components/onboarding/OnboardingModal';
import { useStore } from './store/useStore';
import { useOnboardingStore } from './store/onboardingStore';
import { syncManager } from './services/SyncService';
import { compareDatabaseStructure, ensureDatabaseSchema } from './services/ensureDatabaseSchema';
import { isElectron } from './lib/platform';
import { LandingPage } from './components/LandingPage';
import { PersistenceService } from './services/PersistenceService';
import { OnboardingService } from './services/OnboardingService';
import { ToastContainer } from './components/Toast';

export default function App() {
  const { setSyncStatus, settings, setProfile, landingSkipped, setLandingSkipped, reset: resetStore, addToast } = useStore();
  const { isConfigured, resetOnboarding, setUserId, setStep, setSetupMode, hasHydrated } = useOnboardingStore();
  const [session, setSession] = useState<any>(null);
  const [loading, setLoading] = useState(true);
  // eslint-disable-next-line @typescript-eslint/no-unused-vars
  const _fetchProfile = fetchProfile;

  // If electron, always skip landing
  useEffect(() => {
    if (isElectron() && !landingSkipped) {
      setLandingSkipped(true);
    }
  }, [landingSkipped, setLandingSkipped]);

  // Electron Auto-Update Setup
  useEffect(() => {
    if (!isElectron()) return;

    // Scan for updates 5 seconds after application bootstrap
    const initialCheckTimer = setTimeout(() => {
      console.log('[App Auto-Update] Initial scan triggered');
      (window as any).electron?.checkForUpdates?.();
    }, 5000);

    const cleanupAvailable = (window as any).electron?.onUpdateAvailable?.((info: any) => {
      console.log('[App Auto-Update] Update detected:', info);
      addToast({
        type: 'info',
        message: `A new update (v${info.version}) is available. Downloading...`
      });
    });

    const cleanupDownloaded = (window as any).electron?.onUpdateDownloaded?.((info: any) => {
      console.log('[App Auto-Update] Update completed:', info);
      addToast({
        type: 'success',
        message: `Update v${info.version} downloaded successfully! Restart Gimay to apply changes.`
      });
    });

    const cleanupError = (window as any).electron?.onUpdateError?.((err: string) => {
      console.warn('[App Auto-Update] Scan failure:', err);
      // Suppress dev mock offline environment warning notifications
      if (err !== 'Offline / local server environment') {
        addToast({
          type: 'warning',
          message: `Update verification interrupted: ${err}`
        });
      }
    });

    return () => {
      clearTimeout(initialCheckTimer);
      cleanupAvailable?.();
      cleanupDownloaded?.();
      cleanupError?.();
    };
  }, [addToast]);

  // Sync landingSkipped with URL path on web
  useEffect(() => {
    if (isElectron()) return;

    const handleUrlChange = () => {
      const isAppPath = window.location.pathname === '/app';
      if (isAppPath) {
        if (!landingSkipped) {
          setLandingSkipped(true);
        }
      } else {
        if (landingSkipped) {
          setLandingSkipped(false);
        }
      }
    };

    // Run on mount
    handleUrlChange();

    window.addEventListener('popstate', handleUrlChange);
    return () => window.removeEventListener('popstate', handleUrlChange);
  }, [landingSkipped, setLandingSkipped]);

  // Check for deep link invite
  useEffect(() => {
    if (hasHydrated && !isConfigured) {
      const params = new URLSearchParams(window.location.search);
      const inviteCode = params.get('invite');
      if (inviteCode) {
        setStep('join-invite');
        setSetupMode('join-invite');
        setLandingSkipped(true); // Auto skip landing on invite
        // Clear param without refreshing to avoid re-run
        const newUrl = window.location.origin + window.location.pathname;
        window.history.replaceState({}, document.title, newUrl);
      }
    }
  }, [hasHydrated, isConfigured, setStep, setSetupMode]);
  const [schemaBootstrapLoading, setSchemaBootstrapLoading] = useState(false);
  const [schemaBootstrapMessage, setSchemaBootstrapMessage] = useState('Checking database structure...');
  const [schemaBootstrapError, setSchemaBootstrapError] = useState<string | null>(null);
  const schemaCheckedUserRef = useRef<string | null>(null);

  const fetchProfile = async (userId: string) => {
    try {
      const { data: profile, error } = await supabase
        .from('profiles')
        .select('*')
        .eq('id', userId)
        .single();

      if (error) {
        console.error('Error fetching profile:', error);
        setProfile(null);
      } else {
        setProfile(profile);
      }
    } catch (error) {
      console.error('Error fetching profile:', error);
      setProfile(null);
    }
  };

  useEffect(() => {
    const updateTheme = () => {
      const isDark =
        settings.appearance.theme === 'dark' ||
        (settings.appearance.theme === 'system' && window.matchMedia('(prefers-color-scheme: dark)').matches);

      document.documentElement.classList.toggle('dark', isDark);
      document.documentElement.classList.toggle('light', !isDark);
      document.documentElement.setAttribute('data-theme', isDark ? 'dark' : 'light');
      document.documentElement.style.setProperty('--brand', settings.appearance.accentColor);
      document.documentElement.style.setProperty('--brand-muted', `${settings.appearance.accentColor}1A`);
      document.documentElement.style.setProperty('--brand-border', `${settings.appearance.accentColor}33`);
    };

    updateTheme();

    if (settings.appearance.theme !== 'system') {
      return;
    }

    const matcher = window.matchMedia('(prefers-color-scheme: dark)');
    const listener = () => updateTheme();
    matcher.addEventListener('change', listener);

    return () => matcher.removeEventListener('change', listener);
  }, [settings.appearance.theme, settings.appearance.accentColor]);

  // Auto-recovery: If local storage has valid configuration but the store is not marked configured, auto-align it.
  useEffect(() => {
    if (hasHydrated) {
      const hasConfig = OnboardingService.hasExistingConfiguration();
      if (hasConfig && !isConfigured) {
        console.log('[Onboarding] Found existing configuration in local storage, auto-configuring store.');
        useOnboardingStore.getState().setIsConfigured(true);
      }
    }
  }, [hasHydrated, isConfigured]);

  useEffect(() => {
    if (!hasHydrated) return;

    const unsubscribeSync = syncManager.onStatusChange((status) => {
      setSyncStatus(status);
    });

    const handleAuthChange = async (event: string, session: any) => {
      setSession(session);
      
      if (session?.user?.id) {
        fetchProfile(session.user.id);
        
        const store = useOnboardingStore.getState();
        const currentIsConfigured = store.isConfigured;
        const currentStep = store.step;
        const currentUserId = store.userId;

        // Check for teams if REALLY not configured and at welcome screen
        if (!currentIsConfigured && currentStep === 'welcome') {
          PersistenceService.fetchUserTeams(session.user.id).then(teams => {
            const latestStore = useOnboardingStore.getState();
            if (!latestStore.isConfigured && latestStore.step === 'welcome') {
              if (teams && teams.length > 0) {
                setStep('team-select');
              }
            }
          }).catch(err => console.error('Team check failed:', err));
        }

        // Only reset onboarding if we DEFINITELY have a user ID mismatch, not currently configuring, and neither is the offline fallback user
        if (
          currentUserId && 
          currentUserId !== session.user.id && 
          !currentIsConfigured && 
          currentUserId !== 'offline-user-id' && 
          session.user.id !== 'offline-user-id'
        ) {
          console.warn('[AUTH] User mismatch detected, resetting fallback state');
          resetOnboarding();
          resetStore();
        }

        // If the session changed but we didn't have a userId, or it's a new session, sync it
        if (!currentUserId || (event === 'SIGNED_IN')) {
          setUserId(session.user.id);
        }
      } else {
        // If session is lost completely
        if (event === 'SIGNED_OUT') {
          resetStore();
          resetOnboarding();
          setUserId(null);
        }
      }
      setLoading(false);
    };

    // Initial check
    supabase.auth.getSession().then(({ data: { session } }) => {
      handleAuthChange('INITIAL_SESSION', session);
      if (isElectron() && !session) {
        console.log('[App] Desktop environment without session detected. Auto-launching offline sandbox.');
        setTimeout(() => {
          handleOfflineMode();
        }, 150);
      }
    });

    const { data: { subscription } } = supabase.auth.onAuthStateChange((event, session) => {
      handleAuthChange(event, session);
    });

    return () => {
      subscription.unsubscribe();
      unsubscribeSync();
    };
  }, [hasHydrated, setSyncStatus, setProfile, resetOnboarding, setUserId, resetStore, setStep]);

  const handleOfflineMode = () => {
    const offlineSession = {
      user: {
        id: 'offline-user-id',
        email: 'offline-operator@putmen.io',
        user_metadata: {
          full_name: 'Offline Operator',
          username: 'offline'
        }
      }
    };
    
    // Force onboarding configuration to true for offline sandbox
    setUserId('offline-user-id');
    setStep('complete');
    useOnboardingStore.getState().setIsConfigured(true);

    const mainStore = useStore.getState();
    mainStore.setProfile({
      id: 'offline-user-id',
      email: 'offline-operator@putmen.io',
      full_name: 'Offline Operator',
      username: 'offline',
      avatar_url: undefined,
      preferences: { theme: 'dark', sidebar_width: 300 }
    });

    mainStore.updateSyncMetadata({ isOffline: true });
    mainStore.setSyncStatus('offline');

    setSession(offlineSession);
  };

  const runSchemaBootstrap = useCallback(async () => {
    if (!session?.user?.id || !isConfigured) {
      return;
    }

    if (schemaCheckedUserRef.current === session.user.id) {
      return;
    }

    const { settings } = useStore.getState();
    if (!settings.general.checkDatabaseIntegrity) {
      console.log('[Schema Bootstrap] Database integrity check on load is disabled in settings. Skipping.');
      schemaCheckedUserRef.current = session.user.id;
      return;
    }

    const config = getSupabaseConfig();
    if (!config.url || !config.anonKey) {
      return;
    }

    setSchemaBootstrapError(null);
    setSchemaBootstrapMessage('Checking database structure...');
    setSchemaBootstrapLoading(true);

    // If we are offline, bypass completely (Desktop only)
    const isAppOffline = useStore.getState().syncMetadata.isOffline || (typeof navigator !== 'undefined' && !navigator.onLine);
    if (isElectron() && isAppOffline) {
      console.warn('[Schema Bootstrap] Client is offline. Bypassing database schema bootstrap to support offline mode.');
      schemaCheckedUserRef.current = session.user.id;
      setSchemaBootstrapLoading(false);
      return;
    }

    const compare = await compareDatabaseStructure(config.url, config.anonKey);

    if (!compare.success) {
      const errStr = String(compare.error || '').toLowerCase();
      const isConnectionIssue = errStr.includes('fetch') || errStr.includes('network') || errStr.includes('timeout') || errStr.includes('failed to connect');
      
      if (isElectron() && isConnectionIssue) {
        console.warn('[Schema Bootstrap] Database is unreachable. Bypassing to support offline mode:', compare.error);
        schemaCheckedUserRef.current = session.user.id;
        setSchemaBootstrapLoading(false);
        return;
      }

      setSchemaBootstrapLoading(false);
      setSchemaBootstrapError(compare.error || 'Failed to compare database structure.');
      return;
    }

    // Bypass script updates if table structure is already up-to-date
    if (compare.upToDate) {
      console.log('[Schema Bootstrap] Database structure is up-to-date. Skipping statement-by-statement integrity execution on startup.');
      schemaCheckedUserRef.current = session.user.id;
      setSchemaBootstrapLoading(false);
      return;
    }

    setSchemaBootstrapMessage(`Ensuring database integrity...`);

    const update = await ensureDatabaseSchema(config.url, config.anonKey, (label) => {
      setSchemaBootstrapMessage(label);
    });

    if (!update.success) {
      setSchemaBootstrapLoading(false);
      setSchemaBootstrapError(update.error || 'Failed to auto-update database structure.');
      return;
    }

    schemaCheckedUserRef.current = session.user.id;
    setSchemaBootstrapLoading(false);
  }, [session?.user?.id, isConfigured]);

  useEffect(() => {
    if (session?.user?.id && landingSkipped) {
      runSchemaBootstrap();
    } else {
      schemaCheckedUserRef.current = null;
      setSchemaBootstrapError(null);
      setSchemaBootstrapLoading(false);
    }
  }, [session?.user?.id, landingSkipped, runSchemaBootstrap]);

  if (loading || schemaBootstrapLoading) {
    return (
      <div className="h-screen w-screen flex flex-col items-center justify-center bg-[#050505] text-white select-none relative overflow-hidden font-sans">
        {/* Style block for advanced custom CSS animations (shimmer, dash offset, orb rotation) */}
        <style dangerouslySetInnerHTML={{__html: `
          @keyframes border-shimmer {
            0% { transform: translateX(-100%); }
            100% { transform: translateX(100%); }
          }
          @keyframes pulse-ring {
            0% { transform: scale(0.95); opacity: 0.2; }
            50% { transform: scale(1.05); opacity: 0.6; }
            100% { transform: scale(0.95); opacity: 0.2; }
          }
          @keyframes orbit {
            0% { transform: rotate(0deg); }
            100% { transform: rotate(360deg); }
          }
          .animate-border-shimmer {
            animation: border-shimmer 2.5s cubic-bezier(0.4, 0, 0.2, 1) infinite;
          }
          .animate-pulse-ring {
            animation: pulse-ring 3s ease-in-out infinite;
          }
          .animate-orbit {
            animation: orbit 8s linear infinite;
          }
        `}} />

        {/* Ambient background glows */}
        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[350px] h-[350px] bg-[var(--brand)]/5 rounded-full blur-[80px] pointer-events-none" />
        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[180px] h-[180px] bg-blue-500/5 rounded-full blur-[60px] pointer-events-none" />

        {/* Technical grid lines in the background */}
        <div className="absolute inset-0 bg-[linear-gradient(to_right,rgba(255,255,255,0.01)_1px,transparent_1px),linear-gradient(to_bottom,rgba(255,255,255,0.01)_1px,transparent_1px)] bg-[size:32px_32px] pointer-events-none" />

        <div className="relative flex flex-col items-center justify-center space-y-8 z-10">
          {/* Futuristic Circular Loading Unit */}
          <div className="relative w-32 h-32 flex items-center justify-center">
            {/* Outer dotted tech ring (rotates slowly) */}
            <svg className="absolute w-full h-full animate-[spin_24s_linear_infinite]" viewBox="0 0 100 100">
              <circle 
                cx="50" 
                cy="50" 
                r="46" 
                stroke="var(--brand)" 
                strokeWidth="1" 
                strokeDasharray="2, 6" 
                fill="none" 
                className="opacity-40"
              />
            </svg>

            {/* Middle segmented technical ring (rotates counter-clockwise) */}
            <svg className="absolute w-[90%] h-[90%] animate-[spin_10s_linear_infinite_reverse]" viewBox="0 0 100 100">
              <circle 
                cx="50" 
                cy="50" 
                r="44" 
                stroke="var(--brand)" 
                strokeWidth="1.5" 
                strokeDasharray="25, 40, 10, 15" 
                fill="none" 
                className="opacity-60"
              />
            </svg>

            {/* Inner glowing pulse ring */}
            <div className="absolute w-[76%] h-[76%] border border-blue-500/30 rounded-full animate-pulse-ring" />

            {/* Small technical orbits */}
            <div className="absolute w-full h-full animate-orbit">
              <div className="absolute top-0 left-1/2 -translate-x-1/2 w-1.5 h-1.5 rounded-full bg-[var(--brand)] shadow-[0_0_8px_var(--brand)]" />
            </div>

            {/* Central Gimay glowing terminal brand-mark */}
            <div className="relative w-14 h-14 rounded-xl bg-black border border-white/10 flex items-center justify-center shadow-[0_0_25px_rgba(62,207,142,0.15)] overflow-hidden">
              {/* Internal abstract pattern */}
              <div className="absolute inset-0 bg-gradient-to-tr from-[var(--brand)]/5 via-transparent to-blue-500/5" />
              <svg 
                width="20" 
                height="20" 
                viewBox="0 0 24 24" 
                fill="none" 
                stroke="var(--brand)" 
                strokeWidth="2.5" 
                strokeLinecap="round" 
                strokeLinejoin="round"
                className="drop-shadow-[0_0_8px_rgba(62,207,142,0.6)]"
              >
                <polyline points="4 17 10 11 4 5" />
                <line x1="12" y1="19" x2="20" y2="19" className="animate-pulse" />
              </svg>
            </div>
          </div>

          {/* Dynamic Technical Status Indicators */}
          <div className="flex flex-col items-center space-y-4 max-w-xs w-full">
            {/* Minimal glowing progress line */}
            <div className="w-48 h-[2px] bg-white/[0.04] rounded-full overflow-hidden relative border border-white/[0.02]">
              <div className="absolute top-0 bottom-0 left-0 w-full bg-gradient-to-r from-transparent via-[var(--brand)] to-transparent animate-border-shimmer" />
            </div>

            {/* Status title with dynamic system messages */}
            <div className="flex flex-col items-center space-y-1">
              <span className="text-[10px] font-black text-white uppercase tracking-[0.25em] font-display">
                Gimay Command Node
              </span>
              <p className="text-[8px] font-bold text-[var(--brand)] uppercase tracking-[0.2em] font-mono text-center opacity-90 min-h-[12px] animate-pulse">
                {loading ? 'INITIALIZING SUBSYSTEMS...' : schemaBootstrapMessage.toUpperCase()}
              </p>
            </div>

            {/* Interactive tactical diagnostics hud */}
            <div className="grid grid-cols-2 gap-x-6 gap-y-1.5 pt-4 border-t border-white/[0.05] w-full text-[7px] font-bold font-mono text-[#555555]">
              <div className="flex items-center justify-between">
                <span>SYS.CORE</span>
                <span className="text-[#3ECF8E]/80 animate-pulse">● READY</span>
              </div>
              <div className="flex items-center justify-between">
                <span>NET.CONN</span>
                <span className={typeof navigator !== 'undefined' && !navigator.onLine ? "text-amber-500" : "text-[#3ECF8E]/80 animate-pulse"}>
                  {typeof navigator !== 'undefined' && !navigator.onLine ? "▲ OFFLINE" : "● ONLINE"}
                </span>
              </div>
              <div className="flex items-center justify-between">
                <span>DB.SCHEMA</span>
                <span className={schemaBootstrapLoading ? "text-blue-400 animate-pulse" : "text-[#3ECF8E]/80"}>
                  {schemaBootstrapLoading ? "◌ SYNCING" : "● VERIFIED"}
                </span>
              </div>
              <div className="flex items-center justify-between">
                <span>ENV.SECURE</span>
                <span className="text-[#3ECF8E]/80">● ACTIVE</span>
              </div>
            </div>
          </div>
        </div>
      </div>
    );
  }

  if (schemaBootstrapError && session && isConfigured) {
    return (
      <div className="h-screen w-screen flex flex-col items-center justify-center bg-[var(--bg-deep)] px-6">
        <p className="text-xs font-black text-red-400 uppercase tracking-widest">Schema Check Failed</p>
        <p className="mt-3 text-sm text-[var(--text-muted)] max-w-xl text-center">{schemaBootstrapError}</p>
        <button
          onClick={runSchemaBootstrap}
          className="mt-6 px-4 py-2 rounded-lg bg-[var(--brand)] text-black text-xs font-bold uppercase tracking-wider"
        >
          Retry Auto Update
        </button>
      </div>
    );
  }

  if (!landingSkipped) {
    return (
      <LandingPage 
        onStart={() => {
          if (!isElectron()) {
            window.history.pushState(null, '', '/app');
          }
          setLandingSkipped(true);
        }} 
      />
    );
  }

  return (
    <>
      <ToastContainer />
      {!session && <AuthUI onOfflineMode={handleOfflineMode} />}
      {session && !isConfigured && <OnboardingModal />}
      {session && isConfigured && <RootLayout />}
    </>
  );
}

import React from 'react';
import { AuthConfig, AuthType } from '../types';
import { cn } from '../lib/utils';
import { Shield, Key, Lock, User, Globe, ChevronDown, Zap } from 'lucide-react';

interface AuthEditorProps {
  auth: AuthConfig;
  onChange: (auth: AuthConfig) => void;
  hideInherit?: boolean;
}

export const AuthEditor: React.FC<AuthEditorProps> = ({ auth, onChange, hideInherit }) => {
  if (!auth) {
    return (
      <div className="flex flex-col items-center justify-center p-8 border border-dashed border-[#222222] rounded-xl bg-[#0F0F0F] opacity-50">
        <Shield size={24} className="mb-2 text-[#555555]" />
        <p className="text-[10px] font-black uppercase tracking-widest text-[#555555]">Initializing Auth Protocol...</p>
      </div>
    );
  }

  const handleTypeChange = (type: AuthType) => {
    const newAuth = { ...auth, type };
    if (type === 'apikey' && !newAuth.apiKey) {
      newAuth.apiKey = { key: 'x-api-key', value: '', addTo: 'header' };
    }
    if (type === 'basic' && !newAuth.basic) {
      newAuth.basic = { username: '', password: '' };
    }
    if (type === 'oauth2' && !newAuth.oauth2) {
      newAuth.oauth2 = { accessToken: '', tokenType: 'Bearer' };
    }
    onChange(newAuth);
  };

  return (
    <div className="space-y-6 max-w-2xl">
      <div className="flex flex-col gap-2">
        <label className="text-[9px] font-black text-[#555555] uppercase tracking-[0.2em]">Auth Protocol</label>
        <div className="relative group">
          <select 
            value={auth.type}
            onChange={(e) => handleTypeChange(e.target.value as AuthType)}
            className="w-full bg-[#111111] border border-[#222222] rounded-lg px-4 py-3 text-[11px] font-bold text-white uppercase tracking-widest appearance-none focus:border-[#3ECF8E]/50 outline-none transition-all cursor-pointer"
          >
            <option value="none">No Auth</option>
            {!hideInherit && <option value="inherit">Inherit from parent</option>}
            <option value="bearer">Bearer Token</option>
            <option value="basic">Basic Auth</option>
            <option value="apikey">API Key</option>
            <option value="oauth2">OAuth 2.0</option>
          </select>
          <ChevronDown size={14} className="absolute right-4 top-1/2 -translate-y-1/2 text-[#444444] pointer-events-none" />
        </div>
      </div>

      <div className="p-6 bg-[#0F0F0F] border border-[#222222] rounded-xl space-y-6">
        {auth.type === 'none' && (
          <div className="flex flex-col items-center py-8 opacity-20">
            <Globe size={32} className="mb-2" />
            <p className="text-[10px] font-black uppercase tracking-widest">Public Transmission</p>
          </div>
        )}

        {auth.type === 'inherit' && (
          <div className="space-y-2">
            <div className="flex items-center gap-2 text-[#3ECF8E]">
              <Shield size={14} />
              <p className="text-[11px] font-bold uppercase tracking-widest">Inheriting Sector Clearances</p>
            </div>
            <p className="text-[10px] text-[#555555] leading-relaxed">
              This request will use the authorization settings defined in the parent folder or collection.
            </p>
          </div>
        )}

        {auth.type === 'bearer' && (
          <div className="space-y-3">
            <label className="text-[9px] font-black text-[#555555] uppercase tracking-widest">Token</label>
            <div className="relative">
              <Key size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-[#333333]" />
              <input 
                type="text"
                value={auth.bearer || ''}
                onChange={(e) => onChange({ ...auth, bearer: e.target.value })}
                placeholder="BEARER_TOKEN..."
                className="w-full bg-[#1A1A1A] border border-[#222222] rounded-lg pl-10 pr-4 py-3 text-[11px] font-mono text-white placeholder:text-[#333333] focus:border-[#3ECF8E]/50 outline-none transition-all"
              />
            </div>
          </div>
        )}

        {auth.type === 'oauth2' && (
          <div className="space-y-3">
            <label className="text-[9px] font-black text-[#555555] uppercase tracking-widest">Access Token</label>
            <div className="relative">
              <Zap size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-[#333333]" />
              <input 
                type="text"
                value={auth.oauth2?.accessToken || ''}
                onChange={(e) => onChange({ ...auth, oauth2: { ...auth.oauth2, accessToken: e.target.value } as any })}
                placeholder="ACCESS_TOKEN..."
                className="w-full bg-[#1A1A1A] border border-[#222222] rounded-lg pl-10 pr-4 py-3 text-[11px] font-mono text-white placeholder:text-[#333333] focus:border-[#3ECF8E]/50 outline-none transition-all"
              />
            </div>
            <div className="flex items-center gap-2 mt-2">
               <div className="px-2 py-1 bg-[#1A1A1A] border border-[#222222] rounded text-[8px] font-bold text-[#555555] uppercase">
                 Type: {auth.oauth2?.tokenType || 'Bearer'}
               </div>
               <p className="text-[9px] text-[#333333] uppercase italic">Advanced OAuth2 Handshake protocols coming soon...</p>
            </div>
          </div>
        )}

        {auth.type === 'basic' && (
          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-2">
              <label className="text-[9px] font-black text-[#555555] uppercase tracking-widest">Username</label>
              <div className="relative">
                <User size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-[#333333]" />
                <input 
                  type="text"
                  value={auth.basic?.username || ''}
                  onChange={(e) => onChange({ ...auth, basic: { ...auth.basic, username: e.target.value } as any })}
                  placeholder="USERNAME..."
                  className="w-full bg-[#1A1A1A] border border-[#222222] rounded-lg pl-10 pr-4 py-3 text-[11px] font-mono text-white placeholder:text-[#333333] focus:border-[#3ECF8E]/50 outline-none transition-all"
                />
              </div>
            </div>
            <div className="space-y-2">
              <label className="text-[9px] font-black text-[#555555] uppercase tracking-widest">Password</label>
              <div className="relative">
                <Lock size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-[#333333]" />
                <input 
                  type="password"
                  value={auth.basic?.password || ''}
                  onChange={(e) => onChange({ ...auth, basic: { ...auth.basic, password: e.target.value } as any })}
                  placeholder="PASSWORD..."
                  className="w-full bg-[#1A1A1A] border border-[#222222] rounded-lg pl-10 pr-4 py-3 text-[11px] font-mono text-white placeholder:text-[#333333] focus:border-[#3ECF8E]/50 outline-none transition-all"
                />
              </div>
            </div>
          </div>
        )}

        {auth.type === 'apikey' && (
          <div className="space-y-4">
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-2">
                <label className="text-[9px] font-black text-[#555555] uppercase tracking-widest">Key</label>
                <input 
                  type="text"
                  value={auth.apiKey?.key || ''}
                  onChange={(e) => onChange({ ...auth, apiKey: { ...auth.apiKey, key: e.target.value } as any })}
                  placeholder="x-api-key"
                  className="w-full bg-[#1A1A1A] border border-[#222222] rounded-lg px-4 py-3 text-[11px] font-mono text-white placeholder:text-[#333333] focus:border-[#3ECF8E]/50 outline-none transition-all"
                />
              </div>
              <div className="space-y-2">
                <label className="text-[9px] font-black text-[#555555] uppercase tracking-widest">Value</label>
                <input 
                  type="text"
                  value={auth.apiKey?.value || ''}
                  onChange={(e) => onChange({ ...auth, apiKey: { ...auth.apiKey, value: e.target.value } as any })}
                  placeholder="API_KEY_VALUE..."
                  className="w-full bg-[#1A1A1A] border border-[#222222] rounded-lg px-4 py-3 text-[11px] font-mono text-white placeholder:text-[#333333] focus:border-[#3ECF8E]/50 outline-none transition-all"
                />
              </div>
            </div>
            <div className="space-y-2">
              <label className="text-[9px] font-black text-[#555555] uppercase tracking-widest">Add To</label>
              <div className="flex gap-2">
                {['header', 'query'].map((pos) => (
                  <button 
                    key={pos}
                    onClick={() => onChange({ ...auth, apiKey: { ...auth.apiKey, addTo: pos as any } as any })}
                    className={cn(
                      "px-4 py-1.5 rounded-lg text-[9px] font-black uppercase tracking-widest border transition-all",
                      auth.apiKey?.addTo === pos ? "bg-[#3ECF8E] text-[#111111] border-[#3ECF8E]" : "border-[#222222] text-[#555555] hover:border-[#444444]"
                    )}
                  >
                    {pos}
                  </button>
                ))}
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

import { useMemo, useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'motion/react';
import { 
  Upload, 
  ClipboardPaste, 
  FileJson, 
  X, 
  AlertTriangle, 
  Folder, 
  ChevronDown, 
  ChevronRight,
  Sparkles,
  Check,
  CircleDot
} from 'lucide-react';
import { cn } from '../lib/utils';
import { CollectionImportService, ImportFormat, ImportPreview, ImportNode } from '../services/CollectionImportService';

interface CollectionImportModalProps {
  isOpen: boolean;
  onClose: () => void;
  workspaceId?: string | null;
  userId?: string | null;
  onImported?: () => Promise<void> | void;
  addToast?: (toast: { type: 'success' | 'error' | 'info' | 'warning'; message: string }) => void;
}

type SourceOption = 'auto' | ImportFormat;

const SOURCE_CARDS: Array<{
  id: SourceOption;
  title: string;
  subtitle: string;
  mark: string;
  brandColor: string;
  bgGlow: string;
  borderColor: string;
  markClass: string;
  features: string;
}> = [
  {
    id: 'postman',
    title: 'Postman',
    subtitle: 'Collection v2+',
    mark: 'PM',
    brandColor: '#FF6C37',
    bgGlow: 'hover:shadow-[0_0_25px_rgba(255,108,55,0.06)] hover:bg-[#FF6C37]/5',
    borderColor: 'peer-checked:border-[#FF6C37]/50 active:border-[#FF6C37]/50',
    markClass: 'bg-orange-500/10 text-orange-400 border-orange-500/20',
    features: 'Folders, variables, pre-test scripts',
  },
  {
    id: 'apidog',
    title: 'API Dog',
    subtitle: 'Project JSON',
    mark: 'AD',
    brandColor: '#00B4D8',
    bgGlow: 'hover:shadow-[0_0_25px_rgba(0,180,216,0.06)] hover:bg-[#00B4D8]/5',
    borderColor: 'peer-checked:border-[#00B4D8]/50 active:border-[#00B4D8]/50',
    markClass: 'bg-cyan-500/10 text-cyan-400 border-cyan-500/20',
    features: 'Folders, headers, query parameters',
  },
  {
    id: 'insomnia',
    title: 'Insomnia',
    subtitle: 'Resources',
    mark: 'IN',
    brandColor: '#5856D6',
    bgGlow: 'hover:shadow-[0_0_25px_rgba(88,86,214,0.06)] hover:bg-[#5856D6]/5',
    borderColor: 'peer-checked:border-[#5856D6]/50 active:border-[#5856D6]/50',
    markClass: 'bg-indigo-500/10 text-indigo-300 border-indigo-500/20',
    features: 'Groups, environment values',
  },
  {
    id: 'auto',
    title: 'Auto Detect',
    subtitle: 'Recommended',
    mark: 'AUTO',
    brandColor: '#3ECF8E',
    bgGlow: 'hover:shadow-[0_0_25px_rgba(62,207,142,0.08)] hover:bg-[#3ECF8E]/5',
    borderColor: 'peer-checked:border-[#3ECF8E]/50 active:border-[#3ECF8E]/50',
    markClass: 'bg-[#3ECF8E]/10 text-[#3ECF8E] border-[#3ECF8E]/20',
    features: 'Auto-detect Postman / API Dog / Insomnia',
  },
];

export const CollectionImportModal: React.FC<CollectionImportModalProps> = ({
  isOpen,
  onClose,
  workspaceId,
  userId,
  onImported,
  addToast,
}) => {
  const [source, setSource] = useState<SourceOption>('auto');
  const [raw, setRaw] = useState('');
  const [isDragging, setIsDragging] = useState(false);
  const [isPreviewing, setIsPreviewing] = useState(false);
  const [isImporting, setIsImporting] = useState(false);
  const [preview, setPreview] = useState<ImportPreview | null>(null);
  const [error, setError] = useState<string | null>(null);

  // Tree selection state
  const [selectedNodeIds, setSelectedNodeIds] = useState<Set<string>>(new Set());
  const [expandedNodes, setExpandedNodes] = useState<Record<string, boolean>>({});

  const canImport = !!workspaceId && !!userId && !!preview && selectedNodeIds.size > 0 && !isImporting;

  const selectedCard = useMemo(
    () => SOURCE_CARDS.find((card) => card.id === source) || SOURCE_CARDS[SOURCE_CARDS.length - 1],
    [source]
  );

  const resetState = () => {
    setRaw('');
    setPreview(null);
    setError(null);
    setIsPreviewing(false);
    setIsImporting(false);
    setSource('auto');
    setIsDragging(false);
    setSelectedNodeIds(new Set());
    setExpandedNodes({});
  };

  const handleClose = () => {
    resetState();
    onClose();
  };

  // Debounced auto-preview compiler
  useEffect(() => {
    if (!raw.trim()) {
      setPreview(null);
      setError(null);
      setSelectedNodeIds(new Set());
      return;
    }

    setIsPreviewing(true);
    const timer = setTimeout(() => {
      try {
        const p = CollectionImportService.previewImport(raw, source);
        setPreview(p);
        setError(null);

        // Populate tree checkbox state automatically
        const allIds: string[] = [];
        const collectIds = (nodes: ImportNode[]) => {
          nodes.forEach((n) => {
            if (n.id) allIds.push(n.id);
            if (n.type === 'folder') collectIds(n.children);
          });
        };
        collectIds(p.normalized.items);
        setSelectedNodeIds(new Set(allIds));
      } catch (e: any) {
        setPreview(null);
        setError(e?.message || 'Invalid export syntax or unsupported document format.');
      } finally {
        setIsPreviewing(false);
      }
    }, 400);

    return () => clearTimeout(timer);
  }, [raw, source]);

  const handleFile = async (file: File) => {
    try {
      const text = await file.text();
      setRaw(text);
      setError(null);
    } catch {
      setError('Could not process the uploaded file. Ensure it is a valid text or JSON document.');
    }
  };

  const handleToggleNode = (node: ImportNode, isChecked: boolean) => {
    if (!preview) return;
    const nextSelected = new Set(selectedNodeIds);

    // 1. Cascade downwards
    const toggleDown = (n: ImportNode, checked: boolean) => {
      if (n.id) {
        if (checked) nextSelected.add(n.id);
        else nextSelected.delete(n.id);
      }
      if (n.type === 'folder') {
        n.children.forEach((child) => toggleDown(child, checked));
      }
    };
    toggleDown(node, isChecked);

    // 2. Resolve parents recursively upward
    const buildParentMap = () => {
      const parentMap = new Map<string, ImportNode>();
      const traverse = (n: ImportNode, parent?: ImportNode) => {
        if (n.id && parent) parentMap.set(n.id, parent);
        if (n.type === 'folder') {
          n.children.forEach((c) => traverse(c, n));
        }
      };
      preview.normalized.items.forEach((item) => traverse(item));
      return parentMap;
    };

    const parentMap = buildParentMap();

    if (isChecked) {
      // Checked leaves must hydrate parents
      let curr = node.id ? parentMap.get(node.id) : null;
      while (curr) {
        if (curr.id) nextSelected.add(curr.id);
        curr = curr.id ? parentMap.get(curr.id) : null;
      }
    } else {
      // Uncheck parent if all children are unchecked
      let curr = node.id ? parentMap.get(node.id) : null;
      while (curr) {
        if (curr.type === 'folder') {
          const hasSelectedChildren = curr.children.some((c) => c.id && nextSelected.has(c.id));
          if (!hasSelectedChildren && curr.id) {
            nextSelected.delete(curr.id);
          }
        }
        curr = curr.id ? parentMap.get(curr.id) : null;
      }
    }

    setSelectedNodeIds(nextSelected);
  };

  const handleSelectAll = () => {
    if (!preview) return;
    const allIds: string[] = [];
    const collectIds = (nodes: ImportNode[]) => {
      nodes.forEach((n) => {
        if (n.id) allIds.push(n.id);
        if (n.type === 'folder') collectIds(n.children);
      });
    };
    collectIds(preview.normalized.items);
    setSelectedNodeIds(new Set(allIds));
  };

  const handleSelectNone = () => {
    setSelectedNodeIds(new Set());
  };

  // Count active requests selected
  const selectedRequestsCount = useMemo(() => {
    if (!preview) return 0;
    let count = 0;
    const traverse = (nodes: ImportNode[]) => {
      nodes.forEach((n) => {
        if (n.id && selectedNodeIds.has(n.id)) {
          if (n.type === 'request') count++;
          else if (n.type === 'folder') traverse(n.children);
        }
      });
    };
    traverse(preview.normalized.items);
    return count;
  }, [preview, selectedNodeIds]);

  const handleImport = async () => {
    if (!canImport || !workspaceId || !userId) return;

    setIsImporting(true);
    setError(null);
    try {
      const selectedArray = Array.from(selectedNodeIds);
      const result = await CollectionImportService.importCollection(
        raw,
        workspaceId,
        userId,
        source,
        selectedArray
      );
      await onImported?.();
      addToast?.({
        type: 'success',
        message: `Successfully integrated '${result.collection.name}' (${selectedRequestsCount} requests established).`,
      });
      handleClose();
    } catch (e: any) {
      const message = e?.message || 'Import transaction failed. Structure may violate standard schema constraints.';
      setError(message);
      addToast?.({ type: 'error', message });
    } finally {
      setIsImporting(false);
    }
  };

  // Recursive Tree Node Renderer
  const renderTreeNode = (node: ImportNode, depth = 0) => {
    if (!node.id) return null;
    const isFolder = node.type === 'folder';
    const isExpanded = expandedNodes[node.id] ?? true;
    const isChecked = selectedNodeIds.has(node.id);

    const toggleExpand = (e: React.MouseEvent) => {
      e.stopPropagation();
      if (node.id) {
        setExpandedNodes((prev) => ({ ...prev, [node.id!]: !isExpanded }));
      }
    };

    const getMethodStyle = (method: string) => {
      const m = method.toUpperCase();
      if (m === 'GET') return 'text-[#3ECF8E] bg-[#3ECF8E]/8 border-[#3ECF8E]/15';
      if (m === 'POST') return 'text-[#FF9F0A] bg-[#FF9F0A]/8 border-[#FF9F0A]/15';
      if (m === 'PUT') return 'text-[#0A84FF] bg-[#0A84FF]/8 border-[#0A84FF]/15';
      if (m === 'PATCH') return 'text-[#BF5AF2] bg-[#BF5AF2]/8 border-[#BF5AF2]/15';
      if (m === 'DELETE') return 'text-[#FF453A] bg-[#FF453A]/8 border-[#FF453A]/15';
      return 'text-zinc-400 bg-zinc-500/8 border-zinc-500/15';
    };

    return (
      <div key={node.id} className="select-none text-[10px] uppercase font-bold tracking-wide">
        <div
          className={cn(
            'flex items-center gap-3 py-2 px-3 rounded-lg hover:bg-white/[0.02] cursor-pointer transition-all duration-150 border border-transparent',
            isChecked ? 'text-white' : 'text-zinc-500'
          )}
          onClick={() => handleToggleNode(node, !isChecked)}
          style={{ paddingLeft: `${depth * 20 + 12}px` }}
        >
          {/* Custom Checkbox indicator with elastic pops */}
          <div className="flex items-center justify-center transition-all duration-200">
            <div 
              className={cn(
                "w-4 h-4 rounded-md border flex items-center justify-center transition-all duration-200",
                isChecked 
                  ? "bg-[#3ECF8E] border-[#3ECF8E] shadow-[0_0_10px_rgba(62,207,142,0.25)]" 
                  : "border-zinc-700 bg-zinc-950/80 hover:border-zinc-500"
              )}
            >
              {isChecked && <Check size={10} className="text-[#0A0A0A] stroke-[4]" />}
            </div>
          </div>

          {isFolder ? (
            <>
              <button
                onClick={toggleExpand}
                className="p-0.5 text-zinc-600 hover:text-white transition-colors flex items-center justify-center"
              >
                {isExpanded ? <ChevronDown size={13} /> : <ChevronRight size={13} />}
              </button>
              <Folder size={13} className={cn(isChecked ? 'text-[#3ECF8E]' : 'text-zinc-600')} />
              <span className="truncate tracking-wide font-sans normal-case text-zinc-200">{node.name}</span>
            </>
          ) : (
            <>
              <span className="w-[18px]" />
              <span
                className={cn(
                  'px-1.5 py-0.5 text-[8px] font-black rounded border leading-none font-mono tracking-wider text-center w-12',
                  getMethodStyle(node.request.method)
                )}
              >
                {node.request.method}
              </span>
              <span className="truncate font-sans normal-case tracking-wide text-zinc-200">{node.name}</span>
              <span className="text-[8px] font-mono text-zinc-600 truncate normal-case tracking-tight ml-auto max-w-[260px] pl-3">
                {node.request.url || 'no endpoint'}
              </span>
            </>
          )}
        </div>

        {isFolder && isExpanded && (
          <div className="border-l border-zinc-800/40 ml-[23px] mt-0.5 mb-1 space-y-0.5">
            {node.children.map((child) => renderTreeNode(child, depth + 1))}
          </div>
        )}
      </div>
    );
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-[500] flex items-center justify-center p-4">
      <motion.div
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        exit={{ opacity: 0 }}
        onClick={handleClose}
        className="absolute inset-0 bg-[#000000]/85 backdrop-blur-md"
      />

      <motion.div
        initial={{ opacity: 0, scale: 0.97, y: 12 }}
        animate={{ opacity: 1, scale: 1, y: 0 }}
        exit={{ opacity: 0, scale: 0.97, y: 12 }}
        className="relative w-full max-w-4xl bg-[#0F0F11]/95 border border-white/[0.05] rounded-2xl shadow-[0_30px_70px_rgba(0,0,0,0.8)] overflow-hidden flex flex-col max-h-[85vh] backdrop-blur-xl"
      >
        {/* Futuristic Background Gradients */}
        <div className="absolute top-0 right-0 w-80 h-80 bg-[#3ECF8E]/[0.02] rounded-full blur-[100px] pointer-events-none" />
        <div className="absolute bottom-0 left-0 w-80 h-80 bg-indigo-500/[0.01] rounded-full blur-[100px] pointer-events-none" />

        {/* Header */}
        <div className="px-6 py-5 border-b border-white/[0.04] flex items-center justify-between bg-black/25 shrink-0 z-10">
          <div>
            <div className="flex items-center gap-2">
              <span className="w-1.5 h-1.5 rounded-full bg-[#3ECF8E] animate-pulse" />
              <h2 className="text-[13px] font-black text-white uppercase tracking-[0.2em]">Import Collection</h2>
            </div>
            <p className="text-[9px] text-zinc-500 uppercase tracking-wider mt-1">
              Supports Postman, Insomnia, and API Dog. Automatic parsing with interactive selective tree importing.
            </p>
          </div>
          <button 
            onClick={handleClose} 
            className="w-7 h-7 rounded-lg border border-white/[0.03] bg-white/[0.01] flex items-center justify-center text-zinc-500 hover:text-white hover:border-white/[0.1] hover:bg-white/[0.04] transition-all"
          >
            <X size={15} />
          </button>
        </div>

        {/* Modal Main Content Area */}
        <div className="p-6 space-y-6 overflow-y-auto no-scrollbar flex-1 z-10 bg-transparent">
          {/* Integration source selector */}
          <div className="grid grid-cols-1 md:grid-cols-4 gap-3 shrink-0">
            {SOURCE_CARDS.map((card) => (
              <button
                key={card.id}
                onClick={() => {
                  setSource(card.id);
                  setPreview(null);
                  setError(null);
                }}
                className={cn(
                  'relative text-left p-3.5 rounded-xl border transition-all duration-300',
                  source === card.id
                    ? 'border-white/[0.08] bg-white/[0.02] shadow-[inset_0_1px_1px_rgba(255,255,255,0.05)]'
                    : 'border-white/[0.03] bg-black/40 hover:border-white/[0.06]',
                  card.bgGlow
                )}
              >
                {/* Active Indicator bar */}
                {source === card.id && (
                  <motion.div 
                    layoutId="activeGlowBar"
                    className="absolute inset-x-4 -bottom-px h-0.5 rounded-full"
                    style={{ backgroundColor: card.brandColor }}
                  />
                )}
                
                <div className="flex items-center gap-2.5 mb-2.5">
                  <div className={cn('px-1.5 py-0.5 text-[8px] font-black rounded border tracking-widest leading-none', card.markClass)}>
                    {card.mark}
                  </div>
                  <div>
                    <div className="text-[10px] font-black text-white uppercase tracking-wider">{card.title}</div>
                    <div className="text-[8px] text-zinc-500 uppercase tracking-widest mt-0.5">{card.subtitle}</div>
                  </div>
                </div>
                <div className="text-[8px] text-zinc-400 font-sans tracking-wide leading-relaxed">{card.features}</div>
              </button>
            ))}
          </div>

          {/* Interactive Dropzone */}
          <div
            onDragOver={(e) => {
              e.preventDefault();
              setIsDragging(true);
            }}
            onDragLeave={(e) => {
              e.preventDefault();
              setIsDragging(false);
            }}
            onDrop={(e) => {
              e.preventDefault();
              setIsDragging(false);
              const file = e.dataTransfer.files?.[0];
              if (file) void handleFile(file);
            }}
            className={cn(
              'rounded-xl border-2 border-dashed p-4 transition-all duration-300 shrink-0 relative overflow-hidden',
              isDragging 
                ? 'border-[#3ECF8E] bg-[#3ECF8E]/[0.03]' 
                : 'border-white/[0.04] bg-black/35 hover:border-white/[0.07]'
            )}
          >
            <div className="flex flex-col md:flex-row gap-3 items-center justify-between z-10 relative">
              <div className="flex items-center gap-3.5">
                <div className={cn(
                  "w-11 h-11 rounded-xl flex items-center justify-center border transition-all duration-300",
                  isDragging ? "bg-[#3ECF8E]/10 border-[#3ECF8E]/20" : "bg-white/[0.01] border-white/[0.04]"
                )}>
                  <FileJson size={18} className={cn(isDragging ? "text-[#3ECF8E]" : "text-zinc-400")} />
                </div>
                <div>
                  <div className="text-[11px] font-black text-white uppercase tracking-widest">Drop JSON / Export Payload</div>
                  <div className="text-[8px] text-zinc-500 uppercase tracking-widest mt-0.5">
                    Drag collection exports here, or click to upload from disk
                  </div>
                </div>
              </div>
              
              <label className="px-4 py-2 rounded-lg border border-white/[0.05] bg-white/[0.02] hover:bg-white/[0.05] hover:border-white/[0.1] active:scale-95 cursor-pointer text-[9px] font-black text-zinc-300 hover:text-white uppercase tracking-wider transition-all">
                <input
                  type="file"
                  accept=".json,application/json,text/plain"
                  className="hidden"
                  onChange={(e) => {
                    const file = e.target.files?.[0];
                    if (file) void handleFile(file);
                    e.currentTarget.value = '';
                  }}
                />
                <span className="inline-flex items-center gap-2">
                  <Upload size={11} /> Browse File
                </span>
              </label>
            </div>

            {/* Pasting Editor Area */}
            <div className="mt-4 border border-white/[0.04] rounded-xl overflow-hidden bg-black/45 shadow-inner">
              <div className="px-3.5 py-2.5 bg-white/[0.01] border-b border-white/[0.04] flex items-center justify-between text-[9px] text-zinc-500 uppercase tracking-widest font-black">
