  });
  const [error, setError] = useState<string | null>(null);

  const resetState = () => {
    setTargetUrl('');
    setTargetServiceKey('');
    setIsMigrating(false);
    setProgress({ step: 'idle', message: '', percent: 0 });
    setError(null);
