import React, { useState, useMemo, useEffect } from 'react';
import { motion } from 'motion/react';
import { X, Globe, Download, Upload, Search, Code2, BookOpen } from 'lucide-react';
import { useStore } from '../store/useStore';
import { useDataSync } from '../hooks/useDataSync';
import { PersistenceService } from '../services/PersistenceService';
import { KeyValue, Environment } from '../types';
import { KVEditor } from './KVEditor';
import { cn } from '../lib/utils';
import { EnvironmentBulkModal } from './EnvironmentBulkModal';

interface EnvironmentModalProps {
  isOpen: boolean;
  onClose: () => void;
  environment?: Environment;
  isGlobal?: boolean;
}

export const EnvironmentModal: React.FC<EnvironmentModalProps> = ({ isOpen, onClose, environment, isGlobal = false }) => {
  const { profile, activeWorkspaceId, addToast, updateEnvironment, setEnvironments, globalVariables, setGlobalVariables } = useStore();
  const { fetchEnvironments } = useDataSync();
  
  const [activeTab, setActiveTab] = useState<'variables' | 'scripts' | 'docs'>('variables');
  const [name, setName] = useState(isGlobal ? 'Globals' : (environment?.name || ''));
  const [variables, setVariables] = useState<KeyValue[]>(isGlobal ? globalVariables : (environment?.variables || []));
  const [preRequestScript, setPreRequestScript] = useState(environment?.pre_request_script || '');
  const [testScript, setTestScript] = useState(environment?.test_script || '');
  const [documentation, setDocumentation] = useState(environment?.documentation || '');
  const [searchQuery, setSearchQuery] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [isBulkModalOpen, setIsBulkModalOpen] = useState(false);
  const [_bulkModalInitialMode, setBulkModalInitialMode] = useState<'edit' | 'import'>('edit');

  useEffect(() => {
    if (isOpen) {
      setName(isGlobal ? 'Globals' : (environment?.name || ''));
      setVariables(isGlobal ? (globalVariables || []) : (environment?.variables || []));
      setPreRequestScript(environment?.pre_request_script || '');
      setTestScript(environment?.test_script || '');
      setDocumentation(environment?.documentation || '');
      setActiveTab('variables');
      setSearchQuery('');
    }
  }, [isOpen, environment, isGlobal, globalVariables]);

  const _filteredVariables = useMemo(() => {
    if (!variables) return [];
    if (!searchQuery) return variables;
    const query = searchQuery.toLowerCase();
    return variables.filter(v => 
      (v.key || '').toLowerCase().includes(query) || 
      (v.value || '').toLowerCase().includes(query)
    );
  }, [variables, searchQuery]);

  const handleSave = async () => {
    const userId = profile?.id || 'offline-user-id';
    if (!isGlobal && (!name.trim() || !activeWorkspaceId)) return;
    
    setIsLoading(true);
    try {
      if (isGlobal) {
        setGlobalVariables(variables);
        addToast({ type: 'success', message: 'Global variables updated.' });
      } else if (environment?.id) {
        await PersistenceService.updateEnvironment(environment.id, { 
          name, 
          variables,
          pre_request_script: preRequestScript,
          test_script: testScript,
          documentation
        });
        updateEnvironment(environment.id, { 
          name, 
          variables,
          pre_request_script: preRequestScript,
          test_script: testScript,
          documentation
        });
        addToast({ type: 'success', message: 'Environment updated.' });
      } else {
        const created = await PersistenceService.createEnvironment(
          activeWorkspaceId!, 
          userId, 
          name, 
          variables, 
          false, 
          preRequestScript, 
          testScript, 
          documentation
        );
        const currentEnvs = useStore.getState().environments || [];
        if (!currentEnvs.some(e => e.id === created.id)) {
          setEnvironments([...currentEnvs, created]);
        }
        if (activeWorkspaceId) fetchEnvironments?.(activeWorkspaceId);
        addToast({ type: 'success', message: `Environment "${name}" created.` });
      }
      onClose();
    } catch (error) {
      console.error('Environment save error:', error);
      addToast({ type: 'error', message: 'Failed to save environment settings.' });
    } finally {
      setIsLoading(false);
    }
  };

  const exportJson = () => {
    const data = {
      name,
      variables,
      exportedAt: new Date().toISOString(),
      type: isGlobal ? 'globals' : 'environment'
    };
    const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `${name.toLowerCase().replace(/\s+/g, '_')}_env.json`;
    a.click();
    URL.revokeObjectURL(url);
  };

  const importJson = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const data = JSON.parse(event.target?.result as string);
        if (data.variables) {
          setVariables(data.variables);
          if (data.name && !isGlobal) setName(data.name);
          addToast({ type: 'success', message: 'Environment data imported.' });
        }
      } catch (err) {
        addToast({ type: 'error', message: 'Invalid JSON file.' });
      }
    };
    reader.readAsText(file);
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-[500] flex items-center justify-center p-4">
      <motion.div 
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        exit={{ opacity: 0 }}
        onClick={onClose}
        className="absolute inset-0 bg-[#000000]/80 backdrop-blur-sm"
      />
      
      <motion.div
        initial={{ opacity: 0, scale: 0.95, y: 20 }}
        animate={{ opacity: 1, scale: 1, y: 0 }}
        exit={{ opacity: 0, scale: 0.95, y: 20 }}
        className="relative w-full max-w-4xl bg-[#0F0F0F] border border-[#222222] rounded-2xl shadow-2xl overflow-hidden flex flex-col max-h-[85vh]"
      >
        {/* Header */}
        <div className="p-6 border-b border-[#222222] flex items-center justify-between bg-[#0A0A0A]">
          <div className="flex items-center gap-4">
            <div className={cn(
              "w-10 h-10 rounded-xl flex items-center justify-center border",
              isGlobal ? "bg-amber-500/10 border-amber-500/30 text-amber-500" : "bg-[#3ECF8E]/10 border-[#3ECF8E]/30 text-[#3ECF8E]"
            )}>
              <Globe size={20} />
            </div>
            <div>
              <h2 className="text-[14px] font-black text-white uppercase tracking-widest flex items-center gap-2">
                {isGlobal ? 'Global Variable Registry' : (environment ? 'Configure Environment' : 'Initialize Environment')}
              </h2>
              <div className="flex items-center gap-2 mt-1">
                 <span className="text-[9px] text-[#555555] uppercase tracking-tighter">
                   {isGlobal ? 'Workspace-independent variables' : 'Scope: Active Workspace'}
                 </span>
                 <span className="text-[#222222]">|</span>
                 <span className="text-[9px] text-[#3ECF8E] font-bold uppercase tracking-tighter">
                   {variables.length} active parameters
                 </span>
              </div>
            </div>
          </div>
          
          <div className="flex items-center gap-3">
            <button onClick={exportJson} className="p-2 text-[#444444] hover:text-[#3ECF8E] transition-all" title="Export Configuration">
              <Download size={18} />
            </button>
            <label className="p-2 text-[#444444] hover:text-[#3ECF8E] transition-all cursor-pointer" title="Import Configuration">
              <Upload size={18} />
              <input type="file" className="hidden" accept=".json" onChange={importJson} />
            </label>
            <div className="w-px h-6 bg-[#222222] mx-2" />
            <button onClick={onClose} className="text-[#444444] hover:text-white transition-colors">
              <X size={20} />
            </button>
          </div>
        </div>

        {/* Navigation Tabs */}
        {!isGlobal && (
          <div className="flex px-6 border-b border-[#222222] bg-[#0D0D0D]">
            {[
              { id: 'variables', icon: Globe, label: 'Variables' },
              { id: 'scripts', icon: Code2, label: 'Execution Scripts' },
              { id: 'docs', icon: BookOpen, label: 'Documentation' }
            ].map(tab => (
              <button
                key={tab.id}
                onClick={() => setActiveTab(tab.id as any)}
                className={cn(
                  "flex items-center gap-2 px-6 py-4 text-[10px] font-black uppercase tracking-widest transition-all border-b-2",
                  activeTab === tab.id 
                    ? "border-[#3ECF8E] text-[#3ECF8E] bg-[#3ECF8E]/5" 
                    : "border-transparent text-[#444444] hover:text-[#888888]"
                )}
              >
                <tab.icon size={14} />
                {tab.label}
              </button>
            ))}
          </div>
        )}

        {/* Content */}
        <div className="flex-1 overflow-y-auto p-6 space-y-8 custom-scrollbar">
          {activeTab === 'variables' && (
            <div className="space-y-6">
              {!isGlobal && (
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-[#555555] uppercase tracking-widest">Environment Designation</label>
                  <input 
                    value={name}
                    onChange={(e) => setName(e.target.value)}
                    placeholder="ENV_NAME (e.g. Production, Staging)..."
                    className="w-full bg-[#111111] border border-[#222222] px-4 py-3 rounded-lg text-white font-mono text-[11px] focus:outline-none focus:border-[#3ECF8E] transition-all"
                  />
                </div>
              )}

              <div className="space-y-4">
                <div className="flex items-center justify-between">
                  <div className="flex items-center gap-2">
                    <label className="text-[9px] font-black text-[#555555] uppercase tracking-widest">Variable Stack</label>
                    <button
                      type="button"
                      onClick={() => {
                        setBulkModalInitialMode('import');
                        setIsBulkModalOpen(true);
                      }}
                      className="px-2 py-0.5 rounded bg-[#3ECF8E]/10 border border-[#3ECF8E]/20 text-[8px] font-black text-[#3ECF8E] uppercase tracking-wider hover:bg-[#3ECF8E]/20 transition-all cursor-pointer"
                    >
                      Import Apidog Environment
                    </button>
                    <button
                      type="button"
                      onClick={() => {
                        setBulkModalInitialMode('edit');
                        setIsBulkModalOpen(true);
                      }}
                      className="px-2 py-0.5 rounded bg-[#222222] border border-[#333333] text-[8px] font-black text-[#888888] uppercase tracking-wider hover:bg-[#333333] transition-all cursor-pointer"
                    >
                      Bulk CSV Import
                    </button>
                  </div>
                  <div className="relative">
                    <Search size={12} className="absolute left-3 top-1/2 -translate-y-1/2 text-[#333333]" />
                    <input 
                      value={searchQuery}
                      onChange={(e) => setSearchQuery(e.target.value)}
                      placeholder="Search variables..."
                      className="bg-[#111111] border border-[#222222] pl-8 pr-4 py-1.5 rounded-md text-[10px] text-white focus:outline-none focus:border-[#3ECF8E]/30 w-48"
                    />
                  </div>
                </div>
                
                <div className="bg-[#0A0A0A] border border-[#222222] rounded-xl p-2 min-h-[300px]">
                  <KVEditor 
                    items={variables}
                    onChange={setVariables}
                    isVariableEditor={true}
                    allowMasking={true}
                  />
                </div>
              </div>
            </div>
          )}

          {activeTab === 'scripts' && (
            <div className="space-y-6">
               <div className="grid grid-cols-2 gap-6">
                  <div className="space-y-2">
