  },
];

export const ExportModal: React.FC<ExportModalProps> = ({ isOpen, onClose, initialSelectedIds = [] }) => {
  const { collections, addToast } = useStore();
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set(initialSelectedIds));
  const [searchQuery, setSearchQuery] = useState('');
  const [format, setFormat] = useState<ExportFormat>(ExportFormat.POSTMAN);
  const [isExporting, setIsExporting] = useState(false);
  const [expandedFolders, setExpandedFolders] = useState<Set<string>>(new Set());

  // Initialize selected IDs if initialSelectedIds changes
  useEffect(() => {
    if (initialSelectedIds.length > 0) {
      setSelectedIds(new Set(initialSelectedIds));
    }
  }, [initialSelectedIds, isOpen]);

  const toggleExpand = (id: string) => {
    const next = new Set(expandedFolders);
    if (next.has(id)) next.delete(id);
    else next.add(id);
    setExpandedFolders(next);
  };

  const getAllNodeIds = (node: any): string[] => {
    let ids = [node.id];
    if (node.folders) {
      node.folders.forEach((f: any) => ids = [...ids, ...getAllNodeIds(f)]);
    }
    if (node.requests) {
      node.requests.forEach((r: any) => ids.push(r.id));
    }
    return ids;
  };

  const toggleNodeSelection = (node: any, checked: boolean) => {
    const nodeIds = getAllNodeIds(node);
    const next = new Set(selectedIds);
    if (checked) {
      nodeIds.forEach(id => next.add(id));
    } else {
      nodeIds.forEach(id => next.delete(id));
    }
    setSelectedIds(next);
  };

  const isNodeSelected = (node: any): boolean | 'indeterminate' => {
    const nodeIds = getAllNodeIds(node);
    const selectedCount = nodeIds.filter(id => selectedIds.has(id)).length;
    if (selectedCount === 0) return false;
    if (selectedCount === nodeIds.length) return true;
    return 'indeterminate';
  };

  const filteredCollections = useMemo(() => {
    if (!searchQuery.trim()) return collections;
    
    const query = searchQuery.toLowerCase();
    
    const filterTree = (node: any): any | null => {
      const matchName = node.name.toLowerCase().includes(query);
      
      const filteredFolders = (node.folders || [])
        .map(filterTree)
        .filter(Boolean);
        
      const filteredRequests = (node.requests || [])
        .filter((r: any) => r.name.toLowerCase().includes(query) || matchName);

      if (matchName || filteredFolders.length > 0 || filteredRequests.length > 0) {
        return {
          ...node,
          folders: filteredFolders,
          requests: filteredRequests
        };
      }
      return null;
    };

    return collections.map(filterTree).filter(Boolean) as Collection[];
  }, [collections, searchQuery]);

  const handleSelectAll = () => {
    const next = new Set<string>();
    collections.forEach(c => getAllNodeIds(c).forEach(id => next.add(id)));
    setSelectedIds(next);
  };

  const handleClearSelection = () => {
    setSelectedIds(new Set());
  };

  const handleExport = async () => {
    if (selectedIds.size === 0) return;
    setIsExporting(true);
    
    try {
      // For now, we export each selected collection that has at least one selected item
      // In a real implementation, we would prune the collections based on selectedIds
      const collectionsToExport = collections.filter(c => {
        const nodeIds = getAllNodeIds(c);
        return nodeIds.some(id => selectedIds.has(id));
      });

      for (const col of collectionsToExport) {
        const pruned = CollectionExportService.pruneCollection(col, selectedIds);
        if (pruned) {
          if (format === ExportFormat.CURL_BUNDLE) {
            CollectionExportService.exportCurlBundle(pruned);
          } else {
            CollectionExportService.exportCollection(pruned, format);
          }
        }
      }
      
      addToast({ type: 'success', message: `Successfully exported ${collectionsToExport.length} collections.` });
      onClose();
    } catch (error) {
      addToast({ type: 'error', message: 'Export failed.' });
    } finally {
      setIsExporting(false);
    }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-[120] flex items-center justify-center p-4">
      <motion.div
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        exit={{ opacity: 0 }}
        onClick={onClose}
        className="absolute inset-0 bg-black/60 backdrop-blur-sm"
      />

      <motion.div
        initial={{ opacity: 0, scale: 0.96, y: 10 }}
        animate={{ opacity: 1, scale: 1, y: 0 }}
        exit={{ opacity: 0, scale: 0.96, y: 10 }}
        className="relative w-full max-w-4xl bg-[var(--bg-surface)] border border-[var(--border-subtle)] rounded-2xl shadow-2xl flex flex-col h-[85vh]"
      >
        {/* Header */}
        <div className="p-5 border-b border-[var(--border-subtle)] flex items-center justify-between bg-[var(--bg-elevated)]">
          <div>
            <h2 className="text-[13px] font-black text-[var(--text-main)] uppercase tracking-widest">Export Selection</h2>
            <p className="text-[10px] text-[var(--text-dim)] uppercase tracking-tighter mt-1">
              Select items and format for backup or transfer
            </p>
          </div>
          <button onClick={onClose} className="p-1 text-[var(--text-dim)] hover:text-[var(--text-main)] transition-colors">
            <X size={18} />
          </button>
        </div>

        <div className="flex flex-1 overflow-hidden">
          {/* Left Side: Tree Selection */}
          <div className="flex-1 flex flex-col border-r border-[var(--border-subtle)] bg-[var(--bg-deep)]/30">
            <div className="p-4 border-b border-[var(--border-subtle)] space-y-3">
              <div className="relative group">
                <Search size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-[var(--text-dim)] group-focus-within:text-[var(--brand)] transition-colors" />
                <input 
                  autoFocus
                  type="text" 
                  placeholder="SEARCH_ITEMS..."
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  className="w-full bg-[var(--bg-deep)] border border-[var(--border-subtle)] rounded-lg py-2 pl-10 pr-3 text-[11px] font-mono text-[var(--text-main)] outline-none focus:border-[var(--brand)]/50 transition-all"
                />
              </div>
              <div className="flex items-center justify-between px-1">
                <span className="text-[9px] font-black text-[var(--text-muted)] uppercase tracking-widest">
                  {selectedIds.size} Items Selected
                </span>
                <div className="flex gap-3">
                  <button onClick={handleSelectAll} className="text-[9px] font-black text-[var(--brand)] uppercase hover:opacity-80">Select All</button>
                  <button onClick={handleClearSelection} className="text-[9px] font-black text-red-400 uppercase hover:opacity-80">Clear</button>
                </div>
              </div>
            </div>

            <div className="flex-1 overflow-y-auto p-4 custom-scrollbar">
              {filteredCollections.map(col => (
                <TreeNode 
                  key={col.id}
                  node={col}
                  level={0}
                  selectedIds={selectedIds}
                  toggleNodeSelection={toggleNodeSelection}
                  isNodeSelected={isNodeSelected}
                  toggleExpand={toggleExpand}
                  expandedFolders={expandedFolders}
                />
              ))}
              {filteredCollections.length === 0 && (
                <div className="h-full flex flex-col items-center justify-center opacity-20 py-20">
                  <Filter size={48} className="mb-4" />
                  <p className="text-[10px] font-black uppercase tracking-[0.2em]">No Matches Found</p>
                </div>
              )}
            </div>
          </div>

          {/* Right Side: Export Options */}
          <div className="w-[300px] flex flex-col bg-[var(--bg-elevated)]/50">
            <div className="p-4 border-b border-[var(--border-subtle)]">
              <span className="text-[10px] font-black text-[var(--text-muted)] uppercase tracking-widest">Export Format</span>
            </div>
            <div className="flex-1 overflow-y-auto p-4 space-y-2 custom-scrollbar">
              {FORMAT_OPTIONS.map(opt => (
                <button
                  key={opt.id}
                  onClick={() => setFormat(opt.id)}
                  className={cn(
                    "w-full text-left p-3 rounded-xl border transition-all relative group overflow-hidden",
                    format === opt.id
                      ? opt.color
                      : "bg-[var(--bg-deep)] border-[var(--border-subtle)] hover:border-[var(--text-dim)]/30"
                  )}
                >
                  <div className="flex items-center gap-3">
                    <div className={cn(
                      "w-8 h-8 rounded-lg flex items-center justify-center shrink-0",
                      format === opt.id ? "bg-white/10" : "bg-[var(--bg-elevated)]"
                    )}>
                      <opt.icon size={16} />
                    </div>
                    <div>
                      <div className={cn(
                        "text-[11px] font-black uppercase tracking-wide",
                        format === opt.id ? "" : "text-[var(--text-main)]"
                      )}>
                        {opt.title}
                      </div>
                      <div className={cn(
                        "text-[9px] uppercase tracking-tighter opacity-60",
                        format === opt.id ? "" : "text-[var(--text-dim)]"
                      )}>
                        {opt.subtitle}
                      </div>
                    </div>
                    {format === opt.id && (
                      <div className="ml-auto">
                        <div className="w-5 h-5 rounded-full bg-white/20 flex items-center justify-center">
                          <Check size={12} />
                        </div>
                      </div>
                    )}
                  </div>
                </button>
              ))}
            </div>

            {/* Summary */}
            <div className="p-4 border-t border-[var(--border-subtle)] bg-[var(--bg-deep)]/50 space-y-3">
              <div className="space-y-2">
                <div className="flex justify-between text-[10px] uppercase tracking-tighter text-[var(--text-dim)]">
                  <span>Collections:</span>
                  <span className="font-bold text-[var(--text-main)]">
                    {collections.filter(c => selectedIds.has(c.id)).length}
                  </span>
                </div>
                <div className="flex justify-between text-[10px] uppercase tracking-tighter text-[var(--text-dim)]">
                  <span>Selected Units:</span>
                  <span className="font-bold text-[var(--text-main)]">{selectedIds.size}</span>
                </div>
                <div className="flex justify-between text-[10px] uppercase tracking-tighter text-[var(--text-dim)]">
                  <span>Output Type:</span>
                  <span className="font-bold text-[var(--brand)]">{format.toUpperCase()}</span>
                </div>
              </div>

              <button
                onClick={handleExport}
                disabled={selectedIds.size === 0 || isExporting}
                className="w-full h-10 bg-[var(--brand)] hover:opacity-90 disabled:opacity-30 disabled:cursor-not-allowed rounded-lg flex items-center justify-center gap-2 text-[11px] font-black text-[var(--bg-deep)] uppercase tracking-widest transition-all shadow-lg active:scale-95"
              >
                {isExporting ? (
                  <>Exporting...</>
                ) : (
                  <>
                    <Download size={14} strokeWidth={3} />
                    Export Selected
                  </>
                )}
              </button>
            </div>
          </div>
        </div>
      </motion.div>
    </div>
  );
};

const TreeNode: React.FC<{
  node: any;
  level: number;
  selectedIds: Set<string>;
  toggleNodeSelection: (node: any, checked: boolean) => void;
  isNodeSelected: (node: any) => boolean | 'indeterminate';
  toggleExpand: (id: string) => void;
  expandedFolders: Set<string>;
}> = ({ node, level, selectedIds, toggleNodeSelection, isNodeSelected, toggleExpand, expandedFolders }) => {
  const isSelected = isNodeSelected(node);
  const isOpen = expandedFolders.has(node.id);
  const hasChildren = (node.folders?.length > 0 || node.requests?.length > 0);
  const isRequest = !node.folders && node.method;

  return (
    <div className="space-y-0.5">
      <div 
        className={cn(
          "flex items-center gap-2 py-1 px-2 rounded-md hover:bg-white/5 transition-colors group cursor-pointer",
          isSelected === true ? "bg-white/5" : ""
        )}
        style={{ paddingLeft: `${level * 16 + 8}px` }}
        onClick={() => {
          if (hasChildren) toggleExpand(node.id);
          else toggleNodeSelection(node, isSelected !== true);
        }}
      >
        <div 
          onClick={(e) => {
            e.stopPropagation();
            toggleNodeSelection(node, isSelected !== true);
          }}
          className={cn(
            "w-4 h-4 rounded border flex items-center justify-center transition-all",
            isSelected === true ? "bg-[var(--brand)] border-[var(--brand)]" : 
            isSelected === 'indeterminate' ? "bg-[var(--brand)]/30 border-[var(--brand)]/50" :
            "border-[var(--border-subtle)] bg-[var(--bg-deep)] group-hover:border-[var(--brand)]/50"
          )}
        >
          {isSelected === true && <Check size={10} className="text-[var(--bg-deep)]" />}
          {isSelected === 'indeterminate' && <div className="w-2 h-0.5 bg-[var(--brand)]" />}
        </div>

        {hasChildren ? (
          isOpen ? <ChevronDown size={14} className="text-[var(--text-dim)]" /> : <ChevronRight size={14} className="text-[var(--text-dim)]" />
        ) : (
          <div className="w-3.5" />
        )}

        {isRequest ? (
          <div className={cn(
            "text-[8px] font-black w-7 text-center shrink-0",
            node.method === 'GET' ? 'text-[var(--brand)]' : 
            node.method === 'POST' ? 'text-yellow-500' :
            node.method === 'PUT' ? 'text-blue-500' :
            node.method === 'DELETE' ? 'text-red-500' : 'text-[var(--text-dim)]'
          )}>
            {node.method}
          </div>
        ) : (
          <Folder size={12} className={cn(isSelected ? "text-[var(--brand)]" : "text-[var(--text-dim)]")} />
        )}

        <span className={cn(
          "text-[11px] truncate flex-1",
          isSelected ? "text-[var(--text-main)] font-bold" : "text-[var(--text-muted)]"
        )}>
          {node.name}
        </span>
      </div>

      {isOpen && (
        <div className="animate-in fade-in slide-in-from-top-1 duration-200">
          {node.folders?.map((f: any) => (
            <TreeNode 
              key={f.id}
              node={f}
              level={level + 1}
              selectedIds={selectedIds}
              toggleNodeSelection={toggleNodeSelection}
              isNodeSelected={isNodeSelected}
              toggleExpand={toggleExpand}
              expandedFolders={expandedFolders}
            />
          ))}
          {node.requests?.map((r: any) => (
            <TreeNode 
              key={r.id}
              node={r}
              level={level + 1}
              selectedIds={selectedIds}
              toggleNodeSelection={toggleNodeSelection}
              isNodeSelected={isNodeSelected}
              toggleExpand={toggleExpand}
              expandedFolders={expandedFolders}
            />
          ))}
        </div>
      )}
    </div>
  );
};

import React, { useState, useMemo, useRef, useEffect } from 'react';
import { Plus, Trash2, CheckCircle2, Circle, Edit3, Variable, ShieldAlert, Sparkles, Check, AlertCircle, ExternalLink } from 'lucide-react';
import { KeyValue } from '../types';
import { cn } from '../lib/utils';
import { useStore } from '../store/useStore';
import { VariableService } from '../services/VariableService';
import { motion, AnimatePresence } from 'motion/react';

interface HeaderEditorProps {
  items: KeyValue[];
  onChange: (items: KeyValue[]) => void;
  placeholderKey?: string;
  placeholderValue?: string;
}

export const HeaderEditor: React.FC<HeaderEditorProps> = ({
  items = [],
  onChange,
  placeholderKey = "header-name",
  placeholderValue = "value"
}) => {
  const [isBulkEdit, setIsBulkEdit] = useState(false);
  const [bulkText, setBulkText] = useState('');
  const [searchQuery, setSearchQuery] = useState('');
  const [_hoveredRowId, setHoveredRowId] = useState<string | null>(null);
  const [focusedRowId, setFocusedRowId] = useState<string | null>(null);

  // Per-variable hover tooltip state
  const [hoveredVar, setHoveredVar] = useState<{
    rowIndex: number;
    varName: string;
    scope: string;
    value: string;
    sourceId?: string;
  } | null>(null);
  
  const [editingVarValue, setEditingVarValue] = useState('');
  const hideTimerRef = useRef<number | null>(null);

  const {
    environments,
    activeEnvId,
    collections,
    openTabs,
    activeTabId,
    updateEnvironment,
    updateCollection,
    addTab
  } = useStore();

  const containerRef = useRef<HTMLDivElement>(null);

  // Active Collection retrieval
  const activeTab = openTabs.find(t => t.id === activeTabId);
  const activeCollection = useMemo(() => {
    if (!activeTab) return null;
    if ('requests' in activeTab) return activeTab;
    return collections.find(c => c.id === (activeTab as any).collection_id) || null;
  }, [activeTab, collections]);

  const variableContext = useMemo(() => ({
    environments,
    activeEnvId,
    collection: activeCollection
  }), [environments, activeEnvId, activeCollection]);

  // Normalize items to ensure all items have a unique id
  const normalizedItems = useMemo(() => {
    let changed = false;
    const safeItems = (items || []).filter(Boolean).map(item => {
      if (!item.id) {
        changed = true;
        return {
          ...item,
          id: Math.random().toString(36).substr(2, 9)
        };
      }
      return item;
    });

    if (changed) {
      setTimeout(() => onChange(safeItems), 0);
    }
    return safeItems;
  }, [items, onChange]);

  // Bulk edit management
  const startBulkEdit = () => {
    const text = (normalizedItems || [])
      .filter(item => item && item.active)
      .map(item => `${item.key}: ${item.value}`)
      .join('\n');
    setBulkText(text);
    setIsBulkEdit(true);
  };

  const _saveBulkEdit = () => {
    const lines = bulkText.split('\n');
    const newItems: KeyValue[] = lines
      .filter(line => line.trim() !== '')
      .map(line => {
        let separatorIndex = line.indexOf(':');
        if (separatorIndex === -1) separatorIndex = line.indexOf('=');
        
        let key = '';
        let value = '';
        
        if (separatorIndex !== -1) {
          key = line.substring(0, separatorIndex).trim();
          value = line.substring(separatorIndex + 1).trim();
        } else {
          key = line.trim();
        }

        return {
          id: Math.random().toString(36).substr(2, 9),
          key,
          value,
          active: true
        };
      });
    
    onChange(newItems);
    setIsBulkEdit(false);
  };

  // List operations
  const handleItemChange = (id: string, updates: Partial<KeyValue>) => {
    onChange(normalizedItems.map(item => item.id === id ? { ...item, ...updates } : item));
  };

  const addItem = () => {
    const newItem: KeyValue = {
      id: Math.random().toString(36).substr(2, 9),
      key: '',
      value: '',
      active: true
    };
    onChange([...normalizedItems, newItem]);
  };

  const removeItem = (id: string) => {
    onChange(normalizedItems.filter(item => item.id !== id));
  };

  // Variable parsing helper
  const parseVariables = (text: string) => {
    if (!text || typeof text !== 'string') return [];
    const matches = text.match(/{{(.*?)}}/g);
    if (!matches) return [];
    return matches.map(m => m.slice(2, -2).trim());
  };

  // Filtered headers to preserve layout speed
  const filteredItems = useMemo(() => {
    if (!searchQuery) return normalizedItems;
    const query = searchQuery.toLowerCase();
    return normalizedItems.filter(item => 
      (item.key || '').toLowerCase().includes(query) || 
      (item.value || '').toLowerCase().includes(query)
    );
  }, [normalizedItems, searchQuery]);

  // Click outside listener to dismiss popovers
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (containerRef.current && !containerRef.current.contains(event.target as Node)) {
        setHoveredVar(null);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => {
      document.removeEventListener('mousedown', handleClickOutside);
      if (hideTimerRef.current) window.clearTimeout(hideTimerRef.current);
    };
  }, []);

  const handlePersistQuickVar = (varName: string, val: string, scope: string, _sourceId?: string) => {
    if (scope === 'environment' && activeEnvId) {
      const env = environments.find(e => e.id === activeEnvId);
      if (env) {
        const updatedVars = (env.variables || []).map(kv => 
          kv.key === varName ? { ...kv, value: val } : kv
        );
        updateEnvironment(activeEnvId, { variables: updatedVars });
      }
    } else if (scope === 'collection' && activeCollection) {
      const updatedVars = (activeCollection.variables || []).map(kv => 
        kv.key === varName ? { ...kv, value: val } : kv
      );
      updateCollection(activeCollection.id, { variables: updatedVars });
    }
    setHoveredVar(null);
  };

  const navigateToVariableSource = (scope: string, _sourceId?: string) => {
    if (scope === 'environment' && sourceId) {
      addTab({
        id: 'tab-environments',
        type: 'environment-manager',
        name: 'Environments',
        environmentId: sourceId,
      } as any);
    } else if (scope === 'collection' && activeCollection) {
      addTab(activeCollection as any);
    }
  };

  return (
    <div ref={containerRef} className="space-y-4 w-full relative">
      {/* Sleek Tool Bar */}
      <div className="flex items-center justify-between pb-2 border-b border-[#222222]">
        <div className="flex items-center gap-3">
          <span className="text-[10px] font-black text-[#666666] uppercase tracking-widest">
            Headers ({items.length})
          </span>
          {!isBulkEdit && items.length > 5 && (
            <input
              type="text"
              placeholder="Search headers..."
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="bg-[#111111] border border-[#222222] text-[10px] text-white px-2 py-0.5 rounded outline-none focus:border-[#3ECF8E]/30 transition-all font-medium placeholder:text-[#444444]"
            />
          )}
        </div>
        <button
          onClick={isBulkEdit ? saveBulkEdit : startBulkEdit}
          className="flex items-center gap-1.5 px-3 py-1.5 text-[9px] font-black text-[#888888] hover:text-[#3ECF8E] transition-all uppercase tracking-widest bg-[#141414] border border-[#222222] rounded-lg shadow-lg hover:border-[#3ECF8E]/20"
        >
          {isBulkEdit ? (
            <><CheckCircle2 size={11} className="text-[#3ECF8E]" /> Save Bulk</>
          ) : (
            <><Edit3 size={11} /> Bulk Compiler</>
          )}
        </button>
      </div>

      {isBulkEdit ? (
        <div className="space-y-2 animate-in fade-in duration-200">
          <textarea
            autoFocus
            value={bulkText}
            onChange={(e) => setBulkText(e.target.value)}
            placeholder="Host: api.gimay.com&#10;Authorization: Bearer {{token}}"
            className="w-full h-56 bg-[#090909] text-[11px] font-mono p-4 outline-none border border-[#222222] rounded-xl text-white placeholder:text-[#333333] resize-none focus:border-[#3ECF8E]/30 focus:bg-[#0C0C0C] transition-all"
          />
          <div className="text-[9px] text-[#555555] font-medium italic">
            Enter one Header Key: Value pair per line. Standard Postman variable mapping is fully supported.
          </div>
        </div>
      ) : (
        <div className="space-y-2.5">
          {/* Header Row */}
          {filteredItems.length > 0 && (
            <div className="flex items-center gap-3 px-2 py-1 text-[9px] font-black text-[#444444] uppercase tracking-wider select-none border-b border-[#181818]">
              <div className="w-6 shrink-0" />
              <div className="flex-[0.4] px-1">Header Name</div>
              <div className="flex-[0.6] px-1">Value Configuration</div>
              <div className="w-8 shrink-0" />
            </div>
          )}

          {/* Rows */}
          {filteredItems.map((item, rowIndex) => {
            const variables = parseVariables(item.value);
            const variableSources = variables.map(v => {
              const lookup = VariableService.lookupVariable(v, variableContext);
              return { name: v, lookup };
            });

            const hasVariables = variables.length > 0;

            return (
              <div
                key={`header-row-${item.id || rowIndex}`}
                onMouseEnter={() => setHoveredRowId(item.id)}
                onMouseLeave={() => setHoveredRowId(null)}
                className={cn(
                  "flex items-center gap-3 px-2 py-1 rounded-xl transition-all border relative",
                  item.active 
                    ? "bg-[#0E0E0E]/60 border-[#1B1B1B] hover:border-[#2C2C2C] hover:bg-[#121212]/80"
                    : "bg-[#0A0A0A]/40 border-transparent opacity-40 hover:opacity-75"
                )}
              >
                {/* Active Checkbox */}
                <button
                  onClick={() => handleItemChange(item.id, { active: !item.active })}
                  className={cn(
                    "w-6 h-6 flex items-center justify-center rounded-lg transition-colors border",
                    item.active 
                      ? "text-[#3ECF8E] bg-[#3ECF8E]/5 border-[#3ECF8E]/20" 
                      : "text-[#333333] border-[#222222] hover:border-[#444444]"
                  )}
                >
                  {item.active ? <CheckCircle2 size={12} /> : <Circle size={12} />}
                </button>

                {/* Key Input */}
                <div className="flex-[0.4] min-w-0">
                  <input
                    type="text"
                    value={item.key}
                    onChange={(e) => handleItemChange(item.id, { key: e.target.value })}
                    placeholder={placeholderKey}
                    className="w-full bg-transparent text-[11px] font-semibold text-white px-2.5 py-1.5 outline-none rounded-lg border border-transparent hover:border-[#1F1F1F] focus:border-[#3ECF8E]/30 focus:bg-[#070707] transition-all font-mono"
                  />
                </div>

                {/* Value Input Area */}
                <div className="flex-[0.6] min-w-0 relative">
                  <div className="flex items-center relative group">
                    <input
                      type="text"
                      value={item.value}
                      onChange={(e) => handleItemChange(item.id, { value: e.target.value })}
                      onFocus={() => setFocusedRowId(item.id)}
                      onBlur={() => setFocusedRowId(null)}
                      placeholder={placeholderValue}
                      spellCheck={false}
                      style={(hasVariables && focusedRowId !== item.id) ? { color: 'transparent', caretColor: '#3ECF8E' } : {}}
                      className={cn(
                        "w-full bg-transparent text-[11px] text-[#A0A0A0] px-2.5 py-1.5 pr-8 outline-none rounded-lg border border-transparent hover:border-[#1F1F1F] focus:border-[#3ECF8E]/30 focus:bg-[#070707] transition-all font-mono focus:text-white"
                      )}
                    />

                    {/* Syntax Highlighted Variable overlay */}
                    {hasVariables && focusedRowId !== item.id && (
                      <div 
                        className="absolute inset-0 pointer-events-none text-[11px] font-mono px-2.5 py-1.5 flex items-center gap-0.5 select-none overflow-hidden whitespace-nowrap border border-transparent"
                        style={{ boxSizing: 'border-box' }}
                      >
                        {item.value.split(/(\{\{[^}]+\}\})/g).map((part, index) => {
                          const partKey = `overlay-part-${item.id}-${index}`;
                          if (part.startsWith('{{') && part.endsWith('}}')) {
                            const varName = part.slice(2, -2).trim();
                            const vs = variableSources.find(s => s.name === varName);
                            const scope = vs?.lookup.scope || 'unresolved';

                            return (
                              <span
                                key={partKey}
                                onMouseEnter={() => {
                                  if (hideTimerRef.current) window.clearTimeout(hideTimerRef.current);
                                  const val = vs?.lookup.value || '';
                                  setHoveredVar({
                                    rowIndex,
                                    varName,
                                    scope,
                                    value: val,
                                    sourceId: vs?.lookup.sourceId
                                  });
                                  setEditingVarValue(val);
                                }}
                                onMouseLeave={() => {
                                  hideTimerRef.current = window.setTimeout(() => {
                                    setHoveredVar(null);
                                  }, 200) as any;
                                }}
                                className={cn(
                                  "inline-flex items-center px-1.5 py-0.5 rounded text-[9px] font-black uppercase tracking-tight border pointer-events-auto cursor-help transition-all duration-150",
                                  scope === 'environment' && "bg-[#10B981]/10 text-[#10B981] border-[#10B981]/20 hover:bg-[#10B981]/25 hover:border-[#10B981]/40",
                                  scope === 'collection' && "bg-[#3B82F6]/10 text-[#3B82F6] border-[#3B82F6]/20 hover:bg-[#3B82F6]/25 hover:border-[#3B82F6]/40",
                                  scope === 'unresolved' && "bg-[#EF4444]/10 text-[#EF4444] border-[#EF4444]/20 animate-pulse hover:bg-[#EF4444]/25"
                                )}
                              >
                                {part}
                              </span>
                            );
                          }
                          return <span key={partKey} className="text-[#A0A0A0]">{part}</span>;
                        })}
                      </div>
                    )}
                  </div>

                  {/* Per-variable tooltip card popover anchored to row */}
                  <AnimatePresence>
                    {hoveredVar && hoveredVar.rowIndex === rowIndex && (
                      <motion.div
                        initial={{ opacity: 0, y: 8, scale: 0.98 }}
                        animate={{ opacity: 1, y: 0, scale: 1 }}
                        exit={{ opacity: 0, y: 8, scale: 0.98 }}
                        transition={{ duration: 0.15, ease: 'easeOut' }}
                        onMouseEnter={() => {
                          if (hideTimerRef.current) window.clearTimeout(hideTimerRef.current);
                        }}
                        onMouseLeave={() => {
                          hideTimerRef.current = window.setTimeout(() => {
                            setHoveredVar(null);
                          }, 200) as any;
                        }}
                        className="absolute z-50 left-2 top-full mt-2 w-[320px] bg-[#0A0A0C]/95 backdrop-blur-2xl border border-[#222222] rounded-xl shadow-2xl p-3.5 space-y-3.5"
                      >
                        {/* Header Details */}
                        <div className="flex items-center justify-between pb-1.5 border-b border-[#181818]">
                          <div className="flex items-center gap-1.5">
                            <Variable size={11} className="text-[#3ECF8E]" />
                            <span className="font-mono text-[10px] font-black text-white">
                              {hoveredVar.varName}
                            </span>
                          </div>
                          <span className={cn(
                            "text-[7px] font-black px-1.5 py-0.5 rounded border uppercase tracking-wider",
                            hoveredVar.scope === 'environment' && "bg-[#10B981]/15 text-[#10B981] border-[#10B981]/20",
                            hoveredVar.scope === 'collection' && "bg-[#3B82F6]/15 text-[#3B82F6] border-[#3B82F6]/20",
                            hoveredVar.scope === 'unresolved' && "bg-[#EF4444]/15 text-[#EF4444] border-[#EF4444]/20 animate-pulse"
                          )}>
                            {hoveredVar.scope === 'environment' ? 'Environment' : hoveredVar.scope === 'collection' ? 'Collection' : 'Missing'}
                          </span>
                        </div>

                        {/* Resolved Value or Unresolved Warning */}
                        {hoveredVar.scope === 'unresolved' ? (
                          <div className="bg-red-500/5 border border-red-500/10 rounded-lg p-2.5 text-[9.5px] text-red-400 flex items-start gap-2">
                            <AlertCircle size={14} className="shrink-0 mt-0.5" />
                            <div>
                              <div className="font-bold">Unresolved Variable</div>
                              <div className="opacity-75 mt-0.5">This parameter is not mapped in the active Environment or Collection. Gimay will transmit the raw literal text.</div>
                            </div>
                          </div>
                        ) : (
                          <div className="space-y-3">
                            <div className="space-y-1">
                              <label className="text-[8px] font-black text-[#555] uppercase tracking-widest block">Resolved Value</label>
                              <div className="bg-[#050505] border border-[#161616] rounded-lg p-2 font-mono text-[10px] text-[#3ECF8E] break-all">
                                {hoveredVar.value || <span className="text-[#2B3A30] italic">Empty String</span>}
                              </div>
                            </div>

                            {/* Direct Modifier Form */}
                            <div className="space-y-1.5 pt-2 border-t border-[#181818]">
                              <label className="text-[8px] font-black text-[#555] uppercase tracking-widest block">Quick Modify Value</label>
                              <div className="flex items-center gap-1.5">
                                <input
                                  type="text"
                                  value={editingVarValue}
                                  onChange={(e) => setEditingVarValue(e.target.value)}
                                  className="flex-1 bg-[#050505] border border-[#1C1C1C] rounded-lg px-2 py-1.5 text-[10.5px] font-mono text-white outline-none focus:border-[#3ECF8E]/40 transition-colors"
                                  placeholder="Enter new value"
                                />
                                <button
                                  onClick={() => handlePersistQuickVar(hoveredVar.varName, editingVarValue, hoveredVar.scope, hoveredVar.sourceId)}
                                  className="p-1.5 rounded-lg bg-[#3ECF8E]/10 border border-[#3ECF8E]/20 text-[#3ECF8E] hover:bg-[#3ECF8E]/20 transition-all shadow-md"
                                  title="Save resolved value"
                                >
                                  <Check size={11} />
                                </button>
                              </div>
                            </div>
                          </div>
                        )}

                        {/* Navigation / Open Source button */}
                        {hoveredVar.scope !== 'unresolved' && (
                          <button
                            onClick={() => navigateToVariableSource(hoveredVar.scope, hoveredVar.sourceId)}
                            className="w-full px-2 py-1.5 rounded-lg border border-[#202020] text-[8px] font-black uppercase tracking-widest text-[#888888] hover:text-[#3ECF8E] hover:border-[#3ECF8E]/20 transition-all flex items-center justify-center gap-1.5 bg-[#121214]/50"
                          >
                            <ExternalLink size={10} />
                            Open Variable Source
                          </button>
                        )}
                      </motion.div>
                    )}
                  </AnimatePresence>
                </div>

                {/* Remove button */}
                <button
                  onClick={() => removeItem(item.id)}
                  className="w-8 h-8 flex items-center justify-center text-[#444444] hover:text-red-500 opacity-0 group-hover:opacity-100 transition-all rounded-lg shrink-0 hover:bg-red-500/5 hover:border hover:border-red-500/10 border border-transparent"
                >
                  <Trash2 size={12} />
                </button>
              </div>
            );
          })}

          <button
            onClick={addItem}
            className="mt-3 flex items-center gap-2 px-3 py-1.5 text-[9px] font-black text-[#777777] hover:text-[#3ECF8E] hover:bg-[#3ECF8E]/5 border border-dashed border-[#222222] hover:border-[#3ECF8E]/20 rounded-xl transition-all uppercase tracking-widest"
          >
            <Plus size={11} /> Add Header Field
          </button>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { motion, AnimatePresence } from 'motion/react';
import { 
  Activity, 
  Play, 
  Square, 
  Globe, 
  Settings, 
  Zap, 
  AlertTriangle, 
  CheckCircle2, 
  Clock, 
  HelpCircle 
} from 'lucide-react';

export function SampleSmokeTester() {
  // Input parameters
  const [url, setUrl] = useState('https://www.google.com');
  const [method, setMethod] = useState('GET');
  const [threads, setThreads] = useState(3);
  const [loops, setLoops] = useState(5);
  const [delay, setDelay] = useState(150);

  // Runtime states
  const [isRunning, setIsRunning] = useState(false);
  const [isCompleted, setIsCompleted] = useState(false);
  const [samples, setSamples] = useState<any[]>([]);
  const [progress, setProgress] = useState(0);
  const [hoveredSample, setHoveredSample] = useState<any | null>(null);

  // Abort controller reference
  const isAbortedRef = useRef(false);
  const activeRequestsRef = useRef<Set<AbortController>>(new Set());

  // Automatically reset states when parameters change
  useEffect(() => {
    if (!isRunning) {
      setIsCompleted(false);
      setSamples([]);
      setProgress(0);
    }
  }, [url, method, threads, loops]);

  // Cleanup on unmount
  useEffect(() => {
    return () => {
      isAbortedRef.current = true;
      activeRequestsRef.current.forEach(ctrl => ctrl.abort());
    };
  }, []);

  const stopTest = () => {
    isAbortedRef.current = true;
    activeRequestsRef.current.forEach(ctrl => ctrl.abort());
    activeRequestsRef.current.clear();
    setIsRunning(false);
  };

  const runSingleRequest = async (threadId: number, ctrl: AbortController): Promise<any> => {
    const startTime = performance.now();
    let status = 0;
    let success = false;
    let statusText = 'Connection Refused';

    try {
      const controller = new AbortController();
      activeRequestsRef.current.add(controller);

      // We forward requests to our built-in server proxy to bypass CORS
      const response = await fetch('/api/proxy', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          method,
          url,
        }),
        signal: controller.signal
      });

      activeRequestsRef.current.delete(controller);

      if (isAbortedRef.current) return null;

      const result = await response.json();
      status = result.status || response.status;
      success = status >= 200 && status < 400;
      statusText = result.statusText || response.statusText;
    } catch (err: any) {
      if (err.name === 'AbortError') return null;
      status = 0;
      success = false;
      statusText = err.message || 'CORS Error / Blocked';
    }

    const duration = Math.round(performance.now() - startTime);

    return {
      id: Math.random(),
      threadId,
      status,
      success,
      latency: duration,
      statusText,
      timestamp: Date.now()
    };
  };

  const startTest = async () => {
    isAbortedRef.current = false;
    setIsRunning(true);
    setIsCompleted(false);
    setSamples([]);
    setProgress(0);

    const totalRequests = threads * loops;
    let completedRequests = 0;

    // Helper sleep function
    const sleep = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

    // Define worker function for each thread
    const runWorkerThread = async (threadId: number) => {
      for (let i = 0; i < loops; i++) {
        if (isAbortedRef.current) break;

        const ctrl = new AbortController();
        const sample = await runSingleRequest(threadId, ctrl);

        if (isAbortedRef.current) break;

        if (sample) {
          completedRequests++;
          setSamples(prev => [...prev, sample]);
          setProgress(Math.round((completedRequests / totalRequests) * 100));
        }

        // Delay between loops to prevent excessive client-side locking
        if (i < loops - 1) {
          await sleep(delay);
        }
      }
    };

    // Spawn workers concurrently
    const threadPromises = Array.from({ length: threads }).map((_, id) => runWorkerThread(id));
    
    await Promise.all(threadPromises);

    setIsRunning(false);
    if (!isAbortedRef.current) {
      setIsCompleted(true);
    }
  };

  // Math metrics for display
  const totalCount = samples.length;
  const successCount = samples.filter(s => s.success).length;
  const failureCount = totalCount - successCount;
  const successRate = totalCount > 0 ? Math.round((successCount / totalCount) * 1000) / 10 : 0;
  
  const latencies = samples.map(s => s.latency);
  const avgLatency = latencies.length > 0 ? Math.round(latencies.reduce((a, b) => a + b, 0) / latencies.length) : 0;
  const minLatency = latencies.length > 0 ? Math.min(...latencies) : 0;
  const maxLatency = latencies.length > 0 ? Math.max(...latencies) : 0;

  // Find percentage for visual bars
  const maxSampleLatency = Math.max(...latencies, 150); // Use 150 as default scale ceiling

  return (
    <div className="w-full max-w-4xl mx-auto rounded-xl border border-white/[0.04] bg-[#0A0A0B] p-5 md:p-7 relative overflow-hidden shadow-[0_0_50px_rgba(0,0,0,0.8)]">
      {/* Decorative scanner/laser sweep */}
      <div className="absolute inset-0 bg-[linear-gradient(to_right,rgba(255,255,255,0.01)_1px,transparent_1px),linear-gradient(to_bottom,rgba(255,255,255,0.01)_1px,transparent_1px)] bg-[size:24px_24px] pointer-events-none opacity-40" />
      <div className="absolute top-0 left-0 w-24 h-px bg-gradient-to-r from-transparent via-[#3ECF8E]/30 to-transparent animate-[shimmer_2s_infinite]" />

      <div className="relative z-10 flex flex-col gap-6">
        
        {/* Header Title Grid */}
        <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4 border-b border-white/[0.03] pb-5">
          <div className="flex items-center gap-3">
            <div className={`p-2 rounded-lg ${isRunning ? 'bg-[#3ECF8E]/10 animate-pulse' : 'bg-white/[0.02]'} border border-white/[0.04]`}>
              <Activity size={18} className={isRunning ? 'text-[#3ECF8E]' : 'text-zinc-400'} />
            </div>
            <div>
              <h2 className="text-sm font-black text-white uppercase tracking-widest font-display flex items-center gap-2">
                Interactive Smoke Suite Sandbox
                <span className="text-[7px] font-black tracking-widest px-1.5 py-0.5 rounded bg-[#3ECF8E]/10 text-[#3ECF8E] uppercase">
                  v1.0.0 Live
                </span>
              </h2>
              <p className="text-[9px] text-zinc-500 font-medium">
                Verify server integrity and check real-time latency distributions.
              </p>
            </div>
          </div>

          <div className="flex items-center gap-3 text-[9px] font-mono text-zinc-500 bg-white/[0.01] border border-white/[0.03] px-3 py-1.5 rounded-lg select-none">
            <Globe size={11} className="text-[#3ECF8E]" />
            <span className="uppercase font-bold">Proxy Ingress:</span>
            <span className="text-white">Active Node Engine</span>
          </div>
        </div>

        {/* Input Parameters Controls bar */}
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-4">
          
          {/* URL Input */}
          <div className="lg:col-span-7 flex flex-col gap-1.5">
            <span className="text-[8px] font-black text-zinc-500 uppercase tracking-widest font-mono flex items-center gap-1">
              Endpoint Address
              <span title="Enter any target URL. Default google.com goes through server backend to defeat CORS.">
                <HelpCircle size={10} className="text-zinc-600 cursor-help" />
              </span>
            </span>
            <div className="flex bg-black border border-white/5 rounded-lg overflow-hidden group focus-within:border-[#3ECF8E]/30 focus-within:ring-2 focus-within:ring-[#3ECF8E]/5 transition-all">
              <select
                value={method}
                onChange={(e) => setMethod(e.target.value)}
                disabled={isRunning}
                className="bg-[#0F0F10] px-3 py-2 text-[10px] font-mono font-black border-r border-white/5 text-[#3ECF8E] hover:bg-[#151517] transition-colors cursor-pointer outline-none uppercase"
              >
                <option value="GET">GET</option>
                <option value="POST">POST</option>
                <option value="PUT">PUT</option>
                <option value="DELETE">DELETE</option>
              </select>
              <input
                type="text"
                value={url}
                onChange={(e) => setUrl(e.target.value)}
                disabled={isRunning}
                placeholder="https://example.com/api"
                className="flex-grow bg-transparent px-3.5 py-2 text-[10px] font-mono text-white outline-none placeholder:text-zinc-700"
              />
            </div>
          </div>

          {/* Sizing Parameters */}
          <div className="lg:col-span-5 grid grid-cols-3 gap-3">
            
            {/* Thread Slider */}
            <div className="flex flex-col gap-1.5">
              <span className="text-[8px] font-black text-zinc-500 uppercase tracking-widest font-mono">Threads</span>
              <div className="bg-black border border-white/5 rounded-lg px-2.5 py-1.5 flex items-center justify-between font-mono">
                <input
                  type="number"
                  min="1"
                  max="10"
                  value={threads}
                  disabled={isRunning}
                  onChange={(e) => setThreads(Math.min(10, Math.max(1, parseInt(e.target.value) || 1)))}
                  className="w-8 text-[11px] font-bold text-white bg-transparent outline-none text-center"
                />
                <span className="text-[7px] text-zinc-500 uppercase tracking-tight font-black">Worker</span>
              </div>
            </div>

            {/* Loop Slider */}
            <div className="flex flex-col gap-1.5">
              <span className="text-[8px] font-black text-zinc-500 uppercase tracking-widest font-mono font-bold">Loops</span>
              <div className="bg-black border border-white/5 rounded-lg px-2.5 py-1.5 flex items-center justify-between font-mono">
                <input
                  type="number"
                  min="1"
                  max="50"
                  value={loops}
                  disabled={isRunning}
                  onChange={(e) => setLoops(Math.min(50, Math.max(1, parseInt(e.target.value) || 1)))}
                  className="w-8 text-[11px] font-bold text-white bg-transparent outline-none text-center"
                />
                <span className="text-[7px] text-zinc-500 uppercase tracking-tight font-black">Iter</span>
              </div>
            </div>

            {/* Inter-request delay */}
            <div className="flex flex-col gap-1.5">
              <span className="text-[8px] font-black text-zinc-500 uppercase tracking-widest font-mono">Delay</span>
              <div className="bg-black border border-white/5 rounded-lg px-2 py-1.5 flex items-center justify-between font-mono">
                <input
                  type="number"
                  min="0"
                  max="2000"
                  value={delay}
                  disabled={isRunning}
                  onChange={(e) => setDelay(Math.min(2000, Math.max(0, parseInt(e.target.value) || 0)))}
                  className="w-9 text-[11px] font-bold text-white bg-transparent outline-none text-center"
                />
                <span className="text-[7px] text-zinc-500 uppercase tracking-tight font-black">ms</span>
              </div>
            </div>

          </div>
        </div>

        {/* Trigger Button & Status HUD line */}
        <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4 p-4 bg-white/[0.01] border border-white/[0.03] rounded-lg">
          <div className="flex items-center gap-3">
            {isRunning ? (
              <div className="flex items-center gap-2">
                <div className="w-2 h-2 rounded-full bg-[#3ECF8E] animate-ping" />
                <span className="text-[9px] font-semibold text-zinc-300 font-mono">
                  Transmitting active test load: <strong className="text-white font-black">{samples.length}</strong> / {threads * loops} finished...
                </span>
              </div>
            ) : isCompleted ? (
              <div className="flex items-center gap-2">
                <CheckCircle2 size={13} className="text-[#3ECF8E]" />
                <span className="text-[9px] font-semibold text-zinc-300 font-mono">
                  Transmission finished. Processed <strong className="text-white">{samples.length}</strong> metrics successfully.
                </span>
              </div>
            ) : (
              <div className="flex items-center gap-2">
                <Zap size={13} className="text-zinc-600" />
                <span className="text-[9px] font-semibold text-zinc-400 font-mono">
                  State: <strong className="text-zinc-500 font-black">READY TO DEPLOY TEST ENGINES</strong>
                </span>
              </div>
            )}
          </div>

          <div className="flex items-center gap-2.5">
            {isRunning ? (
              <button
                onClick={stopTest}
                className="px-5 py-2 rounded-md bg-red-500/10 border border-red-500/20 hover:bg-red-500/20 text-red-400 font-black text-[9px] tracking-wider uppercase font-mono flex items-center gap-1.5 cursor-pointer transition-all"
              >
                <Square size={10} fill="currentColor" />
                Abort Safe
              </button>
            ) : (
              <button
                onClick={startTest}
                className="px-6 py-2 rounded-md bg-[#3ECF8E] hover:bg-[#34B37A] text-black font-black text-[9px] tracking-wider uppercase font-mono flex items-center gap-1.5 cursor-pointer shadow-[0_0_20px_rgba(62,207,142,0.15)] hover:scale-[1.02] active:scale-[0.98] transition-all"
              >
                <Play size={10} fill="currentColor" />
                Deploy Suite
              </button>
            )}
          </div>
        </div>

        {/* Live progress and Stats Module Grid */}
        <div className="space-y-4">
          
          {/* Progress Bar (visible only when active/completed) */}
          {(isRunning || totalCount > 0) && (
            <div className="space-y-1.5">
              <div className="flex justify-between items-center text-[7.5px] font-black font-mono tracking-wider text-zinc-500 uppercase">
                <span>Core Sync Progress</span>
                <span className="text-white">{progress}%</span>
              </div>
              <div className="w-full h-[3px] bg-white/[0.02] border border-white/[0.01] rounded-full overflow-hidden">
                <div 
                  className="h-full bg-gradient-to-r from-[#3ECF8E] to-blue-400 transition-all duration-300"
                  style={{ width: `${progress}%` }}
                />
              </div>
            </div>
          )}

          {/* Real-time stats HUD Grid */}
          <div className="grid grid-cols-2 md:grid-cols-4 gap-2">
            
            {/* HUD 1: Success Rate */}
            <div className="bg-[#050506]/85 border border-white/[0.02] rounded-lg p-3 flex flex-col justify-between select-none relative group overflow-hidden">
              <div className="absolute top-0 right-0 w-12 h-12 bg-[#3ECF8E]/2 rounded-full blur-md -mr-4 -mt-4 opacity-50" />
              <span className="text-[7.5px] font-black text-zinc-500 uppercase tracking-wider font-mono">Success Rate</span>
              <div className="mt-2 flex items-baseline gap-1">
                <span className={`text-xl font-mono leading-none font-bold ${totalCount === 0 ? 'text-zinc-600' : successRate >= 90 ? 'text-[#3ECF8E]' : successRate >= 70 ? 'text-amber-500' : 'text-red-400'}`}>
                  {totalCount === 0 ? '---' : `${successRate}%`}
                </span>
              </div>
              <span className="mt-1.5 text-[7px] text-zinc-600 font-bold uppercase tracking-wide font-mono">
                {totalCount === 0 ? 'No load sent' : `${successCount} pkts / ${failureCount} errs`}
              </span>
            </div>

            {/* HUD 2: Avg Latency */}
            <div className="bg-[#050506]/85 border border-white/[0.02] rounded-lg p-3 flex flex-col justify-between select-none relative group overflow-hidden">
              <div className="absolute top-0 right-0 w-12 h-12 bg-blue-500/2 rounded-full blur-md -mr-4 -mt-4 opacity-50" />
              <span className="text-[7.5px] font-black text-zinc-500 uppercase tracking-wider font-mono">Avg Latency</span>
              <div className="mt-2 flex items-baseline gap-0.5">
                <span className="text-xl font-mono leading-none font-bold text-white">
                  {totalCount === 0 ? '---' : `${avgLatency}`}
                </span>
                {totalCount > 0 && <span className="text-[9px] font-bold text-zinc-500 font-mono">ms</span>}
              </div>
              <span className="mt-1.5 text-[7px] text-zinc-600 font-bold uppercase tracking-wide font-mono flex items-center gap-1">
                <Clock size={8} /> Network Roundtrip
              </span>
            </div>

            {/* HUD 3: Performance Ceiling (Min/Max) */}
            <div className="bg-[#050506]/85 border border-white/[0.02] rounded-lg p-3 flex flex-col justify-between select-none relative group overflow-hidden">
              <div className="absolute top-0 right-0 w-12 h-12 bg-purple-500/2 rounded-full blur-md -mr-4 -mt-4 opacity-50" />
              <span className="text-[7.5px] font-black text-zinc-500 uppercase tracking-wider font-mono">Variance Ceiling</span>
              <div className="mt-2 text-white font-mono flex flex-col">
                <span className="text-xs font-bold leading-normal">
                  <span className="text-zinc-600 mr-1">MIN:</span>{totalCount === 0 ? '---' : `${minLatency}ms`}
                </span>
                <span className="text-xs font-bold leading-normal">
                  <span className="text-zinc-600 mr-1">MAX:</span>{totalCount === 0 ? '---' : `${maxLatency}ms`}
                </span>
              </div>
              <span className="mt-1 text-[7px] text-zinc-600 font-bold uppercase tracking-wide font-mono">
