              </span>
            </div>

            {/* HUD 4: Throttling & Queue status */}
            <div className="bg-[#050506]/85 border border-white/[0.02] rounded-lg p-3 flex flex-col justify-between select-none relative group overflow-hidden">
              <div className="absolute top-0 right-0 w-12 h-12 bg-pink-500/2 rounded-full blur-md -mr-4 -mt-4 opacity-50" />
              <span className="text-[7.5px] font-black text-zinc-500 uppercase tracking-wider font-mono">Load Capacity</span>
              <div className="mt-2 flex items-baseline gap-1">
                <span className="text-xl font-mono leading-none font-bold text-[#3ECF8E] drop-shadow-[0_0_8px_rgba(62,207,142,0.1)]">
                  {totalCount === 0 ? '---' : `${Math.round((totalCount / (threads * loops)) * 100)}%`}
                </span>
              </div>
              <span className="mt-1.5 text-[7px] text-zinc-600 font-bold uppercase tracking-wide font-mono">
                {isRunning ? 'TRANSMISSIONS RUNNING' : isCompleted ? 'FULL AUDIT CONCLUDED' : 'Awaiting Deployment'}
              </span>
            </div>

          </div>

          {/* Live distribution CSS-bar visual chart */}
          {totalCount > 0 && (
            <div className="space-y-2 pt-1 border-t border-white/[0.02]">
              <div className="flex justify-between items-center text-[7.5px] font-black font-mono tracking-wider text-zinc-500 uppercase">
                <span>Packet Index & Latency Grid</span>
                <span className="text-zinc-500 lowercase">hover bar for server telemetry diagnostics</span>
              </div>

              <div className="relative">
                {/* Visual grid line marks */}
                <div className="absolute inset-x-0 top-0 h-24 flex flex-col justify-between pointer-events-none border-b border-white/[0.02]">
                  <div className="border-t border-white/[0.03] w-full h-px" />
                  <div className="border-t border-dashed border-white/[0.02] w-full h-px" />
                  <div className="border-t border-dashed border-white/[0.02] w-full h-px" />
                </div>

                {/* Bars Row container */}
                <div className="relative h-24 bg-black/40 border border-white/[0.02] rounded-lg flex items-end p-2 md:gap-1.5 gap-1 overflow-x-auto overflow-y-hidden custom-scrollbar">
                  {samples.map((sample, idx) => {
                    // Height is proportional to latency
                    const heightPct = Math.min(100, (sample.latency / maxSampleLatency) * 100);
                    return (
                      <div
                        key={sample.id}
                        onMouseEnter={() => setHoveredSample(sample)}
                        onMouseLeave={() => setHoveredSample(null)}
                        className="flex-1 min-w-[8px] max-w-[20px] h-full flex items-end justify-center group cursor-pointer"
                      >
                        <div 
                          className={`w-full rounded-t-[1.5px] transition-all duration-300 ${
                            sample.success 
                              ? 'bg-[#3ECF8E]/55 hover:bg-[#3ECF8E]' 
                              : 'bg-red-500/50 hover:bg-red-500'
                          }`}
                          style={{ height: `${Math.max(4, heightPct)}%` }}
                        />
                      </div>
                    );
                  })}
                </div>

                {/* Holographic Tooltip overlays */}
                <AnimatePresence>
                  {hoveredSample && (
                    <motion.div
                      initial={{ opacity: 0, y: 5, scale: 0.95 }}
                      animate={{ opacity: 1, y: 0, scale: 1 }}
                      exit={{ opacity: 0, y: 5, scale: 0.95 }}
                      transition={{ duration: 0.12 }}
                      className="absolute left-1/2 bottom-26 -translate-x-1/2 z-30 bg-[#0E0E10] border border-white/[0.06] shadow-2xl rounded-lg px-3.5 py-2.5 w-60 text-left select-none pointer-events-none flex flex-col gap-1.5 backdrop-blur-md"
                    >
                      <div className="flex items-center justify-between">
                        <span className="text-[7.5px] font-black text-zinc-500 uppercase tracking-widest font-mono">
                          Worker Thread #{hoveredSample.threadId}
                        </span>
                        <span className={`text-[7px] font-black tracking-widest px-1.5 py-0.5 rounded uppercase font-mono ${
                          hoveredSample.success ? 'bg-[#3ECF8E]/10 text-[#3ECF8E]' : 'bg-red-500/10 text-red-400'
                        }`}>
                          HTTP {hoveredSample.status || 'ERR'}
                        </span>
                      </div>
                      <div className="h-px bg-white/[0.04] w-full" />
                      <div className="grid grid-cols-2 gap-y-1 text-[9px] font-mono font-medium">
                        <span className="text-zinc-500">Latency:</span>
                        <span className="text-white text-right font-bold">{hoveredSample.latency} ms</span>
                        <span className="text-zinc-500">Result:</span>
                        <span className={`text-right font-black ${hoveredSample.success ? 'text-[#3ECF8E]' : 'text-red-400'}`}>
                          {hoveredSample.success ? 'SUCCESS' : 'FAILED'}
                        </span>
                        <span className="text-zinc-500">Message:</span>
                        <span className="text-white text-right text-[8px] break-words line-clamp-1">{hoveredSample.statusText}</span>
                      </div>
                    </motion.div>
                  )}
                </AnimatePresence>
              </div>
            </div>
          )}

        </div>

      </div>
    </div>
  );
}

import React, { useEffect, useRef, Suspense } from 'react';
import type { OnMount } from '@monaco-editor/react';
import { Play, Save, X, FileCode } from 'lucide-react';
import { useScriptStore } from '../../store/scriptStore';
import { useStore } from '../../store/useStore';
import { cn } from '../../lib/utils';
import { registerGimayCompletions } from '../../services/monacoCompletion';
import { ScriptEngine } from '../../services/scriptEngine';
import { PersistenceService } from '../../services/PersistenceService';

const Editor = React.lazy(() => import('@monaco-editor/react'));

export const ScriptEditor: React.FC = () => {
  const { openTabs, activeTabId, closeTab, scripts, updateScript, setTabDirty } = useScriptStore();
  const { addToast, settings } = useStore();
  const editorRef = useRef<any>(null);
  const monacoRef = useRef<any>(null);
  const disposablesRef = useRef<any[]>([]);

  const activeTab = openTabs.find(t => t.id === activeTabId);
  const activeScript = scripts.find(s => s.id === activeTab?.scriptId);

  const theme = settings.appearance.theme === 'system' 
    ? (window.matchMedia('(prefers-color-scheme: dark)').matches ? 'dark' : 'light')
    : settings.appearance.theme;

  const handleEditorMount: OnMount = (editor, monaco) => {
    editorRef.current = editor;
    monacoRef.current = monaco;
    
    // Clear old registrations
    disposablesRef.current.forEach(d => d.dispose());
    // Register optimized completions
    disposablesRef.current = registerGimayCompletions(monaco);
    
    updateEditorTheme();
  };

  const updateEditorTheme = () => {
    if (!monacoRef.current) return;
    
    const monaco = monacoRef.current;
    
    monaco.editor.defineTheme('gimay-custom', {
      base: theme === 'light' ? 'vs' : 'vs-dark',
      inherit: true,
      rules: [
        { token: 'comment', foreground: '666666', fontStyle: 'italic' },
        { token: 'keyword', foreground: theme === 'light' ? '008000' : '3ECF8E' },
        { token: 'string', foreground: theme === 'light' ? '000000' : 'E0E0E0' },
        { token: 'variable', foreground: theme === 'light' ? '000000' : 'AAAAAA' },
      ],
      colors: {
        'editor.background': theme === 'light' ? '#FFFFFF' : '#0F0F0F',
        'editor.lineHighlightBackground': theme === 'light' ? '#F3F4F6' : '#1A1A1A',
        'editorLineNumber.foreground': theme === 'light' ? '#9CA3AF' : '#333333',
        'editorLineNumber.activeForeground': theme === 'light' ? '#000000' : '#3ECF8E',
        'editor.selectionBackground': theme === 'light' ? '#3ECF8E44' : '#3ECF8E33',
      }
    });
    
    monaco.editor.setTheme('gimay-custom');
  };

  useEffect(() => {
    updateEditorTheme();
  }, [theme]);

  // Clean up completions on unmount
  useEffect(() => {
    return () => {
      disposablesRef.current.forEach(d => d.dispose());
    };
  }, []);

  const [isSaving, setIsSaving] = React.useState(false);

  const handleSave = async () => {
    if (isSaving) return;
    setIsSaving(true);
    
    if (!activeScript || !activeTab) {
      setIsSaving(false);
      return;
    }
    
    const content = editorRef.current?.getValue();
    if (content === undefined) {
      addToast({ type: 'warning', message: 'Editor not ready.' });
      setIsSaving(false);
      return;
    }

    try {
      await PersistenceService.updateScript(activeScript.id, { 
        content,
        name: activeScript.name 
      });
      updateScript(activeScript.id, { content });
      setTabDirty(activeTab.id, false);
      addToast({ type: 'success', message: 'Script saved.' });
    } catch (e) {
      addToast({ type: 'error', message: 'Save failed.' });
    } finally {
      setIsSaving(false);
    }
  };

  const handleRun = () => {
    if (!activeScript) return;
    const content = editorRef.current?.getValue();
    ScriptEngine.execute(content);
  };

  // Keyboard shortcuts
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if ((e.metaKey || e.ctrlKey) && e.key === 's') {
        e.preventDefault();
        handleSave();
      }
      if ((e.metaKey || e.ctrlKey) && e.key === 'Enter') {
        e.preventDefault();
        handleRun();
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [activeScript, activeTab, isSaving]);

  if (!activeTab || !activeScript) {
    return (
      <div className="flex-1 flex flex-col items-center justify-center bg-[var(--bg-surface)] text-[var(--border-subtle)]">
        <FileCode size={64} className="mb-4 opacity-50 text-[var(--brand)] shadow-[0_0_30px_var(--brand-muted)]" />
        <h3 className="text-sm font-black uppercase tracking-[0.3em] opacity-50 text-[var(--text-dim)]">Select a script to edit</h3>
        <p className="text-[10px] mt-2 font-mono opacity-30 text-[var(--text-dim)]">Ctrl+N to create new</p>
      </div>
    );
  }

  return (
    <div className="flex-1 flex flex-col min-w-0 bg-[var(--bg-surface)]">
      {/* Tabs */}
      <div className="h-10 bg-[var(--bg-deep)] border-b border-[var(--border-subtle)] flex items-center px-1 gap-px overflow-x-auto no-scrollbar">
        {openTabs.map((tab) => {
          const script = scripts.find(s => s.id === tab.scriptId);
          if (!script) return null;
          return (
            <div 
              key={tab.id}
              onClick={() => useScriptStore.getState().setActiveTabId(tab.id)}
              className={cn(
                "h-full px-4 flex items-center gap-2 cursor-pointer transition-all border-t-2 text-[10px] font-bold min-w-[120px] max-w-[200px] shrink-0 group relative",
                activeTabId === tab.id 
                  ? "bg-[var(--bg-surface)] border-[var(--brand)] text-[var(--text-main)]" 
                  : "bg-[var(--bg-deep)] border-transparent text-[var(--text-dim)] hover:bg-[var(--bg-elevated)]"
              )}
            >
              <FileCode size={12} className={activeTabId === tab.id ? "text-[var(--brand)]" : ""} />
              <span className="truncate flex-1 pr-4">{script.name}</span>
              {tab.isDirty && <div className="w-1.5 h-1.5 rounded-full bg-[var(--brand)] shrink-0 mr-1" />}
              <button 
                onClick={(e) => { e.stopPropagation(); closeTab(tab.id); }}
                className="p-1 hover:bg-[var(--bg-elevated)] rounded transition-all opacity-0 group-hover:opacity-100 absolute right-2 top-1/2 -translate-y-1/2"
              >
                <X size={10} />
              </button>
            </div>
          );
        })}
      </div>

      {/* Toolbar */}
      <div className="h-12 border-b border-[var(--border-subtle)] flex items-center justify-between px-6 shrink-0 bg-[var(--bg-elevated)]">
        <div className="flex items-center gap-4">
          <input 
            value={activeScript.name}
            onChange={(e) => updateScript(activeScript.id, { name: e.target.value })}
            className="bg-transparent border-none text-[12px] font-black text-[var(--text-main)] uppercase tracking-widest outline-none focus:text-[var(--brand)] transition-all"
          />
          {activeTab.isDirty && (
            <span className="text-[9px] font-black text-[var(--brand)] uppercase tracking-tighter bg-[var(--brand)]/10 px-2 py-0.5 rounded">Unsaved Changes</span>
          )}
        </div>
        
        <div className="flex items-center gap-3">
          <button 
            onClick={handleSave}
            disabled={isSaving}
            className={cn(
              "flex items-center gap-2 px-3 py-1.5 rounded-lg border border-[var(--border-subtle)] text-[10px] font-black transition-all uppercase",
              isSaving ? "opacity-50 cursor-not-allowed" : "text-[var(--text-muted)] hover:text-[var(--brand)] hover:border-[var(--brand)]/30"
            )}
          >
            <Save size={14} className={isSaving ? "animate-spin text-[var(--brand)]" : ""} /> {isSaving ? 'Saving...' : 'Save'}
          </button>
          <button 
            onClick={handleRun}
            className="flex items-center gap-2 px-4 py-1.5 rounded-lg bg-[var(--brand)] text-[var(--bg-deep)] text-[10px] font-black hover:shadow-[0_0_15px_var(--brand-muted)] transition-all uppercase"
          >
            <Play size={14} fill="currentColor" /> Run Script
          </button>
        </div>
      </div>

      {/* Editor with Lazy Monaco */}
      <div className="flex-1 relative">
        <Suspense fallback={
          <div className="absolute inset-0 flex flex-col items-center justify-center bg-[var(--bg-surface)]">
            <div className="animate-spin text-[var(--brand)] mb-3">
              <FileCode size={36} className="shadow-[0_0_30px_var(--brand-muted)]" />
            </div>
            <span className="text-[10px] font-black uppercase tracking-[0.2em] text-[var(--text-dim)]">Initializing Code Space...</span>
          </div>
        }>
          <Editor
            height="100%"
            defaultLanguage="javascript"
            value={activeScript.content}
            onMount={handleEditorMount}
            onChange={(val) => {
              if (!activeTab.isDirty) setTabDirty(activeTab.id, true);
            }}
            options={{
              minimap: { enabled: false },
              quickSuggestions: { other: true, comments: false, strings: false },
              parameterHints: { enabled: true },
              folding: false,
              fontSize: 13,
              fontFamily: "'JetBrains Mono', 'Fira Code', monospace",
              lineHeight: 22,
              scrollbar: {
                vertical: 'auto',
                horizontal: 'auto'
              },
              padding: { top: 20 },
              smoothScrolling: true,
              cursorBlinking: 'smooth',
              bracketPairColorization: { enabled: true },
              automaticLayout: true
            }}
          />
        </Suspense>
      </div>
    </div>
  );
};

import React, { useEffect } from 'react';
import { motion, AnimatePresence } from 'motion/react';
import { X, Code2, Sparkles, Terminal, Plus } from 'lucide-react';
import { useScriptStore } from '../../store/scriptStore';
import { useStore } from '../../store/useStore';
import { ScriptSidebar } from './ScriptSidebar';
import { ScriptEditor } from './ScriptEditor';
import { ConsolePanel } from './ConsolePanel';
import { PersistenceService } from '../../services/PersistenceService';

interface ScriptLibraryProps {
  isOpen: boolean;
  onClose: () => void;
}

export const ScriptLibrary: React.FC<ScriptLibraryProps> = ({ isOpen, onClose }) => {
  const { profile, activeWorkspaceId, addToast } = useStore();
  const { setScripts, setFolders } = useScriptStore();

  useEffect(() => {
    if (isOpen && activeWorkspaceId && activeWorkspaceId !== 'null' && activeWorkspaceId !== 'undefined') {
      const loadData = async () => {
        try {
          const [scripts, folders] = await Promise.all([
            PersistenceService.fetchScripts(activeWorkspaceId),
            PersistenceService.fetchScriptFolders(activeWorkspaceId)
          ]);
          setScripts(scripts);
          setFolders(folders);
        } catch (e) {
          console.error('Failed to load script library:', e);
        }
      };
      loadData();
    }
  }, [isOpen, activeWorkspaceId]);

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-[200] flex items-center justify-center p-4 md:p-8">
      {/* Backdrop */}
      <motion.div 
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        exit={{ opacity: 0 }}
        onClick={onClose}
        className="absolute inset-0 bg-black/80 backdrop-blur-sm"
      />

      {/* Modal Content */}
      <motion.div
        initial={{ opacity: 0, scale: 0.95, y: 20 }}
        animate={{ opacity: 1, scale: 1, y: 0 }}
        exit={{ opacity: 0, scale: 0.95, y: 20 }}
        className="relative w-full h-full bg-[var(--bg-surface)] border border-[var(--border-subtle)] rounded-2xl shadow-2xl overflow-hidden flex flex-col z-10"
      >
        {/* Header */}
        <div className="h-14 border-b border-[var(--border-subtle)] flex items-center justify-between px-6 bg-[var(--bg-deep)] shrink-0">
          <div className="flex items-center gap-4">
            <div className="w-8 h-8 rounded-xl bg-[var(--brand)] flex items-center justify-center shadow-[0_0_15px_var(--brand-muted)]">
              <Code2 size={16} className="text-[var(--bg-deep)]" />
            </div>
            <div>
              <h1 className="text-[12px] font-black text-[var(--text-main)] uppercase tracking-[0.2em] flex items-center gap-2">
                Script Laboratory
                <Sparkles size={12} className="text-[var(--brand)]" />
              </h1>
            </div>
          </div>

          <div className="flex items-center gap-3">
            <button 
              onClick={async () => {
                if (!profile?.id || !activeWorkspaceId) {
                  addToast({ type: 'warning', message: 'No active workspace detected.' });
                  return;
                }
                try {
                  const newScript = await PersistenceService.createScript({
                    name: 'Untitled Script',
                    content: '// Write your code here\n',
                    workspace_id: activeWorkspaceId,
                    user_id: profile.id,
                  });
                  useScriptStore.getState().addScript(newScript);
                  useScriptStore.getState().addTab(newScript.id);
                  addToast({ type: 'success', message: 'New script initialized.' });
                } catch (e) {
                  addToast({ type: 'error', message: 'Failed to initialize script.' });
                }
              }}
              className="px-3 py-1.5 bg-[var(--brand)] text-[var(--bg-deep)] text-[10px] font-black rounded-lg uppercase tracking-widest hover:brightness-110 transition-all flex items-center gap-2"
            >
              <Plus size={14} /> New Script
            </button>
            <div className="h-4 w-px bg-[var(--border-subtle)]" />
            <button 
              onClick={onClose}
              className="p-1.5 text-[var(--text-dim)] hover:text-[var(--text-main)] transition-all hover:bg-[var(--bg-elevated)] rounded-md"
            >
              <X size={20} />
            </button>
          </div>
        </div>

        {/* Main Content */}
        <div className="flex-1 flex overflow-hidden">
          <ScriptSidebar />
          <div className="flex-1 flex flex-col min-w-0 bg-[var(--bg-surface)]">
            <ScriptEditor />
            <ConsolePanel />
          </div>
        </div>
      </motion.div>
    </div>
  );
};

import React, { useState } from 'react';
import { 
  FileCode, 
  Folder, 
  Plus, 
  Search, 
  ChevronRight, 
  MoreVertical, 
  Trash2, 
  Copy, 
  Edit3,
  Star,
  Upload
} from 'lucide-react';
import { useScriptStore } from '../../store/scriptStore';
import { useStore } from '../../store/useStore';
import { cn } from '../../lib/utils';
import { Script } from '../../types';
import { PersistenceService } from '../../services/PersistenceService';

export const ScriptSidebar: React.FC = () => {
  const { scripts, folders, addTab, activeTabId, addScript, deleteScript, setScripts } = useScriptStore();
  const { profile, activeWorkspaceId, addToast } = useStore();
  const [searchQuery, setSearchQuery] = useState('');

  const filteredScripts = scripts.filter(s => 
    s.name.toLowerCase().includes(searchQuery.toLowerCase())
  );

  const handleCreateScript = async () => {
    if (!profile?.id || !activeWorkspaceId) {
      addToast({ type: 'warning', message: 'No active workspace detected.' });
      return;
    }
    try {
      const newScript = await PersistenceService.createScript({
        name: 'Untitled Script',
        content: '// Write your code here\n',
        workspace_id: activeWorkspaceId,
        user_id: profile.id,
      });
      addScript(newScript);
      addTab(newScript.id);
      addToast({ type: 'success', message: 'New script initialized.' });
    } catch (e) {
      addToast({ type: 'error', message: 'Failed to initialize script.' });
    }
  };

  const handleImportScript = async () => {
    const input = document.createElement('input');
    input.type = 'file';
    input.accept = '.js,.txt,.json';
    input.onchange = async (e: any) => {
      const file = e.target.files?.[0];
      if (!file || !profile?.id || !activeWorkspaceId) return;

      const reader = new FileReader();
      reader.onload = async (event) => {
        const content = event.target?.result as string;
        try {
          const newScript = await PersistenceService.createScript({
            name: file.name.replace(/\.[^/.]+$/, ""),
            content: content || '// Imported script\n',
            workspace_id: activeWorkspaceId,
            user_id: profile.id,
          });
          addScript(newScript);
          addTab(newScript.id);
          addToast({ type: 'success', message: 'Script imported successfully.' });
        } catch (e) {
          addToast({ type: 'error', message: 'Import failed.' });
        }
      };
      reader.readAsText(file);
    };
    input.click();
  };

  const handleDelete = async (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    try {
      await PersistenceService.deleteScript(id);
      deleteScript(id);
      addToast({ type: 'info', message: 'Script deleted.' });
    } catch (e) {
      addToast({ type: 'error', message: 'Deletion failed.' });
    }
  };

  const [renamingId, setRenamingId] = useState<string | null>(null);

  const handleRename = async (id: string, newName: string) => {
    if (!newName.trim()) return;
    try {
      await PersistenceService.updateScript(id, { name: newName });
      useScriptStore.getState().updateScript(id, { name: newName });
      setRenamingId(null);
    } catch (e) {
      addToast({ type: 'error', message: 'Rename failed.' });
    }
  };

  return (
    <div className="w-64 bg-[var(--bg-surface)] border-r border-[var(--border-subtle)] flex flex-col shrink-0">
      <div className="p-4 border-b border-[var(--border-subtle)] space-y-4">
        <div className="flex items-center justify-between">
          <h2 className="text-[11px] font-black text-[var(--text-main)] uppercase tracking-widest">Script Explorer</h2>
          <div className="flex items-center gap-1">
            <button 
              onClick={handleImportScript}
              className="p-1.5 hover:bg-[var(--brand)]/10 hover:text-[var(--brand)] text-[var(--text-muted)] rounded-md transition-all border border-[var(--border-subtle)] hover:border-[var(--brand)]/30"
              title="Import Script"
            >
              <Upload size={14} />
            </button>
            <button 
              onClick={handleCreateScript}
              className="p-1.5 hover:bg-[var(--brand)]/10 hover:text-[var(--brand)] text-[var(--text-muted)] rounded-md transition-all border border-[var(--border-subtle)] hover:border-[var(--brand)]/30"
              title="New Script"
            >
              <Plus size={14} />
            </button>
          </div>
        </div>

        <div className="relative group">
          <Search size={12} className="absolute left-2.5 top-1/2 -translate-y-1/2 text-[var(--border-strong)] group-focus-within:text-[var(--brand)] transition-colors" />
          <input 
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            placeholder="FILTER_SCRIPTS..."
            className="w-full bg-[var(--bg-deep)] border border-[var(--border-subtle)] rounded-md py-1.5 pl-8 pr-3 text-[10px] font-mono text-[var(--text-muted)] focus:border-[var(--brand)]/40 outline-none transition-all"
          />
        </div>
      </div>

      <div className="flex-1 overflow-y-auto py-2 custom-scrollbar">
        {filteredScripts.length === 0 ? (
          <div className="p-8 text-center flex flex-col items-center">
            <FileCode size={32} className="mb-2 text-[var(--border-subtle)]" />
            <p className="text-[9px] font-black text-[var(--border-strong)] uppercase tracking-widest mb-4">No scripts found</p>
            <button 
              onClick={handleCreateScript}
              className="px-4 py-2 bg-[var(--brand)]/10 border border-[var(--brand)]/30 rounded-lg text-[9px] font-black text-[var(--brand)] uppercase tracking-widest hover:bg-[var(--brand)]/20 transition-all flex items-center gap-2"
            >
              <Plus size={12} />
              Create First Script
            </button>
          </div>
        ) : (
          filteredScripts.map((script) => (
            <div 
              key={script.id}
              onClick={() => addTab(script.id)}
              className={cn(
                "group flex items-center px-4 py-2 cursor-pointer transition-all border-l-2",
                useScriptStore.getState().openTabs.find(t => t.scriptId === script.id && t.id === activeTabId)
                  ? "bg-[var(--brand)]/5 border-[var(--brand)] text-[var(--text-main)]" 
                  : "border-transparent text-[var(--text-dim)] hover:bg-[var(--bg-elevated)] hover:text-[var(--text-muted)]"
              )}
            >
              <FileCode size={14} className="mr-3 shrink-0" />
              {renamingId === script.id ? (
                <input 
                  autoFocus
                  defaultValue={script.name}
                  onBlur={(e) => handleRename(script.id, e.target.value)}
                  onKeyDown={(e) => {
                    if (e.key === 'Enter') handleRename(script.id, e.currentTarget.value);
                    if (e.key === 'Escape') setRenamingId(null);
                  }}
                  onClick={(e) => e.stopPropagation()}
                  className="bg-[var(--bg-deep)] border border-[var(--brand)]/30 rounded px-2 py-0.5 text-[10px] text-[var(--text-main)] outline-none w-full"
                />
              ) : (
                <span className="text-[10px] font-bold truncate flex-1">{script.name}</span>
              )}
              
              <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-all">
                <button 
                  onClick={(e) => { e.stopPropagation(); setRenamingId(script.id); }}
                  className="p-1 hover:text-[var(--brand)] text-[var(--border-strong)] transition-all"
                >
                  <Edit3 size={12} />
                </button>
                <button 
                  onClick={(e) => handleDelete(script.id, e)}
                  className="p-1 hover:text-red-500 text-[var(--border-strong)] transition-all"
                >
                  <Trash2 size={12} />
                </button>
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { createPortal } from 'react-dom';
import { motion, AnimatePresence } from 'motion/react';
import { 
  Settings as SettingsIcon, 
  Moon, 
  Sun, 
  Monitor, 
  Shield, 
  Globe, 
  Zap, 
  Database, 
  Info, 
  X, 
  ChevronRight, 
  Lock, 
  Search,
  Eye,
  EyeOff,
  Terminal,
  Cpu,
  Clock,
  HardDrive,
  RefreshCw,
  Layout,
  Type,
  FlaskConical,
  Activity,
  Trash2,
  Download,
  Upload,
  RotateCcw,
  Github,
  CloudDownload,
  ShieldAlert
} from 'lucide-react';
import { useStore } from '../store/useStore';
import { DatabaseMigrationModal } from './DatabaseMigrationModal';
import { cn } from '../lib/utils';
import { AppSettings } from '../types';
import { isElectron } from '../lib/platform';
import { ProxyService } from '../services/ProxyService';

interface SettingsModalProps {
  isOpen: boolean;
  onClose: () => void;
}

type SettingsSection = 'General' | 'Themes' | 'Proxy' | 'SSL/TLS' | 'Cookies' | 'Response & Network' | 'Migration' | 'Experimental' | 'Diagnostics' | 'About';

export const SettingsModal: React.FC<SettingsModalProps> = ({ isOpen, onClose }) => {
  const { settings, updateSettings, resetSettings, activeWorkspaceId, profile, addToast } = useStore();
  const [activeSection, setActiveSection] = useState<SettingsSection>('General');
  const [searchQuery, setSearchQuery] = useState('');
  const [isMigrationOpen, setIsMigrationOpen] = useState(false);
  const [isPulling, setIsPulling] = useState(false);
  const [showClearConfirm, setShowClearConfirm] = useState(false);
  const [showResetConfirm, setShowResetConfirm] = useState(false);

  // Database Integrity States
  const [checkingIntegrity, setCheckingIntegrity] = useState(false);
  const [repairingIntegrity, setRepairingIntegrity] = useState(false);
  const [integrityStatus, setIntegrityStatus] = useState<string | null>(null);
  const [missingTables, setMissingTables] = useState<string[]>([]);

  const handleVerifyIntegrity = async () => {
    setCheckingIntegrity(true);
    setIntegrityStatus('Checking database structure...');
    setMissingTables([]);
    try {
      const { getSupabaseConfig } = await import('../lib/supabase');
      const { compareDatabaseStructure } = await import('../services/ensureDatabaseSchema');
      const config = getSupabaseConfig();
      if (!config.url || !config.anonKey) {
        setIntegrityStatus('Database connection not configured.');
        setCheckingIntegrity(false);
        return;
      }
      const res = await compareDatabaseStructure(config.url, config.anonKey);
      if (res.success) {
        if (res.upToDate) {
          setIntegrityStatus('✓ Database structure is fully consistent and up to date.');
          addToast({ type: 'success', message: 'Database structure verified. No anomalies detected!' });
        } else {
          setIntegrityStatus('⚠️ Schema mismatch or missing elements found.');
          setMissingTables(res.missingTables || []);
          addToast({ type: 'warning', message: 'Database schema mismatch detected. Tap self-repair to resolve.' });
        }
      } else {
        setIntegrityStatus(`✕ Verification Error: ${res.error}`);
        addToast({ type: 'error', message: res.error || 'Failed to verify structure.' });
      }
    } catch (e: any) {
      setIntegrityStatus(`✕ Exception: ${e.message || e}`);
    } finally {
      setCheckingIntegrity(false);
    }
  };

  const handleRepairIntegrity = async () => {
    setRepairingIntegrity(true);
    setIntegrityStatus('Initiating database self-repair sequence...');
    try {
      const { getSupabaseConfig } = await import('../lib/supabase');
      const { ensureDatabaseSchema } = await import('../services/ensureDatabaseSchema');
      const config = getSupabaseConfig();
      if (!config.url || !config.anonKey) {
        setIntegrityStatus('Database connection not configured.');
        setRepairingIntegrity(false);
        return;
      }
      const res = await ensureDatabaseSchema(config.url, config.anonKey, (progressLabel) => {
        setIntegrityStatus(`Repairing: ${progressLabel}`);
      });
      if (res.success) {
        setIntegrityStatus('✓ Database constraints and schema successfully restored and verified!');
        setMissingTables([]);
        addToast({ type: 'success', message: 'Database self-repair successfully executed!' });
      } else {
        setIntegrityStatus(`✕ Repair Halted: ${res.error}`);
        addToast({ type: 'error', message: res.error || 'Failed to apply repair sequence.' });
      }
    } catch (e: any) {
      setIntegrityStatus(`✕ Exception: ${e.message || e}`);
    } finally {
      setRepairingIntegrity(false);
    }
  };

  const handleUpdate = (path: string, value: any) => {
    const parts = path.split('.');
    if (parts.length === 1) {
      updateSettings({ [parts[0]]: value });
    } else {
      const section = parts[0] as keyof AppSettings;
      updateSettings({
        [section]: {
          ...(settings[section] as any),
          [parts[1]]: value,
        },
      });
    }
  };

  const sections: { id: SettingsSection; icon: any; label: string; description?: string }[] = [
    { id: 'General', icon: SettingsIcon, label: 'General' },
    { id: 'Themes', icon: Layout, label: 'Appearance' },
    { id: 'Proxy', icon: Globe, label: 'Proxy' },
    { id: 'SSL/TLS', icon: Shield, label: 'SSL / TLS' },
    { id: 'Cookies', icon: Database, label: 'Cookies' },
    { id: 'Response & Network', icon: Zap, label: 'Network' },
    { id: 'Migration', icon: Database, label: 'Migration' },
    { id: 'Experimental', icon: FlaskConical, label: 'Experimental' },
    { id: 'Diagnostics', icon: Activity, label: 'Diagnostics' },
    { id: 'About', icon: Info, label: 'About' },
  ];

  const filteredSections = useMemo(() => {
    if (!searchQuery) return sections;
    const lowerQuery = searchQuery.toLowerCase();
    return sections.filter(s => 
      s.label.toLowerCase().includes(lowerQuery) || 
      s.id.toLowerCase().includes(lowerQuery)
    );
  }, [searchQuery]);

  const handleClearCache = () => {
    setShowClearConfirm(true);
  };

  const handleExportSettings = () => {
    const data = JSON.stringify(settings, null, 2);
    const blob = new Blob([data], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `gimay-settings-${new Date().toISOString().split('T')[0]}.json`;
    a.click();
  };

  const handleImportSettings = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (ev) => {
      try {
        const imported = JSON.parse(ev.target?.result as string);
        updateSettings(imported);
        addToast({ type: 'success', message: 'Settings imported successfully.' });
      } catch (err) {
        addToast({ type: 'error', message: 'Invalid settings file.' });
      }
    };
    reader.readAsText(file);
  };

  if (!isOpen) return null;

  return createPortal(
    <div className="fixed inset-0 z-[500] flex items-center justify-center p-4">
      <motion.div 
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        exit={{ opacity: 0 }}
        onClick={onClose}
        className="absolute inset-0 bg-black/80 backdrop-blur-sm" 
      />
      
      <motion.div
        initial={{ opacity: 0, scale: 0.95, y: 20 }}
        animate={{ opacity: 1, scale: 1, y: 0 }}
        exit={{ opacity: 0, scale: 0.95, y: 20 }}
        className="relative w-full max-w-4xl h-[650px] bg-[var(--bg-deep)] border border-[var(--border-subtle)] rounded-xl overflow-hidden shadow-2xl flex"
      >
        {showClearConfirm && (
          <div className="absolute inset-0 z-[100] bg-black/95 backdrop-blur-md flex flex-col items-center justify-center p-8 text-center select-none animate-in fade-in duration-200">
            <Trash2 size={40} className="text-red-500 mb-4 animate-[pulse_1.5s_infinite]" />
            <h3 className="text-xs font-black text-white uppercase tracking-[0.2em] mb-2">Purge Application Storage</h3>
            <p className="text-[10px] text-gray-400 max-w-sm mb-6 font-mono leading-relaxed uppercase tracking-tight">
              Are you sure you want to clear all locally cached data and settings? This operation is permanent and will sign you out of all sessions.
            </p>
            <div className="flex gap-3">
              <button
                onClick={() => {
                  try {
                    localStorage.clear();
                  } catch {}
                  window.location.reload();
                }}
                className="px-5 py-2.5 bg-red-600 hover:bg-red-700 text-[10px] font-black uppercase tracking-widest text-white rounded-lg transition-all cursor-pointer"
              >
                Confirm Purge
              </button>
              <button
                onClick={() => setShowClearConfirm(false)}
                className="px-5 py-2.5 bg-[#1C1C24] border border-[#2D2D39] text-[10px] font-black uppercase tracking-widest text-[#88888F] hover:text-white rounded-lg transition-all cursor-pointer"
              >
                Cancel
              </button>
            </div>
          </div>
        )}

        {showResetConfirm && (
          <div className="absolute inset-0 z-[100] bg-black/95 backdrop-blur-md flex flex-col items-center justify-center p-8 text-center select-none animate-in fade-in duration-200">
            <RotateCcw size={40} className="text-yellow-500 mb-4 animate-[spin_4s_linear_infinite]" />
            <h3 className="text-xs font-black text-white uppercase tracking-[0.2em] mb-2">Reset Factory Defaults</h3>
            <p className="text-[10px] text-gray-400 max-w-sm mb-6 font-mono leading-relaxed uppercase tracking-tight">
              Are you sure you want to reset all configurations and settings back to default factory parameters?
            </p>
            <div className="flex gap-3">
              <button
                onClick={() => {
                  resetSettings();
                  setShowResetConfirm(false);
                  addToast({ type: 'success', message: 'All configurations have been reset.' });
                }}
                className="px-5 py-2.5 bg-yellow-600 hover:bg-yellow-700 text-[10px] font-black uppercase tracking-widest text-white rounded-lg transition-all cursor-pointer"
              >
                Confirm Reset
              </button>
              <button
                onClick={() => setShowResetConfirm(false)}
                className="px-5 py-2.5 bg-[#1C1C24] border border-[#2D2D39] text-[10px] font-black uppercase tracking-widest text-[#88888F] hover:text-white rounded-lg transition-all cursor-pointer"
              >
                Cancel
              </button>
            </div>
          </div>
        )}

        {/* Sidebar */}
        <div className="w-64 bg-[var(--bg-surface)] border-r border-[var(--border-subtle)] flex flex-col">
          <div className="p-6">
            <h2 className="text-[11px] font-black uppercase tracking-widest text-[var(--text-dim)] mb-4">Operations Center</h2>
            <div className="relative">
              <Search size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-[var(--border-strong)]" />
              <input 
                type="text"
                placeholder="Find Setting..."
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                className="w-full bg-[var(--bg-deep)] border border-[var(--border-subtle)] rounded-lg pl-9 pr-4 py-2 text-[10px] font-bold text-[var(--text-main)] placeholder:text-[var(--border-strong)] focus:border-[var(--brand)]/50 outline-none transition-all"
              />
            </div>
          </div>

          <div className="flex-1 overflow-y-auto px-3 space-y-1 custom-scrollbar">
            {filteredSections.map((section) => (
              <button
                key={section.id}
                onClick={() => setActiveSection(section.id)}
                className={cn(
                  "w-full flex items-center gap-3 px-3 py-2.5 rounded-lg text-[10px] font-black uppercase tracking-widest transition-all group",
                  activeSection === section.id 
                    ? "bg-[var(--brand)]/10 text-[var(--brand)]" 
                    : "text-[var(--text-dim)] hover:text-[var(--text-main)] hover:bg-[var(--bg-elevated)]"
                )}
              >
                <section.icon size={16} className={cn(
                  "transition-all",
                  activeSection === section.id ? "text-[var(--brand)]" : "text-[var(--border-strong)] group-hover:text-[var(--text-dim)]"
                )} />
                {section.label}
              </button>
            ))}
          </div>

          <div className="p-4 border-t border-[var(--border-subtle)] flex flex-col gap-2">
            <button 
              onClick={() => {
                setShowResetConfirm(true);
              }}
              className="flex items-center gap-2 px-3 py-2 text-[9px] font-black uppercase tracking-widest text-red-500 hover:bg-red-500/5 rounded-lg transition-all"
            >
              <RotateCcw size={14} />
              Reset All
            </button>
            <div className="flex items-center gap-2 px-3 opacity-30 mt-2">
              <div className="w-1.5 h-1.5 rounded-full bg-[var(--brand)] animate-pulse" />
              <span className="text-[8px] font-black uppercase tracking-widest text-[var(--text-muted)]">Mainframe Sync Active</span>
            </div>
          </div>
        </div>

        {/* Content */}
        <div className="flex-1 flex flex-col bg-[var(--bg-deep)]">
          <div className="h-16 border-b border-[var(--border-subtle)] flex items-center justify-between px-8">
            <h1 className="text-sm font-black text-[var(--text-main)] uppercase tracking-[0.2em]">{activeSection}</h1>
            <button 
              onClick={onClose}
              className="p-2 text-[var(--text-dim)] hover:text-[var(--text-main)] transition-all"
            >
              <X size={18} />
            </button>
          </div>

          <div className="flex-1 overflow-y-auto p-8 custom-scrollbar">
            <AnimatePresence mode="wait">
              {activeSection === 'General' && (
                <motion.div
                  key="general"
                  initial={{ opacity: 0, x: 10 }}
                  animate={{ opacity: 1, x: 0 }}
                  exit={{ opacity: 0, x: -10 }}
                  className="space-y-8"
                >
                  <Section title="Sync & Persistence">
                    <SettingToggle 
                      label="Automatic Save" 
                      description="Automatically synchronize all changes to collections, requests, and environments." 
                      enabled={settings.general.autoSave}
                      onChange={(v) => handleUpdate('general.autoSave', v)}
                    />
                  </Section>

                  <Section title="Database Integrity">
                    <SettingToggle 
                      label="Check Database Integrity on Load" 
                      description="Perform automatic schema comparison and constraints alignment during startup." 
                      enabled={settings.general.checkDatabaseIntegrity}
                      onChange={(v) => handleUpdate('general.checkDatabaseIntegrity', v)}
                    />
                    
                    <div className="pt-4 border-t border-[var(--border-subtle)] space-y-4">
                      <div>
                        <div className="text-[11px] font-bold text-[var(--text-main)] uppercase tracking-tight">Manual Integrity Diagnostics</div>
                        <div className="text-[10px] text-[var(--text-dim)] mt-0.5">Perform database structural mapping and verify if any tables or foreign keys are missing.</div>
                      </div>
                      
                      {integrityStatus && (
                        <div className="p-3 bg-[var(--bg-deep)] border border-[var(--border-subtle)] rounded-lg font-mono text-[9px] uppercase tracking-tight space-y-1">
                          <div className="text-[var(--text-main)]">{integrityStatus}</div>
                          {missingTables.length > 0 && (
                            <div className="text-red-400 mt-1">Missing Tables: {missingTables.join(', ')}</div>
                          )}
                        </div>
                      )}

                      <div className="flex gap-2">
                        <button
                          disabled={checkingIntegrity}
                          onClick={handleVerifyIntegrity}
                          className="px-4 py-2 bg-[var(--bg-deep)] hover:bg-[var(--bg-elevated)] border border-[var(--border-subtle)] text-[10px] font-black uppercase tracking-widest text-[var(--text-main)] rounded-lg transition-all"
                        >
                          {checkingIntegrity ? 'Verifying...' : 'Verify Structure'}
                        </button>
                        <button
                          disabled={repairingIntegrity}
                          onClick={handleRepairIntegrity}
                          className="px-4 py-2 bg-[var(--brand)] hover:bg-[var(--brand)]/90 text-black text-[10px] font-black uppercase tracking-widest rounded-lg transition-all"
                        >
                          {repairingIntegrity ? 'Repairing...' : 'Run Self-Repair'}
                        </button>
                      </div>
                    </div>
                  </Section>

                  <Section title="Network Protocol">
                    <div className="space-y-4">
                      <SettingSelect 
                        label="HTTP Version"
                        description="Select the preferred HTTP version for outgoing requests."
                        value={settings.general.httpVersion}
                        options={[
                          { value: 'auto', label: 'Auto (Recommended)' },
                          { value: 'http1.1', label: 'HTTP/1.1' },
                          { value: 'http2', label: 'HTTP/2' },
                          { value: 'http3', label: 'HTTP/3' }
                        ]}
                        onChange={(v) => handleUpdate('general.httpVersion', v)}
                      />
                      
                      <div className="grid grid-cols-2 gap-6">
                        <SettingInput 
                          label="Request Timeout" 
                          description="Interval in milliseconds (0 for none)." 
                          value={settings.general.requestTimeout.toString()}
                          type="number"
                          onChange={(v) => handleUpdate('general.requestTimeout', parseInt(v) || 0)}
                        />
                        <SettingInput 
                          label="Max Response Size" 
                          description="Limit in bytes (default 100MB)." 
                          value={settings.general.maxResponseSize.toString()}
                          type="number"
                          onChange={(v) => handleUpdate('general.maxResponseSize', parseInt(v) || 0)}
                        />
                      </div>
                    </div>
                  </Section>

                  <Section title="Retrieval Logic">
                    <div className="space-y-4">
                      <SettingToggle 
                        label="Follow Redirects" 
                        description="Automatically intercept and follow 3xx redirect status codes." 
                        enabled={settings.general.followRedirects}
                        onChange={(v) => handleUpdate('general.followRedirects', v)}
                      />
                      {settings.general.followRedirects && (
                        <SettingInput 
                          label="Max Redirects" 
                          value={settings.general.maxRedirects.toString()}
                          type="number"
                          onChange={(v) => handleUpdate('general.maxRedirects', parseInt(v) || 0)}
                        />
                      )}
                      <SettingToggle 
                        label="Connection Keep-Alive" 
                        description="Maintains persistent connections to reduce latency." 
                        enabled={settings.general.keepAlive}
                        onChange={(v) => handleUpdate('general.keepAlive', v)}
                      />
                    </div>
                  </Section>
                </motion.div>
              )}

              {activeSection === 'Themes' && (
                <motion.div
                  key="themes"
                  initial={{ opacity: 0, x: 10 }}
                  animate={{ opacity: 1, x: 0 }}
                  exit={{ opacity: 0, x: -10 }}
                  className="space-y-8"
                >
                  <Section title="Interface Style">
                    <div className="grid grid-cols-3 gap-4">
                      {[
                        { id: 'dark', icon: Moon, label: 'Obsidian' },
                        { id: 'light', icon: Sun, label: 'Luminous' },
                        { id: 'system', icon: Monitor, label: 'OS Sync' }
                      ].map((t) => (
                        <button
                          key={t.id}
                          onClick={() => handleUpdate('appearance.theme', t.id)}
                          className={cn(
                            "flex flex-col items-center justify-center gap-3 p-6 rounded-xl border transition-all",
                            settings.appearance.theme === t.id 
                              ? "bg-[var(--brand)]/5 border-[var(--brand)] text-[var(--brand)]" 
                              : "bg-[var(--bg-elevated)] border-[var(--border-subtle)] text-[var(--text-dim)] hover:border-[var(--border-strong)]"
                          )}
                        >
                          <t.icon size={24} />
                          <span className="text-[10px] font-black uppercase tracking-widest">{t.label}</span>
                        </button>
                      ))}
                    </div>
                  </Section>

                  <Section title="Layout Configuration">
                    <div className="space-y-4">
                       <SettingSelect 
                        label="Density Mode"
                        description="Control the information density of the interface."
                        value={settings.appearance.layoutMode}
                        options={[
                          { value: 'compact', label: 'Compact (High Density)' },
                          { value: 'comfortable', label: 'Comfortable (Standard)' }
                        ]}
                        onChange={(v) => handleUpdate('appearance.layoutMode', v)}
                      />
                      <SettingToggle 
                        label="Show Status Bar"
                        description="Display the universal operations rail at the bottom."
                        enabled={settings.appearance.showStatusBar}
                        onChange={(v) => handleUpdate('appearance.showStatusBar', v)}
                      />
                      <div className="grid grid-cols-2 gap-6">
                        <SettingInput 
                          label="Font Size" 
                          value={settings.appearance.fontSize.toString()}
                          type="number"
                          onChange={(v) => handleUpdate('appearance.fontSize', parseInt(v) || 12)}
                        />
                        <div className="space-y-2">
                          <label className="text-[9px] font-black text-[var(--text-dim)] uppercase tracking-widest">Accent Chroma</label>
                          <div className="flex items-center gap-3">
                            <input 
                              type="color" 
                              value={settings.appearance.accentColor}
                              onChange={(e) => handleUpdate('appearance.accentColor', e.target.value)}
                              className="w-10 h-10 bg-transparent border-none cursor-pointer"
                            />
                            <span className="text-[10px] font-mono text-[var(--text-muted)]">{settings.appearance.accentColor.toUpperCase()}</span>
                          </div>
                        </div>
                      </div>
                    </div>
                  </Section>
                </motion.div>
              )}

              {activeSection === 'Proxy' && (
                <motion.div
                  key="proxy"
                  initial={{ opacity: 0, x: 10 }}
                  animate={{ opacity: 1, x: 0 }}
                  exit={{ opacity: 0, x: -10 }}
                  className="space-y-8"
                >
                  <Section title="Routing Proxy Settings">
                    <div className="space-y-6">
                      <SettingSelect 
                        label="Proxy Mode"
                        description="Select how the application handles outbound network routing."
                        value={settings.proxy.mode || (settings.proxy.enabled ? (settings.proxy.useSystemProxy ? 'auto' : 'manual') : 'disabled')}
                        options={[
                          { value: 'auto', label: 'Auto-Detect OS Proxy (Default)' },
                          { value: 'manual', label: 'Manual Configuration' },
                          { value: 'pac', label: 'PAC Script URL' },
                          { value: 'disabled', label: 'Disable Proxy' }
                        ]}
                        onChange={(v) => {
                          const mode = v as 'auto' | 'manual' | 'pac' | 'disabled';
                          handleUpdate('proxy.mode', mode);
                          handleUpdate('proxy.enabled', mode !== 'disabled');
                          handleUpdate('proxy.useSystemProxy', mode === 'auto');
                          
                          // Propagate to Electron if active
                          ProxyService.syncSettings({
                            ...settings.proxy,
                            mode,
                            enabled: mode !== 'disabled',
                            useSystemProxy: mode === 'auto'
                          });
                        }}
                      />

                      {settings.proxy.mode === 'pac' && (
                        <div className="space-y-4 p-4 bg-[var(--bg-deep)] border border-[var(--border-subtle)] rounded-lg animate-in slide-in-from-top-2">
                          <SettingInput 
                            label="PAC Script URL" 
                            description="Automatic proxy configuration script path or URL."
                            placeholder="http://example.com/proxy.pac"
                            value={settings.proxy.pacUrl || ''}
                            onChange={(v) => {
                              handleUpdate('proxy.pacUrl', v);
                              ProxyService.syncSettings({ ...settings.proxy, pacUrl: v });
                            }}
                          />
                        </div>
                      )}

                      {settings.proxy.mode === 'manual' && (
                        <div className="space-y-4 p-4 bg-[var(--bg-deep)] border border-[var(--border-subtle)] rounded-lg animate-in slide-in-from-top-2">
                          <div className="grid grid-cols-2 gap-4">
                            <SettingInput 
                              label="HTTP Proxy Server" 
                              placeholder="e.g. 10.0.0.1:8080"
                              value={settings.proxy.httpProxy || ''}
                              onChange={(v) => {
                                handleUpdate('proxy.httpProxy', v);
                                ProxyService.syncSettings({ ...settings.proxy, httpProxy: v });
                              }}
                            />
                            <SettingInput 
                              label="HTTPS Proxy Server" 
                              placeholder="e.g. 10.0.0.1:8080"
                              value={settings.proxy.httpsProxy || ''}
                              onChange={(v) => {
                                handleUpdate('proxy.httpsProxy', v);
                                ProxyService.syncSettings({ ...settings.proxy, httpsProxy: v });
                              }}
                            />
                          </div>
                          
                          <div className="grid grid-cols-2 gap-4">
                            <SettingInput 
                              label="SOCKS Proxy Server" 
                              placeholder="socks5://127.0.0.1:1080"
                              value={settings.proxy.socksProxy || ''}
                              onChange={(v) => {
                                handleUpdate('proxy.socksProxy', v);
                                ProxyService.syncSettings({ ...settings.proxy, socksProxy: v });
                              }}
                            />
                            <SettingInput 
                              label="Bypass Proxy List" 
                              description="Domains to route directly (comma separated)."
                              placeholder="localhost, 127.0.0.1"
                              value={settings.proxy.bypassList || ''}
                              onChange={(v) => {
                                handleUpdate('proxy.bypassList', v);
                                ProxyService.syncSettings({ ...settings.proxy, bypassList: v });
                              }}
                            />
                          </div>

                          <div className="border-t border-[var(--border-subtle)] pt-4 mt-4 space-y-4">
                            <SettingToggle 
                              label="Proxy Authentication" 
                              description="Specify credentials if your proxy requires authentication."
                              enabled={settings.proxy.auth?.enabled || false}
                              onChange={(v) => {
                                handleUpdate('proxy.auth.enabled', v);
                                ProxyService.syncSettings({
                                  ...settings.proxy,
                                  auth: { ...(settings.proxy.auth || {}), enabled: v }
                                });
                              }}
                            />
                            
                            {settings.proxy.auth?.enabled && (
                              <div className="grid grid-cols-2 gap-4 animate-in slide-in-from-top-1">
                                <SettingInput 
                                  label="Username" 
                                  value={settings.proxy.auth?.username || ''}
                                  onChange={(v) => {
                                    handleUpdate('proxy.auth.username', v);
                                    ProxyService.syncSettings({
                                      ...settings.proxy,
                                      auth: { ...(settings.proxy.auth || {}), username: v }
                                    });
                                  }}
                                />
                                <SettingInput 
                                  label="Password" 
                                  type="password"
                                  value={settings.proxy.auth?.password || ''}
                                  onChange={(v) => {
                                    handleUpdate('proxy.auth.password', v);
                                    ProxyService.syncSettings({
                                      ...settings.proxy,
                                      auth: { ...(settings.proxy.auth || {}), password: v }
                                    });
                                  }}
                                />
                              </div>
                            )}
                          </div>
                        </div>
                      )}
                    </div>
                  </Section>
                </motion.div>
              )}

              {activeSection === 'SSL/TLS' && (
                <motion.div
                  key="ssl"
                  initial={{ opacity: 0, x: 10 }}
                  animate={{ opacity: 1, x: 0 }}
                  exit={{ opacity: 0, x: -10 }}
                  className="space-y-8"
                >
                  <Section title="Encryption Protocol">
                    <div className="space-y-4">
                      <SettingToggle 
                        label="SSL Verification" 
                        description="Strictly validate server certificates. (Disable for self-signed development servers)" 
                        enabled={settings.ssl.verifySSL}
                        onChange={(v) => handleUpdate('ssl.verifySSL', v)}
                      />
                      <SettingSelect 
                        label="Minimum TLS Version"
                        value={settings.ssl.tlsVersion}
                        options={[
                          { value: 'auto', label: 'Auto (Recommended)' },
                          { value: 'TLSv1.1', label: 'TLS v1.1' },
                          { value: 'TLSv1.2', label: 'TLS v1.2' },
                          { value: 'TLSv1.3', label: 'TLS v1.3' }
                        ]}
                        onChange={(v) => handleUpdate('ssl.tlsVersion', v)}
                      />
                      <SettingToggle 
                        label="SSL/TLS Key Log" 
                        description="Log secret keys for network debuggers like Wireshark." 
                        enabled={settings.ssl.keyLogFile}
                        onChange={(v) => handleUpdate('ssl.keyLogFile', v)}
                      />
                    </div>
                  </Section>

                  <Section title="Certificates (PEM)">
                    <div className="space-y-4">
                       <SettingInput 
                          label="Custom CA Certificate" 
                          description="Path to your custom Root CA file."
                          placeholder="/path/to/ca.pem"
                          value={settings.ssl.customCA}
                          onChange={(v) => handleUpdate('ssl.customCA', v)}
                        />
                        <div className="grid grid-cols-2 gap-4">
                           <SettingInput 
                            label="Client Certificate" 
                            placeholder="/path/to/client.crt"
                            value={settings.ssl.clientCert}
                            onChange={(v) => handleUpdate('ssl.clientCert', v)}
                          />
                          <SettingInput 
                            label="Client Key" 
                            placeholder="/path/to/client.key"
                            value={settings.ssl.clientKey}
                            onChange={(v) => handleUpdate('ssl.clientKey', v)}
                          />
                        </div>
                    </div>
                  </Section>
                </motion.div>
              )}

              {activeSection === 'Cookies' && (
                <motion.div
                  key="cookies"
                  initial={{ opacity: 0, x: 10 }}
                  animate={{ opacity: 1, x: 0 }}
                  exit={{ opacity: 0, x: -10 }}
                  className="space-y-8"
                >
                  <Section title="Jar Management">
                    <div className="space-y-4">
                      <SettingToggle 
                        label="Global Cookie Capture" 
                        description="Enables automatic cookie management across all domains." 
                        enabled={settings.cookies.enabled}
                        onChange={(v) => handleUpdate('cookies.enabled', v)}
                      />
                      <SettingToggle 
                        label="Clear on Exit" 
                        description="Purge all session cookies when the application process terminates." 
                        enabled={settings.cookies.clearOnExit}
                        onChange={(v) => handleUpdate('cookies.clearOnExit', v)}
                      />
                      <SettingToggle 
                        label="Workspace Isolation" 
                        description="Keep cookies restricted to their specific workspace jar." 
                        enabled={settings.cookies.workspaceIsolation}
                        onChange={(v) => handleUpdate('cookies.workspaceIsolation', v)}
                      />
                    </div>
                  </Section>
                </motion.div>
              )}

              {activeSection === 'Experimental' && (
                <motion.div
                  key="experimental"
                  initial={{ opacity: 0, x: 10 }}
                  animate={{ opacity: 1, x: 0 }}
                  exit={{ opacity: 0, x: -10 }}
                  className="space-y-8"
                >
                  <Section title="Beta Features">
                    <div className="space-y-4">
                      <SettingToggle 
                        label="Enabled Experimental Subsystem" 
                        description="Unlock cutting-edge features that are still in development." 
                        enabled={settings.experimental.enabled}
                        onChange={(v) => handleUpdate('experimental.enabled', v)}
                      />
                      {settings.experimental.enabled && (
                        <>
                          <SettingToggle 
                            label="New Editor Core" 
                            description="Use the high-performance unified editor for all tabs." 
                            enabled={settings.experimental.useNewEditor}
                            onChange={(v) => handleUpdate('experimental.useNewEditor', v)}
                          />
                          <SettingToggle 
                            label="Verbose Debug Logs" 
                            description="Capture every internal operation and event trace." 
                            enabled={settings.experimental.debugLogs}
                            onChange={(v) => handleUpdate('experimental.debugLogs', v)}
                          />
                        </>
                      )}
                    </div>
                  </Section>
                </motion.div>
              )}

              {activeSection === 'Diagnostics' && (
                <motion.div
                  key="diagnostics"
                  initial={{ opacity: 0, x: 10 }}
                  animate={{ opacity: 1, x: 0 }}
                  exit={{ opacity: 0, x: -10 }}
                  className="space-y-8"
                >
                  <Section title="Maintenance & Health">
                    <div className="space-y-4">
                      <div className="flex items-center justify-between p-4 bg-[var(--bg-elevated)] rounded-lg border border-[var(--border-subtle)]">
                        <div>
                          <div className="text-[11px] font-bold text-[var(--text-main)] uppercase tracking-tight">Application Storage</div>
                          <div className="text-[10px] text-[var(--text-dim)] mt-0.5">Clear all locally cached data and settings.</div>
                        </div>
                        <button 
                          onClick={handleClearCache}
                          className="flex items-center gap-2 px-4 py-2 text-[10px] font-black uppercase tracking-widest text-red-500 hover:bg-red-500/10 rounded-lg transition-all"
                        >
                          <Trash2 size={14} />
                          Purge Storage
                        </button>
                      </div>

                      <div className="flex items-center justify-between p-4 bg-[var(--bg-elevated)] rounded-lg border border-[var(--border-subtle)]">
                        <div>
                          <div className="text-[11px] font-bold text-[var(--text-main)] uppercase tracking-tight">Configuration Backup</div>
                          <div className="text-[10px] text-[var(--text-dim)] mt-0.5">Export or import your current operations setup.</div>
                        </div>
                        <div className="flex gap-2">
                          <button 
                            onClick={handleExportSettings}
                            className="flex items-center gap-2 px-4 py-2 text-[10px] font-black uppercase tracking-widest text-[var(--brand)] hover:bg-[var(--brand)]/10 rounded-lg transition-all"
                          >
                            <Download size={14} />
                            Export
                          </button>
                          <label className="flex items-center gap-2 px-4 py-2 text-[10px] font-black uppercase tracking-widest text-[var(--brand)] hover:bg-[var(--brand)]/10 rounded-lg transition-all cursor-pointer">
                            <Upload size={14} />
                            Import
                            <input type="file" className="hidden" accept=".json" onChange={handleImportSettings} />
                          </label>
                        </div>
                      </div>
                    </div>
                  </Section>

                  <Section title="Connection Diagnostics">
                    <div className="space-y-4">
                      <div className="grid grid-cols-2 gap-4">
                        <div className="p-4 bg-[var(--bg-deep)] border border-[var(--border-subtle)] rounded-lg">
                          <div className="text-[9px] font-black text-[var(--text-dim)] uppercase tracking-wider">Runtime Environment</div>
                          <div className="text-xs font-bold text-[var(--text-main)] mt-1 flex items-center gap-2">
                            <span className="w-1.5 h-1.5 rounded-full bg-[var(--brand)]" />
                            {isElectron() ? 'Electron Desktop Client' : 'Web Browser Session'}
                          </div>
                        </div>

                        <div className="p-4 bg-[var(--bg-deep)] border border-[var(--border-subtle)] rounded-lg">
                          <div className="text-[9px] font-black text-[var(--text-dim)] uppercase tracking-wider">Network Stack Mode</div>
                          <div className="text-xs font-bold text-[var(--text-main)] mt-1">
                            {isElectron() ? 'OS Native (Chromium + Node)' : 'Sandbox Browser Agent'}
                          </div>
                        </div>
                      </div>

                      <div className="grid grid-cols-3 gap-4">
                        <div className="p-4 bg-[var(--bg-deep)] border border-[var(--border-subtle)] rounded-lg">
                          <div className="text-[9px] font-black text-[var(--text-dim)] uppercase tracking-wider">Configured Proxy Mode</div>
                          <div className="text-xs font-bold text-[var(--text-main)] mt-1 uppercase">
                            {settings.proxy.mode || 'auto'}
                          </div>
                        </div>

                        <div className="p-4 bg-[var(--bg-deep)] border border-[var(--border-subtle)] rounded-lg">
                          <div className="text-[9px] font-black text-[var(--text-dim)] uppercase tracking-wider">SSL Security Mode</div>
                          <div className="text-xs font-bold mt-1 flex items-center gap-2">
                            <span className={cn("w-1.5 h-1.5 rounded-full", settings.ssl.verifySSL ? "bg-emerald-500" : "bg-yellow-500")} />
                            <span className={settings.ssl.verifySSL ? "text-emerald-500" : "text-yellow-500"}>
                              {settings.ssl.verifySSL ? 'STRICT (Verified)' : 'INSECURE (Permissive)'}
                            </span>
                          </div>
                        </div>

                        <div className="p-4 bg-[var(--bg-deep)] border border-[var(--border-subtle)] rounded-lg">
                          <div className="text-[9px] font-black text-[var(--text-dim)] uppercase tracking-wider">Offline Protection</div>
                          <div className="text-xs font-bold text-[var(--text-main)] mt-1">
                            {typeof navigator !== 'undefined' && navigator.onLine ? 'ONLINE' : 'OFFLINE'}
                          </div>
                        </div>
                      </div>

                      <div className="p-4 bg-[var(--bg-deep)] border border-[var(--border-subtle)] rounded-lg space-y-2">
                        <div className="text-[9px] font-black text-[var(--text-dim)] uppercase tracking-wider">Real-Time Proxy Resolution Probe</div>
                        <div className="flex gap-2">
                          <input 
                            type="text" 
                            id="proxy-probe-url"
                            placeholder="https://api.github.com" 
                            defaultValue="https://api.github.com"
                            className="flex-1 bg-[var(--bg-elevated)] border border-[var(--border-subtle)] rounded px-3 py-1.5 text-xs text-[var(--text-main)] outline-none"
                          />
                          <button
                            onClick={async () => {
                              const input = document.getElementById('proxy-probe-url') as HTMLInputElement;
                              const url = input?.value || 'https://api.github.com';
                              const resLabel = document.getElementById('proxy-probe-result');
                              if (resLabel) resLabel.innerText = 'Resolving...';
                              try {
                                const resolved = await ProxyService.resolveProxy(url);
                                if (resLabel) resLabel.innerText = `Result: ${resolved}`;
                              } catch (e: any) {
                                if (resLabel) resLabel.innerText = `Error: ${e.message}`;
                              }
                            }}
                            className="px-4 py-1.5 bg-[var(--brand)] hover:bg-[var(--brand)]/90 text-white rounded text-[10px] font-black uppercase tracking-widest transition-all"
                          >
                            Resolve Probe
                          </button>
                        </div>
                        <div id="proxy-probe-result" className="text-[10px] font-mono text-[var(--text-muted)] mt-1">
                          Enter target URL and click probe to test native proxy resolution.
                        </div>
                      </div>
                    </div>
                  </Section>

                  <Section title="System Trace">
                    <div className="bg-[var(--bg-deep)] border border-[var(--border-subtle)] rounded-lg font-mono text-[10px] p-4 text-[var(--text-dim)] space-y-2 max-h-40 overflow-y-auto">
                      <p><span className="text-[var(--brand)]">[SYSTEM]</span> Initializing diagnostics module...</p>
                      <p><span className="text-[var(--brand)]">[SYSTEM]</span> Kernel version: Gimay-OS-Core-9</p>
                      <p><span className="text-yellow-500">[WARN]</span> High memory latency detected in tab sector B</p>
                      <p><span className="text-[var(--brand)]">[SYSTEM]</span> Sync manager operational (IDLE)</p>
                      <p><span className="text-blue-400">[INFO]</span> Persistence link secured via Supabase-Tunnel-1</p>
                      <p><span className="text-[var(--brand)]">[SYSTEM]</span> Awaiting next operation sequence...</p>
                    </div>
                  </Section>
                </motion.div>
              )}

              {activeSection === 'Migration' && (
                <motion.div
                  key="migration"
                  initial={{ opacity: 0, x: 10 }}
                  animate={{ opacity: 1, x: 0 }}
                  exit={{ opacity: 0, x: -10 }}
                  className="space-y-6"
                >
                  <Section title="Database Migration Uplink">
                    <div className="space-y-4 text-left">
                      <div className="text-[10px] text-[var(--text-dim)] uppercase tracking-widest leading-relaxed">
                        Clone all active workspaces, teams, member rosters, folders, requests, scripts, and environments from your current database node directly into another target project database.
                      </div>
                      
                      <div className="p-4 rounded-xl bg-amber-500/[0.03] border border-amber-500/10 flex gap-3 text-amber-500/80">
                        <ShieldAlert size={18} className="shrink-0 mt-0.5" />
                        <div className="text-[9px] uppercase tracking-wide leading-relaxed font-semibold">
                          <span className="font-black text-amber-400">Security Note:</span> You must supply the target project's <span className="font-black text-amber-400">Service Role API Key</span> (service_role) to bypass Row-Level Security (RLS) constraints and perform migration successfully.
                        </div>
                      </div>

                      <button
                        onClick={() => {
                          setIsMigrationOpen(true);
                        }}
                        className="px-5 py-3 bg-[var(--brand)] hover:bg-[var(--brand)]/90 text-black text-[10px] font-black uppercase tracking-widest rounded-xl transition-all shadow-lg shadow-[var(--brand-muted)] cursor-pointer flex items-center gap-2"
                      >
                        <Database size={14} /> Open Migration Console
                      </button>
                    </div>
                  </Section>
                </motion.div>
              )}

              {activeSection === 'About' && (
                <motion.div
                  key="about"
                  initial={{ opacity: 0, x: 10 }}
                  animate={{ opacity: 1, x: 0 }}
                  exit={{ opacity: 0, x: -10 }}
                  className="space-y-8 flex flex-col items-center justify-center py-10"
                >
                   <div className="w-24 h-24 rounded-2xl bg-[var(--bg-elevated)] border border-[var(--border-subtle)] flex items-center justify-center mb-6">
                      <Terminal size={48} className="text-[var(--brand)]" />
                   </div>
                   <div className="text-center space-y-2">
                     <h2 className="text-2xl font-black text-[var(--text-main)] tracking-tighter uppercase italic">GIMAY <span className="text-[var(--brand)]">v0.5.0-ALPHA</span></h2>
                     <p className="text-[10px] font-black uppercase tracking-[0.3em] text-[var(--text-dim)]">Cortex API Management Suite</p>
                   </div>

                   <div className="w-full max-w-sm space-y-2 mt-8">
                      <div className="flex items-center justify-between p-4 bg-[var(--bg-elevated)] rounded-lg border border-[var(--border-subtle)]">
                        <div className="flex items-center gap-3">
                           <Cpu size={14} className="text-[var(--border-strong)]" />
                           <span className="text-[9px] font-black uppercase text-[var(--text-dim)]">Runtime</span>
                        </div>
                        <span className="text-[10px] font-mono text-[var(--text-muted)]">v18.16.0 (Node.js)</span>
                      </div>
                      <div className="flex items-center justify-between p-4 bg-[var(--bg-elevated)] rounded-lg border border-[var(--border-subtle)]">
                        <div className="flex items-center gap-3">
                           <Clock size={14} className="text-[var(--border-strong)]" />
                           <span className="text-[9px] font-black uppercase text-[var(--text-dim)]">Up-Cycle</span>
                        </div>
                        <span className="text-[10px] font-mono text-[var(--text-muted)]">04:22:11:09</span>
                      </div>
                      <div className="flex items-center justify-between p-4 bg-[var(--bg-elevated)] rounded-lg border border-[var(--border-subtle)]">
                        <div className="flex items-center gap-3">
                           <HardDrive size={14} className="text-[var(--border-strong)]" />
                           <span className="text-[9px] font-black uppercase text-[var(--text-dim)]">Identifier</span>
                        </div>
                        <span className="text-[10px] font-mono text-[var(--text-muted)]">CORTEX-X-RAI</span>
                      </div>
                   </div>

                   {isElectron() && (
                     <div className="w-full max-w-sm border border-[var(--brand-border)] bg-[var(--brand-muted)] rounded-xl p-4 space-y-3 mt-4 text-center">
                       <div className="text-[10px] font-black uppercase tracking-widest text-[var(--brand)]">
                         Desktop Environment Update Core
                       </div>
                       <p className="text-[9px] text-[var(--text-muted)] uppercase tracking-wider">
                         Verify client packages and local resources integrity
                       </p>
                       <button
                         onClick={() => {
                           (window as any).electron?.checkForUpdates();
                           addToast({ type: 'info', message: 'Checking for desktop updates...' });
                         }}
                         className="w-full py-2 bg-[var(--brand)] hover:bg-[var(--brand)]/90 text-black text-[9px] font-black uppercase tracking-widest rounded-lg transition-all shadow-lg cursor-pointer"
                       >
                         Scan updates pipeline
                       </button>
                     </div>
                   )}

                   <div className="flex items-center gap-6 mt-8">
                      <button className="text-[10px] font-black uppercase tracking-widest text-[var(--text-dim)] hover:text-[var(--brand)] transition-all">Protocol</button>
                      <button className="text-[10px] font-black uppercase tracking-widest text-[var(--text-dim)] hover:text-[var(--brand)] transition-all">Uplink</button>
                      <button className="text-[10px] font-black uppercase tracking-widest text-[var(--text-dim)] hover:text-[var(--brand)] transition-all flex items-center gap-2">
                        <RefreshCw size={12} />
                        Sync Check
                      </button>
                   </div>
                </motion.div>
              )}
            </AnimatePresence>
          </div>
        </div>
      </motion.div>
      <DatabaseMigrationModal
        isOpen={isMigrationOpen}
        onClose={() => setIsMigrationOpen(false)}
        userId={profile?.id}
        addToast={addToast}
      />
    </div>,
    document.body
  );
};

const Section: React.FC<{ title: string; children: React.ReactNode }> = ({ title, children }) => (
  <div className="space-y-4">
    <h3 className="text-[10px] font-black text-[var(--text-dim)] uppercase tracking-[0.2em]">{title}</h3>
    <div className="bg-[var(--bg-elevated)] border border-[var(--border-subtle)] rounded-xl p-6 space-y-6">
      {children}
    </div>
  </div>
);

const SettingToggle: React.FC<{ 
  label: string; 
  description?: string; 
  enabled: boolean; 
  onChange: (v: boolean) => void 
}> = ({ label, description, enabled, onChange }) => (
  <div className="flex items-center justify-between">
    <div className="flex-1 pr-4">
      <div className="text-[11px] font-bold text-[var(--text-main)] uppercase tracking-tight">{label}</div>
      {description && <div className="text-[10px] text-[var(--text-dim)] mt-0.5">{description}</div>}
    </div>
    <button 
      onClick={() => onChange(!enabled)}
      className={cn(
        "relative w-10 h-5 rounded-full transition-all duration-300",
        enabled ? "bg-[var(--brand)]" : "bg-[var(--border-strong)]"
      )}
    >
      <div className={cn(
        "absolute top-1 w-3 h-3 bg-white rounded-full transition-all duration-300",
        enabled ? "left-6" : "left-1"
      )} />
    </button>
  </div>
);

