            {/* Modal Header */}
            <div className="px-5 py-4 border-b border-[var(--border-subtle)] flex justify-between items-center bg-[var(--bg-deep)]/50">
              <div>
                <h3 className="text-xs font-black text-white uppercase tracking-widest flex items-center gap-2">
                  <Activity size={12} className="text-[#3ECF8E]" />
                  Sample #{selectedSample.id} Details
                </h3>
                <p className="text-[8px] text-[var(--text-dim)] uppercase tracking-widest mt-0.5">
                  Executed at {selectedSample.timestamp} | Latency: {selectedSample.latency}ms
                </p>
              </div>
              <button
                onClick={() => setSelectedSample(null)}
                className="p-1 rounded-lg hover:bg-white/10 text-[var(--text-dim)] hover:text-white transition-colors"
              >
                <X size={16} />
              </button>
            </div>

            {/* Modal Tabs */}
            <div className="flex border-b border-[var(--border-subtle)] bg-[var(--bg-deep)]/20 px-4">
              <button
                onClick={() => setModalTab('request')}
                className={`px-4 py-2.5 text-[9px] font-black uppercase tracking-widest border-b-2 transition-all ${
                  modalTab === 'request' ? 'border-[#3ECF8E] text-[#3ECF8E]' : 'border-transparent text-[var(--text-dim)] hover:text-white'
                }`}
              >
                Request Context
              </button>
              <button
                onClick={() => setModalTab('response')}
                className={`px-4 py-2.5 text-[9px] font-black uppercase tracking-widest border-b-2 transition-all ${
                  modalTab === 'response' ? 'border-[#3ECF8E] text-[#3ECF8E]' : 'border-transparent text-[var(--text-dim)] hover:text-white'
                }`}
              >
                Response Context
              </button>
            </div>

            {/* Modal Body */}
            <div className="flex-1 overflow-y-auto p-5 custom-scrollbar space-y-4">
              {modalTab === 'request' && (
                <div className="space-y-4">
                  {/* URL */}
                  <div className="space-y-1.5">
                    <span className="text-[8px] font-black text-[var(--text-dim)] uppercase tracking-widest">Target URL</span>
                    <div className="flex gap-2 items-center p-2.5 bg-[var(--bg-deep)]/60 border border-[var(--border-subtle)] rounded-lg font-mono text-[10px] text-white">
                      <span className="px-1.5 py-0.5 rounded bg-[#3ECF8E]/10 text-[#3ECF8E] font-black text-[9px]">
                        {selectedSample.request?.method || 'GET'}
                      </span>
                      <span className="break-all">{selectedSample.request?.url || activeRequest.url}</span>
                    </div>
                  </div>

                  {/* Headers */}
                  <div className="space-y-1.5">
                    <span className="text-[8px] font-black text-[var(--text-dim)] uppercase tracking-widest">Request Headers</span>
                    {selectedSample.request?.headers && Object.keys(selectedSample.request.headers).length > 0 ? (
                      <div className="border border-[var(--border-subtle)] rounded-lg overflow-hidden bg-[var(--bg-deep)]/20">
                        <table className="w-full text-left font-mono text-[9px] border-collapse">
                          <thead className="bg-[var(--bg-deep)] text-[8px] font-black uppercase border-b border-[var(--border-subtle)]">
                            <tr>
                              <th className="p-2 pl-3">Header Name</th>
                              <th className="p-2 pr-3">Header Value</th>
                            </tr>
                          </thead>
                          <tbody className="divide-y divide-[var(--border-subtle)]/50">
                            {Object.entries(selectedSample.request.headers).map(([key, val]) => (
                              <tr key={key}>
                                <td className="p-2 pl-3 font-semibold text-[var(--text-dim)]">{key}</td>
                                <td className="p-2 pr-3 text-white break-all">{String(val)}</td>
                              </tr>
                            ))}
                          </tbody>
                        </table>
                      </div>
                    ) : (
                      <div className="text-[9px] font-bold text-[var(--text-dim)] italic p-2 border border-dashed border-[var(--border-subtle)] rounded-lg text-center uppercase tracking-widest">
                        No Custom Headers Sent
                      </div>
                    )}
                  </div>

                  {/* Body */}
                  <div className="space-y-1.5">
                    <span className="text-[8px] font-black text-[var(--text-dim)] uppercase tracking-widest">Request Body</span>
                    {selectedSample.request?.body ? (
                      <pre className="p-3 bg-[var(--bg-deep)] border border-[var(--border-subtle)] rounded-lg font-mono text-[10px] text-white overflow-x-auto custom-scrollbar whitespace-pre-wrap max-h-40">
                        {(() => {
                          const body = selectedSample.request.body;
                          const rawString = typeof body === 'object'
                            ? JSON.stringify(body, null, 2)
                            : String(body);
                          const maxBodyLength = 100000; // 100KB limit
                          if (rawString.length > maxBodyLength) {
                            return `${rawString.slice(0, maxBodyLength)  }\n\n... [Request body truncated. Total size: ${  (rawString.length / 1024).toFixed(1)  } KB] ...`;
                          }
                          return rawString;
                        })()}
                      </pre>
                    ) : (
                      <div className="text-[9px] font-bold text-[var(--text-dim)] italic p-2 border border-dashed border-[var(--border-subtle)] rounded-lg text-center uppercase tracking-widest">
                        No Request Payload Sent
                      </div>
                    )}
                  </div>
                </div>
              )}

              {modalTab === 'response' && (
                <div className="space-y-4">
                  {/* Status Bar */}
                  <div className="space-y-1.5">
                    <span className="text-[8px] font-black text-[var(--text-dim)] uppercase tracking-widest">HTTP Status</span>
                    <div className="flex gap-4 items-center p-2.5 bg-[var(--bg-deep)]/60 border border-[var(--border-subtle)] rounded-lg">
                      <div className="flex items-center gap-1.5">
                        <span className={`px-2 py-0.5 rounded text-[10px] font-black uppercase tracking-widest ${
                          selectedSample.success ? 'bg-[#3ECF8E]/10 text-[#3ECF8E] border border-[#3ECF8E]/20' : 'bg-red-500/10 text-red-400 border border-red-500/20'
                        }`}>
                          {selectedSample.status}
                        </span>
                        <span className="text-[10px] font-bold text-white uppercase tracking-tight">
                          {selectedSample.response?.statusText || (selectedSample.success ? 'OK' : 'Error')}
                        </span>
                      </div>
                      <div className="w-px h-4 bg-[var(--border-subtle)]" />
                      <div className="text-[10px] text-[var(--text-dim)] uppercase tracking-widest font-black">
                        Latency: <span className="text-white font-mono font-normal">{selectedSample.latency}ms</span>
                      </div>
                    </div>
                  </div>

                  {/* Headers */}
                  <div className="space-y-1.5">
                    <span className="text-[8px] font-black text-[var(--text-dim)] uppercase tracking-widest">Response Headers</span>
                    {selectedSample.response?.headers && Object.keys(selectedSample.response.headers).length > 0 ? (
                      <div className="border border-[var(--border-subtle)] rounded-lg overflow-hidden bg-[var(--bg-deep)]/20">
                        <table className="w-full text-left font-mono text-[9px] border-collapse">
                          <thead className="bg-[var(--bg-deep)] text-[8px] font-black uppercase border-b border-[var(--border-subtle)]">
                            <tr>
                              <th className="p-2 pl-3">Header Name</th>
                              <th className="p-2 pr-3">Header Value</th>
                            </tr>
                          </thead>
                          <tbody className="divide-y divide-[var(--border-subtle)]/50">
                            {Object.entries(selectedSample.response.headers).map(([key, val]) => (
                              <tr key={key}>
                                <td className="p-2 pl-3 font-semibold text-[var(--text-dim)]">{key}</td>
                                <td className="p-2 pr-3 text-white break-all">{String(val)}</td>
                              </tr>
                            ))}
                          </tbody>
                        </table>
                      </div>
                    ) : (
                      <div className="text-[9px] font-bold text-[var(--text-dim)] italic p-2 border border-dashed border-[var(--border-subtle)] rounded-lg text-center uppercase tracking-widest">
                        No Response Headers Returned
                      </div>
                    )}
                  </div>

                  {/* Body */}
                  <div className="space-y-1.5">
                    <span className="text-[8px] font-black text-[var(--text-dim)] uppercase tracking-widest">Response Body</span>
                    {selectedSample.response?.body ? (
                      <pre className="p-3 bg-[var(--bg-deep)] border border-[var(--border-subtle)] rounded-lg font-mono text-[10px] text-white overflow-x-auto custom-scrollbar whitespace-pre-wrap max-h-60 max-w-full">
                        {(() => {
                          const body = selectedSample.response.body;
                          let rawString = '';
                          if (typeof body === 'object') {
                            rawString = JSON.stringify(body, null, 2);
                          } else {
                            try {
                              // Try parsing raw string as JSON for clean indenting
                              rawString = JSON.stringify(JSON.parse(body), null, 2);
                            } catch {
                              rawString = String(body);
                            }
                          }
                          const maxBodyLength = 100000; // 100KB limit
                          if (rawString.length > maxBodyLength) {
                            return `${rawString.slice(0, maxBodyLength)  }\n\n... [Response body truncated. Total size: ${  (rawString.length / 1024).toFixed(1)  } KB. Export results to Excel/PDF to download complete logs] ...`;
                          }
                          return rawString;
                        })()}
                      </pre>
                    ) : (
                      <div className="text-[9px] font-bold text-[var(--text-dim)] italic p-2 border border-dashed border-[var(--border-subtle)] rounded-lg text-center uppercase tracking-widest">
                        No Response Body Returned
                      </div>
                    )}
                  </div>
                </div>
              )}
            </div>

            {/* Modal Footer */}
            <div className="px-5 py-3 border-t border-[var(--border-subtle)] flex justify-end bg-[var(--bg-deep)]/30">
              <button
                onClick={() => setSelectedSample(null)}
                className="px-4 py-2 bg-[var(--bg-deep)] border border-[var(--border-subtle)] hover:border-[#3ECF8E]/30 rounded-lg text-[9px] font-black text-white hover:text-[#3ECF8E] uppercase tracking-widest transition-colors"
              >
                Close Details
              </button>
            </div>
          </div>
        </div>
      )}

      {/* MoT Session Intelligence Report Modal */}
      {showMotReport && motReportData && (
        <div className="fixed inset-0 bg-black/85 backdrop-blur-md z-[99999] flex items-center justify-center p-4 overflow-y-auto custom-scrollbar select-none">
          <div className="bg-[#09090D] border border-white/[0.05] rounded-2xl max-w-xl w-full shadow-2xl flex flex-col overflow-hidden animate-in zoom-in-95 duration-200 animate-out shrink-0">
            {/* Modal Header */}
            <div className="p-5 border-b border-white/[0.05] bg-gradient-to-r from-amber-500/10 to-transparent flex justify-between items-center">
              <div className="flex items-center gap-2">
                <Sparkles className="text-amber-500 animate-pulse" size={15} />
                <h3 className="text-[11px] font-black text-white uppercase tracking-widest font-mono">
                  Session Intelligence Report
                </h3>
              </div>
              <button 
                onClick={() => setShowMotReport(false)}
                className="text-[#555] hover:text-white transition-colors cursor-pointer"
              >
                <X size={14} />
              </button>
            </div>

            {/* Modal Content */}
            <div className="p-6 space-y-6 max-h-[70vh] overflow-y-auto custom-scrollbar">
              {/* Target Header */}
              <div className="p-3.5 bg-white/[0.01] border border-white/[0.03] rounded-xl flex items-center justify-between">
                <div>
                  <span className="text-[8px] font-black text-[#555] uppercase tracking-wider block font-mono">Target Request</span>
                  <span className="text-[11px] font-mono font-bold text-white uppercase">
                    {activeRequest?.method || 'GET'} {activeRequest?.name}
                  </span>
                </div>
                <div className="text-right">
                  <span className="text-[8px] font-black text-[#555] uppercase tracking-wider block font-mono">Testing Mode</span>
                  <span className="text-[9px] font-mono text-amber-500 font-bold uppercase tracking-wider">MoT Endurance</span>
                </div>
              </div>

              {/* Bento Grid Analytics */}
              <div className="grid grid-cols-2 md:grid-cols-3 gap-3">
                <div className="bg-[#0c0c12] border border-white/[0.03] rounded-xl p-3.5 space-y-1">
                  <span className="text-[8px] font-black text-amber-500 uppercase tracking-wider block font-mono">Sessions Run</span>
                  <div className="text-lg font-black text-white font-mono">{motReportData.durationSeconds}s</div>
                  <span className="text-[7px] text-[#444] block font-mono">ELAPSED TIME</span>
                </div>

                <div className="bg-[#0c0c12] border border-white/[0.03] rounded-xl p-3.5 space-y-1">
                  <span className="text-[8px] font-black text-[#555] uppercase tracking-wider block font-mono">Total Queries</span>
                  <div className="text-lg font-black text-white font-mono">{motReportData.totalRequests}</div>
                  <span className="text-[7px] text-emerald-400 block font-mono">{motReportData.successCount} passed</span>
                </div>

                <div className="bg-[#0c0c12] border border-white/[0.03] rounded-xl p-3.5 space-y-1">
                  <span className="text-[8px] font-black text-[#555] uppercase tracking-wider block font-mono">Health Quotient</span>
                  <div className={`text-lg font-black font-mono ${motReportData.successRate >= 80 ? 'text-[#3ECF8E]' : 'text-rose-500'}`}>
                    {motReportData.successRate}%
                  </div>
                  <span className="text-[7px] text-[#444] block font-mono">SUCCESS RATIO</span>
                </div>

                <div className="bg-[#0c0c12] border border-white/[0.03] rounded-xl p-3.5 space-y-1">
                  <span className="text-[8px] font-black text-[#555] uppercase tracking-wider block font-mono">Average Latency</span>
                  <div className="text-lg font-black text-white font-mono">{motReportData.avgLatency}ms</div>
                  <span className="text-[7px] text-[#444] block font-mono">RESPONSE MEAN TIME</span>
                </div>

                <div className="bg-[#0c0c12] border border-white/[0.03] rounded-xl p-3.5 space-y-1">
                  <span className="text-[8px] font-black text-[#555] uppercase tracking-wider block font-mono">Latency Jitter</span>
                  <div className="text-lg font-black text-white font-mono">
                    {motReportData.maxLatency - motReportData.minLatency}ms
                  </div>
                  <span className="text-[7px] text-[#444] block font-mono">MIN: {motReportData.minLatency}ms &bull; MAX: {motReportData.maxLatency}ms</span>
                </div>

                <div className="bg-[#0c0c12] border border-white/[0.03] rounded-xl p-3.5 space-y-1">
                  <span className="text-[8px] font-black text-amber-500 uppercase tracking-wider block font-mono">Guard Intercedes</span>
                  <div className="text-lg font-black text-white font-mono">{motReportData.crashPreventionActions}</div>
                  <span className="text-[7px] text-[#444] block font-mono">RESILIENCE ACTIONS</span>
                </div>
              </div>

              {/* Urgent Early Termination Warnings */}
              {motReportData.earlyAbort && (
                <div className="p-4 bg-red-950/20 border border-red-500/20 rounded-xl flex gap-3 animate-pulse">
                  <ShieldAlert className="text-red-400 shrink-0 mt-0.5" size={15} />
                  <div className="space-y-1">
                    <h5 className="text-[10px] font-black text-red-400 uppercase tracking-widest font-mono">
                      PREMATURE SESSION ABORT TRIGGERED
                    </h5>
                    <p className="text-[9px] text-red-300 font-medium leading-relaxed font-mono">
                      {motReportData.abortReason}
                    </p>
                  </div>
                </div>
              )}

              {/* Recommendations */}
              <div className="space-y-2">
                <span className="text-[8px] font-black text-[var(--text-dim)] uppercase tracking-widest block font-mono">
                  Engine Recommendations & Insights
                </span>
                <div className="space-y-2">
                  {motReportData.recommendations.map((rec: string, i: number) => (
                    <div 
                      key={i} 
                      className="p-3 bg-white/[0.02] border border-white/[0.03] rounded-xl flex gap-2.5 items-start text-left"
                    >
                      <Sparkles size={12} className="text-amber-500 shrink-0 mt-0.5" />
                      <p className="text-[9px] text-[#888894] leading-relaxed font-semibold">
                        {rec}
                      </p>
                    </div>
                  ))}
                </div>
              </div>
            </div>

            {/* Modal Footer */}
            <div className="px-5 py-3 border-t border-white/[0.05] flex justify-end gap-3 bg-[var(--bg-deep)]/30">
              <button
                onClick={() => {
                  exportCSV();
                  setShowMotReport(false);
                }}
                className="px-4 h-9 bg-[var(--bg-deep)] border border-[var(--border-subtle)] hover:border-[#3ECF8E]/30 rounded-lg text-[9px] font-black text-white hover:text-[#3ECF8E] uppercase tracking-widest transition-colors cursor-pointer"
              >
                Export CSV Logs
              </button>
              <button
                onClick={() => setShowMotReport(false)}
                className="px-5 h-9 bg-amber-500 hover:bg-amber-600 rounded-lg text-[9px] font-black text-black uppercase tracking-widest transition-colors cursor-pointer"
              >
                Done
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { 
  Wifi, 
  WifiOff, 
  PanelLeftOpen,
  Layout, 
  Shield, 
  Globe, 
  Settings, 
  RefreshCcw, 
  Clock, 
  Save, 
  CheckCircle2, 
  AlertCircle
} from 'lucide-react';
import { useStore } from '../store/useStore';
import { cn } from '../lib/utils';
import { format } from 'date-fns';

export const StatusBar: React.FC = () => {
  const { 
    syncStatus, 
    syncMetadata, 
    settings, 
    activeWorkspaceId, 
    workspaces,
    layoutOrientation,
    sidebarMode,
    sidebarWidth,
    setSidebarMode,
    setLayoutOrientation,
    updateSyncMetadata
  } = useStore();
  const [time, setTime] = useState(new Date());

  const activeWorkspace = workspaces.find(w => w.id === activeWorkspaceId);

  useEffect(() => {
    const timer = setInterval(() => setTime(new Date()), 1000);
    return () => clearInterval(timer);
  }, []);

  if (!settings.appearance.showStatusBar) return null;

  return (
    <div className="h-7 bg-[var(--bg-surface)] border-t border-[var(--border-subtle)] flex items-center justify-between px-3 text-[9px] font-black uppercase tracking-[0.15em] z-[100]">
      {/* Left Section: Context */}
      <div className="flex items-center gap-4">
        <div className="flex items-center gap-1.5 text-[var(--text-muted)]">
          <Globe size={10} />
          <span>{activeWorkspace?.name || 'Local'}</span>
        </div>
        
        <div className="h-3 w-px bg-[var(--border-subtle)]" />
        
        <div className="flex items-center gap-1.5 text-[var(--text-muted)]">
          <Shield size={10} className="text-[var(--brand)]" />
          <span>SSL: Secure</span>
        </div>

        <div className="h-3 w-px bg-[var(--border-subtle)]" />
        
        <div className="flex items-center gap-1.5 text-[var(--text-muted)]">
          <Settings size={10} />
          <span>Proxy: Off</span>
        </div>
      </div>

      {/* Center Section: Sync Status */}
      <div className="flex items-center gap-4 absolute left-1/2 -translate-x-1/2">
        <div className={cn(
          "flex items-center gap-1.5 transition-all",
          syncStatus === 'saving' ? "text-blue-400 animate-pulse" :
          syncStatus === 'saved' ? "text-[var(--brand)]" :
          syncStatus === 'pending' ? "text-yellow-500" :
          syncStatus === 'error' ? "text-red-500" :
          syncMetadata.isOffline ? "text-red-400" :
          "text-[var(--text-dim)]"
        )}>
          {syncStatus === 'saving' && <RefreshCcw size={10} className="animate-spin" />}
          {syncStatus === 'saved' && <CheckCircle2 size={10} />}
          {syncStatus === 'pending' && <Clock size={10} />}
          {syncStatus === 'error' && <AlertCircle size={10} />}
          {syncMetadata.isOffline && <WifiOff size={10} />}
          
          <span>
            {syncMetadata.isOffline ? 'Offline Mode' : 
             syncStatus === 'saving' ? 'Synchronizing' :
             syncStatus === 'saved' ? 'Cloud Synced' :
             syncStatus === 'pending' ? 'Changes Staged' :
             syncStatus === 'error' ? 'Sync Interrupted' : 'System Ready'}
          </span>
        </div>

        {syncMetadata.lastSynced && (
          <div className="text-[8px] text-[var(--text-dim)] lowercase normal-case flex items-center gap-1">
            <Save size={9} />
            <span>last sync: {format(syncMetadata.lastSynced, 'HH:mm:ss')}</span>
          </div>
        )}
      </div>

      {/* Right Section: Time & Connectivity */}
      <div className="flex items-center gap-4">
        <button 
          onClick={async () => {
            const nextOfflineState = !syncMetadata.isOffline;
            updateSyncMetadata({ isOffline: nextOfflineState });
            
            const { syncManager } = await import('../services/SyncService');
            if (nextOfflineState) {
              syncManager.setStatus('offline');
            } else {
              syncManager.setStatus('saving');
              try {
                await syncManager.flushAll();
                syncManager.setStatus('saved');
              } catch (e) {
                console.error('[Sync] Switch to Online Sync failed:', e);
                syncManager.setStatus('error');
              }
            }
          }}
          className={cn(
            "flex items-center gap-1.5 px-2 py-0.5 rounded transition-colors select-none cursor-pointer text-[9px] font-black uppercase tracking-[0.1em]",
            syncMetadata.isOffline 
              ? "text-red-400 hover:bg-red-500/10 border border-red-500/20" 
              : "text-[var(--text-muted)] hover:bg-[var(--bg-elevated)] border border-transparent hover:border-[var(--border-subtle)]"
          )}
          title={syncMetadata.isOffline ? "Switch to Online Mode" : "Switch to Local-Only Offline Mode"}
        >
          {syncMetadata.isOffline ? <WifiOff size={10} className="text-red-400 animate-pulse" /> : <Wifi size={10} className="text-[var(--brand)]" />}
          <span>{syncMetadata.isOffline ? 'Disconnected (Local)' : 'Authenticated (Cloud)'}</span>
        </button>
        
        <div className="flex items-center gap-2">
          <button 
            onClick={() => setSidebarMode(sidebarMode === 'hidden' ? 'expanded' : 'hidden')}
            className={cn(
              "flex items-center gap-1.5 px-2 py-0.5 transition-colors rounded hover:bg-[var(--bg-elevated)]",
              sidebarMode !== 'hidden' ? "text-[var(--brand)]" : "text-[var(--text-dim)]"
            )}
            title="Toggle Sidebar (Ctrl+B)"
          >
            <PanelLeftOpen size={10} />
            {sidebarMode === 'hidden' && <span className="text-[8px]">Show Sidebar</span>}
          </button>
          <button 
            onClick={() => setLayoutOrientation(layoutOrientation === 'vertical' ? 'horizontal' : 'vertical')}
            className="flex items-center gap-1.5 px-2 py-0.5 text-[var(--text-dim)] hover:text-[var(--brand)] hover:bg-[var(--bg-elevated)] transition-colors rounded"
            title="Toggle Layout Orientation"
          >
            <Layout size={10} className={cn(layoutOrientation === 'horizontal' ? "rotate-90" : "")} />
          </button>
        </div>

        <div className="h-3 w-px bg-[var(--border-subtle)]" />
        
        <div className="flex items-center gap-1.5 text-[var(--text-main)] tabular-nums">
          <Clock size={10} />
          <span>{format(time, 'HH:mm:ss')}</span>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { motion, AnimatePresence } from 'motion/react';
import { 
  X, UserPlus, Shield, UserMinus, Crown, ShieldCheck, Mail, QrCode, 
  Copy, Trash2, Calendar, Link as LinkIcon, Users, Settings2, 
  Check, ChevronDown, Activity, ShieldAlert, Sparkles, HelpCircle 
} from 'lucide-react';
import { useStore } from '../store/useStore';
import { PersistenceService } from '../services/PersistenceService';
import { OnboardingService } from '../services/OnboardingService';
import { supabase } from '../lib/supabase';
import { cn } from '../lib/utils';
import { TeamInvite } from '../types';

interface TeamModalProps {
  isOpen: boolean;
  onClose: () => void;
  team?: any; // If provided, we are editing
}

export const TeamModal: React.FC<TeamModalProps> = ({ isOpen, onClose, team }) => {
  const { profile, addToast } = useStore();
  const [name, setName] = useState(team?.name || '');
  const [email, setEmail] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [members, setMembers] = useState<any[]>([]);
  const [invites, setInvites] = useState<TeamInvite[]>([]);
  const [activeTab, setActiveTab] = useState<'members' | 'invites'>('members');
  const [activeRoleDropdown, setActiveRoleDropdown] = useState<string | null>(null);
  const [decommissionCandidateId, setDecommissionCandidateId] = useState<string | null>(null);

  // Generate unique visual color gradient based on operator's name/email initials
  const getAvatarGradient = (seedStr: string) => {
    const gradients = [
      'from-pink-500 to-purple-600',
      'from-cyan-500 to-blue-600',
      'from-emerald-400 to-teal-600',
      'from-amber-400 to-orange-600',
      'from-indigo-500 to-violet-700',
      'from-rose-400 to-red-600'
    ];
    let hash = 0;
    for (let i = 0; i < seedStr.length; i++) {
      hash = seedStr.charCodeAt(i) + ((hash << 5) - hash);
    }
    const idx = Math.abs(hash) % gradients.length;
    return gradients[idx];
  };

  const getInitials = (member: any) => {
    const name = member.profiles?.full_name || member.profiles?.email || 'OP';
    return name.substring(0, 2).toUpperCase();
  };

  useEffect(() => {
    if (!team?.id) return;

    fetchMembers();
    fetchInvites();

    // 1. Real-time Subscription (Instant updates when replication is enabled)
    const channel = supabase
      .channel(`team-members-changes-${team.id}`)
      .on(
        'postgres_changes',
        {
          event: '*',
          schema: 'public',
          table: 'team_members',
          filter: `team_id=eq.${team.id}`,
        },
        () => {
          console.log('[TeamModal] Real-time event detected on team_members. Fetching latest roster...');
          fetchMembers();
          fetchInvites();
        }
      )
      .subscribe();

    // 2. Polling Fallback (Updates every 10 seconds as backup)
    const interval = setInterval(() => {
      fetchMembers();
      fetchInvites();
    }, 10000);

    return () => {
      supabase.removeChannel(channel);
      clearInterval(interval);
    };
  }, [team?.id]);

  const fetchMembers = async () => {
    const { data, error } = await supabase
      .from('team_members')
      .select('*, profiles(email, full_name)')
      .eq('team_id', team.id);
    
    if (data) setMembers(data);
  };

  const fetchInvites = async () => {
    try {
      const data = await OnboardingService.listTeamInvites(team.id);
      setInvites(data);
    } catch (e) {
      console.error('Failed to fetch invites');
    }
  };

  const handleGenerateInvite = async () => {
    if (!team?.id || !profile?.id) return;
    setIsLoading(true);
    try {
      const result = await OnboardingService.createTeamInvite(team.id, profile.id, {
        expiresInDays: 7, // Default 7 days
      });
      if (result.success) {
        addToast({ type: 'success', message: 'Secure temporary onboarding code generated.' });
        fetchInvites();
      } else {
        throw new Error(result.error);
      }
    } catch (error: any) {
      addToast({ type: 'error', message: error.message || 'Failed to generate invite.' });
    } finally {
      setIsLoading(false);
    }
  };

  const handleRevokeInvite = async (inviteId: string) => {
    try {
      await OnboardingService.revokeTeamInvite(inviteId);
      addToast({ type: 'info', message: 'Invite revoked.' });
      fetchInvites();
    } catch (error) {
      addToast({ type: 'error', message: 'Failed to revoke invite.' });
    }
  };

  const copyToClipboard = (text: string, label: string) => {
    navigator.clipboard.writeText(text);
    addToast({ type: 'success', message: `${label} copied to clipboard.` });
  };

  const handleCreate = async () => {
    if (!name.trim() || !profile?.id) return;
    setIsLoading(true);
    try {
      await PersistenceService.createTeam(name, profile.id);
      addToast({ type: 'success', message: `Team "${name}" established.` });
      onClose();
    } catch (error) {
      addToast({ type: 'error', message: 'Failed to establish team.' });
    } finally {
      setIsLoading(false);
    }
  };

  const handleInvite = async () => {
    if (!email.trim() || !team?.id) return;
    setIsLoading(true);
    try {
      await PersistenceService.addTeamMember(team.id, email);
      addToast({ type: 'success', message: `Invite sent to ${email}.` });
      setEmail('');
      fetchMembers();
    } catch (error: any) {
      addToast({ type: 'error', message: error.message || 'Failed to send invite.' });
    } finally {
      setIsLoading(false);
    }
  };

  const handleUpdateRole = async (userId: string, newRole: 'viewer' | 'editor' | 'admin') => {
    if (!team?.id) return;
    try {
      await PersistenceService.updateTeamMemberRole(team.id, userId, newRole);
      addToast({ type: 'success', message: `Operator permission set to ${newRole}.` });
      setActiveRoleDropdown(null);
      fetchMembers();
    } catch (error) {
      addToast({ type: 'error', message: 'Failed to update permissions.' });
    }
  };

  const handleRemove = (userId: string) => {
    setDecommissionCandidateId(userId);
  };

  const handleRemoveConfirmed = async (userId: string) => {
    if (!team?.id) return;
    try {
      await PersistenceService.removeTeamMember(team.id, userId);
      addToast({ type: 'info', message: 'Operator decommissioned.' });
      fetchMembers();
    } catch (error) {
      addToast({ type: 'error', message: 'Failed to decommission operator.' });
    }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-[500] flex items-center justify-center p-4">
      {/* Background Dim Backdrop */}
      <motion.div 
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        exit={{ opacity: 0 }}
        onClick={onClose}
        className="absolute inset-0 bg-black/80 backdrop-blur-md"
      />
      
      <motion.div
        initial={{ opacity: 0, scale: 0.96, y: 15 }}
        animate={{ opacity: 1, scale: 1, y: 0 }}
        exit={{ opacity: 0, scale: 0.96, y: 15 }}
        transition={{ duration: 0.2, ease: "easeOut" }}
        className="relative w-full max-w-lg bg-[#0A0A0C] border border-[#1C1C22] rounded-3xl shadow-[0_30px_60px_rgba(0,0,0,0.8)] overflow-hidden flex flex-col max-h-[85vh]"
      >
        {/* Glowing visual accent line */}
        <div className="h-[2px] bg-gradient-to-r from-[#3ECF8E] via-blue-500 to-indigo-600" />

        {decommissionCandidateId && (
          <div className="absolute inset-0 z-50 bg-[#0A0A0C]/95 backdrop-blur-md flex flex-col items-center justify-center p-6 text-center select-none animate-in fade-in duration-200">
            <ShieldAlert size={36} className="text-red-500 mb-4 animate-[bounce_1s_infinite]" />
            <h3 className="text-xs font-black text-white uppercase tracking-widest mb-2">Decommission Operator</h3>
            <p className="text-[10px] text-gray-400 max-w-xs mb-6 font-mono leading-relaxed uppercase tracking-tight">
              Are you sure you want to decommission this operator? They will lose real-time access to all shared workspace scenarios.
            </p>
            <div className="flex gap-3">
              <button
                onClick={async () => {
                  const uId = decommissionCandidateId;
                  setDecommissionCandidateId(null);
                  await handleRemoveConfirmed(uId);
                }}
                className="px-4 py-2 bg-red-600 hover:bg-red-700 text-[10px] font-black uppercase tracking-widest text-white rounded-lg transition-all cursor-pointer font-bold"
              >
                Decommission
              </button>
              <button
                onClick={() => setDecommissionCandidateId(null)}
                className="px-4 py-2 bg-[#1C1C24] border border-[#2D2D39] text-[10px] font-black uppercase tracking-widest text-[#88888F] hover:text-white rounded-lg transition-all cursor-pointer font-bold"
              >
                Cancel
              </button>
            </div>
          </div>
        )}

        {/* Modal Header */}
        <div className="p-6 border-b border-[#1A1A22]/50 bg-[#0C0C0F] flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 rounded-2xl bg-[#3ECF8E]/10 border border-[#3ECF8E]/20 flex items-center justify-center">
              <Users size={18} className="text-[#3ECF8E]" />
            </div>
            <div>
              <h2 className="text-[13px] font-black text-white uppercase tracking-[0.15em] font-mono flex items-center gap-2">
                {team ? team.name : 'Initialize Team Unit'}
              </h2>
              <p className="text-[9px] text-[#55555C] uppercase tracking-wider font-mono mt-0.5">
                {team ? `UNIT CODE: ${team.id.split('-')[0]}` : 'Configure collaborative sync deployment'}
              </p>
            </div>
          </div>
          <button 
            onClick={onClose} 
            className="p-1.5 rounded-xl text-[#55555C] hover:text-white bg-white/[0.02] hover:bg-white/[0.05] transition-all cursor-pointer"
          >
            <X size={16} />
          </button>
        </div>

        {/* Modal Content */}
        <div className="flex-1 overflow-y-auto no-scrollbar p-6 space-y-6">
          
          {/* TEAM CONFIGURATION FORM (If creating) */}
          {!team && (
            <div className="space-y-5">
              <div className="p-4 bg-[#3ECF8E]/5 border border-[#3ECF8E]/15 rounded-2xl space-y-1.5">
                <span className="text-[9px] font-black text-[#3ECF8E] uppercase tracking-widest font-mono flex items-center gap-1.5"><Sparkles size={11} /> Collaborative Sandbox</span>
                <p className="text-[10px] text-[#888] leading-relaxed font-mono">
                  Initializing a Team Unit enables instant, bi-directional workspace sync. Shared collections, environments, and runner configurations sync in near real-time between all enlistees.
                </p>
              </div>

              <div className="space-y-2">
                <label className="text-[9px] font-black text-[#55555C] uppercase tracking-[0.2em] font-mono">Unit Designation (Name)</label>
                <input 
                  value={name}
                  onChange={(e) => setName(e.target.value)}
                  placeholder="e.g. ALPHA_TEAM"
                  className="w-full bg-[#050507] border border-[#1C1C22] px-4 py-3.5 rounded-xl text-white font-mono text-[11px] placeholder:text-[#333] focus:outline-none focus:border-[#3ECF8E]/40 focus:ring-1 focus:ring-[#3ECF8E]/20 transition-all uppercase"
                />
              </div>
            </div>
          )}

          {/* ACTIVE TEAM MANAGEMENT (If editing) */}
          {team && (
            <>
              {/* Telemetry Metrics Panel */}
              <div className="grid grid-cols-3 gap-3 bg-[#0C0C0F] p-4 border border-[#1A1A22] rounded-2xl font-mono">
                <div className="space-y-1 text-center">
                  <span className="text-[8px] text-[#55555C] uppercase tracking-widest block">Operators</span>
                  <span className="text-sm font-bold text-white block">{members.length}</span>
                </div>
                <div className="space-y-1 text-center border-x border-[#1A1A22]">
                  <span className="text-[8px] text-[#55555C] uppercase tracking-widest block">Realtime Sync</span>
                  <span className="text-xs font-bold text-[#3ECF8E] flex items-center justify-center gap-1.5">
                    <Activity size={10} className="animate-pulse" /> ACTIVE
                  </span>
                </div>
                <div className="space-y-1 text-center">
                  <span className="text-[8px] text-[#55555C] uppercase tracking-widest block">Access Rulings</span>
                  <span className="text-[9px] font-bold text-[#A0A0A9] block">RBAC ENFORCED</span>
                </div>
              </div>

              {/* Navigation Tabs */}
              <div className="flex bg-[#0C0C0F] p-1 rounded-xl border border-[#1A1A22]">
                <button
                  onClick={() => setActiveTab('members')}
                  className={cn(
                    "flex-1 py-2 text-[9px] font-black uppercase tracking-widest rounded-lg transition-all cursor-pointer",
                    activeTab === 'members' 
                      ? "bg-[#1C1C22] text-[#3ECF8E] border border-white/5 shadow-sm" 
                      : "text-[#55555C] hover:text-[#A0A0A9]"
                  )}
                >
                  Roster Operations
                </button>
                <button
                  onClick={() => setActiveTab('invites')}
                  className={cn(
                    "flex-1 py-2 text-[9px] font-black uppercase tracking-widest rounded-lg transition-all flex items-center justify-center gap-2 cursor-pointer",
                    activeTab === 'invites' 
                      ? "bg-[#1C1C22] text-[#3ECF8E] border border-white/5 shadow-sm" 
                      : "text-[#55555C] hover:text-[#A0A0A9]"
                  )}
                >
                  <QrCode size={11} />
                  Secure Invites ({invites.length})
                </button>
              </div>

              {/* TAB 1: MEMBERS ROSTER */}
              {activeTab === 'members' && (
                <div className="space-y-5 animate-in fade-in duration-200">
                  {/* Member Invite Panel */}
                  <div className="space-y-2">
                    <label className="text-[9px] font-black text-[#55555C] uppercase tracking-[0.2em] font-mono">Enlist Operator</label>
                    <div className="flex gap-2">
                      <div className="relative flex-1">
                        <Mail size={13} className="absolute left-3.5 top-1/2 -translate-y-1/2 text-[#333]" />
                        <input 
                          value={email}
                          onChange={(e) => setEmail(e.target.value)}
                          placeholder="operator@email.com"
                          className="w-full bg-[#050507] border border-[#1C1C22] pl-10 pr-4 py-2.5 rounded-xl text-white font-mono text-[11px] placeholder:text-[#333] focus:outline-none focus:border-[#3ECF8E]/40 transition-all"
                        />
                      </div>
                      <button 
                        onClick={handleInvite}
                        disabled={isLoading || !email}
                        className="px-4.5 bg-[#3ECF8E] hover:bg-[#32B379] text-[#070708] text-[9px] font-black uppercase tracking-widest rounded-xl hover:shadow-[0_0_15px_rgba(62,207,142,0.2)] transition-all disabled:opacity-30 cursor-pointer"
                      >
                        Enlist
                      </button>
                    </div>
                  </div>

                  {/* Members List */}
                  <div className="space-y-3">
                    <div className="flex justify-between items-center">
                      <label className="text-[9px] font-black text-[#55555C] uppercase tracking-[0.2em] font-mono">Current Roster ({members.length})</label>
                      <span className="text-[8px] text-[#444] font-mono font-bold">HOVER FOR CONTROLS</span>
                    </div>

                    <div className="space-y-2 max-h-60 overflow-y-auto no-scrollbar pr-1">
                      {members.map((member) => {
                        const initials = getInitials(member);
                        const gradient = getAvatarGradient(member.user_id);
                        const isSelf = member.user_id === profile?.id;
                        
                        return (
                          <div 
                            key={member.user_id} 
                            className="flex items-center justify-between p-3 bg-[#0C0C0F]/60 border border-[#1C1C22] rounded-xl hover:border-white/5 transition-all group/member"
                          >
                            <div className="flex items-center gap-3">
                              {/* Glowing Avatar */}
                              <div className="relative">
                                <div className={cn(
                                  "w-8 h-8 rounded-lg bg-gradient-to-br flex items-center justify-center font-black font-mono text-[10px] text-white shadow-lg border border-white/5",
                                  gradient
                                )}>
                                  {initials}
                                </div>
                                <div className="absolute -bottom-0.5 -right-0.5 w-2 h-2 rounded-full bg-[#3ECF8E] border border-[#0A0A0C] shadow-[0_0_6px_#3ECF8E]" />
                              </div>

                              <div>
                                <div className="text-[11px] font-bold text-[#E0E0E6] flex items-center gap-1.5">
                                  {member.profiles?.full_name || member.profiles?.email}
                                  {isSelf && (
                                    <span className="text-[7px] font-black bg-white/5 text-[#888] px-1 py-0.2 rounded font-mono">YOU</span>
                                  )}
                                </div>
                                <div className="text-[8px] font-black text-[#555] uppercase tracking-widest font-mono mt-0.5">
                                  {member.profiles?.email}
                                </div>
                              </div>
                            </div>
                            
                            {/* Role Selection & Decommission */}
                            <div className="flex items-center gap-2">
                              {/* Role Badge Dropdown Button */}
                              <div className="relative">
                                <button
                                  disabled={member.role === 'owner' || !team}
                                  onClick={() => setActiveRoleDropdown(activeRoleDropdown === member.user_id ? null : member.user_id)}
                                  className={cn(
                                    "px-2 py-1 rounded text-[8px] font-black uppercase tracking-wider font-mono flex items-center gap-1 transition-all border",
                                    member.role === 'owner' 
                                      ? "bg-yellow-500/10 text-yellow-400 border-yellow-500/20" 
                                      : member.role === 'admin' 
                                        ? "bg-cyan-500/10 text-cyan-400 border-cyan-500/20 hover:bg-cyan-500/20" 
                                        : member.role === 'editor'
                                          ? "bg-green-500/10 text-green-400 border-green-500/20 hover:bg-green-500/20"
                                          : "bg-slate-500/10 text-slate-400 border-slate-500/20 hover:bg-slate-500/20",
                                    member.role !== 'owner' && "cursor-pointer"
                                  )}
                                >
                                  {member.role === 'owner' ? 'Commander' : member.role === 'admin' ? 'Officer' : member.role === 'editor' ? 'Editor' : 'Viewer'}
                                  {member.role !== 'owner' && <ChevronDown size={8} />}
                                </button>

                                {/* Custom Floating Role Selector */}
                                <AnimatePresence>
                                  {activeRoleDropdown === member.user_id && (
                                    <>
                                      <div className="fixed inset-0 z-[600]" onClick={() => setActiveRoleDropdown(null)} />
                                      <motion.div
                                        initial={{ opacity: 0, y: 5, scale: 0.95 }}
                                        animate={{ opacity: 1, y: 0, scale: 1 }}
                                        exit={{ opacity: 0, y: 5, scale: 0.95 }}
                                        transition={{ duration: 0.1 }}
                                        className="absolute right-0 mt-1.5 w-32 bg-[#0E0E12] border border-[#222] rounded-xl shadow-2xl z-[700] p-1 space-y-0.5 text-left"
                                      >
                                        {([
                                          { r: 'admin', l: 'Officer', desc: 'Manage access' },
                                          { r: 'editor', l: 'Editor', desc: 'Modify scenario' },
                                          { r: 'viewer', l: 'Viewer', desc: 'Read / Execute' }
                                        ] as const).map((opt) => (
                                          <button
                                            key={opt.r}
                                            onClick={() => handleUpdateRole(member.user_id, opt.r)}
                                            className={cn(
                                              "w-full text-left px-2 py-1.5 rounded-lg text-[9px] font-black tracking-wide font-mono transition-all flex items-center justify-between cursor-pointer",
                                              member.role === opt.r 
                                                ? "bg-[#3ECF8E]/10 text-[#3ECF8E]" 
                                                : "text-[#555] hover:text-[#E0E0E6] hover:bg-white/5"
                                            )}
                                          >
                                            <div>
                                              <div>{opt.l}</div>
                                              <div className="text-[6px] text-[#444] font-normal uppercase tracking-normal">{opt.desc}</div>
                                            </div>
                                            {member.role === opt.r && <Check size={10} />}
                                          </button>
                                        ))}
                                      </motion.div>
                                    </>
                                  )}
                                </AnimatePresence>
                              </div>

                              {/* Decommission Operator Icon */}
                              {!isSelf && member.role !== 'owner' && (
                                <button 
                                  onClick={() => handleRemove(member.user_id)}
                                  className="p-1 text-[#55555C] hover:text-red-400 bg-white/[0.02] hover:bg-red-500/10 rounded-lg border border-transparent hover:border-red-500/20 transition-all cursor-pointer opacity-0 group-hover/member:opacity-100"
                                  title="Decommission Operator"
                                >
                                  <UserMinus size={11} />
                                </button>
                              )}
                            </div>
                          </div>
                        );
                      })}
                    </div>
                  </div>
                </div>
              )}

              {/* TAB 2: SECURE INVITES */}
              {activeTab === 'invites' && (
                <div className="space-y-4 animate-in fade-in duration-200">
                  <div className="flex items-center justify-between">
                    <label className="text-[9px] font-black text-[#55555C] uppercase tracking-[0.2em] font-mono flex items-center gap-1.5">
                       Secure Invitation Tokens
                    </label>
                    <button
                      onClick={handleGenerateInvite}
                      disabled={isLoading}
                      className="text-[9px] font-black text-[#3ECF8E] uppercase tracking-widest hover:underline cursor-pointer flex items-center gap-1"
                    >
                      <Sparkles size={11} /> Generate New Token
                    </button>
                  </div>

                  {/* Invitations list */}
                  <div className="space-y-3 max-h-64 overflow-y-auto no-scrollbar pr-1">
                    {invites.length === 0 ? (
                      <div className="p-8 text-center border border-dashed border-[#1C1C22] rounded-2xl bg-[#070709]/50">
                        <QrCode size={30} className="mx-auto text-[#222] mb-3 opacity-30 animate-pulse" />
                        <p className="text-[10px] text-[#55555C] uppercase tracking-widest leading-relaxed font-mono">
                          No secure codes generated.<br/>Create one for one-click onboarding.
                        </p>
                      </div>
                    ) : (
                      invites.map((invite) => (
                        <div key={invite.id} className="p-4 bg-[#0C0C0F]/80 border border-[#1C1C22] rounded-xl space-y-3.5 group/invite relative overflow-hidden">
                          {/* Copier overlay */}
                          <div className="flex items-center justify-between">
                            <div className="text-[12px] font-mono font-black text-[#3ECF8E] tracking-[0.18em] bg-[#050507] px-2.5 py-1.5 rounded-lg border border-white/5 select-all">
                              {invite.code}
                            </div>
                            <div className="flex items-center gap-1.5">
                              <button 
                                onClick={() => copyToClipboard(invite.code, 'Onboarding code')}
                                className="p-2 text-[#55555C] hover:text-[#3ECF8E] bg-white/[0.02] border border-[#1C1C22] hover:border-[#3ECF8E]/20 rounded-lg transition-all cursor-pointer"
                                title="Copy Invitation Token"
                              >
                                <Copy size={11} />
                              </button>
                              <button 
                                onClick={() => copyToClipboard(`${window.location.origin}/?invite=${invite.code}`, 'Onboarding Join Link')}
                                className="p-2 text-[#55555C] hover:text-[#3ECF8E] bg-white/[0.02] border border-[#1C1C22] hover:border-[#3ECF8E]/20 rounded-lg transition-all cursor-pointer"
                                title="Copy Secure Join Link"
                              >
                                <LinkIcon size={11} />
                              </button>
                              <button 
                                onClick={() => handleRevokeInvite(invite.id)}
                                className="p-2 text-[#55555C] hover:text-red-400 bg-white/[0.02] border border-[#1C1C22] hover:border-red-500/20 rounded-lg transition-all cursor-pointer opacity-0 group-hover/invite:opacity-100"
                                title="Revoke Secure Token"
                              >
                                <Trash2 size={11} />
                              </button>
                            </div>
                          </div>

                          <div className="flex items-center justify-between text-[8px] font-black uppercase tracking-widest text-[#555] font-mono pt-1 border-t border-[#1C1C22]/50">
                            <div className="flex items-center gap-1.5">
                              <Calendar size={10} />
                              {invite.expires_at ? `Exp: ${new Date(invite.expires_at).toLocaleDateString()}` : 'Never'}
                            </div>
                            <div className="flex items-center gap-1.5">
                              <UserPlus size={10} />
                              Uses: {invite.use_count} {invite.max_uses > 0 ? `/ ${invite.max_uses}` : ''}
                            </div>
                          </div>
                        </div>
                      ))
                    )}
                  </div>

                  {/* Informational Security Tip */}
                  <div className="p-4 bg-[#3ECF8E]/5 border border-[#3ECF8E]/10 rounded-2xl flex gap-3">
                    <ShieldAlert size={16} className="text-[#3ECF8E] shrink-0 mt-0.5" />
                    <div>
                      <p className="text-[10px] text-[#3ECF8E] font-bold font-mono">💡 Secure Connection Packages</p>
                      <p className="text-[9px] text-[#55555C] leading-relaxed font-mono mt-0.5">
                        These secure invite codes carry cryptographically compiled references to active Supabase sync hosts. Operators joining using a valid token are instantly logged in and synced without needing to manual-configure server connection hashes.
                      </p>
                    </div>
                  </div>
                </div>
              )}
            </>
          )}

        </div>

        {/* Modal Actions Footer */}
        <div className="p-6 border-t border-[#1A1A22]/50 bg-[#0C0C0F] flex items-center justify-between shrink-0">
          <span className="text-[8px] text-[#444] uppercase tracking-wider font-mono">
            {team ? 'RBAC deployment active' : 'Secure handshake pending'}
          </span>
          
          <div className="flex items-center gap-3">
            <button 
              onClick={onClose}
              className="px-4 py-2 rounded-xl text-[9px] font-black text-[#888] hover:text-white bg-white/[0.02] hover:bg-white/[0.05] border border-[#1A1A22] cursor-pointer uppercase transition-all"
            >
              Close
            </button>
            {!team && (
              <button
                onClick={handleCreate}
                disabled={isLoading || !name.trim()}
                className="px-5 py-2 bg-[#3ECF8E] hover:bg-[#32B379] text-[#070708] text-[9px] font-black uppercase tracking-wider rounded-xl hover:shadow-[0_0_15px_rgba(62,207,142,0.2)] disabled:opacity-30 cursor-pointer transition-all"
              >
                Initialize Deployment
              </button>
            )}
          </div>
        </div>

      </motion.div>
    </div>
  );
};

import React, { useEffect } from 'react';
import { motion, AnimatePresence } from 'motion/react';
import { useStore } from '../store/useStore';
import { CheckCircle2, AlertCircle, Info, AlertTriangle, X } from 'lucide-react';
import { cn } from '../lib/utils';

export const ToastContainer: React.FC = () => {
  const { toasts, removeToast } = useStore();

  return (
    <div className="fixed bottom-12 right-6 z-[200] flex flex-col gap-3 pointer-events-none">
      <AnimatePresence mode="popLayout">
        {toasts.map((toast) => (
          <ToastItem key={toast.id} toast={toast} onRemove={() => removeToast(toast.id)} />
        ))}
      </AnimatePresence>
    </div>
  );
};

const ToastItem: React.FC<{ toast: any; onRemove: () => void }> = ({ toast, onRemove }) => {
  useEffect(() => {
    const timer = setTimeout(onRemove, 5000);
    return () => clearTimeout(timer);
  }, [onRemove]);

  const icons = {
    success: <CheckCircle2 size={16} className="text-[#3ECF8E]" />,
    error: <AlertCircle size={16} className="text-red-500" />,
    info: <Info size={16} className="text-blue-400" />,
    warning: <AlertTriangle size={16} className="text-yellow-500" />,
  };

  const borders = {
    success: 'border-[#3ECF8E]/20',
    error: 'border-red-500/20',
    info: 'border-blue-400/20',
    warning: 'border-yellow-500/20',
  };

  return (
    <motion.div
      initial={{ opacity: 0, x: 20, scale: 0.9 }}
      animate={{ opacity: 1, x: 0, scale: 1 }}
      exit={{ opacity: 0, x: 20, scale: 0.9 }}
      layout
      className={cn(
        "pointer-events-auto flex items-center gap-4 px-4 pb-4 pt-3 bg-[#0C0C0E]/95 backdrop-blur-xl border rounded-xl shadow-2xl min-w-[300px] max-w-sm relative overflow-hidden select-none",
        borders[toast.type as keyof typeof borders]
      )}
    >
      <div className="flex-shrink-0">
        {icons[toast.type as keyof typeof icons]}
      </div>
      <div className="flex-1 text-[11px] font-medium text-white/90 pr-2">
        {toast.message}
      </div>
      <button 
        onClick={onRemove}
        className="text-[#444444] hover:text-white transition-colors shrink-0"
      >
        <X size={14} />
      </button>

      {/* Premium Shrinking Progress Auto-Close Bar */}
      <div className="absolute bottom-0 left-0 right-0 h-[2px] bg-white/5 overflow-hidden rounded-b-xl">
        <motion.div 
          initial={{ width: "100%" }}
          animate={{ width: "0%" }}
          transition={{ duration: 5, ease: "linear" }}
          className={cn(
            "h-full",
            toast.type === 'success' && "bg-[#3ECF8E]",
            toast.type === 'error' && "bg-red-500",
            toast.type === 'info' && "bg-blue-400",
            toast.type === 'warning' && "bg-yellow-500"
          )}
        />
      </div>
    </motion.div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { useStore } from '../store/useStore';
import { cn } from '../lib/utils';
import { Collection, RequestData } from '../types';
import { VariableService } from '../services/VariableService';
import { ExternalLink, AlertTriangle } from 'lucide-react';

interface VariableInputProps {
  value: string;
  onChange: (val: string) => void;
  placeholder?: string;
  className?: string;
  autoFocus?: boolean;
  masked?: boolean;
  disabled?: boolean;
  onNavigateVariable?: (name: string, scope: 'environment' | 'collection') => void;
}

export const VariableInput: React.FC<VariableInputProps> = ({ 
  value = '', 
  onChange, 
  placeholder, 
  className,
  autoFocus,
  masked = false,
  disabled = false,
  onNavigateVariable
}) => {
  const {
    environments,
    activeEnvId,
    collections,
    openTabs,
    activeTabId,
    updateEnvironment,
    updateCollection,
    addTab,
    globalVariables
  } = useStore();
  const [showSuggestions, setShowSuggestions] = useState(false);
  const [suggestionIndex, setSuggestionIndex] = useState(0);
  const [hoveredVariable, setHoveredVariable] = useState<string | null>(null);
  const [editingValue, setEditingValue] = useState('');
  const [isFocused, setIsFocused] = useState(false);
  const containerRef = useRef<HTMLDivElement>(null);
  const hideTooltipTimerRef = useRef<number | null>(null);

  const activeEnv = environments.find(e => e.id === activeEnvId);
  const activeTab = openTabs.find(t => t.id === activeTabId);
  const activeCollection = activeTab && 'requests' in activeTab 
    ? activeTab as Collection 
    : collections.find(c => c.id === (activeTab as RequestData)?.collection_id);

  const variableContext = {
    environments,
    activeEnvId,
    collection: activeCollection || null,
    globalVariables
  };

  const allVariables = (() => {
    const ordered = [
      ...(activeEnv?.variables || []),
      ...(activeCollection?.variables || []),
      ...(globalVariables || []),
    ].filter(v => v.active);

    const seen = new Set<string>();
    return ordered.filter((v) => {
      if (seen.has(v.key)) return false;
      seen.add(v.key);
      return true;
    });
  })();

  const filteredVars = allVariables.filter(v => {
    const safeValue = value || '';
    const match = safeValue.match(/\{\{([^}]*)$/);
    if (!match) return false;
    return (v.key || '').toLowerCase().includes(match[1].toLowerCase());
  });

  const hoveredLookup = hoveredVariable
    ? VariableService.lookupVariable(hoveredVariable, variableContext)
    : null;

  useEffect(() => {
    if (!hoveredLookup) {
      setEditingValue('');
      return;
    }
    setEditingValue(hoveredLookup.value || '');
  }, [hoveredLookup?.name, hoveredLookup?.value, hoveredLookup?.scope]);

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (showSuggestions && filteredVars.length > 0) {
      if (e.key === 'ArrowDown') {
        e.preventDefault();
        setSuggestionIndex(prev => (prev + 1) % filteredVars.length);
      } else if (e.key === 'ArrowUp') {
        e.preventDefault();
        setSuggestionIndex(prev => (prev - 1 + filteredVars.length) % filteredVars.length);
      } else if (e.key === 'Enter' || e.key === 'Tab') {
        e.preventDefault();
        selectSuggestion(filteredVars[suggestionIndex].key);
      } else if (e.key === 'Escape') {
        setShowSuggestions(false);
      }
    }
  };

  const selectSuggestion = (varName: string) => {
    const newValue = value.replace(/\{\{([^}]*)$/, `{{${varName}}}`);
    onChange(newValue);
    setShowSuggestions(false);
  };

  const persistHoveredVariableValue = () => {
    if (!hoveredLookup) return;
    const variableName = hoveredLookup.name;

    if (hoveredLookup.scope === 'environment' && hoveredLookup.sourceId) {
      const env = environments.find(e => e.id === hoveredLookup.sourceId);
      if (!env) return;
      const updatedVariables = (env.variables || []).map(v =>
        v.key === variableName && v.active ? { ...v, value: editingValue } : v
      );
      updateEnvironment(env.id, { variables: updatedVariables });
      return;
    }

    if (hoveredLookup.scope === 'collection' && activeCollection) {
      const updatedVariables = (activeCollection.variables || []).map(v =>
        v.key === variableName && v.active ? { ...v, value: editingValue } : v
      );
      updateCollection(activeCollection.id, { variables: updatedVariables });
    }
  };

  const navigateToVariableSource = () => {
    if (!hoveredLookup) return;
    if (hoveredLookup.scope !== 'environment' && hoveredLookup.scope !== 'collection') return;

    if (onNavigateVariable) {
      onNavigateVariable(hoveredLookup.name, hoveredLookup.scope);
      return;
    }

    if (hoveredLookup.scope === 'environment') {
      addTab({
        id: 'tab-environments',
        type: 'environment-manager',
        name: 'Environments',
        environmentId: hoveredLookup.sourceId,
      } as any);
      return;
    }

    if (hoveredLookup.scope === 'collection' && activeCollection) {
      addTab(activeCollection as any);
    }
  };

  const startHideTooltipTimer = () => {
    if (hideTooltipTimerRef.current) window.clearTimeout(hideTooltipTimerRef.current);
    hideTooltipTimerRef.current = window.setTimeout(() => {
      setHoveredVariable(null);
    }, 120);
  };

  const cancelHideTooltipTimer = () => {
    if (hideTooltipTimerRef.current) {
      window.clearTimeout(hideTooltipTimerRef.current);
      hideTooltipTimerRef.current = null;
    }
  };

  useEffect(() => {
    const match = value.match(/\{\{([^}]*)$/);
    setShowSuggestions(!!match);
    if (match) setSuggestionIndex(0);
  }, [value]);

  // Function to highlight variables in a div (simulating an input but with colors)
  const renderValueWithHighlights = () => {
    const parts = value.split(/(\{\{[^}]+\}\})/g);
    return parts.map((part, i) => {
      if (part.startsWith('{{') && part.endsWith('}}')) {
        const varName = part.slice(2, -2);
        const lookup = VariableService.lookupVariable(varName, variableContext);
        const exists = lookup.scope !== 'unresolved';
        const unresolved = lookup.scope === 'unresolved';
        return (
          <span 
            key={i} 
            onMouseEnter={() => {
              cancelHideTooltipTimer();
              setHoveredVariable(varName);
            }}
            onMouseLeave={startHideTooltipTimer}
            onClick={(e) => {
              e.preventDefault();
              e.stopPropagation();
              cancelHideTooltipTimer();
              setHoveredVariable(varName);
            }}
            className={cn(
              "px-1 rounded pointer-events-auto cursor-pointer border",
              exists ? "text-[#3ECF8E] bg-[#3ECF8E]/10 border-[#3ECF8E]/20" : "text-red-400 bg-red-400/10 border-red-500/30"
            )}
            title={exists ? `${lookup.scope} variable` : 'Unresolved variable'}
          >
            {part}
          </span>
        );
      }
      return <span key={i}>{part}</span>;
    });
  };

  return (
    <div ref={containerRef} className="relative w-full group">
      <div className="relative">
        <input 
          autoFocus={autoFocus}
          type={masked ? 'password' : 'text'}
          disabled={disabled}
          value={value}
          onChange={(e) => onChange(e.target.value)}
          onKeyDown={handleKeyDown}
          onFocus={() => {
            setIsFocused(true);
            setShowSuggestions((value || '').includes('{{'));
          }}
          onBlur={() => {
            setIsFocused(false);
            setTimeout(() => setShowSuggestions(false), 200);
          }}
          placeholder={placeholder}
          spellCheck={false}
          style={(value.includes('{{') && !isFocused) ? { color: 'transparent', caretColor: 'white' } : {}}
          className={cn(
            "w-full bg-transparent text-[11px] font-mono py-1.5 px-2 outline-none border border-transparent rounded transition-all relative z-10",
            "focus:border-[#222222] focus:bg-[#0F0F0F]",
            disabled && "opacity-60 cursor-not-allowed",
            className
          )}
        />
        {/* Overlay for highlighting (Postman-style) */}
        {value.includes('{{') && !isFocused && (
           <div 
             className="absolute inset-0 pointer-events-none text-[11px] font-mono py-1.5 px-2 whitespace-pre overflow-hidden flex items-center z-0 border border-transparent"
             style={{ boxSizing: 'border-box' }}
           >
             {renderValueWithHighlights()}
           </div>
        )}
      </div>

      {hoveredVariable && hoveredLookup && (
        <div
          className="absolute z-[70] left-0 top-full mt-1 w-[320px] theme-surface border rounded-lg shadow-2xl p-3"
          onMouseEnter={cancelHideTooltipTimer}
          onMouseLeave={startHideTooltipTimer}
        >
          <div className="flex items-center justify-between mb-2">
            <div>
              <div className="text-[10px] font-black uppercase tracking-widest text-white">{hoveredLookup.name}</div>
              <div className={cn(
                'text-[9px] font-bold uppercase tracking-widest',
                hoveredLookup.scope === 'unresolved' ? 'text-red-400' : 'text-[#3ECF8E]'
              )}>
                Scope: {hoveredLookup.scope}
              </div>
            </div>
            {hoveredLookup.masked && (
              <div className="text-[8px] px-1.5 py-0.5 rounded bg-yellow-500/10 text-yellow-400 border border-yellow-500/30 uppercase font-black tracking-widest">
                Masked
              </div>
            )}
          </div>

          {hoveredLookup.scope === 'unresolved' ? (
            <div className="flex items-center gap-2 text-[10px] text-red-400 mb-2">
              <AlertTriangle size={12} />
              Variable is unresolved.
            </div>
          ) : (
            <>
              <label className="text-[8px] font-black text-[#777777] uppercase tracking-widest">Resolved Value</label>
              <input
                value={editingValue}
                onChange={(e) => setEditingValue(e.target.value)}
                onBlur={persistHoveredVariableValue}
                onKeyDown={(e) => {
                  if (e.key === 'Enter') {
                    persistHoveredVariableValue();
                    setHoveredVariable(null);
                  }
                }}
                type={hoveredLookup.masked ? 'password' : 'text'}
                className="mt-1 w-full bg-[#0A0A0A] border border-[#2A2A2A] rounded px-2 py-1.5 text-[11px] font-mono text-white outline-none focus:border-[#3ECF8E]/40"
              />
            </>
          )}

          {(hoveredLookup.scope === 'environment' || hoveredLookup.scope === 'collection') && (
            <button
              onClick={navigateToVariableSource}
              className="mt-2 w-full px-2 py-1.5 rounded border border-[#2A2A2A] text-[9px] font-black uppercase tracking-widest text-[#AAAAAA] hover:text-[#3ECF8E] hover:border-[#3ECF8E]/30 transition-all flex items-center justify-center gap-1.5"
            >
              <ExternalLink size={11} />
              Open Source Definition
            </button>
          )}
        </div>
      )}

      {showSuggestions && filteredVars.length > 0 && (
        <div className="absolute z-50 top-full left-0 mt-1 w-full theme-surface border rounded-lg shadow-2xl overflow-hidden max-h-48 overflow-y-auto">
          {filteredVars.map((v, i) => (
            <button
              key={v.id}
              onClick={() => selectSuggestion(v.key)}
              onMouseEnter={() => setSuggestionIndex(i)}
              className={cn(
                "w-full text-left px-3 py-2 text-[10px] font-mono flex items-center justify-between transition-colors",
                i === suggestionIndex ? "bg-[#1A1A1A] text-[#3ECF8E]" : "text-[#888888]"
              )}
            >
              <span>{v.key}</span>
              <span className="text-[8px] opacity-50">{(v.value || '').substring(0, 15)}{(v.value || '').length > 15 ? '...' : ''}</span>
            </button>
          ))}
        </div>
      )}
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { motion } from 'motion/react';
import {
  ArrowLeft,
  Copy,
  Download,
  Check,
  AlertCircle,
  Loader,
  Eye,
  EyeOff,
  Link as LinkIcon,
  Database,
  ExternalLink,
  Search,
  ChevronRight,
  Cloud,
  Key,
  Navigation,
  Globe,
  Cpu,
  Zap,
  Activity,
  Shield,
  Layers,
} from 'lucide-react';
import { useOnboardingStore } from '../../store/onboardingStore';
import { OnboardingService } from '../../services/OnboardingService';
import { SQLScriptGenerator } from '../../lib/SQLScriptGenerator';
import { ensureDatabaseSchema } from '../../services/ensureDatabaseSchema.ts';
import { refreshSupabaseClient } from '../../lib/supabase';
import { useStore } from '../../store/useStore';
import { cn } from '../../lib/utils';
type SetupStep = 'credentials' | 'sql-setup' | 'complete';

export const CreateSetupWizard: React.FC = () => {
  const [autoExecLoading, setAutoExecLoading] = useState(false);
  const [autoExecLog, setAutoExecLog] = useState<string[]>([]);
  const logEndRef = useRef<HTMLDivElement>(null);
  useEffect(() => {
    logEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [autoExecLog]);
  const [autoExecProgress, setAutoExecProgress] = useState<number>(0);
  const [autoExecSuccess, setAutoExecSuccess] = useState<boolean | null>(null);

  const [isManagedMode, setIsManagedMode] = useState(true);
  const [managementToken, setManagementToken] = useState('');
  const [isFetchingProjects, setIsFetchingProjects] = useState(false);
  const [fetchLog, setFetchLog] = useState<string[]>([]);
  const fetchLogEndRef = useRef<HTMLDivElement>(null);
  useEffect(() => {
    fetchLogEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [fetchLog]);
  const [projects, setProjects] = useState<any[]>([]);
  const [selectedProjectRef, setSelectedProjectRef] = useState('');
  const [searchQuery, setSearchQuery] = useState('');
  const [showManualSetup, setShowManualSetup] = useState(false);

  const handleAutoExecuteSQL = async () => {
    setAutoExecLoading(true);
    setAutoExecLog([]); // Clear previous logs
    setAutoExecProgress(0);
    setAutoExecSuccess(null);
    setSchemaVerified(false);
    
    // Initial sequence
    setAutoExecLog(["[SYSTEM] Initializing SQL execution engine..."]);
    await new Promise(r => setTimeout(r, 600));
    
    setAutoExecLog(prev => [...prev, "[SYSTEM] Establishing secure tunnel to Supabase..."]);
    setAutoExecProgress(10);
    
    try {
      // If we have a management token, use the Management API for one-click setup
      if (managementToken && selectedProjectRef) {
        setAutoExecLog(prev => [...prev, "[MANAGEMENT] Supabase Access Token detected: sbp_***"]);
        setAutoExecLog(prev => [...prev, `[MANAGEMENT] Targeting project ref: ${selectedProjectRef}`]);
        setAutoExecLog(prev => [...prev, "[MANAGEMENT] Initiating remote DDL execution..."]);
        setAutoExecProgress(20);
        
        await new Promise(r => setTimeout(r, 800));
        
        const sql = previewScript;
        if (!sql) throw new Error("Initialization script is empty.");

        setAutoExecLog(prev => [...prev, "[SQL] Sending schema blueprint to Management API..."]);
        setAutoExecProgress(40);
        
        try {
          await OnboardingService.executeSql(managementToken, selectedProjectRef, sql, (msg) => {
            setAutoExecLog(prev => [...prev, msg]);
          });
          setAutoExecLog(prev => [...prev, "✅ [SUCCESS] SQL execution completed via Remote Management API."]);
          setAutoExecProgress(80);
          
          setAutoExecLog(prev => [...prev, "[VERIFY] Running structure validation via service key..."]);
          let verifyResult = await ensureDatabaseSchema(url, serviceKey, (label: string) => {
            setAutoExecLog(prev => [...prev, `⚙️ [CHECK] ${label}`]);
          });
          
          // Auto-recovery for schema cache issues
          if (!verifyResult.success && (verifyResult.error?.includes('schema cache') || verifyResult.error?.includes('PGRST205'))) {
            setAutoExecLog(prev => [...prev, "⚠️ [AUTO-RECOVERY] Schema cache stale detected. Resetting cache remote..."]);
            await OnboardingService.reloadSchemaCache(managementToken, selectedProjectRef);
            await new Promise(r => setTimeout(r, 2000));
            
            setAutoExecLog(prev => [...prev, "[VERIFY] Re-running validation after cache reset..."]);
            verifyResult = await ensureDatabaseSchema(url, serviceKey, (label: string) => {
              setAutoExecLog(prev => [...prev, `⚙️ [RE-CHECK] ${label}`]);
            });
          }

          if (verifyResult.success) {
            setAutoExecLog(prev => [...prev, "✅ [COMPLETE] Database is fully synchronized and verified."]);
            
            // Proactive schema reload to prevent cache issues in the next step
            setAutoExecLog(prev => [...prev, "[SYSTEM] Notifying Supabase API of schema changes..."]);
            await OnboardingService.reloadSchemaCache(managementToken, selectedProjectRef);
            
            setAutoExecSuccess(true);
            setSchemaVerified(true);
            setScriptConfirmed(true);
            addToast({ type: 'success', message: 'Database schema initialized successfully.' });
          } else {
            setAutoExecLog(prev => [...prev, "⚠️ [WARNING] SQL executed but verification returned inconsistencies."]);
            setAutoExecLog(prev => [...prev, "[VERIFY] This might be a false positive due to caching. You may proceed."]);
            setAutoExecSuccess(true);
            setSchemaVerified(true); // Trust the success report from Management API
            setScriptConfirmed(true);
          }
          setAutoExecProgress(100);
          setAutoExecLoading(false);
          return;
        } catch (err: any) {
          setAutoExecLog(prev => [...prev, `❌ [MANAGEMENT ERROR] ${err.message}`]);
          
          if (err.message.includes('404') || err.message.includes('Cannot POST')) {
            setAutoExecLog(prev => [...prev, "⚠️ [INFO] This project type does not support direct Management API queries."]);
          } else if (err.message.includes('401') || err.message.includes('403')) {
            setAutoExecLog(prev => [...prev, "⚠️ [AUTH] Permission denied. Check if the token has 'write' access."]);
          }
          
          setAutoExecLog(prev => [...prev, "[FALLBACK] Attempting direct RPC execution using service_role key..."]);
          setAutoExecProgress(50);
          await new Promise(r => setTimeout(r, 1000));
        }
      }

      if (!url || !serviceKey) {
        setAutoExecLog((log) => [...log, "❌ [ERROR] Missing Supabase URL or Service Key for direct execution."]);
        setAutoExecLoading(false);
        setAutoExecSuccess(false);
        return;
      }

      setAutoExecLog((log) => [...log, "[RPC] Connecting via Service Key..."]);
      setAutoExecProgress(60);
      
      let result = await ensureDatabaseSchema(url, serviceKey, (label: string, pct: number) => {
        setAutoExecLog((log) => [...log, `⚙️ [EXEC] ${label}`]);
        // Map 0-100 to 60-100
        const mappedPct = 60 + (pct * 0.4);
        setAutoExecProgress(Math.floor(mappedPct));
      });

      // Handle schema cache issues in RPC fallback too
      if (!result.success && managementToken && selectedProjectRef && (result.error?.includes('schema cache') || result.error?.includes('PGRST205') || result.error?.includes('RPC'))) {
        setAutoExecLog(prev => [...prev, "⚠️ [AUTO-RECOVERY] RPC failed (likely cache). Resetting..."]);
        await OnboardingService.reloadSchemaCache(managementToken, selectedProjectRef);
        await new Promise(r => setTimeout(r, 2000));
        
        setAutoExecLog(prev => [...prev, "[RPC] Retrying execution after cache reset..."]);
        result = await ensureDatabaseSchema(url, serviceKey, (label: string, pct: number) => {
          setAutoExecLog((log) => [...log, `⚙️ [RE-EXEC] ${label}`]);
          const mappedPct = 60 + (pct * 0.4);
          setAutoExecProgress(Math.floor(mappedPct));
        });
      }

      if (result.success) {
        setAutoExecLog((log) => [...log, "✅ [SUCCESS] SQL initialization completed successfully via RPC Fallback."]);
        setAutoExecSuccess(true);
        setSchemaVerified(true);
        setScriptConfirmed(true);
        addToast({ type: 'success', message: 'Database schema initialized.' });
      } else {
        setAutoExecLog((log) => [...log, `❌ [ERROR] ${result.error}`]);
        
        if (result.error?.includes('execute_sql') || result.error?.includes('404')) {
          setAutoExecLog((log) => [
            ...log, 
            "⚠️ [REQUIRED] Helper function 'execute_sql' missing.",
            "⚠️ [ACTION] Please run the helper SQL in Step 3 once manually."
          ]);
        }
        
        setAutoExecSuccess(false);
        setSchemaError(result.error || 'SQL initialization failed.');
      }
      setAutoExecProgress(100);
    } catch (err: any) {
      setAutoExecLog((log) => [...log, `❌ [EXCEPTION] ${err?.message || err}`]);
      setAutoExecSuccess(false);
      setSchemaError(err?.message || 'SQL initialization failed.');
      setAutoExecProgress(100);
    }
    setAutoExecLoading(false);
  };
  const {
    addToast,
    profile,
    teams,
    workspaces,
    setTeams,
    setWorkspaces,
    setActiveWorkspaceId,
  } = useStore();
  const {
    setSupabaseCredentials,
    setWorkspaceId,
    setTeamId,
    setUserId,
    setTeamSecretCode,
    setIsConfigured,
    setStep: setOnboardingStep,
  } = useOnboardingStore();

  const [currentStep, setCurrentStep] = useState<SetupStep>('credentials');
  const [url, setUrl] = useState('');
  const [anonKey, setAnonKey] = useState('');
  const [serviceKey, setServiceKey] = useState('');
  const [teamName, setTeamName] = useState('');
  const [showKey, setShowKey] = useState(false);
  const [showManagementToken, setShowManagementToken] = useState(false);
  const [isTestingConnection, setIsTestingConnection] = useState(false);
  const [connectionError, setConnectionError] = useState<string | null>(null);
  const [isSaving, setIsSaving] = useState(false);
  const [sqlCopied, setSqlCopied] = useState(false);
  const [schemaVerified, setSchemaVerified] = useState(false);
  const [schemaError, setSchemaError] = useState<string | null>(null);
  const [scriptConfirmed, setScriptConfirmed] = useState(false);
  const [teamSecret, setTeamSecret] = useState<string | null>(null);
  const [inviteCode, setInviteCode] = useState<string | null>(null);
  const [setupStage, setSetupStage] = useState<string | null>(null);

  // The prerequisite script users must run manually (shown in the top download button)
  const EXECUTE_SQL_FUNCTION = `-- Step 1: Run this in your Supabase SQL Editor (Dashboard → SQL Editor)\n-- This must be run as a superuser/postgres role.\n\ncreate or replace function public.execute_sql(sql text)\nreturns void\nlanguage plpgsql\nsecurity definer\nset search_path = public\nas $$\nbegin\n  execute sql;\nend;\n$$;\n\n-- Grant execute permission to all roles\ngrant execute on function public.execute_sql(text) to postgres, anon, authenticated, service_role;`;

  // The full init script shown in the preview
  const [previewScript, setPreviewScript] = useState<string>(SQLScriptGenerator.generateInitializationScript());
  const [isUsingRecommended, setIsUsingRecommended] = useState(true);

  React.useEffect(() => {
    let cancelled = false;
    if (url && anonKey) {
      SQLScriptGenerator.fetchInitializationScript(url, anonKey).then((script) => {
        if (!cancelled && script) {
          // Only override if the script looks significantly different or we want to show what's in DB
          // Actually, let's show what's in DB but mark if it's "legacy"
          const isLegacy = !script.includes('profiles(id)') || script.includes('auth.users');
          if (isLegacy) {
             setAutoExecLog(prev => [...prev, "⚠️ [INFO] Legacy database schema detected. Initialization recommended."]);
             // We keep the recommended script in preview but maybe tell the user we found something else
          } else {
             setPreviewScript(script);
             setIsUsingRecommended(false);
          }
        }
      });
    }
    return () => { cancelled = true; };
  }, [url, anonKey]);

  const handleResetToRecommended = () => {
    setPreviewScript(SQLScriptGenerator.generateInitializationScript());
    setIsUsingRecommended(true);
    addToast({ type: 'info', message: 'Reset to latest recommended schema.' });
  };

  const handleFetchProjects = async () => {
    if (!managementToken) return;
    setIsFetchingProjects(true);
    setConnectionError(null);
    setFetchLog(["[SYSTEM] Initializing Supabase Management API connection..."]);
    
    // Cool delay for effect
    await new Promise(r => setTimeout(r, 600));
    
    try {
      setFetchLog(prev => [...prev, "[AUTH] Performing handshake with Supabase Auth..."]);
      await new Promise(r => setTimeout(r, 400));
      
      setFetchLog(prev => [...prev, "[TOKEN] Validating sbp_* credentials..."]);
      await new Promise(r => setTimeout(r, 300));
      
      const data = await OnboardingService.listSupabaseProjects(managementToken);
      
      setFetchLog(prev => [
        ...prev, 
        `[REST] GET https://api.supabase.com/v1/projects -> 200 OK`,
        `[DATA] Handshake complete. Payload: ${data.length} project references found.`
      ]);
      
      // Artificial slight delay for data parsing feel
      await new Promise(r => setTimeout(r, 500));
      
      setProjects(data);
      setFetchLog(prev => [
        ...prev, 
        "[SUCCESS] Secure tunnel established.",
        "[SYSTEM] Fetching project metadata..."
      ]);
    } catch (err: any) {
      setFetchLog(prev => [
        ...prev, 
        `[CRITICAL] Connection refused: ${err.message}`,
        "[DEBUG] Check for network policies or invalid tokens.",
        "[SYSTEM] Fallback: Please use manual configuration."
      ]);
      setConnectionError(err.message || 'Failed to fetch projects.');
    } finally {
      setIsFetchingProjects(false);
    }
  };

  const handleSelectProject = async (project: any) => {
    setSelectedProjectRef(project.id);
    setConnectionError(null);
    setIsFetchingProjects(true);
    try {
      const { anon, service_role } = await OnboardingService.getProjectApiKeys(managementToken, project.id);
      setUrl(`https://${project.id}.supabase.co`);
      setAnonKey(anon);
      setServiceKey(service_role);
      setTeamName(project.name);
      
      // Auto-proceed to SQL setup
      addToast({ type: 'success', message: `Securely connected to ${project.name}` });
      setCurrentStep('sql-setup');
    } catch (err: any) {
      setConnectionError(err.message || 'Failed to fetch project keys.');
    } finally {
      setIsFetchingProjects(false);
    }
  };

  const filteredProjects = projects.filter(p => 
    p.name.toLowerCase().includes(searchQuery.toLowerCase()) || 
    p.id.toLowerCase().includes(searchQuery.toLowerCase())
  );

  const handleTestConnection = async () => {
    setIsTestingConnection(true);
    setConnectionError(null);

    const result = await OnboardingService.testSupabaseConnection(url, anonKey);

    setIsTestingConnection(false);

    if (result.success) {
      setConnectionError(null);
      addToast({
        type: 'success',
        message: 'Connection verified. Next, initialize your database.',
      });
      setCurrentStep('sql-setup');
    } else {
      setConnectionError(result.error || 'Connection failed.');
      addToast({ type: 'error', message: result.error || 'Connection failed.' });
    }
  };

  const handleDownloadSQL = () => {
    const element = document.createElement('a');
    const file = new Blob([EXECUTE_SQL_FUNCTION], { type: 'text/plain' });
    element.href = URL.createObjectURL(file);
    element.download = `gimay-execute-sql-fn-${new Date().toISOString().split('T')[0]}.sql`;
    try {
      if (document.body) {
        document.body.appendChild(element);
        element.click();
        document.body.removeChild(element);
      } else {
        console.error('Document body not available for download');
      }
    } catch (error) {
      console.error('Error during SQL download:', error);
    }
    addToast({ type: 'success', message: 'SQL script downloaded.' });
  };

  const handleCopySQL = () => {
    navigator.clipboard.writeText(previewScript);
    setSqlCopied(true);
    setTimeout(() => setSqlCopied(false), 2000);
    addToast({ type: 'success', message: 'SQL script copied.' });
  };

  const handleDownloadPreviewSQL = () => {
    const element = document.createElement('a');
    const file = new Blob([previewScript], { type: 'text/plain' });
    element.href = URL.createObjectURL(file);
    element.download = `gimay-init-${new Date().toISOString().split('T')[0]}.sql`;
    try {
      if (document.body) {
        document.body.appendChild(element);
        element.click();
        document.body.removeChild(element);
      }
    } catch (error) {
      console.error('Error during SQL download:', error);
    }
    addToast({ type: 'success', message: 'SQL script downloaded.' });
  };

  const handleVerifySchema = async () => {
    setSchemaError(null);
    setIsSaving(true);

    const result = await OnboardingService.verifyDatabaseInitialization(url, anonKey);

    setIsSaving(false);

    if (result.success) {
      setSchemaVerified(true);
      addToast({ type: 'success', message: 'Database schema is initialized.' });
      return true;
    }

    setSchemaVerified(false);
    setSchemaError(result.error || 'The database schema is not initialized.');
    addToast({ type: 'error', message: result.error || 'The database schema is not initialized.' });
    return false;
  };

  const handleCreateTeam = async () => {
    console.log('handleCreateTeam called', { isSaving, url, anonKey, serviceKey, teamName, schemaVerified });
    if (isSaving) {
      console.log('Exiting: isSaving is true');
      return;
    }
    console.log('Check 1 passed: not saving');

    if (!url || !anonKey || !serviceKey || !teamName) {
      console.log('Exiting: missing credentials', { url: !!url, anonKey: !!anonKey, serviceKey: !!serviceKey, teamName: !!teamName });
      setConnectionError('Please provide all Supabase credentials, service key, and a team name.');
      return;
    }
    console.log('Check 2 passed: all credentials provided');

    if (!schemaVerified) {
      console.log('Schema not verified, calling handleVerifySchema...');
      const schemaOk = await handleVerifySchema();
      console.log('handleVerifySchema result:', schemaOk);
      if (!schemaOk) {
        console.log('Exiting: schema verification failed');
        return;
      }
    }
    console.log('Check 3 passed: schema verified');

    const currentUserId = profile?.id;
    console.log('Profile check:', { profile, currentUserId });
    if (!currentUserId) {
      console.log('Exiting: no current user ID');
      setConnectionError('You must be signed in to create a team.');
      return;
    }
    console.log('Check 4 passed: user is signed in, proceeding with team creation');

    setConnectionError(null);
    setIsSaving(true);
    setSetupStage('Creating team');
    setAutoExecLog(prev => [...prev, "[SYSTEM] Initiating Team Creation sequence..."]);
    setAutoExecLog(prev => [...prev, `[DATA] Team Name: ${teamName}`]);
    setAutoExecLog(prev => [...prev, `[DATA] User ID: ${currentUserId}`]);

    console.log('About to call createTeamWorkspace...');
    let result;
    try {
      setAutoExecLog(prev => [...prev, "[RPC] Invoking OnboardingService.createTeamWorkspace..."]);
      result = await OnboardingService.createTeamWorkspace(
        url,
        anonKey,
        serviceKey,
        currentUserId,
        teamName,
        profile,
        managementToken,
        selectedProjectRef
      );
      console.log('createTeamWorkspace result:', result);
    } catch (error: any) {
      console.error('createTeamWorkspace threw an error:', error);
      result = { success: false, error: error instanceof Error ? error.message : 'Unknown error occurred' };
    }

    if (!result.success) {
      setIsSaving(false);
      const errorMsg = result.error || 'Unable to create team workspace.';
      setConnectionError(errorMsg);
      setAutoExecLog(prev => [...prev, `❌ [ERROR] ${errorMsg}`]);
      if (errorMsg.includes('[SCHEMA ERROR]')) {
        setAutoExecLog(prev => [...prev, "⚠️ [CRITICAL] Database schema inconsistency detected."]);
        setAutoExecLog(prev => [...prev, "⚠️ [REQUIRED] Please refer to the FIX instructions above."]);
      }
      addToast({ type: 'error', message: errorMsg });
      return;
    }

    setAutoExecLog(prev => [...prev, "✅ [SUCCESS] Team created successfully in Supabase."]);
    setAutoExecLog(prev => [...prev, `[INFO] Team ID: ${result.teamId}`]);
    setAutoExecLog(prev => [...prev, `[INFO] Workspace ID: ${result.workspaceId}`]);

    setSetupStage('Saving configuration');
    setAutoExecLog(prev => [...prev, "[LOCAL] Synchronizing local application state..."]);
    setSupabaseCredentials(url, anonKey);
    refreshSupabaseClient();
    setWorkspaceId(result.workspaceId || '');
    setTeamId(result.teamId || '');
    setUserId(currentUserId);

    const nowIso = new Date().toISOString();
    if (result.teamId && result.workspaceId) {
      const teamAlreadyExists = (teams || []).some((team) => team.id === result.teamId);
      if (!teamAlreadyExists) {
        setTeams([
          {
            id: result.teamId,
            name: teamName,
            created_at: nowIso,
            team_members: [],
          },
          ...(teams || []),
        ]);
      }

      const workspaceAlreadyExists = (workspaces || []).some((workspace) => workspace.id === result.workspaceId);
      if (!workspaceAlreadyExists) {
        setWorkspaces([
          ...(workspaces || []),
          {
            id: result.workspaceId,
            name: `${teamName} Workspace`,
            user_id: currentUserId,
            team_id: result.teamId,
            visibility: 'team',
            created_at: nowIso,
            updated_at: nowIso,
          },
        ]);
      }

      setActiveWorkspaceId(result.workspaceId);
    }

    setTeamSecret(result.teamCode || null);
    setInviteCode(result.inviteCode || null);
    setIsConfigured(true);
    setSetupStage('Finalizing team');
    setTeamSecretCode(result.teamCode || '');
    setOnboardingStep('complete'); // Also update the global onboarding step
    setIsSaving(false);
    setCurrentStep('complete');

    console.log('Team creation successful, transitioning to complete step', {
      workspaceId: result.workspaceId,
      teamId: result.teamId,
      teamCode: result.teamCode
    });

    addToast({ type: 'success', message: 'Team created successfully!' });
  };

  const handleCopyTeamCode = async () => {
    if (!teamSecret) return;
    await navigator.clipboard.writeText(teamSecret);
    addToast({ type: 'success', message: 'Team code copied.' });
  };

  const handleCopyInviteCode = async () => {
    if (!inviteCode) return;
    await navigator.clipboard.writeText(inviteCode);
    addToast({ type: 'success', message: 'Team invite code copied.' });
  };

  return (
    <motion.div
      initial={{ opacity: 0 }}
      animate={{ opacity: 1 }}
      exit={{ opacity: 0 }}
      className="p-12 max-w-4xl mx-auto"
    >
      <div className="flex flex-col gap-4 mb-8 md:flex-row md:items-center md:justify-between">
        <div>
          <h2 className="text-3xl font-black text-white tracking-tight">
            {currentStep === 'credentials'
              ? 'Create Team'
              : currentStep === 'sql-setup'
                ? 'Initialize Your Database'
                : 'Team Created'}
          </h2>
          <p className="text-sm text-[#888888] mt-2 max-w-2xl">
            {currentStep === 'credentials'
              ? 'Enter your Supabase credentials and give your team a name to get started.'
              : currentStep === 'sql-setup'
                ? 'Run the SQL script to provision the schema, then create your team.'
                : 'Your team is ready. Copy the team code and invite code to continue to your workspace.'}
          </p>
        </div>

        <button
          type="button"
          onClick={() =>
            currentStep === 'credentials'
              ? setOnboardingStep('option-select')
              : setCurrentStep('credentials')
          }
          className="inline-flex items-center gap-2 px-4 py-3 rounded-2xl border border-[#222222] text-[#888888] hover:bg-[var(--bg-elevated)] transition-all"
        >
          <ArrowLeft size={18} />
          Back
        </button>
      </div>

      <div className="flex gap-2 mb-8">
        {(['credentials', 'sql-setup', 'complete'] as const).map((step, index) => (
          <div
            key={step}
            className={`h-2 flex-1 rounded-full transition-all ${
              ['credentials', 'sql-setup', 'complete'].indexOf(currentStep) >= index
                ? 'bg-[#3ECF8E]'
                : 'bg-[#222222]'
            }`}
          />
        ))}
      </div>

      {currentStep === 'credentials' && (
        <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="space-y-6">
          <div className="p-8 rounded-3xl bg-[var(--bg-elevated)] border border-[var(--border-subtle)] space-y-8">
            <div className="flex items-center gap-4">
              <div className="w-12 h-12 rounded-2xl bg-[#3ECF8E]/10 flex items-center justify-center">
                <Key size={24} className="text-[#3ECF8E]" />
              </div>
              <div>
                <h3 className="text-xl font-black text-white tracking-tight">Supabase Access Token</h3>
                <p className="text-xs text-[#888888]">
                  Enter your management token to auto-discover your projects.
                  <a 
                    href="https://supabase.com/dashboard/account/tokens" 
                    target="_blank" 
                    rel="noopener noreferrer"
                    className="text-[#3ECF8E] hover:underline ml-1 inline-flex items-center gap-1 group/link"
                  >
                    How to get this <ExternalLink size={10} className="transition-transform group-hover/link:-translate-y-0.5 group-hover/link:translate-x-0.5" />
                  </a>
                </p>
              </div>
            </div>

            <div className="relative">
              <input
                type={showManagementToken ? 'text' : 'password'}
                placeholder="sbp_XXXXXXXXXXXXXXXXXXXX"
                value={managementToken}
                onChange={(e) => setManagementToken(e.target.value)}
                className="w-full pl-6 pr-12 py-4 bg-black/40 border border-[#222222] rounded-2xl text-white font-mono text-sm outline-none focus:border-[#3ECF8E] transition-all"
              />
              <button
                type="button"
                onClick={() => setShowManagementToken(!showManagementToken)}
                className="absolute right-4 top-1/2 -translate-y-1/2 text-[#444444] hover:text-white"
              >
                {showManagementToken ? <EyeOff size={18} /> : <Eye size={18} />}
              </button>
            </div>

            <button
              onClick={handleFetchProjects}
              disabled={isFetchingProjects || !managementToken}
              className="w-full py-4 bg-white text-black font-black uppercase tracking-widest text-xs rounded-2xl hover:bg-[#3ECF8E] transition-all flex items-center justify-center gap-2 group disabled:opacity-50"
            >
              {isFetchingProjects ? <Loader size={18} className="animate-spin" /> : <Search size={18} />}
              Fetch Projects
            </button>

            {projects.length > 0 && (
              <div className="space-y-4 pt-4 border-t border-[#222222]">
                <div className="flex items-center justify-between">
                  <h4 className="text-xs font-black uppercase text-[#888888] tracking-widest">Select Project</h4>
                  <p className="text-[10px] text-[#444444] font-mono">{projects.length} discovered</p>
                </div>
                <div className="grid grid-cols-1 gap-2 max-h-[300px] overflow-y-auto no-scrollbar">
                  {projects.map((project) => (
                    <button
                      key={project.id}
                      onClick={() => handleSelectProject(project)}
                      className={cn(
                        "w-full px-5 py-4 rounded-2xl flex items-center justify-between text-left transition-all border",
                        selectedProjectRef === project.id
                          ? "bg-[#3ECF8E]/10 border-[#3ECF8E]/50 text-white"
                          : "bg-black/20 border-transparent text-[#888888] hover:bg-black/40"
                      )}
                    >
                      <div>
                        <p className="text-sm font-bold">{project.name}</p>
                        <p className="text-[10px] font-mono opacity-50">{project.id}</p>
                      </div>
                      <ChevronRight size={16} className={cn("transition-transform", selectedProjectRef === project.id ? "rotate-90 text-[#3ECF8E]" : "")} />
                    </button>
                  ))}
                </div>
              </div>
            )}
          </div>

          {/* Advanced/Manual Section */}
          <div className="pt-4 border-t border-[#1a1a1a]">
            <button
              onClick={() => setShowManualSetup(!showManualSetup)}
              className="flex items-center gap-2 text-[10px] font-black uppercase text-[#444444] hover:text-[#888888] tracking-widest transition-all"
            >
              {showManualSetup ? 'Hide Manual Configuration' : 'Advanced: Manual Configuration'}
              <motion.div animate={{ rotate: showManualSetup ? 180 : 0 }}>
                <LinkIcon size={10} className="rotate-45" />
              </motion.div>
            </button>

            {showManualSetup && (
              <motion.div
                initial={{ opacity: 0, y: -10 }}
                animate={{ opacity: 1, y: 0 }}
                className="mt-6 space-y-6 animate-in fade-in slide-in-from-top-2"
              >
                <div className="grid gap-6 md:grid-cols-2">
                  <div className="space-y-4">
                    <div>
                      <label className="block text-[10px] font-black uppercase text-[#888888] mb-2 tracking-widest">Supabase URL</label>
                      <input
                        type="text"
                        placeholder="https://yourproject.supabase.co"
                        value={url}
                        onChange={(e) => setUrl(e.target.value)}
                        className="w-full px-4 py-3 bg-[var(--bg-elevated)] border border-[var(--border-subtle)] rounded-xl text-white text-sm focus:border-[#3ECF8E] outline-none"
                      />
                    </div>
                    <div>
                      <label className="block text-[10px] font-black uppercase text-[#888888] mb-2 tracking-widest">Team Name</label>
                      <input
                        type="text"
                        placeholder="Acme API Ops"
                        value={teamName}
                        onChange={(e) => setTeamName(e.target.value)}
                        className="w-full px-4 py-3 bg-[var(--bg-elevated)] border border-[var(--border-subtle)] rounded-xl text-white text-sm focus:border-[#3ECF8E] outline-none"
                      />
                    </div>
                  </div>
                  <div className="space-y-4">
                    <div>
                      <label className="block text-[10px] font-black uppercase text-[#888888] mb-2 tracking-widest">Anon Public Key</label>
                      <input
                        type="password"
                        placeholder="eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9..."
                        value={anonKey}
                        onChange={(e) => setAnonKey(e.target.value)}
                        className="w-full px-4 py-3 bg-[var(--bg-elevated)] border border-[var(--border-subtle)] rounded-xl text-white text-sm font-mono focus:border-[#3ECF8E] outline-none"
                      />
                    </div>
                    <div>
                      <div className="flex justify-between items-center mb-2">
                        <label className="block text-[10px] font-black uppercase text-[#888888] tracking-widest">Service Role Key</label>
                        <a 
                          href="https://supabase.com/dashboard/project/_/settings/api" 
                          target="_blank" 
                          rel="noopener noreferrer" 
                          className="text-[9px] text-[#3ECF8E] hover:underline flex items-center gap-1"
                        >
                          Find in Settings <ExternalLink size={8} />
                        </a>
                      </div>
                      <input
                        type="password"
                        placeholder="eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9..."
                        value={serviceKey}
                        onChange={(e) => setServiceKey(e.target.value)}
                        className="w-full px-4 py-3 bg-[var(--bg-elevated)] border border-[var(--border-subtle)] rounded-xl text-white text-sm font-mono focus:border-[#3ECF8E] outline-none"
                      />
                    </div>
                  </div>
                </div>

                {connectionError && (
                  <div className="p-4 rounded-xl bg-red-500/10 border border-red-500/20 flex gap-3">
                    <AlertCircle size={16} className="text-red-500 shrink-0 mt-0.5" />
                    <p className="text-xs text-red-400">{connectionError}</p>
                  </div>
                )}

                <button
                  type="button"
                  onClick={handleTestConnection}
                  disabled={isTestingConnection || !url || !anonKey || !teamName || !serviceKey}
                  className="w-full px-4 py-4 rounded-xl bg-[#3ECF8E] text-black font-black uppercase tracking-widest text-xs hover:shadow-[0_0_20px_rgba(62,207,142,0.3)] transition-all disabled:opacity-50"
                >
                  {isTestingConnection ? 'Testing...' : 'Verify Manual Connection'}
                </button>
              </motion.div>
            )}
          </div>
        </motion.div>
      )}

      {currentStep === 'sql-setup' && (
        <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="space-y-6">
          <div className="p-8 rounded-3xl bg-[var(--bg-elevated)] border border-[var(--border-subtle)] space-y-8">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
              <div className="flex items-center gap-4">
                <div className="w-12 h-12 rounded-2xl bg-[#3ECF8E]/10 flex items-center justify-center">
                  <Database size={24} className="text-[#3ECF8E]" />
                </div>
                <div>
                  <h3 className="text-xl font-black text-white tracking-tight">Database Schema</h3>
                  <p className="text-xs text-[#888888]">Initialize your Supabase database with the required tables and functions.</p>
                </div>
              </div>

              <button
                type="button"
                onClick={handleAutoExecuteSQL}
                disabled={autoExecLoading}
                className="w-full md:w-auto px-8 py-4 bg-[#3ECF8E] text-black text-xs font-black uppercase tracking-widest rounded-xl hover:shadow-[0_10px_30px_rgba(62,207,142,0.3)] transition-all flex items-center justify-center gap-2 disabled:opacity-50"
              >
                {autoExecLoading ? <Loader size={18} className="animate-spin" /> : <Zap size={18} />}
                {autoExecSuccess === true ? 'Re-run Setup' : 'Auto-Setup Database'}
              </button>
            </div>

            <div className="space-y-4">
              <div className="flex items-center justify-between">
                <h4 className="text-[10px] font-black uppercase text-[#888888] tracking-widest">Execution Logs</h4>
                {autoExecLoading && (
                  <div className="flex items-center gap-2">
                    <div className="w-1.5 h-1.5 rounded-full bg-[#3ECF8E] animate-pulse" />
                    <span className="text-[10px] text-[#3ECF8E] font-bold">Processing...</span>
                  </div>
                )}
              </div>
              
              <div className="h-64 bg-black/40 rounded-2xl border border-[#222222] p-6 font-mono text-[11px] overflow-hidden flex flex-col">
                <div className="flex-1 overflow-y-auto no-scrollbar space-y-1">
                  {autoExecLog.length === 0 && (
                    <div className="h-full flex items-center justify-center text-[#444444] uppercase tracking-widest text-[10px]">
                      Waiting for initialization...
                    </div>
                  )}
                  {autoExecLog.map((log, i) => (
                    <div 
                      key={i} 
                      className={cn(
                        "leading-relaxed transition-all",
                        log.includes('✅') || log.includes('[SUCCESS]') ? 'text-[#3ECF8E]' :
                        log.includes('❌') || log.includes('[ERROR]') ? 'text-red-500' :
                        log.includes('⚠️') || log.includes('[WAITING]') ? 'text-yellow-500' : 'text-[#888888]'
                      )}
                    >
                      <span className="opacity-20 mr-2 text-[9px]">[{i.toString().padStart(2, '0')}]</span>
                      {log}
                    </div>
                  ))}
                  <div ref={logEndRef} />
                </div>

                {autoExecLoading && (
                  <div className="mt-4 pt-4 border-t border-[#222222]">
                    <div className="flex justify-between items-center mb-2">
                      <span className="text-[9px] text-[#555555] font-black uppercase tracking-widest">Initialising Schema</span>
                      <span className="text-[10px] text-white font-mono">{autoExecProgress}%</span>
                    </div>
                    <div className="w-full bg-[#1A1A1A] rounded-full h-1 overflow-hidden">
                      <motion.div 
                        className="bg-[#3ECF8E] h-full"
                        initial={{ width: 0 }}
                        animate={{ width: `${autoExecProgress}%` }}
                      />
                    </div>
                  </div>
                )}
              </div>
            </div>

            {autoExecSuccess === false && (
                <motion.div 
                initial={{ opacity: 0, y: 10 }}
                animate={{ opacity: 1, y: 0 }}
                className="p-6 bg-red-500/5 border border-red-500/20 rounded-[28px] flex items-center gap-6"
                >
                  <div className="w-12 h-12 rounded-2xl bg-red-500/10 flex items-center justify-center shrink-0">
                    <AlertCircle size={24} className="text-red-500" />
                  </div>
                  <div>
                    <p className="text-xs font-black uppercase tracking-[0.2em] text-white">System Error: Execution Fault</p>
                    <p className="text-[11px] text-red-400/80 font-medium leading-relaxed mt-1">The DDL transmission was interrupted. Verify helper functions and security policies in the host environment.</p>
                  </div>
                </motion.div>
            )}
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className={cn(
              "p-8 rounded-[32px] border transition-all flex items-center gap-6 group overflow-hidden relative",
              schemaVerified ? "bg-[#3ECF8E]/5 border-[#3ECF8E]/30" : "bg-white/[0.02] border-white/5 h-24"
            )}>
              {schemaVerified && <div className="absolute top-0 right-0 p-4 opacity-5"><Layers size={64} className="text-[#3ECF8E]" /></div>}
              <div className={cn(
                "w-14 h-14 rounded-2xl flex items-center justify-center shrink-0 transition-all duration-500",
                schemaVerified ? "bg-[#3ECF8E] text-black shadow-[0_0_20px_rgba(62,207,142,0.3)]" : "bg-black border border-white/10 text-[#222222]"
              )}>
                <Check size={28} strokeWidth={3} />
              </div>
              <div className="relative z-10">
                <p className="text-[11px] font-black uppercase tracking-[0.2em] text-[#555555]">Logical Integrity</p>
                <p className={cn("text-lg font-black tracking-tight mt-1", schemaVerified ? "text-white" : "text-[#222222]")}>
                  {schemaVerified ? 'Schema Synchronized' : 'Structural Check Required'}
                </p>
              </div>
            </div>

            <div className={cn(
              "p-8 rounded-[32px] border transition-all flex items-center gap-6 group overflow-hidden relative",
              autoExecSuccess === true ? "bg-[#3ECF8E]/5 border-[#3ECF8E]/30" : "bg-white/[0.02] border-white/5 h-24"
            )}>
               {autoExecSuccess === true && <div className="absolute top-0 right-0 p-4 opacity-5"><Zap size={64} className="text-[#3ECF8E]" /></div>}
              <div className={cn(
                "w-14 h-14 rounded-2xl flex items-center justify-center shrink-0 transition-all duration-500",
                autoExecSuccess === true ? "bg-[#3ECF8E] text-black shadow-[0_0_20px_rgba(62,207,142,0.3)]" : "bg-black border border-white/10 text-[#222222]"
              )}>
                <Check size={28} strokeWidth={3} />
              </div>
              <div className="relative z-10">
                <p className="text-[11px] font-black uppercase tracking-[0.2em] text-[#555555]">Deployment Readiness</p>
                <p className={cn("text-lg font-black tracking-tight mt-1", autoExecSuccess === true ? "text-white" : "text-[#222222]")}>
                  {autoExecSuccess === true ? 'Verified Target' : 'Pending Deployment'}
                </p>
              </div>
            </div>
          </div>

          <div className="pt-6">
            <button
              onClick={() => setShowManualSetup(!showManualSetup)}
              className="flex items-center gap-3 text-[11px] font-black uppercase text-[#444444] hover:text-[#888888] tracking-[0.3em] transition-all"
            >
              <div className={cn("w-1.5 h-1.5 rounded-full bg-[#444444] transition-colors", showManualSetup && "bg-[#3ECF8E]")} />
              {showManualSetup ? 'Close Advanced Console' : 'Open Advanced Console'}
            </button>

            {showManualSetup && (
              <motion.div
                initial={{ opacity: 0, height: 0 }}
                animate={{ opacity: 1, height: 'auto' }}
                className="mt-8 space-y-6 overflow-hidden"
              >
                <div className="bg-black/60 border border-white/5 rounded-[32px] overflow-hidden shadow-2xl">
                  <div className="px-8 py-5 bg-white/5 flex items-center justify-between border-b border-white/5">
                    <div className="flex items-center gap-4">
                      <span className="text-[11px] uppercase font-black tracking-[0.2em] text-[#888888]">DDL Script Preview</span>
                      {!isUsingRecommended && (
                        <button 
                          onClick={handleResetToRecommended}
                          className="px-3 py-1 rounded bg-[#3ECF8E]/10 text-[#3ECF8E] text-[9px] font-black uppercase tracking-widest border border-[#3ECF8E]/20 hover:bg-[#3ECF8E]/20 transition-all"
                        >
                          Reset to Recommended
                        </button>
                      )}
                    </div>
                    <div className="flex gap-3">
                       <button onClick={handleCopySQL} className="w-10 h-10 flex items-center justify-center bg-white/5 hover:bg-white/10 rounded-xl transition-all border border-white/5 group">
                        {sqlCopied ? <Check size={16} className="text-[#3ECF8E]" /> : <Copy size={16} className="text-[#888888] group-hover:text-white" />}
                       </button>
                       <button onClick={handleDownloadPreviewSQL} className="w-10 h-10 flex items-center justify-center bg-white/5 hover:bg-white/10 rounded-xl transition-all border border-white/5 group">
                        <Download size={16} className="text-[#888888] group-hover:text-white" />
                       </button>
                    </div>
                  </div>
                  <div className="p-8 max-h-[400px] overflow-y-auto custom-scrollbar">
                    <pre className="text-[11px] text-[#666666] font-mono leading-relaxed whitespace-pre-wrap">
                      {previewScript}
                    </pre>
                  </div>
                </div>
                
                <div className="p-8 rounded-[32px] bg-yellow-500/[0.03] border border-yellow-500/10 relative overflow-hidden">
                   <div className="absolute top-0 right-0 p-8 opacity-[0.03] rotate-12"><AlertCircle size={120} className="text-yellow-500" /></div>
                   
                   <div className="relative z-10">
                    <h5 className="text-[11px] text-yellow-500 font-black mb-4 uppercase tracking-[0.3em]">Manual Installation Protocol</h5>
                    <p className="text-sm text-[#888888] leading-relaxed mb-8 max-w-2xl font-medium">
                      If the automated provisioner fails due to host security policies, you must ensure the <code className="text-[#3ECF8E] bg-[#3ECF8E]/5 px-2 py-0.5 rounded border border-[#3ECF8E]/10 font-mono">execute_sql</code> kernel is installed in the public schema.
                      <button onClick={handleDownloadSQL} className="text-[#3ECF8E] hover:underline font-black uppercase text-[10px] tracking-widest ml-4 bg-[#3ECF8E]/10 px-4 py-2 rounded-xl border border-[#3ECF8E]/20">Fetch Kernel SQL</button>
                    </p>

                    <div className="pt-8 border-t border-white/5 flex flex-col sm:flex-row items-center gap-8">
                      <label className="flex items-center gap-4 cursor-pointer group flex-1">
                        <div className="relative">
                          <input
                            type="checkbox"
                            checked={scriptConfirmed}
                            onChange={(e) => setScriptConfirmed(e.target.checked)}
                            className="sr-only"
                          />
                          <div className={cn(
                            "w-8 h-8 rounded-xl border transition-all flex items-center justify-center",
                            scriptConfirmed ? "bg-[#3ECF8E] border-[#3ECF8E]" : "bg-black border-white/10"
                          )}>
                            {scriptConfirmed && <Check size={16} strokeWidth={3} className="text-black" />}
                          </div>
                        </div>
                        <span className="text-xs font-bold text-[#888888] group-hover:text-white transition-colors tracking-tight">
                          I have successfully verified the manual DDL execution.
                        </span>
                      </label>

                      <button
                        type="button"
                        onClick={handleVerifySchema}
                        disabled={!scriptConfirmed || isSaving}
                        className="w-full sm:w-auto px-10 py-5 rounded-[22px] border border-white/5 bg-white/5 text-[11px] font-black uppercase tracking-[0.3em] text-[#888888] hover:text-white hover:bg-white/10 hover:border-white/10 transition-all disabled:opacity-50"
                      >
                        Run Topology Validation
                      </button>
                    </div>
                   </div>
                </div>
              </motion.div>
            )}
          </div>
        </motion.div>
      )}
      {currentStep === 'complete' && teamSecret && (
        <motion.div initial={{ opacity: 0, scale: 0.95 }} animate={{ opacity: 1, scale: 1 }} className="space-y-6">
          <div className="p-8 rounded-3xl bg-[#3ECF8E]/5 border-2 border-[#3ECF8E]/20 text-center space-y-6">
            <div className="w-20 h-20 rounded-full bg-[#3ECF8E] flex items-center justify-center mx-auto shadow-[0_0_30px_rgba(62,207,142,0.3)]">
              <Check size={40} className="text-black" />
            </div>

            <div className="space-y-2">
              <h3 className="text-2xl font-black text-white tracking-tight">Team Created Successfully!</h3>
              <p className="text-sm text-[#888888] max-w-md mx-auto">
                Your workspace is ready. Save these codes as you will need them to manage your team or invite members.
              </p>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4 text-left">
              <div className="p-6 rounded-2xl bg-black/40 border border-[#222222] space-y-4">
                <div className="flex items-center justify-between">
                  <p className="text-[10px] font-black uppercase text-[#888888] tracking-widest">Team Code (Secret)</p>
                  <Shield size={14} className="text-[#3ECF8E]" />
                </div>
                <div className="flex items-center gap-3">
                  <code className="flex-1 px-4 py-3 bg-black rounded-xl border border-[#222222] text-white font-mono text-xs break-all">
                    {teamSecret}
                  </code>
                  <button
                    onClick={handleCopyTeamCode}
                    className="p-3 bg-[#1A1A1A] hover:bg-[#222222] rounded-xl text-[#888888] hover:text-white transition-all"
                  >
                    <Copy size={18} />
                  </button>
                </div>
                <p className="text-[10px] text-red-400 font-medium">NEVER share this code with anyone but co-admins.</p>
              </div>

              {inviteCode && (
                <div className="p-6 rounded-2xl bg-black/40 border border-[#222222] space-y-4">
                  <div className="flex items-center justify-between">
                    <p className="text-[10px] font-black uppercase text-[#888888] tracking-widest">Team Invite Code</p>
                    <LinkIcon size={14} className="text-[#3ECF8E]" />
                  </div>
                  <div className="flex items-center gap-3">
                    <code className="flex-1 px-4 py-3 bg-black rounded-xl border border-[#222222] text-white font-mono text-xs break-all">
                      {inviteCode}
                    </code>
                    <button
                      onClick={handleCopyInviteCode}
                      className="p-3 bg-[#1A1A1A] hover:bg-[#222222] rounded-xl text-[#888888] hover:text-white transition-all"
                    >
                      <Copy size={18} />
                    </button>
                  </div>
                  <p className="text-[10px] text-[#444444]">Valid for 24 hours. Your team can use this to join.</p>
                </div>
              )}
            </div>
          </div>
        </motion.div>
      )}

      <div className="flex gap-3 mt-8 pt-8 border-t border-[#222222]">
        {currentStep === 'sql-setup' && (
          <button
            type="button"
            onClick={() => setCurrentStep('credentials')}
            className="flex-1 px-4 py-3 rounded-2xl bg-[var(--bg-elevated)] border border-[var(--border-subtle)] text-[var(--text-main)] font-bold hover:bg-[var(--bg-surface)] transition-all"
          >
            Back
          </button>
        )}

        <button
          type="button"
          onClick={currentStep === 'credentials' ? handleTestConnection : handleCreateTeam}
          disabled={
            isTestingConnection ||
            isSaving ||
            !url ||
            !anonKey ||
            !serviceKey ||
            (currentStep === 'credentials' && (!teamName || Boolean(connectionError))) ||
            (currentStep === 'sql-setup' && !scriptConfirmed && !schemaVerified)
          }
          className="flex-1 px-4 py-3 rounded-2xl bg-[#3ECF8E] text-[var(--text-on-brand)] font-bold hover:shadow-[0_0_20px_rgba(62,207,142,0.4)] transition-all disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-2"
        >
          {(isTestingConnection || isSaving) && <Loader size={16} className="animate-spin" />}
          {currentStep === 'credentials'
            ? 'Continue'
            : isSaving
              ? 'Creating Team...'
              : 'Create Team'}
        </button>
      </div>
    </motion.div>
  );
};

import React, { useState } from 'react';
import { motion } from 'motion/react';
import { ArrowLeft, Loader, AlertCircle, CheckCircle2, QrCode } from 'lucide-react';
import { useOnboardingStore } from '../../store/onboardingStore';
import { OnboardingService } from '../../services/OnboardingService';
import { useStore } from '../../store/useStore';

export const JoinInviteWizard: React.FC = () => {
  const { addToast, profile } = useStore();
  const {
    setStep: setOnboardingStep,
    setIsConfigured,
    setWorkspaceId,
    setTeamId,
    setSupabaseCredentials,
    setUserId,
  } = useOnboardingStore();

  const [inviteCode, setInviteCode] = useState('');
  const [isJoining, setIsJoining] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleJoinInvite = async () => {
    setError(null);
    setIsJoining(true);

    if (!inviteCode) {
      setError('Please enter your team invite code.');
      setIsJoining(false);
      return;
    }

    if (!OnboardingService.isValidInviteCodeFormat(inviteCode)) {
      setError('Invalid invite code format. Expected: TEMP-XXXX-XXXX-XXXX');
      setIsJoining(false);
      return;
    }

    if (!profile?.id) {
      setError('Active session not detected.');
      setIsJoining(false);
      return;
    }

    const userId = profile.id;

    try {
      const result = await OnboardingService.joinByInviteCode(inviteCode, userId);

      if (result.success) {
        // Fetch invite details to get credentials (needed for local store)
        const validation = await OnboardingService.validateInviteCode(inviteCode);
        if (validation.invite) {
          setSupabaseCredentials(validation.invite.supabase_url, validation.invite.supabase_anon_key);
        }
        
        setWorkspaceId(result.workspaceId || '');
        setTeamId(result.teamId || '');
        setUserId(userId);
        setIsConfigured(true);

        addToast({
          type: 'success',
          message: 'Successfully joined team via invite!',
        });

        setTimeout(() => {
          window.location.reload();
        }, 1500);
      } else {
        setError(result.error || 'Failed to join team');
      }
    } catch (e: any) {
      setError(e.message || 'An unexpected error occurred');
    } finally {
      setIsJoining(false);
    }
  };

  return (
    <motion.div
      initial={{ opacity: 0 }}
      animate={{ opacity: 1 }}
      exit={{ opacity: 0 }}
      className="p-12"
    >
      {/* Header */}
      <div className="flex items-center justify-between mb-8">
        <h2 className="text-2xl font-black text-white tracking-tight">
          Join via Invite
        </h2>
        <button
          onClick={() => setOnboardingStep('option-select')}
          className="p-2 hover:bg-[#1A1A1A] rounded-lg transition-all"
        >
          <ArrowLeft size={20} className="text-[#888888]" />
        </button>
      </div>

      <div className="space-y-6">
        <div className="p-4 rounded-xl bg-[#3ECF8E]/10 border border-[#3ECF8E]/20 flex gap-4 items-center">
          <div className="w-12 h-12 rounded-lg bg-[#3ECF8E]/20 flex items-center justify-center shrink-0">
            <QrCode size={24} className="text-[#3ECF8E]" />
          </div>
          <div>
            <p className="text-sm font-bold text-white">Secure Onboarding</p>
            <p className="text-xs text-[#888888]">
              Your team connection details will be fetched automatically.
            </p>
          </div>
        </div>

        <p className="text-sm text-[#888888]">
          Enter the secure team invite code provided by your team administrator.
        </p>

        {/* Temporary Code Input */}
        <div>
          <label className="block text-xs font-black uppercase text-[#888888] mb-2 tracking-widest">
            Team Invite Code
          </label>
          <input
            type="text"
            placeholder="TEMP-XXXX-XXXX-XXXX"
            value={inviteCode}
            onChange={(e) => setInviteCode(e.target.value.toUpperCase())}
            maxLength={24}
            className="w-full px-4 py-4 bg-[#1A1A1A] border border-[#222222] rounded-lg text-white placeholder:text-[#555555] focus:border-[#3ECF8E] focus:outline-none transition-all font-mono tracking-widest text-center text-xl"
          />
          <p className="text-xs text-[#555555] mt-2 text-center">
            Format: TEMP-XXXX-XXXX-XXXX
          </p>
        </div>

        {/* Code Validation Helper */}
        {inviteCode && (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            className={`p-3 rounded-lg border flex items-center gap-2 ${
              OnboardingService.isValidInviteCodeFormat(inviteCode)
                ? 'bg-green-500/10 border-green-500/30'
                : 'bg-red-500/10 border-red-500/30'
            }`}
          >
            {OnboardingService.isValidInviteCodeFormat(inviteCode) ? (
              <>
                <CheckCircle2 size={16} className="text-green-500" />
                <p className="text-xs text-green-400">Valid invite code format</p>
              </>
            ) : (
              <>
                <AlertCircle size={16} className="text-red-500" />
                <p className="text-xs text-red-400">Invalid invite code format</p>
              </>
            )}
          </motion.div>
        )}

        {/* Error */}
        {error && (
          <motion.div
            initial={{ opacity: 0, y: -10 }}
            animate={{ opacity: 1, y: 0 }}
            className="p-4 rounded-lg bg-red-500/10 border border-red-500/30 flex gap-3"
          >
            <AlertCircle size={18} className="text-red-500 shrink-0 mt-0.5" />
            <p className="text-sm text-red-400">{error}</p>
          </motion.div>
        )}

        {/* Join Button */}
        <button
          onClick={handleJoinInvite}
          disabled={
            isJoining ||
            !inviteCode ||
            !OnboardingService.isValidInviteCodeFormat(inviteCode)
          }
          className="w-full px-4 py-4 bg-[#3ECF8E] text-[var(--text-on-brand)] font-black rounded-lg hover:shadow-[0_0_20px_rgba(62,207,142,0.4)] transition-all disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-2 text-md"
        >
          {isJoining && <Loader size={20} className="animate-spin" />}
          {isJoining ? 'Verifying Invite...' : 'Secure Join'}
        </button>
      </div>
    </motion.div>
  );
};

import React, { useState } from 'react';
import { motion } from 'motion/react';
import { ArrowLeft, Loader, AlertCircle, CheckCircle2 } from 'lucide-react';
import { useOnboardingStore } from '../../store/onboardingStore';
import { OnboardingService } from '../../services/OnboardingService';
import { useStore } from '../../store/useStore';

type JoinStep = 'input-code' | 'joining' | 'complete';

export const JoinTeamWizard: React.FC = () => {
  const { addToast, profile } = useStore();
  const {
    setStep: setOnboardingStep,
    setIsConfigured,
    setWorkspaceId,
    setTeamId,
    setSupabaseCredentials,
    setUserId,
  } = useOnboardingStore();

  const [joinStep, setJoinStep] = useState<JoinStep>('input-code');
  const [teamCode, setTeamCode] = useState('');
  const [inviteCode, setInviteCode] = useState('');
  const [isJoining, setIsJoining] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleJoinTeam = async () => {
    setError(null);
    setIsJoining(true);

    if (!inviteCode) {
      setError('Please enter your team invite code.');
      setIsJoining(false);
      return;
    }

    if (!OnboardingService.isValidInviteCodeFormat(inviteCode)) {
      setError('Invalid invite code format. Expected: TEMP-XXXX-XXXX-XXXX');
      setIsJoining(false);
      return;
    }

    if (!profile?.id) {
      setError('Active session not detected.');
      setIsJoining(false);
      return;
    }

    const userId = profile.id;

    try {
      // 1. Fetch connection details from the temporary code
      const validation = await OnboardingService.validateInviteCode(inviteCode);
      if (!validation.success || !validation.invite) {
        setError(validation.error || 'Invalid invite code.');
        setIsJoining(false);
        return;
      }

      const { supabase_url, supabase_anon_key, teams } = validation.invite;
      const actualTeamCode = teamCode || teams?.team_code;

      if (!actualTeamCode) {
        setError('Could not determine team code. Please enter it manually or check your invite code.');
        setIsJoining(false);
        return;
      }

      // 2. Perform the join
      const result = await OnboardingService.joinTeam(
        supabase_url,
        supabase_anon_key,
        userId,
        actualTeamCode,
        inviteCode
      );

      if (result.success) {
        setSupabaseCredentials(supabase_url, supabase_anon_key);
        setWorkspaceId(result.workspaceId || '');
        setTeamId(result.teamId || '');
        setUserId(userId);
        setJoinStep('complete');
        setIsConfigured(true);

        addToast({
          type: 'success',
          message: 'Successfully joined team!',
        });

        setTimeout(() => {
          window.location.reload();
        }, 1500);
      } else {
        setError(result.error || 'Failed to join team');
      }
    } catch (e: any) {
      setError(e.message || 'An unexpected error occurred during join.');
    } finally {
      setIsJoining(false);
    }
  };

  return (
    <motion.div
      initial={{ opacity: 0 }}
      animate={{ opacity: 1 }}
      exit={{ opacity: 0 }}
      className="p-12"
    >
      {/* Header */}
      <div className="flex items-center justify-between mb-8">
        <h2 className="text-2xl font-black text-white tracking-tight">
          Join Team
        </h2>
        <button
          onClick={() => setOnboardingStep('option-select')}
          className="p-2 hover:bg-[#1A1A1A] rounded-lg transition-all"
        >
          <ArrowLeft size={20} className="text-[#888888]" />
        </button>
      </div>

      {/* Content */}
      <div className="space-y-6">
        <div className="p-4 rounded-xl bg-[#3ECF8E]/10 border border-[#3ECF8E]/20 flex gap-4 items-center mb-2">
          <div className="w-12 h-12 rounded-lg bg-[#3ECF8E]/20 flex items-center justify-center shrink-0">
            <CheckCircle2 size={24} className="text-[#3ECF8E]" />
          </div>
          <div>
            <p className="text-sm font-bold text-white">Simplified Access</p>
            <p className="text-xs text-[#888888]">
              Supabase credentials will be configured automatically from your code.
            </p>
          </div>
        </div>

        <p className="text-sm text-[#888888]">
          Enter your team invite code to automatically configure your workspace.
        </p>

        {/* Temporary Code Input */}
        <div>
          <label className="block text-xs font-black uppercase text-[#888888] mb-2 tracking-widest">
            Team Invite Code
          </label>
          <input
            type="text"
            placeholder="TEMP-XXXX-XXXX-XXXX"
            value={inviteCode}
            onChange={(e) => setInviteCode(e.target.value.toUpperCase())}
            maxLength={24}
            className="w-full px-4 py-4 bg-[#1A1A1A] border border-[#222222] rounded-lg text-white placeholder:text-[#555555] focus:border-[#3ECF8E] focus:outline-none transition-all font-mono tracking-widest text-center text-xl"
          />
          <p className="text-xs text-[#555555] mt-2 text-center font-mono">
            Format: TEMP-XXXX-XXXX-XXXX
          </p>
        </div>

        {/* Optional Team Code Input */}
        <div>
          <label className="block text-xs font-black uppercase text-[#888888] mb-2 tracking-widest">
            Team Code (Optional)
          </label>
          <input
            type="text"
            placeholder="TEAM-XXXX-XXXX-XXXX"
            value={teamCode}
            onChange={(e) => setTeamCode(e.target.value.toUpperCase())}
            maxLength={24}
            className="w-full px-4 py-3 bg-[#1A1A1A] border border-[#222222] rounded-lg text-white placeholder:text-[#555555] focus:border-[#3ECF8E] focus:outline-none transition-all font-mono tracking-wider text-center"
          />
          <p className="text-[10px] text-[#555555] mt-2 italic text-center">
            Usually fetched automatically from your team invite code.
          </p>
        </div>

        {/* Error */}
        {error && (
          <motion.div
            initial={{ opacity: 0, y: -10 }}
            animate={{ opacity: 1, y: 0 }}
            className="p-4 rounded-lg bg-red-500/10 border border-red-500/30 flex gap-3"
          >
            <AlertCircle size={18} className="text-red-500 shrink-0 mt-0.5" />
            <p className="text-sm text-red-400">{error}</p>
          </motion.div>
        )}

        {/* Join Button */}
        <button
          onClick={handleJoinTeam}
          disabled={
            isJoining ||
            !inviteCode ||
            !OnboardingService.isValidInviteCodeFormat(inviteCode)
          }
          className="w-full px-4 py-4 bg-[#3ECF8E] text-[var(--text-on-brand)] font-black rounded-lg hover:shadow-[0_0_20px_rgba(62,207,142,0.4)] transition-all disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-2 text-lg uppercase tracking-wider"
        >
          {isJoining && <Loader size={20} className="animate-spin" />}
          {isJoining ? 'Initializing...' : 'Join Workspace'}
        </button>
      </div>
    </motion.div>
  );
};

import React, { useState } from 'react';
import { motion, AnimatePresence } from 'motion/react';
import { LogOut, ArrowLeft } from 'lucide-react';
import { useOnboardingStore } from '../../store/onboardingStore';
import { useStore } from '../../store/useStore';
import { useAuth } from '../../hooks/useAuth';
import { OnboardingWelcome } from './OnboardingWelcome';
import { OptionSelection } from './OptionSelection';
import { CreateSetupWizard } from './CreateSetupWizard';
import { JoinTeamWizard } from './JoinTeamWizard';
import { JoinInviteWizard } from './JoinInviteWizard';
import { TeamSelection } from './TeamSelection';

export const OnboardingModal: React.FC = () => {
  const { step, setupMode, isConfigured } = useOnboardingStore();
  const { teams, setLandingSkipped } = useStore();
  const { logout } = useAuth();

  if (isConfigured) {
    return null;
  }

  const hasTeams = teams.length > 0;

  return (
    <div className="fixed inset-0 z-[9999] flex items-center justify-center p-4 bg-[var(--bg-deep)]/40 backdrop-blur-sm">
      <motion.div
        initial={{ opacity: 0, scale: 0.95, y: 20 }}
        animate={{ opacity: 1, scale: 1, y: 0 }}
        exit={{ opacity: 0, scale: 0.95, y: 20 }}
        className="w-full max-w-2xl max-h-[90vh] overflow-y-auto bg-[var(--bg-surface)] border border-[#222222] rounded-2xl shadow-2xl relative"
      >
        {/* Universal Escape Rail */}
        <div className="absolute top-6 right-6 z-10 flex items-center gap-4">
          {step === 'welcome' && (
            <button
              onClick={() => setLandingSkipped(false)}
              className="flex items-center gap-2 text-[10px] font-black uppercase tracking-widest text-[#555555] hover:text-[#3ECF8E] transition-colors"
            >
              <ArrowLeft size={14} /> Back to Landing
            </button>
          )}
          {step !== 'welcome' && step !== 'team-select' && (
             <button
              onClick={() => useOnboardingStore.getState().setStep(hasTeams ? 'team-select' : 'welcome')}
              className="flex items-center gap-2 text-[10px] font-black uppercase tracking-widest text-[#555555] hover:text-[#3ECF8E] transition-colors"
            >
              <ArrowLeft size={14} /> {hasTeams ? 'Back to Selection' : 'Reset Flow'}
            </button>
          )}
          <div className="h-3 w-px bg-[#222222]" />
          <button
            onClick={() => logout()}
            className="flex items-center gap-2 text-[10px] font-black uppercase tracking-widest text-[#555555] hover:text-red-500 transition-colors"
          >
            <LogOut size={14} /> Logout
          </button>
        </div>

        <AnimatePresence mode="wait">
          {step === 'welcome' && <OnboardingWelcome key="welcome" />}
          {step === 'option-select' && <OptionSelection key="option-select" />}
          {step === 'create-setup' && setupMode === 'create' && (
            <CreateSetupWizard key="create-setup" />
          )}
          {step === 'join-team' && setupMode === 'join' && (
            <JoinTeamWizard key="join-team" />
          )}
          {step === 'join-invite' && setupMode === 'join-invite' && (
            <JoinInviteWizard key="join-invite" />
          )}
          {step === 'team-select' && <TeamSelection key="team-select" />}
        </AnimatePresence>
      </motion.div>
    </div>
  );
};

