import React, { useEffect, useState } from 'react';
import { motion } from 'motion/react';
import { Users, ChevronRight, LayoutGrid, Plus, Search, LogOut, Database, Key, Settings } from 'lucide-react';
import { useOnboardingStore } from '../../store/onboardingStore';
import { useStore } from '../../store/useStore';
import { PersistenceService } from '../../services/PersistenceService';
import { Team } from '../../types';
import { cn } from '../../lib/utils';
import { useAuth } from '../../hooks/useAuth';
import { globalSupabase } from '../../lib/supabase';
import { DatabaseMigrationModal } from '../DatabaseMigrationModal';

export const TeamSelection: React.FC = () => {
  const { setStep, setSetupMode, setIsConfigured, setWorkspaceId, setTeamId, setUserId } = useOnboardingStore();
  const { profile, setActiveWorkspaceId, setTeams, addToast } = useStore();
  const [userTeams, setUserTeams] = useState<Team[]>([]);
  const [loading, setLoading] = useState(true);
  const [filterQuery, setFilterQuery] = useState('');
  const { logout } = useAuth();

  const [selectingTeamId, setSelectingTeamId] = useState<string | null>(null);
  const [isMigrationModalOpen, setIsMigrationModalOpen] = useState(false);

  const globalUrl = (globalSupabase as any).config?.url || 'unknown';

  useEffect(() => {
    const loadTeams = async () => {
      if (!profile?.id) return;
      try {
        const teams = await PersistenceService.fetchUserTeams(profile.id);
        setUserTeams(teams);
        setTeams(teams);
      } catch (error) {
        console.error('Failed to load teams:', error);
      } finally {
        setLoading(false);
      }
    };

    loadTeams();
  }, [profile?.id, setTeams]);

  const handleSelectTeam = async (team: Team) => {
    if (selectingTeamId) return;
    
    setSelectingTeamId(team.id);
    console.group(`%c[TeamSelection] Selecting team: ${team.name}`, 'color: #3ECF8E; font-weight: bold;');
    console.log(`[Diagnostic] User Profile ID: ${profile?.id}`);
    console.log(`[Diagnostic] Global Endpoint: ${globalUrl}`);
    
    try {
      // Find workspaces for this team
      console.log('Fetching workspaces for team...');
      let workspaces = await PersistenceService.fetchWorkspacesByTeam(team.id);
      console.log(`Found ${workspaces.length} workspaces:`, workspaces);
      
      if (workspaces.length === 0 && profile?.id) {
        console.warn('CRITICAL: No workspaces found for team. Attempting emergency self-healing...');
        try {
          const newWorkspace = await PersistenceService.createWorkspace('General', profile.id, team.id);
          console.log('Self-healing successful. Created workspace:', newWorkspace);
          workspaces = [newWorkspace];
        } catch (wsError: any) {
          console.error('Self-healing failed. Root cause:', wsError.message);
          if (wsError.message.includes('column')) {
            throw new Error(`DATABASE_SCHEMA_ERROR: The 'workspaces' table in your global project (${globalUrl}) is missing the 'team_id' column. Please run the initialization script again.`);
          }
          throw wsError;
        }
      }

      if (workspaces.length > 0) {
        const targetWorkspace = workspaces[0];
        console.log('Target workspace:', targetWorkspace.name, targetWorkspace.id);
        
        // 1. Update onboarding store (persisted metadata)
        console.log('Updating onboarding store...');
        setTeamId(team.id);
        setUserId(profile.id);
        setWorkspaceId(targetWorkspace.id);
        
        // 2. Update global app store
        console.log('Updating global app store...');
        setActiveWorkspaceId(targetWorkspace.id);
        
        // 3. Mark as configured (triggers UI flip in App.tsx)
        console.log('Finalizing configuration...');
        setIsConfigured(true);
        setStep('complete');
        
        addToast({ 
          type: 'success', 
          message: `Mission objective locked. Connected to ${team.name}.` 
        });
      } else {
        console.warn('No workspaces found for this team. This shouldn\'t happen for standard setup.');
        addToast({ 
          type: 'error', 
          message: 'Structural error: No workspace found for this sector.' 
        });
      }
    } catch (error: any) {
      console.error('Team selection failed:', error);
      addToast({ 
        type: 'error', 
        message: `Connection failed: ${error.message || 'Unknown protocol error'}` 
      });
    } finally {
      console.groupEnd();
      setSelectingTeamId(null);
    }
  };

  const filteredTeams = userTeams.filter(t => 
    t.name.toLowerCase().includes(filterQuery.toLowerCase())
  );

  return (
    <motion.div
      initial={{ opacity: 0, y: 10 }}
      animate={{ opacity: 1, y: 0 }}
      exit={{ opacity: 0, y: -10 }}
      className="p-12 flex flex-col h-full"
    >
      <div className="flex items-center justify-between mb-8">
        <div>
          <h2 className="text-2xl font-black text-white tracking-tight">System Access</h2>
          <p className="text-sm text-[#888888] mt-1 italic tracking-wide lowercase">Initialize secure uplink to available infrastructure nodes...</p>
        </div>
        <button
          onClick={() => logout()}
          className="p-2 hover:bg-red-500/10 rounded-lg transition-all group"
          title="Logout"
        >
          <LogOut size={20} className="text-[#555555] group-hover:text-red-500" />
        </button>
      </div>

      <div className="relative mb-6">
        <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-[#555555]" size={16} />
        <input 
          type="text"
          value={filterQuery}
          onChange={(e) => setFilterQuery(e.target.value)}
          placeholder="SEARCH_INFRASTRUCTURE..."
          className="w-full bg-black border border-[#222222] rounded-xl py-3 pl-10 pr-4 text-xs font-mono uppercase tracking-widest text-[#AAAAAA] focus:outline-none focus:border-[#3ECF8E]/40 transition-all"
        />
      </div>

      {loading ? (
        <div className="flex-1 flex items-center justify-center py-12">
          <div className="w-8 h-8 border-2 border-[#3ECF8E]/20 border-t-[#3ECF8E] rounded-full animate-spin" />
        </div>
      ) : (
        <div className="flex-1 space-y-3 overflow-y-auto pr-2 custom-scrollbar no-scrollbar">
          {filteredTeams.map((team) => (
            <motion.button
              key={team.id}
              disabled={!!selectingTeamId}
              whileHover={{ x: 4 }}
              whileTap={{ scale: 0.99 }}
              onClick={() => handleSelectTeam(team)}
              className={cn(
                "w-full group p-4 rounded-xl bg-gradient-to-r from-[#1A1A1A] to-transparent border transition-all text-left flex items-center gap-4",
                selectingTeamId === team.id ? "border-[#3ECF8E] bg-[#3ECF8E]/5" : "border-[#222222] hover:border-[#3ECF8E]/30 hover:from-[#3ECF8E]/5",
                selectingTeamId && selectingTeamId !== team.id ? "opacity-40 grayscale" : ""
              )}
            >
              <div className={cn(
                "w-12 h-12 rounded-lg bg-[var(--bg-surface)] border flex items-center justify-center shrink-0 transition-all",
                selectingTeamId === team.id ? "border-[#3ECF8E] bg-[#3ECF8E]/10" : "border-[#222222] group-hover:border-[#3ECF8E]/40 group-hover:bg-[#3ECF8E]/10"
              )}>
                {selectingTeamId === team.id ? (
                  <div className="w-4 h-4 border-2 border-[#3ECF8E]/20 border-t-[#3ECF8E] rounded-full animate-spin" />
                ) : (
                  <Users size={20} className="text-[#555555] group-hover:text-[#3ECF8E]" />
                )}
              </div>

              <div className="flex-1 min-w-0">
                <h3 className="text-sm font-black text-white truncate uppercase tracking-widest">{team.name}</h3>
                <div className="flex items-center gap-2 mt-1">
                   <div className="flex items-center gap-1 text-[9px] font-bold text-[#555555] uppercase tracking-tighter">
                      <LayoutGrid size={10} />
                      {selectingTeamId === team.id ? 'Establishing Sync...' : 'Infrastructure Node Ready'}
                   </div>
                </div>
              </div>

              <ChevronRight size={18} className={cn(
                "text-[#3ECF8E] transition-all",
                selectingTeamId === team.id ? "opacity-100" : "opacity-0 group-hover:opacity-100"
              )} />
            </motion.button>
          ))}

          {filteredTeams.length === 0 && (
            <div className="text-center py-12 border-2 border-dashed border-[#222222] rounded-2xl">
              <Users size={32} className="mx-auto text-[#222222] mb-3" />
              <p className="text-xs font-bold text-[#555555] uppercase tracking-widest">No matching teams found</p>
            </div>
          )}
        </div>
      )}

      <div className="mt-8 pt-6 border-t border-[#222222]">
        <div className="mb-4 px-2">
            <h4 className="text-[10px] font-black text-[#444444] uppercase tracking-[0.2em] mb-1">Active Infrastructure Node</h4>
            <div className="text-[9px] font-mono text-[#3ECF8E]/40 truncate bg-black/40 p-2 rounded-lg border border-[#222222]/50">
              {globalUrl || 'NOT_CONNECTED_ERROR'}
            </div>
        </div>
        <div className="grid grid-cols-2 gap-3">
          <button
            onClick={() => {
              setSetupMode('create');
              setStep('create-setup');
            }}
            className="flex items-center justify-center gap-2 py-3 px-4 rounded-xl bg-[#1A1A1A] border border-[#222222] text-[10px] font-black text-[#888888] uppercase tracking-widest hover:text-white hover:border-[#3ECF8E]/30 transition-all"
          >
            <Plus size={14} className="text-[#3ECF8E]" /> Setup Team
          </button>
          <button
            onClick={() => {
              setSetupMode('join');
              setStep('join-team');
            }}
            className="flex items-center justify-center gap-2 py-3 px-4 rounded-xl bg-[#1A1A1A] border border-[#222222] text-[10px] font-black text-[#888888] uppercase tracking-widest hover:text-white hover:border-[#3ECF8E]/30 transition-all"
          >
            <Key size={14} className="text-[#3ECF8E]" /> Join with Code
          </button>
          <button
            onClick={() => setIsMigrationModalOpen(true)}
            className="col-span-2 flex items-center justify-center gap-2 py-3 rounded-xl bg-[#1A1A1A] border border-[#222222] text-[10px] font-black text-[#888888] uppercase tracking-widest hover:text-white hover:border-[#3ECF8E]/30 transition-all"
          >
            <Database size={14} className="text-[#3ECF8E]" /> Migrate Database
          </button>
        </div>
      </div>

      <DatabaseMigrationModal
        isOpen={isMigrationModalOpen}
        onClose={() => setIsMigrationModalOpen(false)}
        userId={profile?.id}
        addToast={addToast}
      />
    </motion.div>
  );
};

import React, { useState, useEffect, Suspense } from 'react';
import { useStore } from '../../store/useStore';
import { useDataSync } from '../../hooks/useDataSync';
import { KeyValue, Collection } from '../../types';
import { KVEditor } from '../../components/KVEditor';
import { PersistenceService } from '../../services/PersistenceService';
import { motion, AnimatePresence } from 'motion/react';
import { 
  Variable, 
  FileText, 
  Code2, 
  Settings, 
  Save, 
  Trash2, 
  Eye, 
  PenLine,
  RefreshCcw,
  Cloud,
  ChevronRight,
  Key,
  Clock
} from 'lucide-react';
const Editor = React.lazy(() => import('@monaco-editor/react'));
import { registerGimayCompletions } from '../../services/monacoCompletion';
import ReactMarkdown from 'react-markdown';
import { cn } from '../../lib/utils';
import { AuthEditor } from '../../components/AuthEditor';
import { ScriptLibraryModal } from '../scripts/ScriptLibraryModal';

interface CollectionEditorProps {
  collectionId: string;
}

export const CollectionEditor: React.FC<CollectionEditorProps> = ({ collectionId }) => {
  const { 
    collections, 
    updateCollection, 
    updateTab,
    canPerformAction,
    syncStatus,
    settings,
    pendingSyncIds,
    syncResource,
    setIsScriptLibraryOpen,
    addToast,
    theme
  } = useStore();

  const collection = collections.find(c => c.id === collectionId);
  const [activeSection, setActiveSection] = useState<'Variables' | 'Authorization' | 'Documentation' | 'Scripts'>('Variables');
  const [docMode, setDocMode] = useState<'edit' | 'preview'>('preview');
  const [isSavingManual, setIsSavingManual] = useState(false);
  const [activeScriptTarget, setActiveScriptTarget] = useState<'pre_request_script' | 'test_script'>('pre_request_script');

  const isPending = !!collection && pendingSyncIds.has(collection.id);
  const showSaveButton = !settings.general.autoSave && isPending;

  const handleManualSave = async () => {
    if (!collection) return;
    setIsSavingManual(true);
    await syncResource('collection', collection.id);
    setIsSavingManual(false);
  };

  if (!collection) {
    return (
      <div className="flex-1 flex flex-col items-center justify-center text-[#555555]">
        <Trash2 size={48} className="mb-4 opacity-20" />
        <h2 className="text-xl font-black uppercase tracking-widest">Collection Expired</h2>
        <p className="text-sm">This resource is no longer reachable in this sector.</p>
      </div>
    );
  }

  const canEdit = canPerformAction(collection, 'edit');

  const handleUpdate = (updates: Partial<Collection>) => {
    if (!canEdit) return;
    
    // Optimistic update + Sync (handled by store)
    updateTab(collectionId, updates);
    updateCollection(collectionId, updates);
  };

  return (
    <div className="flex-1 flex flex-col bg-[#0A0A0A] overflow-hidden">
      {/* Header Info */}
      <div className="px-8 py-6 border-b border-[#222222] bg-[#0F0F0F] flex items-center justify-between">
        <div className="flex items-center gap-4">
          <div className="p-3 bg-[#3ECF8E]/10 rounded-xl">
             <Variable className="text-[#3ECF8E]" size={24} />
          </div>
          <div>
            <div className="flex items-center gap-2 mb-1">
              <h1 className="text-xl font-black text-[#E0E0E0] uppercase tracking-tighter">
                {collection.name}
              </h1>
              <div className="px-2 py-0.5 rounded border border-[#3ECF8E]/20 bg-[#3ECF8E]/5 text-[#3ECF8E] text-[8px] font-black uppercase tracking-widest">
                Collection Protocol
              </div>
            </div>
            <div className="flex items-center gap-4 text-[10px] font-bold text-[#555555] uppercase tracking-widest">
              <span>Variables Shared Across Requests</span>
              <ChevronRight size={10} />
              <span>Scripts Evaluated Globally</span>
            </div>
          </div>
        </div>

        <div className="flex items-center gap-4">
          <AnimatePresence>
            {showSaveButton && (
              <motion.button
                initial={{ opacity: 0, x: 20 }}
                animate={{ opacity: 1, x: 0 }}
                exit={{ opacity: 0, x: 20 }}
                onClick={handleManualSave}
                disabled={isSavingManual}
                className="px-4 py-2 bg-[#3ECF8E] text-[#0A0A0A] rounded-lg text-[10px] font-black uppercase tracking-widest flex items-center gap-2 hover:bg-[#34B37A] transition-all"
              >
                {isSavingManual ? <RefreshCcw size={14} className="animate-spin" /> : <Save size={14} />}
                Save Collection
              </motion.button>
            )}
          </AnimatePresence>
          
          {syncStatus === 'saving' ? (
            <div className="flex items-center gap-2 text-[10px] font-black text-blue-400 uppercase tracking-widest animate-pulse">
              <RefreshCcw size={12} className="animate-spin" />
              Synchronizing
            </div>
          ) : syncStatus === 'error' ? (
            <div className="flex items-center gap-2 text-[10px] font-black text-red-500 uppercase tracking-widest">
              <Cloud size={12} className="text-red-500" />
              Sync Interrupted
            </div>
          ) : syncStatus === 'pending' ? (
            <div className="flex items-center gap-2 text-[10px] font-black text-yellow-500 uppercase tracking-widest">
              <Clock size={12} className="text-yellow-500" />
              Changes Staged
            </div>
          ) : (
            <div className="flex items-center gap-2 text-[10px] font-black text-[#3ECF8E] uppercase tracking-widest">
              <Cloud size={12} />
              {syncStatus === 'saved' ? 'Sector Synced' : 'Sector Stored'}
            </div>
          )}
        </div>
      </div>

      {/* Navigation */}
      <div className="px-8 border-b border-[#222222] flex gap-8 bg-[#0F0F0F]">
        {([
          { id: 'Variables', icon: Variable },
          { id: 'Authorization', icon: Key },
          { id: 'Documentation', icon: FileText },
          { id: 'Scripts', icon: Code2 }
        ] as const).map(({ id, icon: Icon }) => (
          <button
            key={id}
            onClick={() => setActiveSection(id as any)}
            className={cn(
              "flex items-center gap-2 py-4 text-[10px] font-black uppercase tracking-widest relative transition-all",
              activeSection === id ? "text-[#3ECF8E]" : "text-[#555555] hover:text-[#AAAAAA]"
            )}
          >
            <Icon size={14} />
            {id}
            {activeSection === id && (
              <motion.div 
                layoutId="collection-section-indicator" 
                className="absolute bottom-0 left-0 right-0 h-0.5 bg-[#3ECF8E]" 
              />
            )}
          </button>
        ))}
      </div>

      {/* Workspace Area */}
      <div className="flex-1 overflow-y-auto custom-scrollbar p-8">
        <div className="max-w-5xl mx-auto">
          <AnimatePresence mode="wait">
            {activeSection === 'Variables' && (
              <motion.div
                key="variables"
                initial={{ opacity: 0, y: 10 }}
                animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0, y: -10 }}
                className="space-y-6"
              >
                <div className="flex items-center justify-between">
                  <div>
                    <h3 className="text-sm font-black text-[#E0E0E0] uppercase tracking-widest mb-1">Collection Variables</h3>
                    <p className="text-[11px] text-[#555555]">Inject these values using &#123;&#123;variable_name&#125;&#125; in any request within this collection.</p>
                  </div>
                </div>
                <div className={cn("bg-[#111111] rounded-xl border border-[#222222] p-4", !canEdit && "opacity-50 pointer-events-none")}>
                  <KVEditor 
                    items={collection.variables || []} 
                    onChange={(variables) => handleUpdate({ variables })}
                    placeholderKey="VARIABLE_NAME"
                    placeholderValue="CURRENT_VALUE"
                    isVariableEditor={true}
                  />
                </div>
              </motion.div>
            )}

            {activeSection === 'Authorization' && (
              <motion.div
                key="auth"
                initial={{ opacity: 0, y: 10 }}
                animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0, y: -10 }}
                className="space-y-6"
              >
                <div>
                  <h3 className="text-sm font-black text-[#E0E0E0] uppercase tracking-widest mb-1">Sector Clearances</h3>
                  <p className="text-[11px] text-[#555555]">These credentials will be automatically disseminated to all nested requests using the 'Inherit' protocol.</p>
                </div>
                <div className={cn("bg-[#111111] rounded-xl border border-[#222222] p-8", !canEdit && "opacity-50 pointer-events-none")}>
                  <AuthEditor 
                    auth={collection.auth} 
                    onChange={(auth) => handleUpdate({ auth })} 
                    hideInherit={true}
                  />
                </div>
              </motion.div>
            )}

            {activeSection === 'Documentation' && (
              <motion.div
                key="documentation"
                initial={{ opacity: 0, y: 10 }}
                animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0, y: -10 }}
                className="space-y-6"
              >
                <div className="flex items-center justify-between">
                  <div>
                    <h3 className="text-sm font-black text-[#E0E0E0] uppercase tracking-widest mb-1">Collection Intelligence</h3>
                    <p className="text-[11px] text-[#555555]">Maintain technical specifications and domain knowledge for this subsystem.</p>
                  </div>
                  {canEdit && (
                    <div className="flex p-1 bg-[#1A1A1A] rounded-lg border border-[#333333]">
                      <button 
                        onClick={() => setDocMode('preview')}
                        className={cn(
                          "px-3 py-1 rounded-md text-[10px] font-black uppercase tracking-tighter flex items-center gap-2 transition-all",
                          docMode === 'preview' ? "bg-[#3ECF8E] text-[#0A0A0A]" : "text-[#555555] hover:text-[#AAAAAA]"
                        )}
                      >
                        <Eye size={12} />
                        Preview
                      </button>
                      <button 
                        onClick={() => setDocMode('edit')}
                        className={cn(
                          "px-3 py-1 rounded-md text-[10px] font-black uppercase tracking-tighter flex items-center gap-2 transition-all",
                          docMode === 'edit' ? "bg-[#3ECF8E] text-[#0A0A0A]" : "text-[#555555] hover:text-[#AAAAAA]"
                        )}
                      >
                        <PenLine size={12} />
                        Edit
                      </button>
                    </div>
                  )}
                </div>

                <div className="bg-[#111111] rounded-xl border border-[#222222] overflow-hidden min-h-[400px]">
                  {docMode === 'edit' && canEdit ? (
                    <Suspense fallback={
                      <div className="absolute inset-0 flex items-center justify-center bg-[#0F0F0F] text-[#555555] text-xs font-mono">
                        Drawing documentation editor...
                      </div>
                    }>
                      <Editor
                        height="500px"
                        language="markdown"
                        theme={theme === 'light' ? 'vs' : 'vs-dark'}
                        value={collection.documentation || ''}
                        onChange={(val) => handleUpdate({ documentation: val || '' })}
                        options={{
                          minimap: { enabled: false },
                          fontSize: 13,
                          fontFamily: 'JetBrains Mono',
                          lineNumbers: 'on',
                          automaticLayout: true,
                          wordWrap: 'on',
                          padding: { top: 16 }
                        }}
                      />
                    </Suspense>
                  ) : (
                    <div className="p-8 prose prose-invert prose-emerald max-w-none prose-sm">
                      <ReactMarkdown>
                        {collection.documentation || '*No documentation available for this sector.*'}
                      </ReactMarkdown>
                    </div>
                  )}
                </div>
              </motion.div>
            )}

            {activeSection === 'Scripts' && (
              <motion.div
                key="scripts"
                initial={{ opacity: 0, y: 10 }}
                animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0, y: -10 }}
                className="space-y-8"
              >
                <div className="flex items-center justify-between">
                  <div>
                    <h3 className="text-sm font-black text-[#E0E0E0] uppercase tracking-widest mb-1">Global Interceptors</h3>
                    <p className="text-[11px] text-[#555555]">Scripts defined here run before every request or after every execution in this collection.</p>
                  </div>
                  <button
                    onClick={() => setIsScriptLibraryOpen(true)}
                    className="px-3 py-1.5 rounded-lg border border-[#3ECF8E]/30 bg-[#3ECF8E]/10 hover:bg-[#3ECF8E]/20 text-[9px] font-black text-[#3ECF8E] uppercase tracking-widest flex items-center gap-1.5 transition-all"
                  >
                    <Code2 size={12} />
                    Load from Script Laboratory
                  </button>
                </div>

                <div className="space-y-4">
                  <div className="flex items-center justify-between">
                    <label className="text-[10px] font-black text-[#555555] uppercase tracking-widest">Global Pre-request Sequence</label>
                  </div>
                  <div className={cn("border border-[#222222] rounded-xl overflow-hidden bg-[#111111]", !canEdit && "opacity-50 pointer-events-none")}>
                    <Suspense fallback={
                      <div className="h-[250px] flex items-center justify-center bg-[#0F0F0F] text-[#555555] text-xs font-mono">
                        Loading pre-request editor...
                      </div>
                    }>
                      <Editor
                        height="250px"
                        language="javascript"
                        theme={theme === 'light' ? 'vs' : 'vs-dark'}
                        value={collection.pre_request_script || ''}
                        onMount={(editor, monaco) => {
                          editor.onDidFocusEditorText(() => setActiveScriptTarget('pre_request_script'));
                          registerGimayCompletions(monaco);
                        }}
                        onChange={(val) => handleUpdate({ pre_request_script: val || '' })}
                        options={{
                          minimap: { enabled: false },
                          fontSize: 13,
                          fontFamily: 'JetBrains Mono',
                          lineNumbers: 'on',
                          automaticLayout: true,
                          padding: { top: 16 }
                        }}
                      />
                    </Suspense>
                  </div>
                </div>

                <div className="space-y-4">
                  <div className="flex items-center justify-between">
                    <label className="text-[10px] font-black text-[#555555] uppercase tracking-widest">Global Post-Execution Tests</label>
                  </div>
                  <div className={cn("border border-[#222222] rounded-xl overflow-hidden bg-[#111111]", !canEdit && "opacity-50 pointer-events-none")}>
                    <Suspense fallback={
                      <div className="h-[250px] flex items-center justify-center bg-[#0F0F0F] text-[#555555] text-xs font-mono">
                        Loading test editor...
                      </div>
                    }>
                      <Editor
                        height="250px"
                        language="javascript"
                        theme={theme === 'light' ? 'vs' : 'vs-dark'}
                        value={collection.test_script || ''}
                        onMount={(editor, monaco) => {
                          editor.onDidFocusEditorText(() => setActiveScriptTarget('test_script'));
                          registerGimayCompletions(monaco);
                        }}
                        onChange={(val) => handleUpdate({ test_script: val || '' })}
                        options={{
                          minimap: { enabled: false },
                          fontSize: 13,
                          fontFamily: 'JetBrains Mono',
                          lineNumbers: 'on',
                          automaticLayout: true,
                          padding: { top: 16 }
                        }}
                      />
                    </Suspense>
                  </div>
                </div>
              </motion.div>
            )}
          </AnimatePresence>
        </div>
      </div>
      <ScriptLibraryModal
        onInsertScript={(script) => {
          const current = collection[activeScriptTarget] || '';
          handleUpdate({
            [activeScriptTarget]: current + (current ? '\n\n' : '') + script
          });
          addToast({ type: 'success', message: 'Script integrated into protocol' });
        }}
      />
    </div>
  );
};

