import React, { Suspense } from 'react';
import { useStore } from '../../store/useStore';
import { cn } from '../../lib/utils';
import { motion, AnimatePresence } from 'motion/react';
import { Clock, Database, Globe, Save, Terminal } from 'lucide-react';
import { PersistenceService } from '../../services/PersistenceService';

const Editor = React.lazy(() => import('@monaco-editor/react'));

export const ResponseViewer: React.FC = () => {
  const { lastResponse, theme } = useStore();
  const [activeTab, setActiveTab] = React.useState<'Body' | 'Headers' | 'Tests' | 'Console'>('Body');

  if (!lastResponse) {
    return (
      <div className="h-full flex flex-col items-center justify-center text-[#222222] bg-[#0A0A0A] relative overflow-hidden">
        <motion.div
          animate={{ 
            scale: [1, 1.1, 1],
            opacity: [0.05, 0.1, 0.05] 
          }}
          transition={{ 
            duration: 4, 
            repeat: Infinity, 
            ease: "easeInOut" 
          }}
        >
          <Globe size={64} className="mb-6" />
        </motion.div>
        <div className="space-y-2 text-center">
          <p className="text-[10px] font-black uppercase tracking-[0.3em] opacity-20 animate-pulse">Awaiting Signal</p>
          <div className="flex justify-center gap-1">
            {[0, 1, 2].map(i => (
              <motion.div 
                key={i}
                animate={{ opacity: [0.2, 1, 0.2] }}
                transition={{ duration: 1.5, repeat: Infinity, delay: i * 0.2 }}
                className="w-1 h-1 rounded-full bg-[#3ECF8E]"
              />
            ))}
          </div>
        </div>
      </div>
    );
  }

  const isError = lastResponse.status >= 400;
  const content = typeof lastResponse.body === 'string' ? lastResponse.body : JSON.stringify(lastResponse.body, null, 2);

  return (
    <div className="h-full flex flex-col bg-[#0A0A0A]">
      {/* Response Header */}
      <div className="h-9 px-4 border-b border-[#1A1A1A] flex items-center justify-between bg-[#0F0F0F] shrink-0">
        <div className="flex items-center gap-4">
          <div className="flex items-center gap-2">
            <div className={cn(
              "w-1.5 h-1.5 rounded-full",
              isError ? "bg-red-500 shadow-[0_0_8px_rgba(239,68,68,0.4)]" : "bg-[#3ECF8E] shadow-[0_0_8px_rgba(62,207,142,0.4)]"
            )} />
            <span className={cn(
              "text-[9px] font-black uppercase tracking-[0.15em]",
              isError ? "text-red-500" : "text-[#3ECF8E]"
            )}>
              {lastResponse.status} {lastResponse.statusText || (isError ? 'Error' : 'Success')}
            </span>
          </div>

          <div className="flex items-center gap-3 text-[#444444]">
            <div className="flex items-center gap-1">
              <Clock size={9} />
              <span className="text-[8px] font-bold tabular-nums tracking-tighter">{lastResponse.time}ms</span>
            </div>
            <div className="flex items-center gap-1">
              <Database size={9} />
              <span className="text-[8px] font-bold tabular-nums tracking-tighter">{(lastResponse.size / 1024).toFixed(2)}KB</span>
            </div>
          </div>
        </div>

        <div className="flex items-center">
            <button 
              onClick={async () => {
                const { activeTabId, addToast, profile } = useStore.getState();
                if (!activeTabId || !profile?.id) return;
                try {
                  await PersistenceService.createSavedResponse(activeTabId, profile.id, lastResponse);
                  addToast({ type: 'success', message: 'Mission footprint archived' });
                } catch (error) {
                  addToast({ type: 'error', message: 'Failed to preserve status' });
                }
              }}
              className="mr-3 px-2 py-1 flex items-center gap-1.5 text-[8px] font-black text-[#555555] hover:text-[#3ECF8E] transition-all uppercase tracking-widest hover:bg-white/5 rounded"
            >
              <Save size={10} />
              Snapshot
            </button>
            <div className="w-px h-3 bg-[#222222] mr-3" />
            <div className="flex">
              {(['Body', 'Headers', 'Tests', 'Console'] as const).map((tab) => (
                <button
                   key={tab}
                   onClick={() => setActiveTab(tab)}
                   className={cn(
                     "h-9 px-3 text-[8px] font-black uppercase tracking-[0.2em] border-b-2 transition-all relative",
                     activeTab === tab ? "border-[#3ECF8E] text-[#3ECF8E]" : "border-transparent text-[#444444] hover:text-[#888888]"
                   )}
                >
                  {tab}
                  {tab === 'Tests' && lastResponse.testResults && (
                    <span className={cn(
                      "ml-1.5 px-1 rounded-[2px] text-[7px] font-bold",
                      lastResponse.testResults.every(r => r.status === 'pass') ? "bg-[#3ECF8E]/20 text-[#3ECF8E]" : "bg-red-500/20 text-red-500"
                    )}>
                      {lastResponse.testResults.filter(r => r.status === 'pass').length}/{lastResponse.testResults.length}
                    </span>
                  )}
                  {tab === 'Console' && lastResponse.consoleLogs && lastResponse.consoleLogs.length > 0 && (
                    <span className="ml-1.5 px-1 rounded-[2px] text-[7px] font-bold bg-blue-500/20 text-blue-400">
                      {lastResponse.consoleLogs.length}
                    </span>
                  )}
                </button>
              ))}
            </div>
        </div>
      </div>

      {/* Response Content */}
      <div className="flex-1 overflow-auto custom-scrollbar p-3">
        <div className="h-full w-full rounded-lg border border-[#1A1A1A] bg-[#0F0F0F] overflow-hidden shadow-2xl">
          {activeTab === 'Body' && (
            <Suspense fallback={
              <div className="absolute inset-0 flex items-center justify-center bg-[#0F0F0F] text-[#555555] text-xs font-mono">
                Drawing response body...
              </div>
            }>
              <Editor
                height="100%"
                language={(lastResponse.contentType || '').includes('json') ? 'json' : (lastResponse.contentType || '').includes('html') ? 'html' : 'text'}
                value={content}
                theme={theme === 'light' ? 'vs' : 'vs-dark'}
                options={{
                  readOnly: true,
                  minimap: { enabled: true },
                  fontSize: 12,
                  fontFamily: 'JetBrains Mono',
                  lineNumbers: 'on',
                  scrollBeyondLastLine: false,
                  automaticLayout: true,
                  padding: { top: 20 }
                }}
              />
            </Suspense>
          )}

          {activeTab === 'Headers' && (
            <div className="p-6 space-y-2">
              {Object.entries(lastResponse.headers || {}).map(([key, value]) => (
                <div key={key} className="flex border-b border-[#222222] pb-2 last:border-0">
                  <div className="w-1/3 text-[10px] font-black text-[#555555] uppercase tracking-widest">{key}</div>
                  <div className="flex-1 text-[11px] font-mono text-[#AAAAAA] break-all">{value}</div>
                </div>
              ))}
            </div>
          )}

          {activeTab === 'Tests' && (
            <div className="p-6 space-y-4">
               {lastResponse.testResults?.map((result, i) => (
                 <div key={i} className="flex items-center justify-between p-4 bg-[#111111] rounded-xl border border-[#222222]">
                    <div className="flex items-center gap-3">
                       <div className={cn(
                         "w-1.5 h-1.5 rounded-full",
                         result.status === 'pass' ? "bg-[#3ECF8E]" : "bg-red-500"
                       )} />
                       <div className="text-[11px] font-bold text-white uppercase tracking-tight">{result.name}</div>
                    </div>
                    <div className={cn(
                      "text-[9px] font-black uppercase tracking-widest px-2 py-0.5 rounded",
                      result.status === 'pass' ? "bg-[#3ECF8E]/10 text-[#3ECF8E]" : "bg-red-500/10 text-red-500"
                    )}>
                      {result.status}
                    </div>
                 </div>
               ))}
               {(!lastResponse.testResults || lastResponse.testResults.length === 0) && (
                 <div className="h-40 flex flex-col items-center justify-center text-[#222222]">
                    <span className="text-[10px] font-black uppercase tracking-widest opacity-20">No Protocol Verifications Found</span>
                 </div>
               )}
            </div>
          )}

          {activeTab === 'Console' && (
            <div className="flex flex-col h-full bg-[#050505]">
               <div className="flex-1 overflow-y-auto font-mono text-[11px] selection:bg-[#3ECF8E]/30 custom-scrollbar divide-y divide-white/[0.03]">
                    {lastResponse.consoleLogs?.map((log, i) => (
                      <div key={i} className="flex gap-0 hover:bg-white/[0.02] transition-colors group items-start">
                        <div className="px-4 py-1.5 text-[#333333] shrink-0 tabular-nums text-[9px] border-r border-white/[0.02] bg-white/[0.01] min-w-[100px] text-center">
                          LOG-SEG-{(i+1).toString().padStart(3, '0')}
                        </div>
                        <div className="flex-1 flex gap-3 px-4 py-1.5 items-start">
                          <div className={cn(
                            "text-[7px] font-black uppercase tracking-widest px-1 py-0.5 rounded shrink-0 min-w-[40px] text-center mt-0.5 border",
                            log.level === 'error' ? "bg-red-500/10 border-red-500/20 text-red-500" :
                            log.level === 'warn' ? "bg-yellow-500/10 border-yellow-500/20 text-yellow-500" :
                            "bg-[#3ECF8E]/10 border-[#3ECF8E]/20 text-[#3ECF8E]"
                          )}>{log.level}</div>
                          
                          <div className="flex-1 overflow-x-auto no-scrollbar pb-1">
                            <div className={cn(
                              "flex flex-wrap gap-2 leading-tight font-medium",
                              log.level === 'error' ? 'text-red-400' :
                              log.level === 'warn' ? 'text-yellow-400' : 'text-[#999999]'
                            )}>
                              {(log.args || []).map((arg: any, j: number) => (
                                <div key={j} className="whitespace-pre-wrap break-all">
                                  {typeof arg === 'object' ? (
                                    <span className="text-[#3ECF8E]/80">{JSON.stringify(arg, null, 2)}</span>
                                  ) : (
                                    <span>{String(arg)}</span>
                                  )}
                                </div>
                              ))}
                            </div>
                          </div>
                        </div>
                      </div>
                    ))}
                    {(!lastResponse.consoleLogs || lastResponse.consoleLogs.length === 0) && (
                      <div className="h-64 flex flex-col items-center justify-center text-[#222222]">
                        <Terminal size={24} className="mb-4 opacity-5" />
                        <span className="text-[10px] font-black uppercase tracking-[0.4em] opacity-10">Awaiting Signal</span>
                      </div>
                    )}
               </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useMemo } from 'react';
import { useStore } from '../../store/useStore';
import { motion, AnimatePresence } from 'motion/react';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer,
  LineChart, Line, AreaChart, Area, PieChart, Pie, Cell
} from 'recharts';
import { BarChart3, Layout, PieChart as PieChartIcon, TrendingUp, Code2, Info } from 'lucide-react';
import { cn } from '../../lib/utils';

const COLORS = ['#3ECF8E', '#3b82f6', '#f59e0b', '#ef4444', '#8b5cf6', '#ec4899'];

export const VisualizerPanel: React.FC = () => {
  const { lastResponse } = useStore();
  const [viewMode, setViewMode] = React.useState<'auto' | 'html' | 'chart'>('auto');
  const [chartType, setChartType] = React.useState<'bar' | 'line' | 'area' | 'pie'>('bar');

  const data = useMemo(() => {
    if (!lastResponse?.body) return null;
    try {
      return typeof lastResponse.body === 'string' 
        ? JSON.parse(lastResponse.body) 
        : lastResponse.body;
    } catch {
      return null;
    }
  }, [lastResponse?.body]);

  const chartData = useMemo(() => {
    if (!data) return null;
    
    // If it's an array of objects, we can plot it
    if (Array.isArray(data) && data.length > 0 && typeof data[0] === 'object') {
      return data;
    }
    
    // If it's an object with a data array
    if (typeof data === 'object' && !Array.isArray(data)) {
      const arrayKey = Object.keys(data).find(key => Array.isArray(data[key]));
      if (arrayKey) return data[arrayKey];
    }
    
    return null;
  }, [data]);

  const numericKeys = useMemo(() => {
    if (!chartData || !chartData[0]) return [];
    return Object.keys(chartData[0]).filter(key => typeof chartData[0][key] === 'number');
  }, [chartData]);

  const stringKeys = useMemo(() => {
    if (!chartData || !chartData[0]) return [];
    return Object.keys(chartData[0]).filter(key => typeof chartData[0][key] === 'string');
  }, [chartData]);

  if (!data) {
    return (
      <div className="h-full flex flex-col items-center justify-center p-12 text-center space-y-4 opacity-30 grayscale">
        <Layout size={48} />
        <p className="text-[10px] font-black uppercase tracking-[0.2em]">No Data to Visualize</p>
      </div>
    );
  }

  return (
    <div className="h-full flex flex-col bg-[var(--bg-deep)]">
      {/* Visualizer Toolbar */}
      <div className="h-12 px-6 border-b border-[var(--border-subtle)] flex items-center justify-between bg-[var(--bg-surface)] shrink-0">
        <div className="flex items-center gap-4">
          <div className="flex bg-[var(--bg-elevated)] rounded-lg p-1">
            <button
              onClick={() => setViewMode('auto')}
              className={cn(
                "px-3 py-1 rounded-md text-[10px] font-black uppercase tracking-widest transition-all",
                viewMode === 'auto' ? "bg-[var(--brand)] text-[var(--bg-deep)] shadow-lg shadow-[var(--brand)]/20" : "text-[var(--text-dim)] hover:text-[var(--text-main)]"
              )}
            >
              Auto
            </button>
            <button
              onClick={() => setViewMode('chart')}
              className={cn(
                "px-3 py-1 rounded-md text-[10px] font-black uppercase tracking-widest transition-all",
                viewMode === 'chart' ? "bg-[var(--brand)] text-[var(--bg-deep)] shadow-lg shadow-[var(--brand)]/20" : "text-[var(--text-dim)] hover:text-[var(--text-main)]"
              )}
            >
              Charts
            </button>
            <button
              onClick={() => setViewMode('html')}
              className={cn(
                "px-3 py-1 rounded-md text-[10px] font-black uppercase tracking-widest transition-all",
                viewMode === 'html' ? "bg-[var(--brand)] text-[var(--bg-deep)] shadow-lg shadow-[var(--brand)]/20" : "text-[var(--text-dim)] hover:text-[var(--text-main)]"
              )}
            >
              HTML
            </button>
          </div>

          {viewMode === 'chart' && chartData && (
            <div className="flex items-center gap-1 border-l border-[var(--border-strong)] ml-2 pl-4">
              <button 
                onClick={() => setChartType('bar')}
                className={cn("p-1.5 rounded transition-all", chartType === 'bar' ? "text-[var(--brand)] bg-[var(--brand)]/10" : "text-[var(--text-dim)] hover:text-[var(--text-main)]")}
              >
                <BarChart3 size={14} />
              </button>
              <button 
                onClick={() => setChartType('line')}
                className={cn("p-1.5 rounded transition-all", chartType === 'line' ? "text-[var(--brand)] bg-[var(--brand)]/10" : "text-[var(--text-dim)] hover:text-[var(--text-main)]")}
              >
                <TrendingUp size={14} />
              </button>
              <button 
                onClick={() => setChartType('pie')}
                className={cn("p-1.5 rounded transition-all", chartType === 'pie' ? "text-[var(--brand)] bg-[var(--brand)]/10" : "text-[var(--text-dim)] hover:text-[var(--text-main)]")}
              >
                <PieChartIcon size={14} />
              </button>
            </div>
          )}
        </div>

        <div className="flex items-center gap-2">
            <span className="text-[9px] font-black text-[var(--text-dim)] uppercase tracking-tighter bg-[var(--bg-elevated)] px-2 py-0.5 rounded">
              Engine V1.0
            </span>
        </div>
      </div>

      {/* Surface Area */}
      <div className="flex-1 overflow-auto p-8 bg-[var(--bg-deep)]">
        <AnimatePresence mode="wait">
          {viewMode === 'chart' && (
            <div className="h-full space-y-8 animate-in fade-in duration-200">
              {chartData ? (
                <div className="w-full bg-[var(--bg-surface)] border border-[var(--border-subtle)] rounded-2xl p-6 shadow-xl flex flex-col justify-between">
                  {/* Header metadata */}
                  <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4 mb-8">
                    <div>
                      <h4 className="text-[10px] font-black text-white uppercase tracking-widest font-mono flex items-center gap-2">
                        <span className="w-2 h-2 rounded-full bg-[#3ECF8E] animate-pulse" />
                        {chartType.toUpperCase()} Telemetry Breakdown
                      </h4>
                      <p className="text-[8px] text-[var(--text-dim)] font-mono uppercase tracking-tight mt-1">
                        Active rendering of first 15 structural points to preserve interface performance
                      </p>
                    </div>
                    <div className="flex flex-wrap gap-3">
                      {numericKeys.slice(0, 3).map((key, idx) => (
                        <div key={key} className="flex items-center gap-2 text-[9px] font-mono text-[var(--text-dim)] uppercase bg-[#000]/25 px-2.5 py-1 rounded-md border border-[var(--border-subtle)]/30">
                          <span className="w-1.5 h-1.5 rounded-full" style={{ backgroundColor: COLORS[idx % COLORS.length] }} />
                          <span className="text-white font-black">{key}</span>
                        </div>
                      ))}
                    </div>
                  </div>

                  {/* Core Bars Rendering Stage */}
                  <div className="h-[280px] flex items-end gap-3 border-b border-[var(--border-strong)] pb-2 pt-6 overflow-x-auto no-scrollbar">
                    {chartData.slice(0, 15).map((node: any, idx: number) => {
                      const label = String(node[stringKeys[0]] || node['id'] || node['name'] || `Item ${idx + 1}`);
                      return (
                        <div key={idx} className="flex-1 flex flex-col items-center justify-end h-full min-w-[36px] group relative">
                          <div className="w-full flex gap-1 justify-center items-end h-[220px]">
                            {numericKeys.slice(0, 2).map((key, keyIdx) => {
                              const val = Number(node[key]) || 0;
                              // Walk correct maximum limit
                              const maxVal = Math.max(...chartData.map((d: any) => Number(d[key]) || 1)) || 1;
                              const heightPercent = Math.max(3, Math.min(100, (val / maxVal) * 100));
                              return (
                                <div
                                  key={key}
                                  className="w-full rounded-t-lg relative group/bar cursor-pointer transition-all duration-300 hover:scale-x-105 hover:brightness-125 shadow-lg"
                                  style={{
                                    height: `${heightPercent}%`,
                                    backgroundColor: COLORS[keyIdx % COLORS.length],
                                  }}
                                >
                                  {/* Hover Floating Tooltip widget */}
                                  <div className="absolute bottom-full mb-2.5 left-1/2 -translate-x-1/2 bg-[#0C0C10]/95 border border-[#1E1E28] text-white text-[8px] font-mono p-3 rounded-lg shadow-2xl opacity-0 translate-y-2 group-hover/bar:opacity-100 group-hover/bar:translate-y-0 transition-all z-50 pointer-events-none whitespace-nowrap backdrop-blur-md">
