                  <BarChart3 size={32} className="mb-4 text-[var(--brand)]" />
                  <h3 className="text-sm font-black text-[var(--text-main)] uppercase tracking-[0.2em] mb-2">Incompatible Data Structure</h3>
                  <p className="text-[10px] text-[var(--text-dim)] max-w-xs uppercase leading-relaxed font-mono">Charts require an array of objects with numeric properties to render correctly.</p>
                </div>
              )}

              {chartData && (
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                   {numericKeys.map((key, i) => {
                      const values = chartData.map((d: any) => d[key]);
                      let max = 0;
                      let min = 0;
                      if (values.length > 0) {
                        max = values[0];
                        min = values[0];
                        for (const val of values) {
                          if (val > max) max = val;
                          if (val < min) min = val;
                        }
                      }
                      const sum = values.reduce((a: number, b: number) => a + b, 0);
                      const avg = values.length > 0 ? sum / values.length : 0;

                      return (
                        <div key={key} className="bg-[var(--bg-surface)] border border-[var(--border-subtle)] p-6 rounded-2xl shadow-lg">
                           <div className="text-[9px] font-black text-[var(--text-dim)] uppercase tracking-widest mb-4 flex items-center justify-between">
                              <span>{key}</span>
                              <div className="w-2 h-2 rounded-full" style={{ backgroundColor: COLORS[i % COLORS.length] }} />
                           </div>
                           <div className="grid grid-cols-2 gap-4">
                              <div className="space-y-1">
                                 <p className="text-[8px] text-[var(--text-dim)] uppercase">Average</p>
                                 <p className="text-xl font-black text-[var(--text-main)]">{avg.toLocaleString(undefined, { maximumFractionDigits: 1 })}</p>
                              </div>
                              <div className="space-y-1">
                                 <p className="text-[8px] text-[var(--text-dim)] uppercase">Peak</p>
                                 <p className="text-xl font-black text-[var(--brand)]">{max.toLocaleString()}</p>
                              </div>
                           </div>
                        </div>
                      );
                   })}
                </div>
              )}
            </div>
          )}

          {viewMode === 'html' && (
            <div className="h-full flex flex-col bg-[var(--bg-surface)] border border-[var(--border-subtle)] rounded-2xl overflow-hidden shadow-2xl">
              <div className="h-10 px-4 border-b border-[var(--border-subtle)] bg-[var(--bg-deep)] flex items-center justify-between">
                 <div className="flex items-center gap-2">
                    <Code2 size={12} className="text-amber-500" />
                    <span className="text-[9px] font-black text-[var(--text-dim)] uppercase tracking-widest">Isolated HTML Rendering</span>
                 </div>
                 <div className="flex items-center gap-4">
                    <div className="flex items-center gap-1">
                       <div className="w-1.5 h-1.5 rounded-full bg-green-500 shadow-[0_0_8px_rgba(34,197,94,0.4)]" />
                       <span className="text-[8px] font-bold text-[var(--text-dim)] uppercase">Safe Shell</span>
                    </div>
                 </div>
              </div>
              <div className="flex-1 bg-white">
                <iframe 
                  title="visualizer-output"
                  srcDoc={lastResponse?.contentType?.includes('html') ? lastResponse.body : `
                    <html>
                      <head>
                        <style>
                          body { font-family: -apple-system, system-ui, sans-serif; padding: 40px; color: #333; background: #fff; line-height: 1.6; }
                          .header { margin-bottom: 30px; border-bottom: 2px solid #000; padding-bottom: 20px; }
                          h1 { margin: 0; font-size: 24px; text-transform: uppercase; letter-spacing: 2px; }
                          pre { background: #f5f5f5; padding: 20px; border-radius: 8px; font-size: 13px; overflow: auto; border: 1px solid #ddd; }
                          .badge { background: #3ECF8E; color: #000; padding: 4px 8px; border-radius: 4px; font-size: 11px; font-weight: bold; }
                        </style>
                      </head>
                      <body>
                        <div class="header">
                          <span class="badge">API Response Visualized</span>
                          <h1>Raw Data View</h1>
                        </div>
                        <pre>${JSON.stringify(data, null, 2)}</pre>
                      </body>
                    </html>
                  `}
                  className="w-full h-full border-none"
                />
              </div>
            </div>
          )}

          {viewMode === 'auto' && (
            <div className="space-y-6">
               <div className="flex items-start gap-6">
                  <div className="flex-1 bg-[var(--bg-surface)] border border-[var(--border-subtle)] rounded-2xl p-8 shadow-xl">
                     <div className="flex items-center gap-3 mb-8">
                        <div className="w-10 h-10 rounded-xl bg-[var(--brand)]/10 border border-[var(--brand)]/30 flex items-center justify-center">
                           <Info size={20} className="text-[var(--brand)]" />
                        </div>
                        <div>
                           <h2 className="text-[12px] font-black text-[var(--text-main)] uppercase tracking-[0.2em]">Intel Analysis</h2>
                           <p className="text-[9px] text-[var(--text-dim)] uppercase tracking-widest mt-1">Structural Meta-Examination</p>
                        </div>
                     </div>

                     <div className="grid grid-cols-2 lg:grid-cols-4 gap-8">
                        <div className="space-y-1">
                           <p className="text-[8px] text-[var(--text-dim)] uppercase tracking-widest">Data Type</p>
                           <p className="text-[13px] font-bold text-[var(--brand)] uppercase">{Array.isArray(data) ? 'Collection' : 'Object Shell'}</p>
                        </div>
                        <div className="space-y-1">
                           <p className="text-[8px] text-[var(--text-dim)] uppercase tracking-widest">Entry Nodes</p>
                           <p className="text-[13px] font-bold text-[var(--text-main)]">{Array.isArray(data) ? data.length : Object.keys(data).length}</p>
                        </div>
                        <div className="space-y-1">
                           <p className="text-[8px] text-[var(--text-dim)] uppercase tracking-widest">Depth Index</p>
                           <p className="text-[13px] font-bold text-[var(--text-main)]">Level {calculateDepth(data)}</p>
                        </div>
                        <div className="space-y-1">
                           <p className="text-[8px] text-[var(--text-dim)] uppercase tracking-widest">Weight</p>
                           <p className="text-[13px] font-bold text-[var(--text-main)]">{(JSON.stringify(data).length / 1024).toFixed(2)} KB</p>
                        </div>
                     </div>
                  </div>
               </div>

               {Array.isArray(data) && data.length > 0 && typeof data[0] === 'object' && (
                  <div className="bg-[var(--bg-surface)] border border-[var(--border-subtle)] rounded-2xl overflow-hidden shadow-2xl">
                     <div className="px-6 py-4 border-b border-[var(--border-subtle)] bg-[var(--bg-elevated)] flex items-center justify-between">
                        <div className="flex items-center gap-2">
                           <Layout size={14} className="text-[var(--brand)]" />
                           <span className="text-[10px] font-black text-[var(--text-main)] uppercase tracking-widest">Grid Inspector</span>
                        </div>
                        <span className="text-[9px] font-bold text-[var(--text-dim)] uppercase">{data.length} Records Detected</span>
                     </div>
                     <div className="overflow-x-auto min-h-[300px]">
                        <table className="w-full border-collapse">
                           <thead>
                              <tr className="bg-[var(--bg-deep)] border-b border-[var(--border-subtle)]">
                                 {Object.keys(data[0]).slice(0, 8).map(key => (
                                    <th key={key} className="px-6 py-3 text-left text-[9px] font-black text-[var(--text-dim)] uppercase tracking-widest">{key}</th>
                                 ))}
                              </tr>
                           </thead>
                           <tbody className="divide-y divide-[var(--border-subtle)]/30">
                              {data.slice(0, 10).map((row, i) => (
                                 <tr key={i} className="hover:bg-[var(--bg-elevated)]/50 transition-all">
                                    {Object.values(row).slice(0, 8).map((val: any, j) => (
                                       <td key={j} className="px-6 py-3 text-[11px] font-medium text-[var(--text-muted)] truncate max-w-[200px]">
                                          {typeof val === 'object' ? '{...}' : String(val)}
                                       </td>
                                    ))}
                                 </tr>
                              ))}
                           </tbody>
                        </table>
                        {data.length > 10 && (
                           <div className="p-4 text-center border-t border-[var(--border-subtle)] bg-[var(--bg-deep)]">
                              <p className="text-[9px] text-[var(--text-dim)] uppercase tracking-widest">Truncated View - Showing first 10 entries</p>
                           </div>
                        )}
                     </div>
                  </div>
               )}
            </div>
          )}
        </AnimatePresence>
      </div>
    </div>
  );
};

function calculateDepth(obj: any, currentDepth = 0): number {
  if (currentDepth > 10) return 10;
  if (typeof obj !== 'object' || obj === null) return 0;
  
  if (Array.isArray(obj)) {
    if (obj.length === 0) return 1;
    const sample = obj.slice(0, 5);
    return 1 + Math.max(0, ...sample.map(val => calculateDepth(val, currentDepth + 1)));
  }

  const keys = Object.keys(obj);
  if (keys.length === 0) return 1;
  const maxKeysToCheck = keys.slice(0, 15);
  return 1 + Math.max(0, ...maxKeysToCheck.map(key => calculateDepth(obj[key], currentDepth + 1)));
}

import React, { useState, useEffect, useRef } from 'react';
import { 
  CheckCircle2, 
  Copy, 
  Download, 
  Search, 
  Terminal,
  Activity,
  Clock,
  Database,
  Layout,
  Sparkles,
  Eye,
  FileCode
} from 'lucide-react';
import { useStore } from '../../store/useStore';
import { cn } from '../../lib/utils';
import { motion } from 'motion/react';
import Editor from 'react-simple-code-editor';
import { highlight, languages } from 'prismjs';
import 'prismjs/components/prism-json';
import '../../themes/prism-gimay.css';

export const ResponseViewer: React.FC = () => {
  const { lastResponse, isSending, addToast } = useStore();
  const [activeView, setActiveView] = useState<'pretty' | 'raw' | 'headers' | 'tests'>('pretty');
  const [shouldBeautify, setShouldBeautify] = useState(true);

  if (isSending) {
    return <LoadingState />;
  }

  if (!lastResponse) {
    return <EmptyResponseState />;
  }

  const getFormattedBody = () => {
    if (!lastResponse || !lastResponse.body) return '';
    const bodyStr = typeof lastResponse.body === 'object' 
      ? JSON.stringify(lastResponse.body, null, 2)
      : lastResponse.body;
      
    if (!shouldBeautify) {
      return bodyStr;
    }
    
    try {
      const parsed = typeof lastResponse.body === 'string' ? JSON.parse(lastResponse.body) : lastResponse.body;
      return JSON.stringify(parsed, null, 2);
    } catch (e) {
      return bodyStr;
    }
  };

  const isSuccess = lastResponse.status >= 200 && lastResponse.status < 300;

  return (
    <div className="h-full flex flex-col bg-[#0A0A0A] border-l border-[#222222]">
      {/* Response Metrics */}
      <div className="h-14 border-b border-[#222222] flex items-center px-6 justify-between bg-[#141414]">
        <div className="flex items-center gap-6">
          <div className="flex items-center gap-2">
            <div className={cn(
              "w-2 h-2 rounded-full",
              isSuccess ? "bg-[#3ECF8E]" : "bg-red-500"
            )} />
            <span className={cn(
              "text-[11px] font-black uppercase tracking-widest",
              isSuccess ? "text-[#3ECF8E]" : "text-red-500"
            )}>
              {lastResponse.status} {lastResponse.statusText}
            </span>
          </div>
          <div className="flex items-center gap-2 text-[#555555]">
            <Clock size={12} />
            <span className="text-[10px] font-mono">{lastResponse.time}ms</span>
          </div>
          <div className="flex items-center gap-2 text-[#555555]">
            <Database size={12} />
            <span className="text-[10px] font-mono">{(lastResponse.size / 1024).toFixed(2)} KB</span>
          </div>
        </div>

        <div className="flex gap-1 bg-[#0A0A0A] p-1 rounded-lg border border-[#222222]">
          {[
            { id: 'pretty', icon: Eye, label: 'PRETTY' },
            { id: 'raw', icon: FileCode, label: 'RAW' },
            { id: 'headers', icon: Layout, label: 'HEADERS' },
            { id: 'tests', icon: Terminal, label: 'TESTS' }
          ].map(view => (
            <button 
              key={view.id}
              onClick={() => setActiveView(view.id as any)}
              className={cn(
                "px-3 py-1.5 rounded-md text-[9px] font-black uppercase tracking-widest transition-all flex items-center gap-1.5",
                activeView === view.id 
                  ? "bg-[#3ECF8E] text-[#0A0A0A]" 
                  : "text-[#444444] hover:text-[#AAAAAA]"
              )}
            >
              <view.icon size={12} />
              <span className="hidden xl:inline">{view.label}</span>
            </button>
          ))}
        </div>
      </div>

      {/* Main Response Area */}
      <div className="flex-1 overflow-hidden flex flex-col">
        <div className="flex-1 overflow-y-auto custom-scrollbar p-6">
          {activeView === 'pretty' && (
            <div className="font-mono text-xs text-[#AAAAAA]">
              <Editor
                value={getFormattedBody()}
                onValueChange={() => {}}
                highlight={(code) => highlight(code, languages.json, 'json')}
                padding={10}
                className="prism-editor bg-[#0A0A0A]"
                readOnly
              />
            </div>
          )}

          {activeView === 'raw' && (
            <div className="font-mono text-xs text-[#AAAAAA] whitespace-pre-wrap break-all bg-[#0A0A0A] p-4 rounded-xl border border-white/[0.03]">
              {typeof lastResponse.body === 'object' ? JSON.stringify(lastResponse.body) : lastResponse.body}
            </div>
          )}

          {activeView === 'headers' && (
            <div className="space-y-2">
              {Object.entries(lastResponse.headers).map(([key, value]) => (
                <div key={key} className="flex border-b border-[#222222] py-2 group">
                  <span className="w-48 text-[10px] font-black text-[#555555] uppercase tracking-wider">{key}</span>
                  <span className="flex-1 text-[11px] font-mono text-[#AAAAAA] break-all">{value}</span>
                </div>
              ))}
            </div>
          )}
        </div>

        {/* Action Bar */}
        <div className="h-10 border-t border-[#222222] bg-[#0F0F0F] px-4 flex items-center justify-between">
           <div className="text-[9px] font-mono text-[#333333] uppercase flex items-center gap-4">
             <span>{lastResponse.contentType}</span>
             {activeView === 'pretty' && (
               <button 
                 onClick={() => {
                   try {
                     const bodyStr = typeof lastResponse.body === 'object' 
                       ? JSON.stringify(lastResponse.body) 
                       : lastResponse.body;
                     JSON.parse(bodyStr);
                     setShouldBeautify(!shouldBeautify);
                     addToast({ 
                       type: 'success', 
                       message: shouldBeautify ? 'Beautifier disabled.' : 'Beautifier enabled.' 
                     });
                   } catch (e) {
                     addToast({ 
                       type: 'error', 
                       message: 'Response payload is not valid JSON.' 
                     });
                   }
                 }}
                 className={cn(
                   "px-2 py-0.5 rounded border text-[8px] font-black uppercase tracking-widest transition-all flex items-center gap-1 cursor-pointer active:scale-95 shadow-sm",
                   shouldBeautify 
                     ? "bg-[#3ECF8E]/20 text-[#3ECF8E] border-[#3ECF8E]/40" 
                     : "border-[#222222] text-[#555555] hover:border-[#444444]"
                 )}
               >
                 <Sparkles size={10} />
                 <span>Beautify</span>
               </button>
             )}
           </div>
           <div className="flex gap-4">
             <button className="text-[#444444] hover:text-[#3ECF8E] transition-all flex items-center gap-2">
               <Copy size={12} /> <span className="text-[9px] font-black uppercase tracking-widest">Copy Body</span>
             </button>
             <button className="text-[#444444] hover:text-[#3ECF8E] transition-all flex items-center gap-2">
               <Download size={12} /> <span className="text-[9px] font-black uppercase tracking-widest">Download</span>
             </button>
           </div>
        </div>
      </div>
    </div>
  );
};

const LoadingState = () => {
  return (
    <div className="h-full flex flex-col items-center justify-center bg-[#0A0A0A] overflow-hidden select-none">
      <div className="relative w-40 h-40 flex items-center justify-center">
        {/* Outer Ring 1: Glowing Emerald dashed */}
        <div className="absolute inset-0 rounded-full border border-dashed border-[#3ECF8E]/40 animate-[spin_8s_linear_infinite]" />
        
        {/* Outer Ring 2: Electric Blue gradient line */}
        <div className="absolute inset-4 rounded-full border-2 border-transparent border-t-[#3ECF8E] border-b-blue-500 animate-[spin_3s_linear_infinite]" />
        
        {/* Ring 3: Deep blue pulse */}
        <div className="absolute inset-8 rounded-full border border-blue-400/20 animate-ping opacity-60" />
        
        {/* Center Orb: Glassmorphic sphere with glowing radial background */}
        <div className="absolute inset-12 rounded-full bg-gradient-to-tr from-[#3ECF8E]/20 to-blue-500/20 backdrop-blur-md border border-white/[0.08] shadow-[0_0_24px_rgba(62,207,142,0.3)] flex items-center justify-center">
          <Activity size={28} className="text-[#3ECF8E] animate-pulse" />
        </div>

        {/* Orbiting data packets */}
        <div className="absolute w-2 h-2 bg-[#3ECF8E] rounded-full shadow-[0_0_8px_#3ECF8E] animate-[orbit_2.5s_linear_infinite]" />
        <div className="absolute w-1.5 h-1.5 bg-blue-400 rounded-full shadow-[0_0_6px_#60A5FA] animate-[orbit_2.5s_linear_infinite_1.25s]" />
      </div>

      <div className="text-center mt-8 space-y-2 z-10">
        <h3 className="text-xs font-black text-white uppercase tracking-[0.3em] animate-pulse">
          Transmitting Packet
        </h3>
        <p className="text-[8px] text-[var(--text-dim)] uppercase tracking-widest font-mono">
          Model execution active • payload resolving
        </p>
      </div>

      <style>{`
        @keyframes orbit {
          0% { transform: rotate(0deg) translateX(70px) rotate(0deg); }
          100% { transform: rotate(360deg) translateX(70px) rotate(-360deg); }
        }
      `}</style>
    </div>
  );
};

