export enum ExportFormat {
  POSTMAN = 'postman',
  INSOMNIA = 'insomnia',
  HOPPSCOTCH = 'hoppscotch',
  BRUNO = 'bruno',
  OPENAPI_V3 = 'openapi_v3',
  CURL_BUNDLE = 'curl_bundle',
  JSON = 'json',
  JMETER = 'jmeter'
}

export class CollectionExportService {
  static exportCollection(collection: Collection, format: ExportFormat = ExportFormat.POSTMAN) {
    if (format === ExportFormat.CURL_BUNDLE) {
      return this.exportCurlBundle(collection);
    }
    if (format === ExportFormat.JMETER) {
      return this.exportJMeter(collection);
    }
    const postmanCollection = {
      info: {
        name: collection.name,
        schema: 'https://schema.getpostman.com/json/collection/v2.1.0/collection.json',
        _postman_id: collection.id,
        description: collection.description || ''
      },
      item: this.processItems(collection),
      event: this.processScripts(collection.pre_request_script, collection.test_script),
      variable: (collection.variables || []).map(v => ({
        key: v.key,
        value: v.value,
        type: 'string'
      })),
      auth: this.processAuth(collection.auth)
    };

    const blob = new Blob([JSON.stringify(postmanCollection, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `${collection.name.replace(/\s+/g, '_')}.postman_collection.json`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  }

  static pruneCollection(collection: Collection, selectedIds: Set<string>): Collection {
    const pruned = JSON.parse(JSON.stringify(collection));
    // Implementation to remove non-selected items
    const filterNodes = (nodes: any[]): any[] => {
      return nodes.filter(node => selectedIds.has(node.id)).map(node => {
        if (node.folders) node.folders = filterNodes(node.folders);
        if (node.requests) node.requests = node.requests.filter((r: any) => selectedIds.has(r.id));
        return node;
      });
    };
    if (pruned.folders) pruned.folders = filterNodes(pruned.folders);
    if (pruned.requests) pruned.requests = pruned.requests.filter((r: any) => selectedIds.has(r.id));
    return pruned;
  }

  static exportCurlBundle(collection: Collection) {
    let script = '#!/bin/bash\n\n';
    const processItems = (items: any[]) => {
      items.forEach(item => {
        if (item.method && item.url) {
          script += `curl -X ${item.method} "${item.url}" \\\n`;
          (item.headers || []).forEach((h: any) => {
            if (h.active) script += `  -H "${h.key}: ${h.value}" \\\n`;
          });
          script += '\n';
        }
      });
    };
    processItems(collection.requests || []);
    
    const blob = new Blob([script], { type: 'text/x-shellscript' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `${collection.name.replace(/\s+/g, '_')}.sh`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  }

  private static processItems(collection: Collection): any[] {
    const items: any[] = [];

    // Map folders
    (collection.folders || []).forEach(folder => {
      items.push(this.mapFolderToItem(folder));
    });

    // Map root requests
    (collection.requests || []).filter(r => !r.folder_id).forEach(request => {
      items.push(this.mapRequestToItem(request));
    });

    return items;
  }

  private static mapFolderToItem(folder: Folder): any {
    return {
      name: folder.name,
      item: [
        ...(folder.folders || []).map(f => this.mapFolderToItem(f)),
        ...(folder.requests || []).map(r => this.mapRequestToItem(r))
      ],
      description: folder.description || '',
      event: this.processScripts('', ''), // Folders can have scripts but we use inheritance logic
      auth: this.processAuth(folder.auth)
    };
  }

  private static mapRequestToItem(request: RequestData): any {
    return {
      name: request.name,
      request: {
        method: request.method,
        header: (request.headers || []).map(h => ({
          key: h.key,
          value: h.value,
          disabled: !h.active
        })),
        body: this.processBody(request.body, request.bodyType),
        url: {
          raw: request.url,
          protocol: request.url.split('://')[0],
          host: request.url.split('://')[1]?.split('/')[0].split('.') || [],
          path: request.url.split('://')[1]?.split('/').slice(1) || [],
          query: (request.params || []).map(p => ({
            key: p.key,
            value: p.value,
            disabled: !p.active
          }))
        },
        auth: this.processAuth(request.auth),
        description: ''
      },
      event: this.processScripts(request.pre_request_script, request.test_script)
    };
  }

  private static processScripts(preRequest?: string, test?: string) {
    const events = [];
    if (preRequest) {
      events.push({
        listen: 'prerequest',
        script: {
          type: 'text/javascript',
          exec: preRequest.split('\n')
        }
      });
    }
    if (test) {
      events.push({
        listen: 'test',
        script: {
          type: 'text/javascript',
          exec: test.split('\n')
        }
      });
    }
    return events;
  }

  private static processAuth(auth: any) {
    if (!auth || auth.type === 'inherit') return null;
    return {
      type: auth.type,
      [auth.type]: Object.entries(auth.config || {}).map(([key, value]) => ({
        key,
        value,
        type: 'string'
      }))
    };
  }

  private static processBody(body: any, type: string) {
    if (type === 'none') return null;
    return {
      mode: type === 'json' ? 'raw' : type,
      raw: body,
      options: type === 'json' ? { raw: { language: 'json' } } : undefined
    };
  }

  static exportJMeter(collection: Collection) {
    const escapeXml = (unsafe: string) => {
      if (!unsafe) return '';
      return unsafe.replace(/[<>&'"]/g, (c) => {
        switch (c) {
          case '<': return '&lt;';
          case '>': return '&gt;';
          case '&': return '&amp;';
          case '\'': return '&apos;';
          case '"': return '&quot;';
          default: return c;
        }
      });
    };

    let xml = `<?xml version="1.0" encoding="UTF-8"?>
<jmeterTestPlan version="1.2" properties="5.0" jmeter="5.4.1">
  <hashTree>
    <TestPlan guiclass="TestPlanGui" testclass="TestPlan" testname="${escapeXml(collection.name)}" enabled="true">
      <stringProp name="TestPlan.comments">${escapeXml(collection.description || '')}</stringProp>
      <boolProp name="TestPlan.functional_mode">false</boolProp>
      <boolProp name="TestPlan.tearDown_on_shutdown">true</boolProp>
      <boolProp name="TestPlan.serialize_threadgroups">false</boolProp>
      <elementProp name="TestPlan.user_defined_variables" elementType="Arguments" guiclass="ArgumentsPanel" testclass="Arguments" testname="User Defined Variables" enabled="true">
        <collectionProp name="Arguments.arguments">`;

    (collection.variables || []).forEach(v => {
      xml += `
          <elementProp name="${escapeXml(v.key)}" elementType="Argument">
            <stringProp name="Argument.name">${escapeXml(v.key)}</stringProp>
            <stringProp name="Argument.value">${escapeXml(v.value)}</stringProp>
            <stringProp name="Argument.metadata">=</stringProp>
          </elementProp>`;
    });

    xml += `
        </collectionProp>
      </elementProp>
      <stringProp name="TestPlan.user_define_classpath"></stringProp>
    </TestPlan>
    <hashTree>
      <ThreadGroup guiclass="ThreadGroupGui" testclass="ThreadGroup" testname="Thread Group" enabled="true">
        <stringProp name="ThreadGroup.on_sample_error">continue</stringProp>
        <elementProp name="ThreadGroup.main_controller" elementType="LoopController" guiclass="LoopControlPanel" testclass="LoopController" testname="Loop Controller" enabled="true">
          <boolProp name="LoopController.continue_forever">false</boolProp>
          <stringProp name="LoopController.loops">1</stringProp>
        </elementProp>
        <stringProp name="ThreadGroup.num_threads">1</stringProp>
        <stringProp name="ThreadGroup.ramp_time">1</stringProp>
        <boolProp name="ThreadGroup.scheduler">false</boolProp>
        <stringProp name="ThreadGroup.duration"></stringProp>
        <stringProp name="ThreadGroup.delay"></stringProp>
        <boolProp name="ThreadGroup.same_user_on_next_iteration">true</boolProp>
      </ThreadGroup>
      <hashTree>`;

    const requests: RequestData[] = [];
    const collectRequests = (node: any) => {
      if (node.requests) {
        node.requests.forEach((r: any) => requests.push(r));
      }
      if (node.folders) {
        node.folders.forEach((f: any) => collectRequests(f));
      }
    };
    
    collectRequests(collection);

    requests.forEach((req) => {
      let protocol = 'http';
      let domain = '';
      let port = '';
      let path = '';

      try {
        if (req.url) {
          const urlStr = req.url.trim();
          if (urlStr.startsWith('http://') || urlStr.startsWith('https://')) {
            const urlObj = new URL(urlStr);
            protocol = urlObj.protocol.replace(':', '');
            domain = urlObj.hostname;
            port = urlObj.port;
            path = urlObj.pathname + urlObj.search;
          } else {
            path = urlStr;
          }
        }
      } catch {
        path = req.url || '';
      }

      const hasRawBody = req.bodyType === 'json' || req.bodyType === 'raw' || req.bodyType === 'xml';
      const bodyContent = typeof req.body === 'string' ? req.body : req.body?.content || '';

      xml += `
        <HTTPSamplerProxy guiclass="HttpTestSampleGui" testclass="HTTPSamplerProxy" testname="${escapeXml(req.name)}" enabled="true">`;

      if (hasRawBody && bodyContent) {
        xml += `
          <boolProp name="HTTPSampler.postBodyRaw">true</boolProp>
          <elementProp name="HTTPsampler.Arguments" elementType="Arguments">
            <collectionProp name="Arguments.arguments">
              <elementProp name="" elementType="HTTPArgument">
                <boolProp name="HTTPArgument.always_encode">false</boolProp>
                <stringProp name="Argument.value">${escapeXml(bodyContent)}</stringProp>
                <stringProp name="Argument.metadata">=</stringProp>
              </elementProp>
            </collectionProp>
          </elementProp>`;
      } else {
        xml += `
          <elementProp name="HTTPsampler.Arguments" elementType="Arguments" guiclass="HTTPArgumentsPanel" testclass="Arguments" testname="User Defined Variables" enabled="true">
            <collectionProp name="Arguments.arguments">`;
        
        (req.params || []).forEach(p => {
          if (p.active) {
            xml += `
              <elementProp name="${escapeXml(p.key)}" elementType="HTTPArgument">
                <boolProp name="HTTPArgument.always_encode">true</boolProp>
                <stringProp name="Argument.value">${escapeXml(p.value)}</stringProp>
                <stringProp name="Argument.metadata">=</stringProp>
                <boolProp name="HTTPArgument.use_equals">true</boolProp>
                <stringProp name="Argument.name">${escapeXml(p.key)}</stringProp>
              </elementProp>`;
          }
        });

        xml += `
            </collectionProp>
          </elementProp>`;
      }

      xml += `
          <stringProp name="HTTPSampler.domain">${escapeXml(domain)}</stringProp>
          <stringProp name="HTTPSampler.port">${escapeXml(port)}</stringProp>
          <stringProp name="HTTPSampler.protocol">${escapeXml(protocol)}</stringProp>
          <stringProp name="HTTPSampler.contentEncoding">UTF-8</stringProp>
          <stringProp name="HTTPSampler.path">${escapeXml(path)}</stringProp>
          <stringProp name="HTTPSampler.method">${escapeXml(req.method || 'GET')}</stringProp>
          <boolProp name="HTTPSampler.follow_redirects">true</boolProp>
          <boolProp name="HTTPSampler.auto_redirects">false</boolProp>
          <boolProp name="HTTPSampler.use_keepalive">true</boolProp>
          <boolProp name="HTTPSampler.DO_MULTIPART_POST">false</boolProp>
          <stringProp name="HTTPSampler.embedded_url_re"></stringProp>
          <stringProp name="HTTPSampler.connect_timeout"></stringProp>
          <stringProp name="HTTPSampler.response_timeout"></stringProp>
        </HTTPSamplerProxy>
        <hashTree>`;

      const activeHeaders = (req.headers || []).filter(h => h.active);
      if (activeHeaders.length > 0) {
        xml += `
          <HeaderManager guiclass="HeaderPanel" testclass="HeaderManager" testname="HTTP Header Manager" enabled="true">
            <collectionProp name="HeaderManager.headers">`;
        
        activeHeaders.forEach(h => {
          xml += `
              <elementProp name="" elementType="Header">
                <stringProp name="Header.name">${escapeXml(h.key)}</stringProp>
                <stringProp name="Header.value">${escapeXml(h.value)}</stringProp>
              </elementProp>`;
        });

        xml += `
            </collectionProp>
          </HeaderManager>
          <hashTree/>`;
      }

      xml += `
        </hashTree>`;
    });

    xml += `
      </hashTree>
    </hashTree>
  </hashTree>
</jmeterTestPlan>`;

    const blob = new Blob([xml], { type: 'application/xml' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `${collection.name.replace(/\s+/g, '_')}.jmx`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  }
}

import { BodyType, HttpMethod, RequestBody } from '../types';
import { PersistenceService } from './PersistenceService';
import { RequestUtils } from '../utils/RequestUtils';
import yaml from 'js-yaml';

export type ImportFormat = 'postman' | 'insomnia' | 'apidog' | 'openapi';

export type ImportNode =
  | { id?: string; type: 'folder'; name: string; children: ImportNode[] }
  | {
    id?: string;
    type: 'request';
    name: string;
    request: {
      method: HttpMethod;
      url: string;
      headers: Array<{ key: string; value: string; active: boolean }>;
      params: Array<{ key: string; value: string; active: boolean }>;
      body: RequestBody;
      bodyType: BodyType;
      pre_request_script: string;
      test_script: string;
      auth: any;
    };
  };

type NormalizedImport = {
  name: string;
  variables: Array<{ key: string; value: string; active: boolean }>;
  pre_request_script?: string;
  test_script?: string;
  documentation?: string;
  items: ImportNode[];
};

export type ImportPreview = {
  format: ImportFormat;
  normalized: NormalizedImport;
  stats: {
    folders: number;
    requests: number;
    variables: number;
    scripts: number;
  };
  warnings: string[];
};

export class CollectionImportService {
  static previewImport(raw: string, sourceHint: ImportFormat | 'auto' = 'auto'): ImportPreview {
    let parsed: any;
    try {
      parsed = JSON.parse(raw);
    } catch {
      try {
        parsed = yaml.load(raw);
      } catch {
        throw new Error('Invalid JSON or YAML. Please paste or upload a valid export file.');
      }
    }

    const format = sourceHint === 'auto' ? this.detectFormat(parsed) : sourceHint;
    if (!format) {
      throw new Error('Unsupported import format. Supported formats: Postman, API Dog, Insomnia.');
    }

    const normalized =
      format === 'postman'
        ? this.parsePostman(parsed)
        : format === 'insomnia'
          ? this.parseInsomnia(parsed)
          : format === 'apidog'
            ? this.parseApiDog(parsed)
            : this.parseOpenApi(parsed);

    if (!normalized.name || !normalized.items.length) {
      throw new Error('No importable collection data found in this export.');
    }

    let idCounter = 0;
    const assignIds = (nodes: ImportNode[], parentPath = '') => {
      nodes.forEach((node) => {
        const currentPath = parentPath ? `${parentPath}/${node.name}` : node.name;
        node.id = `${currentPath}::${idCounter++}`;
        if (node.type === 'folder') {
          assignIds(node.children, currentPath);
        }
      });
    };
    assignIds(normalized.items);

    const stats = this.collectStats(normalized);
    const warnings: string[] = [];
    if (stats.requests === 0) warnings.push('No requests detected in this file.');

    return { format, normalized, stats, warnings };
  }

  static async importCollection(
    jsonString: string,
    workspaceId: string,
    userId: string,
    sourceHint: ImportFormat | 'auto' = 'auto',
    selectedNodeIds?: string[]
  ) {
    const preview = this.previewImport(jsonString, sourceHint);

    const collection = await PersistenceService.createCollection(workspaceId, userId, preview.normalized.name);
    await PersistenceService.updateCollection(collection.id, {
      variables: preview.normalized.variables,
      pre_request_script: preview.normalized.pre_request_script || '',
      test_script: preview.normalized.test_script || '',
      documentation: preview.normalized.documentation || '',
    } as any);

    await this.importNodes(preview.normalized.items, collection.id, workspaceId, userId, null, selectedNodeIds);
    return { collection, format: preview.format, stats: preview.stats };
  }

  private static detectFormat(parsed: any): ImportFormat | null {
    if (parsed?.info?.schema?.includes('postman') || (parsed?.info?.name && Array.isArray(parsed?.item))) {
      return 'postman';
    }

    if (Array.isArray(parsed?.resources) || parsed?._type === 'export') {
      return 'insomnia';
    }

    if (
      parsed?.apiInfo ||
      parsed?.data?.apiInfo ||
      parsed?.apiTreeList ||
      parsed?.data?.apiTreeList ||
      parsed?.apis ||
      parsed?.data?.apis
    ) {
      return 'apidog';
    }

    if (parsed?.openapi || parsed?.swagger) {
      return 'openapi';
    }

    return null;
  }

  private static parsePostman(collectionData: any): NormalizedImport {
    const name = collectionData?.info?.name || 'Imported Postman Collection';
    const variables = this.mapVariables(collectionData?.variable || []);
    const pre_request_script = this.parsePostmanScript(collectionData?.event, 'prerequest');
    const test_script = this.parsePostmanScript(collectionData?.event, 'test');

    const items = (collectionData?.item || []).map((item: any) => this.parsePostmanItem(item)).filter(Boolean) as ImportNode[];

    return {
      name,
      variables,
      pre_request_script,
      test_script,
      documentation: collectionData?.info?.description || '',
      items,
    };
  }

  private static parsePostmanItem(item: any): ImportNode | null {
    if (Array.isArray(item?.item)) {
      return {
        type: 'folder',
        name: item?.name || 'Folder',
        children: item.item.map((child: any) => this.parsePostmanItem(child)).filter(Boolean) as ImportNode[],
      };
    }

    if (!item?.request) return null;

    const request = item.request;
    const bodyInfo = this.parsePostmanBody(request.body);
    const headers = (request.header || []).map((h: any) => ({
      key: h?.key || '',
      value: h?.value || '',
      active: !h?.disabled,
    }));
    const params = (request?.url?.query || []).map((q: any) => ({
      key: q?.key || '',
      value: q?.value || '',
      active: !q?.disabled,
    }));

    return {
      type: 'request',
      name: item?.name || 'Imported Request',
      request: {
        method: (request.method || 'GET') as HttpMethod,
        url: typeof request.url === 'string' ? request.url : request?.url?.raw || '',
        headers,
        params,
        body: bodyInfo.body,
        bodyType: bodyInfo.bodyType,
        pre_request_script: this.parsePostmanScript(item.event, 'prerequest'),
        test_script: this.parsePostmanScript(item.event, 'test'),
        auth: this.parsePostmanAuth(request.auth),
      },
    };
  }

  private static parsePostmanBody(body: any): { body: RequestBody; bodyType: BodyType } {
    if (!body) return { body: RequestUtils.normalizeRequestBody('', 'none'), bodyType: 'none' };

    let type: BodyType = 'none';
    let content = '';

    if (body.mode === 'raw') {
      const language = body?.options?.raw?.language;
      type = language === 'json' ? 'json' : 'raw';
      content = body.raw || '';
    } else if (body.mode === 'formdata') {
      type = 'form-data';
    } else if (body.mode === 'urlencoded') {
      type = 'urlencoded';
    } else if (body.mode === 'graphql') {
      type = 'graphql';
    }

    const normalizedBody = RequestUtils.normalizeRequestBody(content, type);

    if (type === 'form-data' && Array.isArray(body.formdata)) {
      normalizedBody.formData = body.formdata.map((fd: any) => ({
        id: Math.random().toString(36).substr(2, 9),
        key: fd.key || '',
        value: fd.value || '',
        type: fd.type === 'file' ? 'file' : 'text',
        active: !fd.disabled,
        description: fd.description || ''
      }));
    } else if (type === 'urlencoded' && Array.isArray(body.urlencoded)) {
      normalizedBody.urlencoded = body.urlencoded.map((ue: any) => ({
        id: Math.random().toString(36).substr(2, 9),
        key: ue.key || '',
        value: ue.value || '',
        active: !ue.disabled,
        description: ue.description || ''
      }));
    } else if (type === 'graphql' && body.graphql) {
      normalizedBody.graphql = {
        query: body.graphql.query || '',
        variables: body.graphql.variables || ''
      };
    }

    return { body: normalizedBody, bodyType: type };
  }

  private static parsePostmanScript(events: any[], type: 'prerequest' | 'test') {
    if (!Array.isArray(events)) return '';
    const event = events.find((e: any) => e.listen === type);
    const exec = event?.script?.exec;
    if (exec === undefined || exec === null) return '';
    return Array.isArray(exec) ? exec.join('\n') : String(exec);
  }

  private static parsePostmanAuth(auth: any) {
    if (!auth?.type) return { type: 'inherit' };

    if (auth.type === 'bearer') {
      const token = (auth.bearer || []).find((it: any) => it.key === 'token')?.value || '';
      return { type: 'bearer', bearer: token };
    }

    if (auth.type === 'basic') {
      const username = (auth.basic || []).find((it: any) => it.key === 'username')?.value || '';
      const password = (auth.basic || []).find((it: any) => it.key === 'password')?.value || '';
      return { type: 'basic', basic: { username, password } };
    }

    if (auth.type === 'apikey' || auth.type === 'apiKey') {
      const key = (auth.apikey || auth.apiKey || []).find((it: any) => it.key === 'key')?.value || '';
      const value = (auth.apikey || auth.apiKey || []).find((it: any) => it.key === 'value')?.value || '';
      const addTo = (auth.apikey || auth.apiKey || []).find((it: any) => it.key === 'in')?.value;
      return { type: 'apikey', apiKey: { key, value, addTo: addTo === 'query' ? 'query' : 'header' } };
    }

    return { type: 'inherit' };
  }

  private static parseInsomnia(payload: any): NormalizedImport {
    const resources = Array.isArray(payload?.resources) ? payload.resources : [];
    const workspace = resources.find((r: any) => r._type === 'workspace');
    const groups = resources.filter((r: any) => r._type === 'request_group');
    const requests = resources.filter((r: any) => r._type === 'request');
    const environments = resources.filter((r: any) => r._type === 'environment');

    const parentRoot = workspace?._id;
    const groupChildren = (parentId: string) =>
      groups
        .filter((g: any) => g.parentId === parentId)
        .sort((a: any, b: any) => (a.metaSortKey || 0) - (b.metaSortKey || 0));
    const requestChildren = (parentId: string) =>
      requests
        .filter((r: any) => r.parentId === parentId)
        .sort((a: any, b: any) => (a.metaSortKey || 0) - (b.metaSortKey || 0));

    const parseNode = (parentId: string): ImportNode[] => {
      const folders = groupChildren(parentId).map((g: any) => ({
        type: 'folder' as const,
        name: g.name || 'Folder',
        children: parseNode(g._id),
      }));

      const reqs = requestChildren(parentId).map((r: any) => {
        const headers = (r.headers || []).map((h: any) => ({
          key: h.name || '',
          value: h.value || '',
          active: !h.disabled,
        }));
        const params = (r.parameters || []).map((p: any) => ({
          key: p.name || p.key || '',
          value: p.value || '',
          active: !p.disabled,
        }));

        const mime = r.body?.mimeType || '';
        const bodyType: BodyType = mime.includes('json')
          ? 'json'
          : mime.includes('x-www-form-urlencoded')
            ? 'urlencoded'
            : mime.includes('multipart/form-data')
              ? 'form-data'
              : mime.includes('xml')
                ? 'xml'
                : r.body?.text
                  ? 'raw'
                  : 'none';

        return {
          type: 'request' as const,
          name: r.name || 'Imported Request',
          request: {
            method: (r.method || 'GET') as HttpMethod,
            url: r.url || '',
            headers,
            params,
            body: RequestUtils.normalizeRequestBody(r.body?.text || '', bodyType),
            bodyType,
            pre_request_script: r.preRequestScript || '',
            test_script: r.afterResponseScript || '',
            auth: { type: 'inherit' },
          },
        };
      });

      return [...folders, ...reqs];
    };

    const envVars = environments.flatMap((env: any) => {
      const data = env?.data || {};
      return Object.keys(data).map((key) => ({ key, value: String(data[key] ?? ''), active: true }));
    });

    return {
      name: workspace?.name || 'Imported Insomnia Collection',
      variables: envVars,
      items: parentRoot ? parseNode(parentRoot) : [],
      documentation: payload?.description || '',
    };
  }

  private static parseApiDog(payload: any): NormalizedImport {
    const root = payload?.data || payload;

    // Some API Dog exports are already Postman-compatible.
    if (root?.info?.name && Array.isArray(root?.item)) {
      return this.parsePostman(root);
    }

    const name = root?.apiInfo?.name || root?.name || 'Imported API Dog Collection';
    const vars = this.mapVariables(root?.variables || root?.globalVariables || []);
    const tree = root?.apiTreeList || root?.items || root?.apis || [];

    const parseNode = (node: any): ImportNode | null => {
      const children = node?.children || node?.items || node?.item || [];
      if (Array.isArray(children) && children.length) {
        return {
          type: 'folder',
          name: node?.name || node?.title || 'Folder',
          children: children.map((child: any) => parseNode(child)).filter(Boolean) as ImportNode[],
        };
      }

      const req = node?.request || node;
      if (!req?.method && !(req?.url || req?.path)) return null;

      const headers = this.mapKeyValueArray(req?.headers || req?.header || []);
      const params = this.mapKeyValueArray(req?.params || req?.query || req?.queryParameters || []);

      const bodyRaw = typeof req?.body === 'string' ? req.body : req?.body?.raw || req?.body?.text || '';
      const rawBodyType = req?.bodyType || req?.body?.type || (bodyRaw ? 'raw' : 'none');
      const bodyType = this.normalizeBodyType(rawBodyType);

      return {
        type: 'request',
        name: node?.name || node?.title || 'Imported Request',
        request: {
          method: (req?.method || 'GET') as HttpMethod,
          url: req?.url || req?.path || '',
          headers,
          params,
          body: RequestUtils.normalizeRequestBody(bodyRaw, bodyType),
          bodyType,
          pre_request_script: req?.preRequestScript || req?.pre_script || '',
          test_script: req?.testScript || req?.tests || '',
          auth: { type: 'inherit' },
        },
      };
    };

    return {
      name,
      variables: vars,
      items: (tree || []).map((node: any) => parseNode(node)).filter(Boolean) as ImportNode[],
      documentation: root?.description || '',
    };
  }

  private static parseOpenApi(payload: any): NormalizedImport {
    const title = payload?.info?.title || 'Imported OpenAPI Collection';
    const description = payload?.info?.description || '';

    // Convert paths to requests
    const items: ImportNode[] = [];
    const paths = payload?.paths || {};

    const serverUrl = Array.isArray(payload?.servers) && payload.servers.length > 0
      ? payload.servers[0].url
      : (payload?.host ? `${payload?.schemes?.[0] || 'http'}://${payload.host}${payload.basePath || ''}` : '');

    for (const [path, methods] of Object.entries(paths)) {
      if (typeof methods !== 'object' || !methods) continue;

      for (const [method, operation] of Object.entries(methods)) {
        if (!['get', 'post', 'put', 'patch', 'delete', 'options', 'head'].includes(method.toLowerCase())) continue;

        const op = operation as any;
        const name = op.summary || op.operationId || `${method.toUpperCase()} ${path}`;

        const params: Array<{ key: string; value: string; active: boolean }> = [];
        const headers: Array<{ key: string; value: string; active: boolean }> = [];

        // Parse parameters
        (op.parameters || []).forEach((p: any) => {
          if (p.in === 'query') {
            params.push({ key: p.name, value: '', active: true });
          } else if (p.in === 'header') {
            headers.push({ key: p.name, value: '', active: true });
          }
        });

        let bodyContent = '';
        let bodyType: BodyType = 'none';

        // Parse requestBody (OpenAPI 3)
        if (op.requestBody?.content) {
          const content = op.requestBody.content;
          if (content['application/json']) {
            bodyType = 'json';
            const schema = content['application/json'].schema;
            if (schema && schema.type === 'object') {
              bodyContent = '{\n}';
            }
          } else if (content['application/x-www-form-urlencoded']) {
            bodyType = 'urlencoded';
          } else if (content['multipart/form-data']) {
            bodyType = 'form-data';
          } else if (content['application/xml']) {
            bodyType = 'xml';
          } else {
            bodyType = 'raw';
          }
        }

        const body = RequestUtils.normalizeRequestBody(bodyContent, bodyType);

        // Extract tags to use as folders
        const tags = op.tags || ['Default'];
        const tag = tags[0];

        const reqNode: ImportNode = {
          type: 'request',
          name,
          request: {
            method: method.toUpperCase() as HttpMethod,
            url: `${serverUrl}${path}`,
            headers,
            params,
            body,
            bodyType,
            pre_request_script: '',
            test_script: '',
            auth: { type: 'inherit' }
          }
        };

        // Find or create folder
        let folder = items.find(i => i.type === 'folder' && i.name === tag) as { type: 'folder', name: string, children: ImportNode[] };
        if (!folder) {
          folder = { type: 'folder', name: tag, children: [] };
          items.push(folder);
        }
        folder.children.push(reqNode);
      }
    }

    return {
      name: title,
      variables: [],
      items,
      documentation: description
    };
  }

  private static mapVariables(list: any[]): Array<{ key: string; value: string; active: boolean }> {
    if (!Array.isArray(list)) return [];
    return list
      .map((v: any) => ({
        key: v?.key || v?.name || '',
        value: String(v?.value ?? ''),
        active: !(v?.disabled || v?.enable === false),
      }))
      .filter((v) => !!v.key);
  }

  private static mapKeyValueArray(list: any[]): Array<{ key: string; value: string; active: boolean }> {
    if (!Array.isArray(list)) return [];
    return list
      .map((v: any) => ({
        key: v?.key || v?.name || '',
        value: String(v?.value ?? ''),
        active: !(v?.disabled || v?.enable === false),
      }))
      .filter((v) => !!v.key);
  }

  private static normalizeBodyType(type: string): BodyType {
    const normalized = String(type || '').toLowerCase();
    if (normalized === 'json') return 'json';
    if (normalized === 'formdata' || normalized === 'form-data') return 'form-data';
    if (normalized === 'urlencoded' || normalized === 'form-urlencoded') return 'urlencoded';
    if (normalized === 'graphql') return 'graphql';
    if (normalized === 'raw' || normalized === 'text') return 'raw';
    return 'none';
  }

  private static collectStats(normalized: NormalizedImport) {
    let folders = 0;
    let requests = 0;
    let scripts = 0;

    const visit = (nodes: ImportNode[]) => {
      nodes.forEach((node) => {
        if (node.type === 'folder') {
          folders += 1;
          visit(node.children);
        } else {
          requests += 1;
          if (node.request.pre_request_script) scripts += 1;
          if (node.request.test_script) scripts += 1;
        }
      });
    };

    visit(normalized.items);

    return {
      folders,
      requests,
      variables: normalized.variables.length,
      scripts,
    };
  }

  private static async importNodes(
    nodes: ImportNode[],
    collectionId: string,
    workspaceId: string,
    userId: string,
    folderId: string | null,
    selectedNodeIds?: string[]
  ) {
    for (const node of nodes) {
      if (selectedNodeIds && node.id && !selectedNodeIds.includes(node.id)) {
        continue;
      }

      if (node.type === 'folder') {
        const folder = await PersistenceService.createFolder(node.name, collectionId, userId, folderId || undefined, workspaceId);
        await this.importNodes(node.children, collectionId, workspaceId, userId, folder.id, selectedNodeIds);
      } else {
        await PersistenceService.createRequest({
          collection_id: collectionId,
          folder_id: folderId,
          workspace_id: workspaceId,
          user_id: userId,
          name: node.name,
          type: 'rest',
          method: node.request.method,
          url: node.request.url,
          headers: node.request.headers,
          params: node.request.params,
          body: node.request.body, // This is already a RequestBody object
          bodyType: node.request.bodyType,
          pre_request_script: node.request.pre_request_script,
          test_script: node.request.test_script,
          auth: node.request.auth,
        } as any);
      }
    }
  }
}

import { createClient } from '@supabase/supabase-js';
import { globalSupabase } from '../lib/supabase';
import { ensureDatabaseSchema } from './ensureDatabaseSchema';

export type MigrationProgress = {
  step: 'idle' | 'schema' | 'fetching' | 'injecting' | 'complete' | 'failed';
  message: string;
  percent: number;
};

export class DatabaseMigrationService {
  static async migrate(
    targetUrl: string,
    targetServiceKey: string,
    currentUserId: string,
    onProgress: (prog: MigrationProgress) => void
  ) {
    try {
      // Step 1: Ensure target database schema
      onProgress({ step: 'schema', message: 'Assuring schema on target database...', percent: 10 });
      const schemaResult = await ensureDatabaseSchema(targetUrl, targetServiceKey, (label, pct) => {
        onProgress({ step: 'schema', message: `Target Schema: ${label}`, percent: 10 + Math.round(pct * 0.3) });
      });

      if (!schemaResult.success) {
        throw new Error(schemaResult.error || 'Failed to establish schema on target database.');
      }

      onProgress({ step: 'fetching', message: 'Establishing target client link...', percent: 40 });
      const targetClient = createClient(targetUrl, targetServiceKey);
      
      // Step 2: Fetch all source records
      onProgress({ step: 'fetching', message: 'Harvesting source records from current database...', percent: 45 });
      
      // A. Profile
      const { data: profile } = await globalSupabase.from('profiles').select('*').eq('id', currentUserId).single();
      
      // B. Team Memberships
      const { data: memberships } = await globalSupabase.from('team_members').select('*').eq('user_id', currentUserId);
      const teamIds = memberships?.map(m => m.team_id) || [];
      
      // C. Teams
      let teams: any[] = [];
      if (teamIds.length > 0) {
        const { data: fetchedTeams } = await globalSupabase.from('teams').select('*').in('id', teamIds);
        teams = fetchedTeams || [];
      }
      
      // D. Workspaces
      const workspaces: any[] = [];
      
      // Personal workspaces
      const { data: personalWorkspaces } = await globalSupabase.from('workspaces').select('*').eq('user_id', currentUserId);
      if (personalWorkspaces) workspaces.push(...personalWorkspaces);
      
      // Team workspaces
      if (teamIds.length > 0) {
        const { data: teamWorkspaces } = await globalSupabase.from('workspaces').select('*').in('team_id', teamIds);
        if (teamWorkspaces) {
          teamWorkspaces.forEach(tw => {
            if (!workspaces.some(w => w.id === tw.id)) workspaces.push(tw);
          });
        }
      }
      
      const workspaceIds = workspaces.map(w => w.id);
      
      // E. Collections
      let collections: any[] = [];
      if (workspaceIds.length > 0) {
        const { data: fetchedCollections } = await globalSupabase.from('collections').select('*').in('workspace_id', workspaceIds);
        collections = fetchedCollections || [];
      }
      
      const collectionIds = collections.map(c => c.id);
      
      // H. Environments
      let environments: any[] = [];
      if (workspaceIds.length > 0) {
        const { data: fetchedEnvironments } = await globalSupabase.from('environments').select('*').in('workspace_id', workspaceIds);
        environments = fetchedEnvironments || [];
      }
      
      // I. Scripts
      let scripts: any[] = [];
      if (workspaceIds.length > 0) {
        const { data: fetchedScripts } = await globalSupabase.from('scripts').select('*').in('workspace_id', workspaceIds);
        scripts = fetchedScripts || [];
      }

      // F. Folders
      let folders: any[] = [];
      if (collectionIds.length > 0) {
        const { data: fetchedFolders } = await globalSupabase.from('folders').select('*').in('collection_id', collectionIds);
        folders = fetchedFolders || [];
      }
      
      // G. Requests
      let requests: any[] = [];
      if (collectionIds.length > 0) {
        const { data: fetchedRequests } = await globalSupabase.from('requests').select('*').in('collection_id', collectionIds);
        requests = fetchedRequests || [];
      }

      onProgress({ step: 'injecting', message: 'Injecting records into target schema...', percent: 60 });

      // Step 3: Inject records to the target
      // Standard order to prevent foreign key constraint issues:
      // 1. profiles
      // 2. teams
      // 3. team_members
      // 4. workspaces
      // 5. collections
      // 6. folders
      // 7. requests
      // 8. environments
      // 9. scripts

      if (profile) {
        onProgress({ step: 'injecting', message: 'Upserting profile info...', percent: 65 });
        const { error } = await targetClient.from('profiles').upsert(profile);
        if (error) throw new Error(`Profile insert failed: ${error.message}`);
      }

      if (teams.length > 0) {
        onProgress({ step: 'injecting', message: 'Upserting teams configuration...', percent: 70 });
        const { error } = await targetClient.from('teams').upsert(teams);
        if (error) throw new Error(`Teams insert failed: ${error.message}`);
      }

      if (memberships && memberships.length > 0) {
        onProgress({ step: 'injecting', message: 'Upserting member rosters...', percent: 75 });
        const { error } = await targetClient.from('team_members').upsert(memberships);
        if (error) throw new Error(`Members insert failed: ${error.message}`);
      }

      if (workspaces.length > 0) {
        onProgress({ step: 'injecting', message: 'Upserting workspaces...', percent: 80 });
        const { error } = await targetClient.from('workspaces').upsert(workspaces);
        if (error) throw new Error(`Workspaces insert failed: ${error.message}`);
      }

      if (collections.length > 0) {
        onProgress({ step: 'injecting', message: 'Upserting collections...', percent: 85 });
        const { error } = await targetClient.from('collections').upsert(collections);
        if (error) throw new Error(`Collections insert failed: ${error.message}`);
      }

      if (folders.length > 0) {
        onProgress({ step: 'injecting', message: 'Upserting folders structure...', percent: 90 });
        const { error } = await targetClient.from('folders').upsert(folders);
        if (error) throw new Error(`Folders insert failed: ${error.message}`);
      }

      if (requests.length > 0) {
        onProgress({ step: 'injecting', message: 'Upserting API requests...', percent: 92 });
        const { error } = await targetClient.from('requests').upsert(requests);
        if (error) throw new Error(`Requests insert failed: ${error.message}`);
      }

      if (environments.length > 0) {
        onProgress({ step: 'injecting', message: 'Upserting active environments...', percent: 95 });
        const { error } = await targetClient.from('environments').upsert(environments);
        if (error) throw new Error(`Environments insert failed: ${error.message}`);
      }

      if (scripts.length > 0) {
        onProgress({ step: 'injecting', message: 'Upserting Custom scripts...', percent: 98 });
        const { error } = await targetClient.from('scripts').upsert(scripts);
        if (error) throw new Error(`Scripts insert failed: ${error.message}`);
      }

      onProgress({ step: 'complete', message: 'Database migration transaction completed successfully!', percent: 100 });
    } catch (e: any) {
      onProgress({ step: 'failed', message: e.message || 'Migration failed due to target database error.', percent: 0 });
      throw e;
    }
  }
}

import axios from 'axios';
import { Collection, RequestData, Folder } from '../types';
import { useStore } from '../store/useStore';
import { PersistenceService } from './PersistenceService';
import { CollectionImportService } from './CollectionImportService';

export class GitHubService {
  private static get config() {
    return useStore.getState().settings.github;
  }

  private static get headers() {
    return {
      Authorization: `token ${this.config.token}`,
      Accept: 'application/vnd.github.v3+json',
    };
  }

  static async pullUpdates(workspaceId: string, userId: string) {
    const { repo, branch, path } = this.config;
    if (!repo || !this.config.token) {
      throw new Error('GitHub configuration incomplete (Token and Repo required)');
    }

    try {
      // Get the contents of the path
      const url = `https://api.github.com/repos/${repo}/contents/${path}?ref=${branch}`;
      const response = await axios.get(url, { headers: this.headers });

      if (!Array.isArray(response.data)) {
        throw new Error('Specified path is not a directory or is empty.');
      }

      const files = response.data.filter((f: any) => f.type === 'file' && f.name.endsWith('.json'));
      let importedCount = 0;

      for (const file of files) {
        const fileRes = await axios.get(file.download_url);
        const raw = JSON.stringify(fileRes.data);
        
        try {
          await CollectionImportService.importCollection(raw, workspaceId, userId, 'auto');
          importedCount++;
        } catch (err) {
          console.error(`Failed to import ${file.name}:`, err);
        }
      }

      useStore.getState().updateSettings({
        github: { ...this.config, lastPulledAt: new Date().toISOString() }
      });

      return importedCount;
    } catch (error: any) {
      console.error('GitHub Pull Error:', error);
      throw new Error(error.response?.data?.message || error.message || 'Failed to pull from GitHub');
    }
  }

  static async pushUpdates(collection: Collection) {
    const { repo, branch, path: configPath } = this.config;
    if (!repo || !this.config.token) {
       throw new Error('GitHub configuration incomplete');
    }

    try {
      const fileName = `${collection.name.replace(/[^a-z0-9]/gi, '_').toLowerCase()}.json`;
      const fullPath = configPath ? `${configPath}/${fileName}` : fileName;
      
      // We need to fetch all details for the collection (requests and folders)
      // Since collection.requests might be partial, we should ideally fetch from DB
      // But for now, we'll assume the passed collection is the one we want to sync.
      
      const payload = JSON.stringify(collection, null, 2);
      const url = `https://api.github.com/repos/${repo}/contents/${fullPath}`;

      // Check if file exists to get SHA
      let sha: string | undefined;
      try {
        const getRes = await axios.get(`${url}?ref=${branch}`, { headers: this.headers });
        sha = getRes.data.sha;
      } catch (e) {
        // File doesn't exist, which is fine for first push
      }

      await axios.put(url, {
        message: `Sync collection: ${collection.name}`,
        content: btoa(unescape(encodeURIComponent(payload))),
        branch,
        sha
      }, { headers: this.headers });

      useStore.getState().updateSettings({
        github: { ...this.config, lastPushedAt: new Date().toISOString() }
      });

      return true;
    } catch (error: any) {
      console.error('GitHub Push Error:', error);
      throw new Error(error.response?.data?.message || error.message || 'Failed to push to GitHub');
    }
  }
}

import { createClient } from '@supabase/supabase-js';
import { SecureConfigStorage } from '../lib/SecureConfigStorage';
import { supabase, getSupabaseConfig, globalSupabase } from '../lib/supabase';

interface RetryOptions {
  attempts?: number;
  delayMs?: number;
}

export class OnboardingService {
  static async retryRequest<T>(fn: () => Promise<T>, options: RetryOptions = {}): Promise<T> {
    const attempts = options.attempts ?? 3;
    const delayMs = options.delayMs ?? 250;
    let lastError: any;

    for (let attempt = 1; attempt <= attempts; attempt += 1) {
      try {
        return await fn();
      } catch (error: any) {
        lastError = error;
        if (attempt < attempts) {
          await new Promise((resolve) => setTimeout(resolve, delayMs * attempt));
        }
      }
    }

    throw lastError;
  }

  static normalizeSupabaseUrl(url: string): string {
    return url.trim().replace(/\/+$/, '');
  }

  static async createAuthenticatedClient(
    url: string,
    anonKey: string,
    userId: string
  ): Promise<{
    client: any;
    sessionMatched: boolean;
    error?: string;
  }> {
    const normalizedUrl = this.normalizeSupabaseUrl(url);
    const client: any = createClient(normalizedUrl, anonKey);
    const currentConfig = getSupabaseConfig();
    const { data: { session } } = await supabase.auth.getSession();

    console.group('[OnboardingService] createAuthenticatedClient');
    console.log('Configuration Parameters:', {
      providedUrl: normalizedUrl,
      providedAnonKey: anonKey ? `***${  anonKey.slice(-4)}` : 'MISSING',
      userId
    });
    console.log('Current App Session:', {
      exists: !!session,
      userId: session?.user?.id,
      email: session?.user?.email
    });
    console.log('Environment Matching:', {
      urlsMatch: currentConfig.url === normalizedUrl,
      anonKeysMatch: currentConfig.anonKey === anonKey
    });

    // Check if user is signed into the main app
    if (session?.user?.id === userId) {
      console.log('Step: User session ID matches intended userId');
      // If they're creating a team in the same project as the main app, use the existing session
      if (currentConfig.url === normalizedUrl && currentConfig.anonKey === anonKey) {
        console.log('Step: Using existing session for current project');
        await client.auth.setSession(session);
        console.groupEnd();
        return { client, sessionMatched: true };
      }
      // If they're creating a team in a different project, we need to sign them in
      console.log('Step: Different project detected. Proceeding as authenticated via userId matching.');
      console.groupEnd();
      return { client, sessionMatched: true };
    }

    console.warn('Step: Authentication mismatch or missing session');
    console.groupEnd();
    return {
      client,
      sessionMatched: false,
      error:
        'You must be signed in to the application before creating or joining a team.',
    };
  }

  static async testSupabaseConnection(url: string, anonKey: string): Promise<{
    success: boolean;
    error?: string;
  }> {
    try {
      if (!url || !anonKey) {
        return { success: false, error: 'Supabase URL and anon key are required.' };
      }

      const normalizedUrl = this.normalizeSupabaseUrl(url);

      if (!normalizedUrl.includes('supabase.co') && !normalizedUrl.includes('supabase.in')) {
        return { success: false, error: 'Invalid Supabase URL format.' };
      }

      const client = createClient(normalizedUrl, anonKey);

      const { error: sessionError } = await client.auth.getSession();
      if (sessionError && !sessionError.message.includes('Auth session missing')) {
        return { success: false, error: sessionError.message };
      }

      return { success: true };
    } catch (error: any) {
      return { success: false, error: error?.message || 'Connection test failed.' };
    }
  }

  static async verifyDatabaseInitialization(url: string, anonKey: string): Promise<{
    success: boolean;
    missingTables?: string[];
    error?: string;
  }> {
    try {
      if (!url || !anonKey) {
        return { success: false, error: 'Supabase URL and anon key are required.' };
      }

      const normalizedUrl = this.normalizeSupabaseUrl(url);
      const client = createClient(normalizedUrl, anonKey);
      const requiredTables = ['workspaces', 'teams', 'team_members', 'collections', 'environments'];
      const missingTables: string[] = [];

      for (const table of requiredTables) {
        const { error } = await client.from(table).select('id').limit(1);
        if (error) {
          const message = (error.message || '').toLowerCase();
          if (message.includes('does not exist') || message.includes('not found')) {
            missingTables.push(table);
          } else {
            return { success: false, error: error.message };
          }
        }
      }

      if (missingTables.length > 0) {
        return {
          success: false,
          missingTables,
          error: `Schema init required. Missing tables: ${missingTables.join(', ')}.`,
        };
      }

      return { success: true };
    } catch (error: any) {
      return { success: false, error: error?.message || 'Failed to verify database initialization.' };
    }
  }

  static generateTeamCode(): string {
    const generateSegment = () =>
      Math.random().toString(36).substring(2, 6).toUpperCase().padEnd(4, '0');
    return `TEAM-${generateSegment()}-${generateSegment()}-${generateSegment()}`;
  }

  static generateInviteCode(): string {
    const generateSegment = () =>
      Math.random().toString(36).substring(2, 6).toUpperCase().padEnd(4, '0');
    return `TEMP-${generateSegment()}-${generateSegment()}-${generateSegment()}`;
  }

  static hashInviteCode(code: string): string {
    const normalized = code.trim().toUpperCase();
    const bytes = new TextEncoder().encode(normalized);
    let binary = '';

    bytes.forEach((value) => {
      binary += String.fromCharCode(value);
    });

    return typeof btoa === 'function'
      ? btoa(binary)
      : Buffer.from(bytes).toString('base64');
  }

  static isValidTeamCodeFormat(code: string): boolean {
    return /^TEAM-[A-Z0-9]{4}-[A-Z0-9]{4}-[A-Z0-9]{4}$/.test(code.trim().toUpperCase());
  }

  static isValidInviteCodeFormat(code: string): boolean {
    return /^TEMP-[A-Z0-9]{4}-[A-Z0-9]{4}-[A-Z0-9]{4}$/.test(code.trim().toUpperCase());
  }

  static async listSupabaseProjects(accessToken: string): Promise<any[]> {
    console.log('[SUPABASE API] Initiating project list request via Proxy...');
    
    try {
      const response = await fetch('/api/proxy', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          method: 'GET',
          url: 'https://api.supabase.com/v1/projects',
          headers: {
            Authorization: `Bearer ${accessToken}`,
          },
        }),
      });

      if (!response.ok) {
        throw new Error(`Proxy error: ${response.status}`);
      }

      const result = await response.json();
      
      if (result.status >= 400) {
        console.log(`[SUPABASE API] Project list request failed via proxy with status: ${result.status}`);
        const errorMsg = result.data?.message || `Failed to fetch projects (Status: ${result.status})`;
        throw new Error(errorMsg);
      }

      console.log(`[SUPABASE API] Successfully retrieved ${result.data.length} projects via proxy.`);
      return result.data;
    } catch (err: any) {
      console.log(`[SUPABASE API] Error during proxy request:`, err);
      throw new Error(err.message || 'Network error while connecting to proxy.');
    }
  }

  static async getProjectApiKeys(accessToken: string, projectRef: string): Promise<{ anon: string; service_role: string }> {
    console.log(`[SUPABASE API] Fetching API keys for ${projectRef} via Proxy...`);
    
    try {
      const response = await fetch('/api/proxy', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          method: 'GET',
          url: `https://api.supabase.com/v1/projects/${projectRef}/api-keys`,
          headers: {
            Authorization: `Bearer ${accessToken}`,
          },
        }),
      });

      if (!response.ok) {
        throw new Error(`Proxy error: ${response.status}`);
      }

      const result = await response.json();

      if (result.status >= 400) {
        throw new Error(result.data?.message || `Failed to fetch API keys (Status: ${result.status})`);
      }

      const keys = result.data;
      const anon = keys.find((k: any) => k.name === 'anon')?.api_key;
      const service_role = keys.find((k: any) => k.name === 'service_role')?.api_key;

      if (!anon || !service_role) {
        throw new Error('Could not find anon or service_role keys for this project.');
      }

      return { anon, service_role };
    } catch (err: any) {
      throw new Error(err.message || 'Failed to fetch API keys via proxy.');
    }
  }

  static async executeSql(
    accessToken: string, 
    projectRef: string, 
    sql: string,
    onLog?: (msg: string) => void
  ): Promise<any> {
    console.log(`[SUPABASE API] Executing SQL on ${projectRef} via Proxy...`);
    
    const runQuery = async (url: string, body: any) => {
      onLog?.(`[REST] POST ${url}...`);
      const response = await fetch('/api/proxy', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          method: 'POST',
          url,
          headers: {
            Authorization: `Bearer ${accessToken}`,
            'x-supabase-project': projectRef,
            'Accept': 'application/json',
            'Content-Type': 'application/json'
          },
          data: body
        }),
      });

      if (!response.ok) {
        return { status: response.status, data: { message: `Proxy connection error ${response.status}` } };
      }

      const result = await response.json();
      return result;
    };

    try {
      // 1. Try the standard Management API DDL endpoint (PLURAL)
      // NOTE: This is the official documented endpoint: https://api.supabase.com/v1/projects/{ref}/queries
      let result = await runQuery(`https://api.supabase.com/v1/projects/${projectRef}/queries`, { query: sql });

      // 2. If that fails with 401/403/404, try the legacy SQL endpoint
      if (result.status >= 400 && result.status < 500) {
        onLog?.(`⚠️ [MANAGEMENT] Main queries endpoint returned ${result.status}, trying legacy /sql...`);
        result = await runQuery(`https://api.supabase.com/v1/projects/${projectRef}/sql`, { query: sql });
      }

      // 3. Fallback to generic queries endpoint if still missing
      if (result.status === 404 || result.status === 405) {
        onLog?.(`⚠️ [MANAGEMENT] Specific project endpoints not found, trying query (singular)...`);
        result = await runQuery(`https://api.supabase.com/v1/projects/${projectRef}/query`, { query: sql });
      }

      if (result.status >= 400) {
        console.log(`[SUPABASE API] All SQL execution attempts failed. Final status: ${result.status}`, result.data);
        
        let hint = "";
        if (result.status === 404) hint = "\n\nHINT: The Supabase Management API queries endpoint might be disabled or the project reference is invalid.";
        if (result.status === 401 || result.status === 403) hint = "\n\nHINT: Your access token might have expired or lacks permission to execute DDL.";
        
        const errorMsg = result.data?.message || result.data?.error || `SQL Execution failed (Status: ${result.status})${hint}`;
        throw new Error(errorMsg);
      }

      onLog?.(`✅ [MANAGEMENT] SQL execution completed.`);
      return result.data;
    } catch (err: any) {
      console.error('[SUPABASE API] executeSql Error:', err);
      throw err;
    }
  }

  static async reloadSchemaCache(accessToken: string, projectRef: string): Promise<boolean> {
    try {
      await this.executeSql(accessToken, projectRef, "NOTIFY pgrst, 'reload schema';");
      return true;
    } catch (err) {
      console.warn('[SUPABASE API] Schema reload notification failed:', err);
      return false;
    }
  }

  static async createTeamWorkspace(
    supabaseUrl: string,
    supabaseAnonKey: string,
    supabaseServiceKey: string,
    userId: string,
    teamName: string,
    userProfile?: { email?: string; full_name?: string; username?: string; avatar_url?: string; preferences?: any; created_at?: string; updated_at?: string; } | null,
    managementToken?: string,
    projectRef?: string
  ): Promise<{
    success: boolean;
    workspaceId?: string;
    teamId?: string;
    teamCode?: string;
    inviteCode?: string;
    error?: string;
  }> {
    console.group(`[OnboardingService] createTeamWorkspace("${teamName}")`);
    console.log('Inputs:', { supabaseUrl, userId, hasAnonKey: !!supabaseAnonKey, hasServiceKey: !!supabaseServiceKey, hasManagementToken: !!managementToken });

    if (!supabaseUrl || !supabaseAnonKey) {
      console.error('Validation Failed: Missing credentials');
      console.groupEnd();
      return { success: false, error: 'Supabase credentials are required.' };
    }
    if (!userId) {
      console.error('Validation Failed: Missing userId');
      console.groupEnd();
      return { success: false, error: 'Authenticated user is required to create a team.' };
    }
    const normalizedTeamName = teamName.trim();
    if (!normalizedTeamName) {
      console.error('Validation Failed: Empty team name');
      console.groupEnd();
      return { success: false, error: 'Team name is required.' };
    }

    const normalizedUrl = this.normalizeSupabaseUrl(supabaseUrl);
    console.log('Normalized URL:', normalizedUrl);

    console.log('Attempting to create authenticated client...');
    const { client, sessionMatched, error: authError } = await this.createAuthenticatedClient(
      normalizedUrl,
      supabaseAnonKey,
      userId
    );

    if (!sessionMatched) {
      console.error('Auth Error:', authError);
      console.groupEnd();
      return { success: false, error: authError || 'You must be signed in to the application before creating a team.' };
    }

    console.log('Clients initialized. Proceeding with database operations...');

    // Use service key client for database operations that need to bypass RLS
    const serviceClient: any = createClient(normalizedUrl, supabaseServiceKey);
    const authenticatedClient: any = client;

    const teamCode = this.generateTeamCode();
    const inviteCode = this.generateInviteCode();
    const secretHash = this.hashInviteCode(inviteCode);
    console.log('Generated Identifiers:', { teamCode, inviteCode });

    let retryCount = 0;
    const maxRetries = 1;

    const executeOperations = async (): Promise<any> => {
      // Ensure user profile exists in target project
      console.log('--- DB OP: Ensure User Profile ---');
      console.log(`Checking profile for userId: ${userId}`);
      
      try {
        const { data: existingProfile, error: profileCheckError } = await serviceClient
          .from('profiles')
          .select('id, email')
          .eq('id', userId)
          .maybeSingle();

        if (profileCheckError) {
          console.error('Profile check error:', profileCheckError);
          
          // Handle specific PostgREST errors
          const isCacheError = profileCheckError.code === 'PGRST205' || profileCheckError.message?.includes('schema cache');
          
          if (isCacheError && managementToken && projectRef && retryCount < maxRetries) {
            console.warn('[AUTO-RECOVERY] Schema cache stale. Attempting remote reload...');
            retryCount++;
            await this.reloadSchemaCache(managementToken, projectRef);
            await new Promise(r => setTimeout(r, 2000)); // Give it a moment
            return executeOperations(); // Recursive retry
          }

          if (isCacheError) {
            throw new Error(`[SCHEMA CACHE STALE] The database tables were created but the Supabase API hasn't loaded them yet.\n\nFIX: Go to your Supabase Dashboard -> Settings -> API -> click "Save" (even without changes) or wait 30 seconds for the cache to refresh.`);
          }
          
          if (profileCheckError.message?.includes('not find') && profileCheckError.message?.includes('profiles')) {
            throw new Error(`[TABLE MISSING] The 'profiles' table is missing from your database.\n\nFIX: Go back to Step 3 (SQL Setup), click "Smart Initialize" or manually run the script in the Supabase SQL Editor.`);
          }

          throw new Error(`Profile verify failed: ${profileCheckError.message}`);
        }

        if (!existingProfile) {
          console.log('Profile not found. Attempting insertion...');
          const insertData = {
            id: userId,
            email: userProfile?.email || 'user@example.com',
            full_name: userProfile?.full_name || 'User',
            username: userProfile?.username,
            avatar_url: userProfile?.avatar_url,
            preferences: userProfile?.preferences || {},
          };
          console.log('Insertion data:', insertData);

          const { error: profileError } = await serviceClient
            .from('profiles')
            .insert(insertData);

          if (profileError) {
            console.error('Profile insert error:', profileError);
            if (profileError.code === '23503' && profileError.message.includes('profiles_id_fkey')) {
              throw new Error(`[SCHEMA ERROR] Reference constraint violation on Profiles (ID).\n\nThis project is using strict Supabase Auth references that prevent multi-tenant sync.\n\nFIX: Go to Step 3 (SQL Setup) and click "Smart Initialize" to auto-fix constraints.`);
            }
            if (profileError.code === '23505' || profileError.message.includes('duplicate key') || profileError.message.includes('already exists') || profileError.message.includes('Conflict')) {
              console.log('Conflict detected but ignored (profile likely created in parallel)');
            } else {
              throw new Error(`Failed to create user profile: ${profileError.message}`);
            }
          } else {
            console.log('Profile created successfully');
          }
        } else {
          console.log('Verified: Profile exists.', existingProfile);
        }
      } catch (subError: any) {
        if (subError.message.includes('[SCHEMA') || subError.message.includes('[TABLE')) throw subError;
        throw new Error(`Error during user profile verification: ${subError.message}`);
      }

      console.log('--- DB OP: Insert Team ---');
      const teamPayload = {
        name: normalizedTeamName,
        owner_id: userId,
        team_code: teamCode,
        secret_code_hash: secretHash,
      };
      console.log('Team payload:', teamPayload);

      const result = await serviceClient
        .from('teams')
        .insert([teamPayload])
        .select()
        .single();

      if (result.error) {
        console.error('Team insertion failed:', result.error);
        if (result.error.code === '23503') {
          const tableMap: Record<string, string> = {
            'teams_owner_id_fkey': 'Teams (Owner ID)',
            'team_members_user_id_fkey': 'Team Members (User ID)',
            'profiles_id_fkey': 'Profiles (ID)',
            'workspaces_user_id_fkey': 'Workspaces (User ID)',
            'collections_user_id_fkey': 'Collections (User ID)',
            'requests_user_id_fkey': 'Requests (User ID)'
          };

          let affectedTable = 'Database table references';
          for (const [key, label] of Object.entries(tableMap)) {
            if (result.error.message.includes(key)) {
              affectedTable = label;
              break;
            }
          }

          throw new Error(`[SCHEMA ERROR] Reference constraint violation on ${affectedTable}.\n\nThis project is using strict Supabase Auth references that prevent multi-tenant sync.\n\nFIX: Go to Step 3 (SQL Setup), click "Smart Initialize" to auto-fix constraints, OR manually run the fix script.`);
        }

        if (result.error.code === '42703') {
          throw new Error(`[SCHEMA ERROR] Missing column in database: ${result.error.message}.\n\nFIX: Go back to Step 3 (SQL Setup) and run "Smart Initialize" again. This will update the schema with missing columns (like owner_id).`);
        }

        throw new Error(result.error.message || 'Team creation failed.');
      }

      console.log('Team inserted successfully:', result.data.id);
      return result.data;
    };

    try {
      const createdTeam = await this.retryRequest(executeOperations);

      if (!createdTeam || !createdTeam.id) {
        console.error('Final check failed: Team object is null or missing ID');
        console.groupEnd();
        return { success: false, error: 'Team creation returned invalid data.' };
      }

      console.log('--- DB OP: Insert Owner as Team Member ---');
      const { error: memberError } = await serviceClient.from('team_members').insert([
        { team_id: createdTeam.id, user_id: userId, role: 'owner' },
      ]);

      if (memberError) {
        console.error('Member insertion failed:', memberError);
        console.log('Rolling back team record...', createdTeam.id);
        await serviceClient.from('teams').delete().eq('id', createdTeam.id);
        console.groupEnd();
        return { success: false, error: `Failed to add owner to team members: ${memberError.message}` };
      }

      console.log('--- DB OP: Insert Team Workspace ---');
      const { data: workspace, error: workspaceError } = await serviceClient
        .from('workspaces')
        .insert([
          {
            name: `${normalizedTeamName} Workspace`,
            user_id: userId,
            team_id: createdTeam.id,
            visibility: 'team',
          },
        ])
        .select()
        .single();

      if (workspaceError || !workspace) {
        console.error('Workspace creation failed:', workspaceError);
        console.log('Rolling back membership and team...');
        await serviceClient.from('team_members').delete().eq('team_id', createdTeam.id);
        await serviceClient.from('teams').delete().eq('id', createdTeam.id);
        console.groupEnd();
        return { success: false, error: workspaceError?.message || 'Failed to create workspace for team.' };
      }

      console.log('--- DB OP: Initialize Resources (Collection & Env) ---');
      const [collectionResult, envResult] = await Promise.all([
        serviceClient.from('collections').insert([
          {
            name: 'My Requests',
            workspace_id: workspace.id,
            user_id: userId,
            team_id: createdTeam.id,
            visibility: 'team',
          },
        ]),
        serviceClient.from('environments').insert([
          {
            name: 'Development',
            workspace_id: workspace.id,
            user_id: userId,
            is_active: true,
            variables: [],
          },
        ]),
      ]);

      if (collectionResult.error || envResult.error) {
        console.error('Resource initialization failed:', { coll: collectionResult.error, env: envResult.error });
        // Non-fatal for the team itself, but unexpected
        console.warn('Initial resources failed, but team and workspace are created.');
      }

      console.log('Finalizing Team Setup in config storage...');
      SecureConfigStorage.saveSupabaseConfig(normalizedUrl, supabaseAnonKey);
      SecureConfigStorage.saveWorkspaceMetadata({
        workspaceId: workspace.id,
        teamId: createdTeam.id,
        userId,
        setupMode: 'create',
      });

      console.log('✅ Team Workspace fully initialized.');
      console.groupEnd();
      return {
        success: true,
        workspaceId: workspace.id,
        teamId: createdTeam.id,
        teamCode,
        inviteCode,
      };
    } catch (error: any) {
      console.error('Unhandled Exception in createTeamWorkspace:', error);
      console.groupEnd();
      return { success: false, error: error?.message || 'Unable to create team workspace.' };
    }
  }

  static async initializeWorkspace(
    supabaseUrl: string,
    supabaseAnonKey: string,
    userId: string,
    workspaceName: string = 'My Workspace'
  ): Promise<{
    success: boolean;
    workspaceId?: string;
    error?: string;
  }> {
    if (!supabaseUrl || !supabaseAnonKey) {
      return { success: false, error: 'Supabase credentials are required.' };
    }

    if (!userId) {
      return { success: false, error: 'Authenticated user is required to initialize a workspace.' };
    }

    const normalizedUrl = this.normalizeSupabaseUrl(supabaseUrl);
    const client = createClient(normalizedUrl, supabaseAnonKey);

    try {
      const { data: workspace, error: workspaceError } = await client
        .from('workspaces')
        .insert([
          {
            name: workspaceName,
            user_id: userId,
            visibility: 'private',
          },
        ])
        .select()
        .single();

      if (workspaceError) {
        return { success: false, error: workspaceError.message };
      }

      if (!workspace) {
        return { success: false, error: 'Failed to create workspace.' };
      }

      const [collectionResult, envResult] = await Promise.all([
        client.from('collections').insert([
          {
            name: 'My Requests',
            workspace_id: workspace.id,
            user_id: userId,
            visibility: 'private',
          },
        ]),
        client.from('environments').insert([
          {
            name: 'Development',
            workspace_id: workspace.id,
            user_id: userId,
            is_active: true,
            variables: [],
          },
        ]),
      ]);

      if (collectionResult.error || envResult.error) {
        return { success: false, error: collectionResult.error?.message || envResult.error?.message || 'Failed to initialize workspace resources.' };
      }

      SecureConfigStorage.saveSupabaseConfig(normalizedUrl, supabaseAnonKey);
      SecureConfigStorage.saveWorkspaceMetadata({
        workspaceId: workspace.id,
        userId,
        setupMode: 'create',
      });

      return { success: true, workspaceId: workspace.id };
    } catch (error: any) {
      return { success: false, error: error?.message || 'Workspace initialization failed.' };
    }
  }

  static async joinTeam(
    supabaseUrl: string,
    supabaseAnonKey: string,
    userId: string,
    teamCode: string,
    inviteCode: string
  ): Promise<{
    success: boolean;
    teamId?: string;
    workspaceId?: string;
    teamName?: string;
    workspaceName?: string;
    error?: string;
  }> {
    if (!supabaseUrl || !supabaseAnonKey) {
      return { success: false, error: 'Supabase credentials are required.' };
    }
    if (!userId) {
      return { success: false, error: 'Authenticated user is required to join a team.' };
    }
    if (!this.isValidTeamCodeFormat(teamCode)) {
      return { success: false, error: 'Invalid team code format. Expected TEAM-XXXX-XXXX-XXXX.' };
    }
    if (!this.isValidInviteCodeFormat(inviteCode)) {
      return { success: false, error: 'Invalid temporary code format. Expected TEMP-XXXX-XXXX-XXXX.' };
    }

    const normalizedUrl = this.normalizeSupabaseUrl(supabaseUrl);
    const { client, sessionMatched, error: authError } = await this.createAuthenticatedClient(
      normalizedUrl,
      supabaseAnonKey,
      userId
    );

    if (!sessionMatched) {
      return { success: false, error: authError || 'You must be signed in to the same Supabase project before joining a team.' };
    }

    const authenticatedClient: any = client;
    const hashedCode = this.hashInviteCode(inviteCode);

    try {
      const { data: team, error: teamError } = await client
        .from('teams')
        .select('*')
        .eq('team_code', teamCode)
        .single();

      if (teamError || !team) {
        return { success: false, error: 'Team not found. Please check the team code.' };
      }

      // Check if this invite code is registered centrally for this team
      console.log('[OnboardingService] joinTeam: Validating invite code centrally...');
      const inviteValidation = await this.validateInviteCode(inviteCode);
      const isRegisteredCentrally = inviteValidation.success && inviteValidation.invite && inviteValidation.invite.team_id === team.id;

      if (!isRegisteredCentrally) {
        console.log('[OnboardingService] joinTeam: Invite not central. Falling back to legacy secret_code_hash comparison.');
        const expectedInviteHash = team.secret_code_hash;
        if (expectedInviteHash !== hashedCode) {
          return { success: false, error: 'Temporary code does not match the specified team.' };
        }
      } else {
        console.log('[OnboardingService] joinTeam: Centrally validated. Legacy secret_code_hash check bypassed.');
      }

      // Directly insert to avoid RLS read-permission bootstrap blocks
      console.log('[OnboardingService] joinTeam: Directly inserting membership...');
      const { error: membershipError } = await client.from('team_members').insert([
        { team_id: team.id, user_id: userId, role: 'member' },
      ]);

      if (membershipError) {
        const msg = membershipError.message || '';
        const isConflict = membershipError.code === '23505' || msg.includes('duplicate key') || msg.includes('already exists') || msg.includes('Conflict');
        
        if (isConflict) {
          console.log('[OnboardingService] User is already a member of this team. Proceeding...');
        } else {
          console.error('[OnboardingService] Failed to insert team membership:', membershipError);
          return { success: false, error: `Failed to join team: ${membershipError.message}` };
        }
      }

      const { data: workspace, error: workspaceError } = await client
        .from('workspaces')
        .select('*')
        .eq('team_id', team.id)
        .limit(1)
        .single();

      let workspaceId = workspace?.id;
      let workspaceName = workspace?.name;

      if (workspaceError || !workspace) {
        const { data: newWorkspace, error: createError } = await client
          .from('workspaces')
          .insert([
            {
              name: `${team.name} Workspace`,
              user_id: userId,
              team_id: team.id,
              visibility: 'team',
            },
          ])
          .select()
          .single();

        if (createError || !newWorkspace) {
          return { success: false, error: createError?.message || 'Failed to initialize team workspace.' };
        }

        workspaceId = newWorkspace.id;
        workspaceName = newWorkspace.name;
      }

      SecureConfigStorage.saveSupabaseConfig(normalizedUrl, supabaseAnonKey);
      SecureConfigStorage.saveWorkspaceMetadata({
        workspaceId: workspaceId!,
        teamId: team.id,
        userId,
        setupMode: 'join',
      });

      return {
        success: true,
        teamId: team.id,
        workspaceId: workspaceId!,
        teamName: team.name,
        workspaceName,
      };
    } catch (error: any) {
      return { success: false, error: error?.message || 'Failed to join team.' };
    }
  }

  static hasExistingConfiguration(): boolean {
    const config = SecureConfigStorage.getSupabaseConfig();
    const metadata = SecureConfigStorage.getWorkspaceMetadata();
    return !!(config && metadata && metadata.workspaceId);
  }

  static async createTeamInvite(
    teamId: string,
    userId: string,
    options: {
      expiresInDays?: number;
      maxUses?: number;
    } = {}
  ): Promise<{ success: boolean; invite?: any; error?: string }> {
    try {
      const { url, anonKey } = getSupabaseConfig();
      if (!url || !anonKey) throw new Error('Supabase not configured');

      const code = this.generateInviteCode();
      const expiresAt = options.expiresInDays
        ? new Date(Date.now() + options.expiresInDays * 24 * 60 * 60 * 1000).toISOString()
        : null;

      const { data, error } = await globalSupabase
        .from('team_invites')
        .insert([
          {
            team_id: teamId,
            created_by: userId,
            code,
            supabase_url: url,
            supabase_anon_key: anonKey,
            expires_at: expiresAt,
            max_uses: options.maxUses || 0,
          },
        ])
        .select()
        .single();

      if (error) throw error;
      return { success: true, invite: data };
    } catch (error: any) {
      return { success: false, error: error.message };
    }
  }

  static async listTeamInvites(teamId: string): Promise<any[]> {
    const { data, error } = await globalSupabase
      .from('team_invites')
      .select('*')
      .eq('team_id', teamId)
      .eq('is_revoked', false)
      .order('created_at', { ascending: false });

    if (error) throw error;
    return data || [];
  }

  static async revokeTeamInvite(inviteId: string): Promise<void> {
    const { error } = await globalSupabase
      .from('team_invites')
      .update({ is_revoked: true })
      .eq('id', inviteId);

    if (error) throw error;
  }

  static async validateInviteCode(code: string): Promise<{
    success: boolean;
    invite?: any;
    error?: string;
  }> {
    try {
      console.log('[OnboardingService] Validating invite code centrally (flat lookup):', code);
      let { data: invite, error } = await globalSupabase
        .from('team_invites')
        .select('*')
        .eq('code', code.trim().toUpperCase())
        .single();

      // Fallback to active/local database client if not found centrally
      if (error || !invite) {
        console.log('[OnboardingService] Invite not found centrally. Falling back to active database client...');
        const localResult = await supabase
          .from('team_invites')
          .select('*')
          .eq('code', code.trim().toUpperCase())
          .single();

        if (!localResult.error && localResult.data) {
          invite = localResult.data;
          error = null;
          console.log('[OnboardingService] Invite successfully resolved from local/active database!');
        }
      }

      if (error || !invite) {
        console.error('[OnboardingService] Invite lookup failed in both global and local databases:', error);
        return { success: false, error: 'Team invite code not found or invalid.' };
      }

      if (invite.is_revoked) {
        return { success: false, error: 'This invite has been revoked.' };
      }

      if (invite.expires_at && new Date(invite.expires_at) < new Date()) {
        return { success: false, error: 'This invite has expired.' };
      }

      if (invite.max_uses > 0 && invite.use_count >= invite.max_uses) {
        return { success: false, error: 'This invite has reached its maximum number of uses.' };
      }

      // Fetch team details dynamically from the target tenant database to bypass global schema constraints
      try {
        console.log('[OnboardingService] Fetching team details from target database:', invite.supabase_url);
        const tenantClient = createClient(invite.supabase_url, invite.supabase_anon_key);
        const { data: team, error: teamError } = await tenantClient
          .from('teams')
          .select('name, description, team_code')
          .eq('id', invite.team_id)
          .single();

        if (!teamError && team) {
          invite.teams = team;
        } else {
          console.warn('[OnboardingService] Failed to fetch team info from tenant database:', teamError);
          invite.teams = {
            name: 'Shared Team Workspace',
            description: 'Collaborative environment',
            team_code: ''
          };
        }
      } catch (teamFetchErr) {
        console.warn('[OnboardingService] Failed to connect to tenant database for team info:', teamFetchErr);
        invite.teams = {
          name: 'Shared Team Workspace',
          description: 'Collaborative environment',
          team_code: ''
        };
      }

      return { success: true, invite };
    } catch (error: any) {
      return { success: false, error: error.message };
    }
  }

  static async joinByInviteCode(
    code: string,
    userId: string
  ): Promise<{
    success: boolean;
    teamId?: string;
    workspaceId?: string;
    error?: string;
  }> {
    const validation = await this.validateInviteCode(code);
    if (!validation.success || !validation.invite) {
      return { success: false, error: validation.error };
    }

    const { invite } = validation;

    // Connect to the project specified in the invite
    const joinResult = await this.joinTeam(
      invite.supabase_url,
      invite.supabase_anon_key,
      userId,
      '', // teamCode - our legacy join used TEAM-XXX but we allow bypass if we have the right invite
      invite.code // We use code as inviteCode
    );

    // If joinTeam failed because we bypassed teamCode, let's fix it or adapt it.
    // Actually, joinTeam (lines 454+) is quite strict. Let's make a more flexible version or modify joinTeam.
    
    // Wait, joinTeam checks teamCode. But we have invite.team_id.
    // Let's implement the specialized logic here instead of relying on legacy joinTeam if it's too restrictive.
    
    if (joinResult.success) {
      // Increment use count
      await globalSupabase
        .from('team_invites')
        .update({ use_count: (invite.use_count || 0) + 1 })
        .eq('id', invite.id);
        
      return joinResult;
    }

    // Try a direct path if joinTeam (designed for manual input) failed
    try {
      const client = createClient(invite.supabase_url, invite.supabase_anon_key);
      const { data: { session } } = await supabase.auth.getSession();
      if (session) await client.auth.setSession(session);

      const { error: membershipError } = await client.from('team_members').insert([
        { team_id: invite.team_id, user_id: userId, role: 'member' },
      ]);

      if (membershipError && !membershipError.message.includes('duplicate key')) {
        throw membershipError;
      }

      const { data: workspace } = await client
        .from('workspaces')
        .select('id')
        .eq('team_id', invite.team_id)
        .limit(1)
        .single();

      SecureConfigStorage.saveSupabaseConfig(invite.supabase_url, invite.supabase_anon_key);
      SecureConfigStorage.saveWorkspaceMetadata({
        workspaceId: workspace?.id || '',
        teamId: invite.team_id,
        userId,
        setupMode: 'join',
      });

      // Increment use count
      await globalSupabase
        .from('team_invites')
        .update({ use_count: (invite.use_count || 0) + 1 })
        .eq('id', invite.id);

      return {
        success: true,
        teamId: invite.team_id,
        workspaceId: workspace?.id
      };
    } catch (e: any) {
      return { success: false, error: e.message };
    }
  }
}

import { supabase, globalSupabase } from '../lib/supabase';
import { RequestData, Collection, Environment, Workspace, Folder, Profile, KeyValue, ScriptExecutionLog } from '../types';
import { isElectron } from '../lib/platform';

export class PersistenceService {
  private static store: any = null;

  static registerStore(store: any) {
    this.store = store;
  }

  private static isOffline(): boolean {
    if (typeof window !== 'undefined' && !window.navigator.onLine) return true;
    return this.store?.getState()?.syncMetadata?.isOffline ?? false;
  }

  private static setOffline(offline: boolean) {
    if (this.store) {
      this.store.getState().updateSyncMetadata({ isOffline: offline });
      const { syncManager } = require('./SyncService');
      syncManager.setStatus(offline ? 'offline' : 'idle');
    }
  }

  private static async runResilientAction<T>(
    onlineAction: () => Promise<T>,
    offlineAction: () => T,
    enqueueAction: (offlineResult: T) => void
  ): Promise<T> {
    // If running in Desktop/Electron, we ALWAYS prioritize offline-first!
    // This executes mutations locally with 0ms latency to maximize speed and stability,
    // and registers syncing as a background, non-blocking queue action.
    if (isElectron() || this.isOffline()) {
      console.log('[PersistenceService] Offline-First Priority Active (Desktop/Local Mode). Execution local-first.');
      const result = offlineAction();
      try {
        enqueueAction(result);
      } catch (syncErr) {
        console.warn('[PersistenceService] Async sync enqueuing failed:', syncErr);
      }
      return result;
    }

    try {
      return await onlineAction();
    } catch (err: any) {
      const isNetworkError = err.message?.includes('Network Error') || 
        err.message?.includes('Failed to fetch') || 
        err.message?.includes('timeout') ||
        err.code === 'ECONNABORTED' ||
        err.status === 0;

      if (isNetworkError) {
        console.warn('[PersistenceService] Database write request timed out or was cut off. Transitioning to local cache buffer.');
        this.setOffline(true);
        const result = offlineAction();
        enqueueAction(result);
        return result;
      }
      throw err;
    }
  }

  // --- Workspace Actions ---
  static async createWorkspace(name: string, userId: string, teamId?: string) {
    return this.runResilientAction(
      () => this.createWorkspaceOnline(name, userId, teamId),
