  static async createRequestOnline(data: Partial<RequestData>) {
    const bodyToSave = typeof data.body === 'object' 
      ? JSON.stringify(data.body) 
      : data.body;

    const mappedData = {
      ...data,
      body: bodyToSave,
      body_type: data.bodyType,
