      const isUuid = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(workspaceId || '');
      if (!isUuid) return [];
      let { data, error } = await supabase
        .from('folders')
        .select('*')
        .eq('workspace_id', workspaceId)
        .is('parent_id', null);

      if (error && String(error.message || '').match(/column.*not exist|schema cache/i)) {
        const fallback = await supabase
          .from('folders')
          .select('*')
          .is('parent_id', null);
        data = fallback.data;
        error = fallback.error;
      }

      if (error) throw error;
      return data || [];
    } catch (e) {
      return [];
    }
  }

  static async createScript(data: any) {
    if (this.isOffline()) {
      const mockScript = {
        id: `offline-${  Math.random().toString(36).substr(2, 9)}`,
        ...data,
        created_at: new Date().toISOString()
      };
      return mockScript;
    }
    const { data: script, error } = await supabase
      .from('scripts')
      .insert([data])
      .select()
      .single();
    if (error) throw error;
    return script;
  }

  static async updateScript(id: string, updates: any) {
    if (this.isOffline()) {
      return { id, ...updates };
    }
    const { data, error } = await supabase
      .from('scripts')
      .update(updates)
      .eq('id', id)
      .select()
      .single();
    if (error) throw error;
    return data;
  }

  static async deleteScript(id: string) {
    if (this.isOffline()) return;
    const { error } = await supabase.from('scripts').delete().eq('id', id);
    if (error) throw error;
  }
}

import { isElectron } from '../lib/platform';

export class ProxyService {
  private static cache = new Map<string, { proxy: string; timestamp: number }>();
  private static CACHE_TTL = 5 * 60 * 1000; // 5 minutes cache TTL

  /**
   * Resolves the proxy configuration for a given URL.
   * On Web, it relies completely on the browser stack.
   * On Electron, it resolves the proxy dynamically through the main process session.
   */
  static async resolveProxy(url: string): Promise<string> {
    if (!isElectron()) {
      return 'DIRECT (Native Browser Stack)';
    }

    try {
      const parsed = new URL(url);
      const hostKey = parsed.host;

      // Check resolved proxy cache
      const cached = this.cache.get(hostKey);
      if (cached && Date.now() - cached.timestamp < this.CACHE_TTL) {
        return cached.proxy;
      }

      const ipc = (window as any).ipcRenderer;
      if (ipc) {
        const proxyStr = await ipc.invoke('resolve-proxy', url);
        this.cache.set(hostKey, { proxy: proxyStr, timestamp: Date.now() });
        return proxyStr;
      }
    } catch (e) {
      console.warn('[ProxyService] Dynamic proxy resolution fallback to DIRECT:', e);
    }

    return 'DIRECT';
  }

  /**
   * Syncs proxy settings configuration with the Electron main process session.
   */
  static syncSettings(proxySettings: any) {
    if (!isElectron()) return;
    try {
      const ipc = (window as any).ipcRenderer;
      if (ipc) {
        ipc.send('update-proxy-settings', proxySettings);
      }
    } catch (e) {
      console.error('[ProxyService] Failed to sync proxy settings to main process:', e);
    }
  }
}

import axios, { AxiosRequestConfig, AxiosResponse } from 'axios';
import { RequestData, ResponseData, KeyValue, AuthConfig, Collection } from '../types';
import { VariableService } from './VariableService';
import { AuthService } from './AuthService';
import { useStore } from '../store/useStore';
import { isElectron } from '../lib/platform';
import { ProxyService } from './ProxyService';

interface NetworkDiagnostic {
  errorType: 'DNS_FAILURE' | 'SSL_ERROR' | 'CORS_ERROR' | 'TIMEOUT' | 'OFFLINE' | 'PROXY_ERROR' | 'CONNECTION_REFUSED' | 'GENERIC_ERROR';
  message: string;
  recommendation: string;
}

export interface MswMockConfig {
  enabled: boolean;
  status: number;
  statusText: string;
  latency: number;
  responseType: 'json' | 'text' | 'empty';
  responseBody: string;
}

export class RequestService {
  public static mswConfig: MswMockConfig = (() => {
    try {
      const saved = localStorage.getItem('gmy-msw-mock-config');
      if (saved) return JSON.parse(saved);
    } catch {}
    return {
      enabled: false,
      status: 200,
      statusText: 'OK',
      latency: 10,
      responseType: 'json',
      responseBody: '{\n  "status": "success",\n  "msw_mocked": true,\n  "message": "Intercepted successfully by MSW service layer"\n}'
    };
  })();

  public static saveMswConfig(config: MswMockConfig) {
    this.mswConfig = config;
    try {
      localStorage.setItem('gmy-msw-mock-config', JSON.stringify(config));
    } catch {}
  }

  private static diagnoseError(error: any, isWeb: boolean): NetworkDiagnostic {
    if (typeof navigator !== 'undefined' && !navigator.onLine) {
      return {
        errorType: 'OFFLINE',
        message: 'System is offline.',
        recommendation: 'Check your internet connection or network adapter.'
      };
    }

    const code = error?.code || '';
    const message = (error?.message || '').toLowerCase();

    if (code === 'ECONNABORTED' || message.includes('timeout') || message.includes('exceeded')) {
      return {
        errorType: 'TIMEOUT',
        message: 'Request timed out.',
        recommendation: 'Increase the timeout setting in the request or general settings.'
      };
    }

    if (code === 'ENOTFOUND' || message.includes('enotfound') || message.includes('dns')) {
      return {
        errorType: 'DNS_FAILURE',
        message: 'DNS resolution failed. Hostname could not be resolved.',
        recommendation: 'Check your DNS settings or ensure the domain name is spelled correctly.'
      };
    }

    if (message.includes('ssl') || message.includes('cert') || message.includes('tls') || code.includes('DEPTH_ZERO_SELF_SIGNED_CERT')) {
      return {
        errorType: 'SSL_ERROR',
        message: 'SSL/TLS handshake or certificate verification failed.',
        recommendation: 'Disable "SSL Verification" in SSL/TLS settings if using self-signed development certificates.'
      };
    }

    if (message.includes('proxy') || code.includes('PROXY')) {
      return {
        errorType: 'PROXY_ERROR',
        message: 'Failed to establish connection through proxy.',
        recommendation: 'Verify that your active proxy server is running, authenticated, and reachable.'
      };
    }

    if (code === 'ECONNREFUSED' || message.includes('refused')) {
      return {
        errorType: 'CONNECTION_REFUSED',
        message: 'Connection refused by target server.',
        recommendation: 'Check if the target server is active and listening on the specified port.'
      };
    }

    if (isWeb && (message.includes('network error') || (error?.isAxiosError && !error?.response))) {
      return {
        errorType: 'CORS_ERROR',
        message: 'CORS policy blocked request or network link was cut.',
        recommendation: 'Verify the target server allows CORS from your origin, or use the Desktop version of the application to bypass browser CORS sandbox restrictions.'
      };
    }

    return {
      errorType: 'GENERIC_ERROR',
      message: error?.message || 'An unknown network error occurred.',
      recommendation: 'Check browser/application console logs or verify the target endpoint directly.'
    };
  }

  static async execute(request: RequestData, context: {
    environments: any[];
    activeEnvId: string | null;
    collections: Collection[];
    workspaceVariables?: KeyValue[];
    variables?: Record<string, any>;
    signal?: AbortSignal;
  }): Promise<ResponseData> {
    const state = useStore.getState();
    const globalSettings = state.settings;
    const start = Date.now();
    
    // 1. Find Collection for Auth Inheritance
    const activeCollection = context.collections.find(c => c.id === request.collection_id) || null;
    const variableContext = { ...context, collection: activeCollection };

    // 3. Resolve variables
    let resolvedUrl = VariableService.resolve(request.url, variableContext);

    // Normalize URL: prepend protocol if missing and not a relative path
    if (resolvedUrl) {
      const trimmedUrl = resolvedUrl.trim();
      const hasProtocol = /^[a-zA-Z]+:\/\//.test(trimmedUrl) || trimmedUrl.startsWith('//');
      const isPathRelative = trimmedUrl.startsWith('/');
      if (!hasProtocol && !isPathRelative) {
        resolvedUrl = `http://${  trimmedUrl}`;
      }
    }

    // 3.3. MSW Inspired Virtual Network Interceptor Check
    if (RequestService.mswConfig.enabled) {
      if (RequestService.mswConfig.latency > 0) {
        await new Promise(resolve => setTimeout(resolve, RequestService.mswConfig.latency));
      }
      const end = Date.now();
      return {
        id: `msw-${  Math.random().toString(36).substr(2, 9)}`,
        status: RequestService.mswConfig.status,
        statusText: `MSW Intercept: ${RequestService.mswConfig.statusText}`,
        headers: {
          'content-type': RequestService.mswConfig.responseType === 'json' ? 'application/json' : 'text/plain',
          'x-gimay-msw-mocked': 'true',
          'access-control-allow-origin': '*'
        },
        body: RequestService.mswConfig.responseBody,
        time: end - start,
        size: RequestService.mswConfig.responseBody ? RequestService.mswConfig.responseBody.length : 0,
        contentType: RequestService.mswConfig.responseType === 'json' ? 'application/json' : 'text/plain',
        request_config: {
          runtimeEnv: 'MSW Virtual Service Worker',
          urlIntercepted: resolvedUrl,
          method: request.method
        }
      };
    }
    
    // 3.5. Inject Network Chaos Fuzzer
    const isChaosEnabled = (request.settings as any)?.chaosEnabled ?? false;
    if (isChaosEnabled) {
      // 1. Latency Jitter simulation
      const minDelay = (request.settings as any)?.chaosMinDelay ?? 0;
      const maxDelay = (request.settings as any)?.chaosMaxDelay ?? 0;
      if (maxDelay > minDelay) {
        const jitter = Math.floor(Math.random() * (maxDelay - minDelay) + minDelay);
        await new Promise(resolve => setTimeout(resolve, jitter));
      }

      // 2. HTTP Status Failure Fuzzing
      const failureRate = (request.settings as any)?.chaosFailureRate ?? 0;
      if (Math.random() * 100 < failureRate) {
        const end = Date.now();
        const fuzzedErrors = [
          { status: 408, text: 'Request Timeout (Fuzzed)', msg: 'Target timeout limit exceeded.' },
          { status: 429, text: 'Too Many Requests (Fuzzed)', msg: 'API Rate limit throttled by Chaos Fuzzer.' },
          { status: 500, text: 'Internal Server Error (Fuzzed)', msg: 'Simulated backend database collision.' },
          { status: 503, text: 'Service Unavailable (Fuzzed)', msg: 'Backend instance reported unhealthy.' },
          { status: 504, text: 'Gateway Timeout (Fuzzed)', msg: 'Ingress proxy socket dropped link.' }
        ];
        const errorTemplate = fuzzedErrors[Math.floor(Math.random() * fuzzedErrors.length)];
        
        return {
          id: Math.random().toString(36).substr(2, 9),
          status: errorTemplate.status,
          statusText: `Chaos Intercept: ${errorTemplate.text}`,
          headers: { 'x-gimay-chaos': 'active' },
          body: JSON.stringify({
            error: errorTemplate.text,
            message: errorTemplate.msg,
            recommendation: 'Verify your client application handles network retries, throttles, and server crash screens gracefully.'
          }, null, 2),
          time: end - start,
          size: 0,
          contentType: 'application/json',
          request_config: {
            runtimeEnv: isElectron() ? 'Electron/Desktop' : 'Web Browser',
            chaosFuzzer: 'Active intercept'
          }
        };
      }
    }

    const resolvedHeaders = this.resolveKeyValues(request.headers, variableContext);
    const resolvedParams = this.resolveKeyValues(request.params, variableContext);
    
    // Normalize body if it's a string (legacy)
    const body = typeof request.body === 'string' 
      ? { type: request.bodyType, content: request.body } as any 
      : request.body;

    const configHeaders = this.mapHeaders(resolvedHeaders);
    if (!configHeaders['Connection'] && !configHeaders['connection']) {
      configHeaders['Connection'] = 'close'; // Prompts immediate close of sockets, reducing memory retention
    }

    // 4. Prepare Axios Config
    const config: AxiosRequestConfig = {
      url: resolvedUrl,
      method: request.method,
      headers: configHeaders,
      params: this.mapParams(resolvedParams),
      data: this.prepareBody(body, request.bodyType, variableContext),
      validateStatus: () => true,
      
      // Let browser/Electron native Chromium stack handle proxies and network
      proxy: false,
      
      // Global Settings Merged with Overrides
      timeout: request.settings?.timeout || globalSettings.general.requestTimeout || 0,
      maxRedirects: request.settings?.maxRedirects || globalSettings.general.maxRedirects || 10,
      maxContentLength: globalSettings.general.maxResponseSize,
    };

    // 5. Apply Auth (Inheritance handled here)
    const effectiveAuth = AuthService.getEffectiveAuth(request, context.collections);
    this.applyAuth(config, effectiveAuth, variableContext);

    // Resolve Proxy for Diagnostics and Execution Context
    const resolvedProxy = await ProxyService.resolveProxy(resolvedUrl);

    // Retry settings
    const retryCount = globalSettings.general.retryCount || 0;
    const retryDelay = globalSettings.general.retryDelay || 1000;

    let response: AxiosResponse | null = null;
    let lastError: any = null;
    let attempts = 0;

    // Determine local or path-relative environments
    const originStr = typeof window !== 'undefined' ? window.location.origin : '';
    const isLocalhost = resolvedUrl ? (
      resolvedUrl.includes('localhost') || 
      resolvedUrl.includes('127.0.0.1') || 
      resolvedUrl.includes('0.0.0.0') || 
      resolvedUrl.includes('.local') ||
      resolvedUrl.startsWith('/') ||
      (originStr && resolvedUrl.startsWith(originStr))
    ) : false;

    const isFormData = config.data instanceof FormData || (config.data && config.data.constructor?.name === 'FormData');
    const useWebProxy = !isElectron() && !isFormData && !isLocalhost; // In browser, route external non-form requests through local CORS proxy server to bypass CORS!

    while (attempts <= retryCount) {
      try {
        if (useWebProxy) {
          // Route request through our internal Express CORS proxy bridge
          let requestData = config.data;
          if (requestData && (requestData instanceof URLSearchParams || requestData.constructor?.name === 'URLSearchParams' || typeof requestData.append === 'function')) {
            requestData = requestData.toString();
          }

          const proxyResponse = await axios.post('/api/proxy', {
            method: config.method,
            url: config.url,
            headers: config.headers,
            data: requestData,
            params: config.params,
            timeout: config.timeout
          }, {
            signal: context.signal,
            timeout: config.timeout ? config.timeout + 1500 : undefined
          });

          // Map the proxy's server-to-server request response to look exactly like standard AxiosResponse
          response = {
            status: proxyResponse.data.status,
            statusText: proxyResponse.data.statusText,
            headers: proxyResponse.data.headers,
            data: proxyResponse.data.data,
            config: config,
            headersText: ''
          } as AxiosResponse;
        } else {
          // In Electron native process, direct axios works perfectly
          config.signal = context.signal;
          response = await axios(config);
        }
        break; // Success! Break loop
      } catch (error: any) {
        // If the error comes from our CORS proxy server, extract the original underlying server message
        if (error.response?.data?.error) {
          lastError = new Error(error.response.data.error);
          if (error.response.data.details) {
            lastError.stack = typeof error.response.data.details === 'string' 
              ? error.response.data.details 
              : JSON.stringify(error.response.data.details);
          }
        } else {
          lastError = error;
        }
        attempts++;
        if (attempts <= retryCount) {
          await new Promise((resolve) => setTimeout(resolve, retryDelay));
        }
      }
    }

    const end = Date.now();

    if (response) {
      const responseStatus = response.status;
      const responseStatusText = response.statusText;
      const responseHeaders = response.headers;
      const responseData = response.data;

      // Safe size estimation of the payload without doing full JSON.stringify string duplication
      const contentLengthHeader = responseHeaders ? (responseHeaders['content-length'] || responseHeaders['Content-Length']) : null;
      let calculatedSize = 0;
      if (contentLengthHeader) {
        calculatedSize = parseInt(String(contentLengthHeader), 10) || 0;
      } else if (responseData) {
        if (typeof responseData === 'string') {
          calculatedSize = responseData.length;
        } else {
          try {
            // For general objects, estimate or only stringify if reasonable size
            calculatedSize = JSON.stringify(responseData).length;
          } catch {
            calculatedSize = 0;
          }
        }
      }

      const contentTypeValue = responseHeaders ? String(responseHeaders['content-type'] || responseHeaders['Content-Type'] || 'text/plain') : 'text/plain';

      // Aggressively dereference bulky response objects for garbage collection
      (response as any) = null;

      return {
        id: Math.random().toString(36).substr(2, 9),
        status: responseStatus,
        statusText: responseStatusText,
        headers: responseHeaders as any,
        body: responseData,
        time: end - start,
        size: calculatedSize,
        contentType: contentTypeValue,
        request_config: {
          resolvedProxy,
          runtimeEnv: isElectron() ? 'Electron/Desktop' : 'Web Browser',
          sslStatus: globalSettings.ssl.verifySSL ? 'Strict (Verified)' : 'Disabled'
        }
      };
    } else {
      let diagnostics = this.diagnoseError(lastError, !isElectron());
      let traceSteps: any[] = [];

      if (isElectron() && typeof (window as any).electron?.runNetworkDiagnostics === 'function') {
        try {
          const nativeDiag = await (window as any).electron.runNetworkDiagnostics(resolvedUrl);
          if (nativeDiag) {
            diagnostics = {
              errorType: nativeDiag.errorType,
              message: nativeDiag.message,
              recommendation: nativeDiag.recommendation
            };
            traceSteps = nativeDiag.steps || [];
          }
        } catch (diagErr) {
          console.error('[RequestService] Native socket diagnostics tracer failed:', diagErr);
        }
      }

      return {
        id: Math.random().toString(36).substr(2, 9),
        status: 0,
        statusText: `Network Error: ${diagnostics.errorType}`,
        headers: {},
        body: JSON.stringify({
          error: lastError?.message || 'Network Error',
          diagnostics: {
            type: diagnostics.errorType,
            message: diagnostics.message,
            recommendation: diagnostics.recommendation,
            trace: traceSteps.length > 0 ? traceSteps : undefined
          },
          details: lastError?.stack || 'Request execution failed after retries'
        }, null, 2),
        time: end - start,
        size: 0,
        contentType: 'application/json',
        request_config: {
          resolvedProxy,
          runtimeEnv: isElectron() ? 'Electron/Desktop' : 'Web Browser',
          sslStatus: globalSettings.ssl.verifySSL ? 'Strict (Verified)' : 'Disabled'
        }
      };
    }
  }

  private static resolveKeyValues(items: KeyValue[], context: any): KeyValue[] {
    if (!items) return [];
    return items.map(item => ({
      ...item,
      key: VariableService.resolve(item.key, context),
      value: VariableService.resolve(item.value, context),
    }));
  }

  private static mapHeaders(headers: KeyValue[]): Record<string, string> {
    const result: Record<string, string> = {};
    headers.forEach(h => {
      if (h.active && h.key) result[h.key] = String(h.value);
    });
    return result;
  }

  private static mapParams(params: KeyValue[]): Record<string, string> {
    const result: Record<string, string> = {};
    params.forEach(p => {
      if (p.active && p.key) result[p.key] = p.value;
    });
    return result;
  }

  private static prepareBody(body: any, type: string, context: any): any {
    if (!body || type === 'none') return null;

    if (type === 'json') {
      const resolved = VariableService.resolve(body.content || '', context);
      try {
        return JSON.parse(resolved);
      } catch {
        return resolved;
      }
    }

    if (type === 'form-data') {
      const formData = new FormData();
      (body.formData || []).forEach((item: any) => {
        if (!item || item.active === false || !item.key) return;
        if (item.type === 'file' && item.file) {
          formData.append(item.key, item.file);
        } else {
          formData.append(item.key, VariableService.resolve(item.value || '', context));
        }
      });
      return formData;
    }

    if (type === 'urlencoded') {
      const params = new URLSearchParams();
      (body.urlencoded || []).forEach((item: any) => {
        if (item && item.active !== false && item.key) {
          params.append(item.key, VariableService.resolve(item.value || '', context));
        }
      });
      return params;
    }

    if (type === 'graphql') {
      const query = VariableService.resolve(body.graphql?.query || '', context);
      const variablesStr = VariableService.resolve(body.graphql?.variables || '{}', context);
      try {
        const variables = JSON.parse(variablesStr);
        return { query, variables };
      } catch {
        return { query, variables: {} };
      }
    }

    if (type === 'binary') {
      return body.binary?.file || null;
    }

    // Default: raw, xml, etc.
    return VariableService.resolve(body.content || '', context);
  }

  private static applyAuth(config: AxiosRequestConfig, auth: AuthConfig, context: any) {
    if (!auth || auth.type === 'none') return;

    if (auth.type === 'bearer' && auth.bearer) {
      const token = VariableService.resolve(auth.bearer, context);
      config.headers = { ...config.headers, Authorization: `Bearer ${token}` };
    }

    if (auth.type === 'basic' && auth.basic) {
      const user = VariableService.resolve(auth.basic.username || '', context);
      const pass = VariableService.resolve(auth.basic.password || '', context);
      const encoded = btoa(`${user}:${pass}`);
      config.headers = { ...config.headers, Authorization: `Basic ${encoded}` };
    }

    if (auth.type === 'apikey' && auth.apiKey) {
      const key = VariableService.resolve(auth.apiKey.key, context);
      const value = VariableService.resolve(auth.apiKey.value, context);
      if (auth.apiKey.addTo === 'header') {
        config.headers = { ...config.headers, [key]: value };
      } else {
        config.params = { ...config.params, [key]: value };
      }
    }

    if (auth.type === 'oauth2' && auth.oauth2) {
      const token = VariableService.resolve(auth.oauth2.accessToken || '', context);
      const type = auth.oauth2.tokenType || 'Bearer';
      if (token) {
        config.headers = { ...config.headers, Authorization: `${type} ${token}` };
      }
    }
  }
}

import { supabase } from '../lib/supabase';
import { ScriptCategory, ScriptTemplate } from '../types';
import { defaultScriptCategories, defaultScripts } from '../lib/defaultScripts';

export class ScriptLibraryService {
  static async fetchCategories(): Promise<ScriptCategory[]> {
    const { data, error } = await supabase
      .from('script_categories')
      .select('*')
      .order('name');
      
    if (error) {
      console.warn('Failed to fetch script categories:', error);
      return [];
    }
    
    if (!data || data.length === 0) {
      const seeded = await this.seedBuiltInScripts();
      if (seeded) {
        const { data: newData } = await supabase
          .from('script_categories')
          .select('*')
          .order('name');
        return newData || [];
      }
    }
    
    return data || [];
  }

  static async fetchTemplates(): Promise<ScriptTemplate[]> {
    const { data, error } = await supabase
      .from('script_library')
      .select('*, categories(*)')
      .order('is_builtin', { ascending: false })
      .order('name');
    if (error) throw error;
    return data || [];
  }

  static async toggleFavorite(scriptId: string, userId: string, isFavorite: boolean) {
    if (isFavorite) {
      const { error } = await supabase.from('script_favorites').insert([{ script_id: scriptId, user_id: userId }]);
      if (error) throw error;
    } else {
      const { error } = await supabase.from('script_favorites').delete().match({ script_id: scriptId, user_id: userId });
      if (error) throw error;
    }
  }

  static async fetchFavorites(userId: string): Promise<string[]> {
    const { data, error } = await supabase.from('script_favorites').select('script_id').eq('user_id', userId);
    if (error) throw error;
    return data.map(d => d.script_id);
  }

  static async logExecution(logData: {
    request_id?: string;
    workspace_id?: string;
    user_id: string;
    logs: any[];
    errors: any[];
    duration: number;
    variables_changed: Record<string, any>;
  }) {
    const { error } = await supabase.from('script_execution_logs').insert([logData]);
    if (error) console.error('Error saving execution log:', error);
  }

  static async seedBuiltInScripts(): Promise<boolean> {
    try {
      // Insert categories
      const { data: cats, error: catError } = await supabase
        .from('script_categories')
        .insert(defaultScriptCategories)
        .select();
      
      if (catError) {
        console.warn('Skipping script seed (likely insufficient permissions):', catError.message);
        return false;
      }
      if (!cats) return false;

      // Map categories to get IDs
      const catMap = cats.reduce((acc: Record<string, string>, cat) => {
        acc[cat.name] = cat.id;
        return acc;
      }, {});

      const scriptsToInsert = defaultScripts.map(script => ({
        name: script.name,
        description: script.description,
        content: script.content,
        category_id: catMap[script.categoryName],
        variables_used: script.variables_used,
        version: script.version,
        is_builtin: true,
        tags: script.tags
      }));

      const { error: scriptError } = await supabase.from('script_library').insert(scriptsToInsert);
      if (scriptError) {
        console.warn('Failed to seed script library:', scriptError.message);
        return false;
      }
      return true;
    } catch (err) {
      console.warn('Exception during script seeding:', err);
      return false;
    }
  }
}

import { ResponseData } from '../types';
import { SandboxRunner } from './sandboxRunner';

export class ScriptService {
  static async executePreRequest(scripts: string | string[], request: any, context: any) {
    const scriptsToRun = (Array.isArray(scripts) ? scripts : [scripts])
      .map(s => s ? s.trim() : '')
      .filter(Boolean);
    const logs: { level: 'log' | 'info' | 'warn' | 'error'; args: any[]; timestamp: string }[] = [];

    const variablesMap = { ...(context.variables || {}) };

    const activeEnv = context.activeEnvId && context.environments
      ? context.environments.find((env: any) => env.id === context.activeEnvId)
      : null;
    const environmentVariablesMap: Record<string, any> = {};
    if (activeEnv && activeEnv.variables) {
      activeEnv.variables.forEach((v: any) => {
        if (v.active) environmentVariablesMap[v.key] = v.value;
      });
    }

    const environmentMutations: Record<string, any> = {};

    if (scriptsToRun.length > 0) {
      // Bundling multiple scripts into a single safe block-scoped script runs them inside the same Worker isolate
      // which avoids thread creation and communication overhead.
      const bundledScript = scriptsToRun.map(script => `{\n${script}\n}`).join('\n;\n');
      
      try {
        const result = await SandboxRunner.run(bundledScript, {
          variables: variablesMap,
          environmentVariables: environmentVariablesMap,
          signal: context.signal,
          request: {
            method: request?.method || 'GET',
            url: request?.url || '',
            headers: request?.headers || [],
            body: request?.body || ''
          }
        }, 5000, !!context.useWorker);
        
        // Sync variables modifications back
        const changedVars = result?.changedVariables || {};
        Object.assign(variablesMap, changedVars);
        if (context.variables) {
          for (const [key, value] of Object.entries(changedVars)) {
            if (value === null) {
              delete context.variables[key];
            } else {
              context.variables[key] = value;
            }
          }
        }

        // Sync environment modifications back
        if (result?.changedEnvironment) {
          Object.assign(environmentMutations, result.changedEnvironment);
          for (const [key, value] of Object.entries(result.changedEnvironment)) {
            if (value === null) {
              delete environmentVariablesMap[key];
            } else {
              environmentVariablesMap[key] = value;
            }
          }
        }
        
        // Sync request modifications back
        if (result?.changedRequest) {
          if (result.changedRequest.url) request.url = result.changedRequest.url;
          if (result.changedRequest.method) request.method = result.changedRequest.method;
          if (result.changedRequest.headers) request.headers = result.changedRequest.headers;
          if (result.changedRequest.body !== undefined) {
             if (typeof request.body === 'object' && request.body !== null) {
                 if ('content' in request.body) request.body.content = result.changedRequest.body;
                 else request.body = result.changedRequest.body;
             } else {
                 request.body = result.changedRequest.body;
             }
          }
        }
        
        // Collect sandbox logs
        const sLogs = result?.logs || [];
        sLogs.forEach(log => {
          logs.push({
            level: log.level === 'log' ? 'log' : log.level === 'warn' ? 'warn' : log.level === 'error' ? 'error' : 'info',
            args: [log.message],
            timestamp: new Date().toISOString()
          });
        });
      } catch (error: any) {
        logs.push({
          level: 'error',
          args: [`Pre-request execution error: ${  error.message}`],
          timestamp: new Date().toISOString()
        });
      }
    }

    return { request, logs, environmentMutations };
  }

  static async executeTests(scripts: string | string[], response: ResponseData, request: any, context: any) {
    const scriptsToRun = (Array.isArray(scripts) ? scripts : [scripts])
      .map(s => s ? s.trim() : '')
      .filter(Boolean);
    const results: { name: string; status: 'pass' | 'fail'; message?: string }[] = [];
    const logs: { level: 'log' | 'info' | 'warn' | 'error'; args: any[]; timestamp: string }[] = [];

    const variablesMap = { ...(context.variables || {}) };

    const activeEnv = context.activeEnvId && context.environments
      ? context.environments.find((env: any) => env.id === context.activeEnvId)
      : null;
    const environmentVariablesMap: Record<string, any> = {};
    if (activeEnv && activeEnv.variables) {
      activeEnv.variables.forEach((v: any) => {
        if (v.active) environmentVariablesMap[v.key] = v.value;
      });
    }

    const environmentMutations: Record<string, any> = {};

    if (scriptsToRun.length > 0) {
      // Bundling multiple scripts into a single safe block-scoped script runs them inside the same Worker isolate
      // which avoids thread creation and communication overhead.
      const bundledScript = scriptsToRun.map(script => `{\n${script}\n}`).join('\n;\n');
      
      try {
        const result = await SandboxRunner.run(bundledScript, {
          variables: variablesMap,
          environmentVariables: environmentVariablesMap,
          signal: context.signal,
          request: {
            method: request?.method || 'GET',
            url: request?.url || '',
            headers: request?.headers || [],
            body: request?.body || ''
          },
          response: {
            status: response.status,
            statusText: response.statusText,
            headers: response.headers,
            time: response.time,
            size: response.size,
            body: response.body
          }
        }, 5000, !!context.useWorker);
        
        // Sync variables modifications back
        const changedVars = result?.changedVariables || {};
        Object.assign(variablesMap, changedVars);
        if (context.variables) {
          for (const [key, value] of Object.entries(changedVars)) {
            if (value === null) {
              delete context.variables[key];
            } else {
              context.variables[key] = value;
            }
          }
        }

        // Sync environment modifications back
        if (result?.changedEnvironment) {
          Object.assign(environmentMutations, result.changedEnvironment);
          for (const [key, value] of Object.entries(result.changedEnvironment)) {
            if (value === null) {
              delete environmentVariablesMap[key];
            } else {
              environmentVariablesMap[key] = value;
            }
          }
        }
        
        // Collect sandbox logs
        const sLogs = result?.logs || [];
        sLogs.forEach(log => {
          logs.push({
            level: log.level === 'log' ? 'log' : log.level === 'warn' ? 'warn' : log.level === 'error' ? 'error' : 'info',
            args: [log.message],
            timestamp: new Date().toISOString()
          });
        });

        // Collect test assertions
        const sResults = result?.testResults || [];
        sResults.forEach(tr => {
          results.push({
            name: tr.name,
            status: tr.status,
            message: tr.message
          });
        });
      } catch (error: any) {
        logs.push({
          level: 'error',
          args: [`Test execution error: ${  error.message}`],
          timestamp: new Date().toISOString()
        });
      }
    }

    return { results, logs, environmentMutations };
  }
}

import { supabase } from '../lib/supabase';
import { AuthErrorHandler, AuthErrorResponse } from '../utils/AuthErrorHandler';

export interface AuthResponse {
  success: boolean;
  error?: AuthErrorResponse;
  data?: any;
}

export class SupabaseAuthService {
  /**
   * UX Layer Pre-check: Check if a profile exists for this email.
   * Note: This only checks public.profiles, not auth.users.
   */
  static async checkEmailExists(email: string): Promise<boolean> {
    try {
      const { data } = await supabase
        .from('profiles')
        .select('id')
        .eq('email', email)
        .maybeSingle();
      
      return !!data;
    } catch (e) {
      return false;
    }
  }

  static async signUp(email: string, password: string, fullName?: string): Promise<AuthResponse> {
    try {
      // 1. Optional UX Pre-check
      const exists = await this.checkEmailExists(email);
      if (exists) {
        return {
          success: false,
          error: {
            type: 'user_exists',
            message: 'This email is already registered. Please log in instead.'
          }
        };
      }

      // 2. Proceed with Supabase Auth SignUp
      const { data, error } = await supabase.auth.signUp({
        email,
        password,
        options: {
          data: {
            full_name: fullName || email.split('@')[0],
          }
        }
      });

      if (error) {
        return { success: false, error: AuthErrorHandler.handle(error) };
      }

      // 3. Handle the "silent" already registered case (identities is empty)
      const identities = data?.user?.identities;
      if (data?.user && Array.isArray(identities) && identities.length === 0) {
        return {
          success: false,
          error: {
            type: 'user_exists',
            message: 'This email is already registered. Please log in instead.'
          }
        };
      }

      return { success: true, data };
    } catch (e) {
      return { 
        success: false, 
        error: { type: 'network_error', message: 'Connection failed. Please check your network.' } 
      };
    }
  }

  static async signIn(email: string, password: string): Promise<AuthResponse> {
    try {
      const { data, error } = await supabase.auth.signInWithPassword({
        email,
        password
      });

      if (error) {
        return { success: false, error: AuthErrorHandler.handle(error) };
      }
      
      return { success: true, data };
    } catch (e) {
      return { 
        success: false, 
        error: { type: 'network_error', message: 'Connection failed. Please check your network.' } 
      };
    }
  }

  static async signOut(): Promise<AuthResponse> {
    const { error } = await supabase.auth.signOut();
    if (error) return { success: false, error: AuthErrorHandler.handle(error) };
    return { success: true };
  }

  static async getCurrentUser() {
    const { data: { user } } = await supabase.auth.getUser();
    return user;
  }
}

import { PersistenceService } from './PersistenceService';
import { useStore } from '../store/useStore';

type SyncStatus = 'idle' | 'saving' | 'saved' | 'error' | 'pending' | 'offline';
type ResourceType = 'request' | 'collection' | 'environment' | 'workspace' | 'profile' | 'folder';

interface PendingChange {
  type: ResourceType;
  action: 'create' | 'update' | 'delete';
  id: string;
  data: any;
  timestamp: number;
}

class SyncManager {
  private queue: Map<string, PendingChange> = new Map();
  private timers: Map<string, NodeJS.Timeout> = new Map();
  private statusListeners: Set<(status: SyncStatus) => void> = new Set();
  private currentStatus: SyncStatus = 'idle';
  private DEBOUNCE_MS = 5000;
  private MAX_RETRIES = 5;
  private processingKeys: Set<string> = new Set();
  private processingPromises: Map<string, Promise<void>> = new Map();

  constructor() {
    if (typeof window !== 'undefined') {
      // 1. Load persisted queue from localStorage
      try {
        const savedQueue = localStorage.getItem('gimay-offline-sync-queue');
        if (savedQueue) {
          const parsed = JSON.parse(savedQueue);
          if (Array.isArray(parsed)) {
            parsed.forEach(([key, change]: [string, PendingChange]) => {
              this.queue.set(key, change);
            });
            console.log(`[SyncManager] Restored ${this.queue.size} pending offline actions.`);
            this.updatePendingIds();
          }
        }
      } catch (err) {
        console.error('[SyncManager] Failed to restore offline sync queue:', err);
      }

      window.addEventListener('beforeunload', (e) => {
        if (this.queue.size > 0 && !useStore.getState().syncMetadata.isOffline) {
          this.flushAll();
        }
      });

      window.addEventListener('online', () => this.handleConnectivityChange(true));
      window.addEventListener('offline', () => this.handleConnectivityChange(false));
      
      // Init offline state
      setTimeout(() => {
        try {
          this.handleConnectivityChange(window.navigator.onLine);
        } catch (e) {
          console.warn('SyncManager: Delayed initialization failed, will retry on next check.', e);
        }
      }, 0);
    }
  }

  private handleConnectivityChange(isOnline: boolean) {
    useStore.getState().updateSyncMetadata({ isOffline: !isOnline });
    if (isOnline) {
      if (this.queue.size > 0) {
        this.flushAll();
      } else {
        this.setStatus(this.queue.size > 0 ? 'pending' : 'idle');
      }
    } else {
      this.setStatus('offline');
    }
  }

  public isPending(id: string): boolean {
    return Array.from(this.queue.values()).some(change => change.id === id);
  }

  private updatePendingIds() {
    const ids = new Set(Array.from(this.queue.values()).map(c => c.id));
    useStore.getState().setPendingSyncIds(ids);
  }

  private persistQueue() {
    if (typeof window !== 'undefined') {
      try {
        const serialized = JSON.stringify(Array.from(this.queue.entries()));
        localStorage.setItem('gimay-offline-sync-queue', serialized);
      } catch (err) {
        console.error('[SyncManager] Failed to persist offline queue:', err);
      }
    }
  }

  onStatusChange(listener: (status: SyncStatus) => void) {
    this.statusListeners.add(listener);
    listener(this.currentStatus);
    return () => this.statusListeners.delete(listener);
  }

  public setStatus(status: SyncStatus) {
    this.currentStatus = status;
    this.statusListeners.forEach(l => l(status));
    useStore.getState().setSyncStatus(status);
  }

  public enqueueAction(type: ResourceType, action: 'create' | 'update' | 'delete', id: string, data: any) {
    const key = `${type}:${action}:${id}`;
    
    // For updates, check if there is an existing 'create' in the queue for this same temporary ID
    // If so, we merge the updates directly into the pending creation data!
    if (action === 'update') {
      const createKey = `${type}:create:${id}`;
      const existingCreate = this.queue.get(createKey);
      if (existingCreate) {
        existingCreate.data = { ...existingCreate.data, ...data };
        existingCreate.timestamp = Date.now();
        this.persistQueue();
        return;
      }
    }

    const existing = this.queue.get(key);
    this.queue.set(key, {
      type,
      action,
      id,
      data: existing ? { ...existing.data, ...data } : data,
      timestamp: Date.now()
    });

    this.updatePendingIds();
    this.persistQueue();
    useStore.getState().updateSyncMetadata({ lastSaved: Date.now() });

    const state = useStore.getState();
    const autoSave = state.settings.general.autoSave;

    if (!state.syncMetadata.isOffline) {
      if (autoSave) {
        this.setStatus('saving');
      } else {
        if (this.currentStatus !== 'saving' && this.currentStatus !== 'error') {
          this.setStatus('pending');
        }
      }

      if (this.timers.has(key)) {
        clearTimeout(this.timers.get(key)!);
      }

      if (autoSave) {
        const timer = setTimeout(() => {
          this.syncResource(key);
        }, this.DEBOUNCE_MS);
        this.timers.set(key, timer);
      }
    } else {
      this.setStatus('offline');
    }
  }

  public enqueue(type: ResourceType, id: string, data: any) {
    // Preserve old enqueue interface, map to update action
    this.enqueueAction(type, 'update', id, data);
  }

  private async syncResource(key: string, retryCount = 0): Promise<void> {
    if (this.processingPromises.has(key) && retryCount === 0) {
      return this.processingPromises.get(key);
    }

    const change = this.queue.get(key);
    if (!change) {
      this.checkCompletion();
      return;
    }

    if (useStore.getState().syncMetadata.isOffline) {
      this.setStatus('offline');
      return;
    }

    const syncPromise = (async () => {
      try {
        this.processingKeys.add(key);
        this.timers.delete(key);
        
        switch (change.action) {
          case 'create':
            switch (change.type) {
              case 'collection':
                const createdCol = await PersistenceService.createCollectionOnline(change.data.workspace_id, change.data.user_id, change.data.name);
                this.remapId(change.id, createdCol.id, 'collection');
                break;
              case 'folder':
                const createdFolder = await PersistenceService.createFolderOnline(change.data.name, change.data.collection_id, change.data.user_id, change.data.parent_id, change.data.workspace_id);
                this.remapId(change.id, createdFolder.id, 'folder');
                break;
              case 'request':
                const createdReq = await PersistenceService.createRequestOnline(change.data);
                this.remapId(change.id, createdReq.id, 'request');
                break;
              case 'environment':
                const createdEnv = await PersistenceService.createEnvironmentOnline(change.data.workspace_id, change.data.user_id, change.data.name, change.data.variables, change.data.is_global, change.data.pre_request_script, change.data.test_script, change.data.documentation);
                this.remapId(change.id, createdEnv.id, 'environment');
                break;
              case 'workspace':
                const createdWS = await PersistenceService.createWorkspaceOnline(change.data.name, change.data.user_id, change.data.team_id);
                this.remapId(change.id, createdWS.id, 'workspace');
                break;
            }
            break;

          case 'update':
            switch (change.type) {
              case 'request':
                await PersistenceService.saveRequestOnline(change.data);
                break;
              case 'collection':
                await PersistenceService.updateCollectionOnline(change.id, change.data);
                break;
              case 'environment':
                await PersistenceService.updateEnvironmentOnline(change.id, change.data);
                break;
              case 'workspace':
                await PersistenceService.updateWorkspaceOnline(change.id, change.data);
                break;
              case 'profile':
                await PersistenceService.updateProfileOnline(change.id, change.data);
                break;
              case 'folder':
                await PersistenceService.updateFolderOnline(change.id, change.data);
                break;
            }
            break;

          case 'delete':
            switch (change.type) {
              case 'collection':
                await PersistenceService.deleteCollectionOnline(change.id);
                break;
              case 'folder':
                await PersistenceService.deleteFolderOnline(change.id);
                break;
              case 'request':
                await PersistenceService.deleteRequestOnline(change.id);
                break;
              case 'environment':
                await PersistenceService.deleteEnvironmentOnline(change.id);
                break;
              case 'workspace':
                await PersistenceService.deleteWorkspaceOnline(change.id);
                break;
            }
            break;
        }

        this.queue.delete(key);
        this.updatePendingIds();
        this.persistQueue();
        useStore.getState().updateSyncMetadata({ 
          lastSynced: Date.now(),
          retryCount: 0 
        });
        
      } catch (error: any) {
        console.error(`Sync failed for ${key}:`, error);
        
        // Handle immediate offline transitions resiliently
        const isNetworkError = !window.navigator.onLine || 
          error.message?.includes('Network Error') || 
          error.message?.includes('Failed to fetch') || 
          error.message?.includes('timeout') ||
          error.code === 'ECONNABORTED' ||
          error.status === 0;

        if (isNetworkError) {
          console.warn(`[SyncManager] Connection cut detected during active sync for ${key}. Safe-buffering locally.`);
          this.handleConnectivityChange(false);
          return;
        }
        
        if (retryCount < this.MAX_RETRIES) {
          const delay = Math.pow(2, retryCount) * 1000;
          console.log(`Retrying in ${delay}ms... (Attempt ${retryCount + 1})`);
          useStore.getState().updateSyncMetadata({ retryCount: retryCount + 1 });
          
          await new Promise(resolve => setTimeout(resolve, delay));
          return this.syncResource(key, retryCount + 1);
        } else {
          console.error(`Sync FATAL failure for ${key} after ${this.MAX_RETRIES} retries:`, error);
          this.setStatus('error');
          throw error;
        }
      } finally {
        this.processingKeys.delete(key);
        this.processingPromises.delete(key);
        this.checkCompletion();
      }
    })();

    this.processingPromises.set(key, syncPromise);
    return syncPromise;
  }

  private remapId(tempId: string, realId: string, type: 'collection' | 'folder' | 'request' | 'environment' | 'workspace') {
    console.log(`[SyncManager] Remapping ${type} ID from temporary ${tempId} to real ${realId}`);
    const state = useStore.getState();

    // 1. Update active tab ID if active
    if (state.activeTabId === tempId) {
      state.setActiveTab(realId);
    }

    // 2. Update open tabs
    const newTabs = state.openTabs.map(t => {
      if (t.id === tempId) {
        return { ...t, id: realId } as any;
      }
      if ('collection_id' in t && t.collection_id === tempId) {
        return { ...t, collection_id: realId } as any;
      }
      if ('folder_id' in t && t.folder_id === tempId) {
        return { ...t, folder_id: realId } as any;
      }
      return t;
    });
    state.setUserTabs(newTabs);

    // 3. Update tree nodes
    if (type === 'collection') {
      const newCollections = state.collections.map(c => {
        if (c.id === tempId) return { ...c, id: realId };
        return c;
      });
      state.setCollections(newCollections);
    } else if (type === 'folder') {
      const updateFolders = (folders: any[]): any[] => {
        return folders.map(f => {
          if (f.id === tempId) return { ...f, id: realId };
          if (f.folders) return { ...f, folders: updateFolders(f.folders) };
          return f;
        });
      };
      const newCollections = state.collections.map(c => ({
        ...c,
        folders: c.folders ? updateFolders(c.folders) : []
      }));
      state.setCollections(newCollections);
    } else if (type === 'request') {
      const updateFolders = (folders: any[]): any[] => {
        return folders.map(f => {
          if (f.requests) {
            f.requests = f.requests.map((r: any) => r.id === tempId ? { ...r, id: realId } : r);
          }
          if (f.folders) {
            f.folders = updateFolders(f.folders);
          }
          return f;
        });
      };
      const newCollections = state.collections.map(c => {
        const rootRequests = (c.requests || []).map(r => r.id === tempId ? { ...r, id: realId } : r);
        const subFolders = c.folders ? updateFolders(c.folders) : [];
        return { ...c, requests: rootRequests, folders: subFolders };
      });
      state.setCollections(newCollections);
    } else if (type === 'environment') {
      const newEnvironments = state.environments.map(e => e.id === tempId ? { ...e, id: realId } : e);
      state.setEnvironments(newEnvironments);
      if (state.activeEnvId === tempId) {
        state.setActiveEnvId(realId);
      }
    } else if (type === 'workspace') {
      const newWorkspaces = state.workspaces.map(w => w.id === tempId ? { ...w, id: realId } : w);
      state.setWorkspaces(newWorkspaces);
      if (state.activeWorkspaceId === tempId) {
        state.setActiveWorkspaceId(realId);
      }
    }

    // 4. Update subsequent enqueued items in queue
    const entries = Array.from(this.queue.entries());
    for (const [key, change] of entries) {
      if (change.id === tempId && change.type === type) {
        this.queue.delete(key);
        const newKey = `${type}:${change.action}:${realId}`;
        this.queue.set(newKey, { ...change, id: realId });
      }
      
      // Update relational IDs in parent relations of children
      if (change.type === 'request' && type === 'collection' && change.data.collection_id === tempId) {
        change.data.collection_id = realId;
      }
      if (change.type === 'request' && type === 'folder' && change.data.folder_id === tempId) {
        change.data.folder_id = realId;
      }
      if (change.type === 'folder' && type === 'collection' && change.data.collection_id === tempId) {
        change.data.collection_id = realId;
      }
      if (change.type === 'folder' && type === 'folder' && change.data.parent_id === tempId) {
        change.data.parent_id = realId;
      }
    }
    this.persistQueue();
  }

  private checkCompletion() {
    if (this.queue.size === 0 && this.processingKeys.size === 0) {
      this.setStatus('saved');
      setTimeout(() => {
        if (this.queue.size === 0 && this.processingKeys.size === 0) {
          this.setStatus('idle');
        }
      }, 2000);
    }
  }

  public async flushAll() {
    if (useStore.getState().syncMetadata.isOffline) return;
    
    this.setStatus('saving');
    const keys = Array.from(this.queue.keys());
    const promises = keys.map(key => this.syncResource(key));
    await Promise.all(promises);
    
    this.checkCompletion();
  }

  public triggerSync(type: ResourceType, id: string) {
    const key = `${type}:update:${id}`;
    if (this.timers.has(key)) {
      clearTimeout(this.timers.get(key)!);
    }
    
    this.setStatus('saving');
    return this.syncResource(key);
  }

  public cancelSync(type: ResourceType, id: string) {
    const key = `${type}:update:${id}`;
    if (this.timers.has(key)) {
      clearTimeout(this.timers.get(key)!);
      this.timers.delete(key);
    }
    this.queue.delete(key);
    this.updatePendingIds();
    this.persistQueue();
    if (this.queue.size === 0) this.setStatus('idle');
  }

  public forcePushAll() {
    return this.flushAll();
  }

  public getStatus() {
    return this.currentStatus;
  }
}

