import { KeyValue, Environment, Collection } from '../types';

export class VariableService {
  static resolve(text: string, context: {
    environments: Environment[];
    activeEnvId: string | null;
    collection: Collection | null;
    workspaceVariables?: KeyValue[];
    variables?: Record<string, any>;
  }): string {
    if (!text || typeof text !== 'string') return text;

    let resolved = text;
    // 0. Dynamic Variables (e.g. {{$guid}}, {{$timestamp}})
    resolved = resolved.replace(/{{(\$.*?)}}/g, (match, key) => {
      switch (key) {
        case '$guid': return Math.random().toString(36).substring(2) + Math.random().toString(36).substring(2);
        case '$timestamp': return Math.floor(Date.now() / 1000).toString();
        case '$randomInt': return Math.floor(Math.random() * 1000).toString();
        case '$isoTimestamp': return new Date().toISOString();
        default: return match;
      }
    });

    const variableMap: Record<string, string> = {};

    // 1. Workspace Variables (Lowest priority)
    if (context.workspaceVariables) {
      context.workspaceVariables.forEach(v => {
        if (v.active) variableMap[v.key] = v.value;
      });
    }

    // 2. Collection Variables
    if (context.collection && context.collection.variables) {
      context.collection.variables.forEach(v => {
        if (v.active) variableMap[v.key] = v.value;
      });
    }

    // 3. Environment Variables (Highest priority)
    if (context.activeEnvId) {
      const activeEnv = context.environments.find(e => e.id === context.activeEnvId);
      if (activeEnv && activeEnv.variables) {
        activeEnv.variables.forEach(v => {
          if (v.active) variableMap[v.key] = v.value;
        });
      }
    }

    // 4. Script-set Variables (Top priority)
    if (context.variables) {
      Object.entries(context.variables).forEach(([key, value]) => {
        variableMap[key] = String(value);
      });
    }

    // Replace {{key}} patterns
    // Using a loop to handle nested variables like {{BASE_URL}}/{{API_VERSION}}
    // Limit to 5 iterations to prevent infinite recursion
    for (let i = 0; i < 5; i++) {
      const matches = resolved.match(/{{(.*?)}}/g);
      if (!matches) break;

      let changed = false;
      matches.forEach(match => {
        const key = match.slice(2, -2);
        if (variableMap[key] !== undefined) {
          resolved = resolved.replace(match, variableMap[key]);
          changed = true;
        }
      });
      if (!changed) break;
    }

    return resolved;
  }

  static getResolvedVariableMap(context: {
    environments: Environment[];
    activeEnvId: string | null;
    collection: Collection | null;
    workspaceVariables?: KeyValue[];
    variables?: Record<string, any>;
  }): Record<string, string> {
    const variableMap: Record<string, string> = {};

    // 1. Workspace Variables
    if (context.workspaceVariables) {
      context.workspaceVariables.forEach(v => {
        if (v.active) variableMap[v.key] = v.value;
      });
    }

    // 2. Collection Variables
    if (context.collection && context.collection.variables) {
      context.collection.variables.forEach(v => {
        if (v.active) variableMap[v.key] = v.value;
      });
    }

    // 3. Environment Variables
    if (context.activeEnvId) {
      const activeEnv = context.environments.find(e => e.id === context.activeEnvId);
      if (activeEnv && activeEnv.variables) {
        activeEnv.variables.forEach(v => {
          if (v.active) variableMap[v.key] = v.value;
        });
      }
    }

    // 4. Script-set Variables
    if (context.variables) {
      Object.entries(context.variables).forEach(([key, value]) => {
        variableMap[key] = String(value);
      });
    }

    return variableMap;
  }

  static lookupVariable(key: string, context: {
    environments: Environment[];
    activeEnvId: string | null;
    collection: Collection | null;
    workspaceVariables?: KeyValue[];
    variables?: Record<string, any>;
    globalVariables?: KeyValue[];
  }): { 
    value: string; 
    source: string; 
    name: string; 
    scope: 'environment' | 'collection' | 'workspace' | 'global' | 'script' | 'unresolved';
    sourceId?: string;
    masked?: boolean;
  } {
    // Check in reverse order of priority (Script -> Env -> Coll -> Workspace -> Global)

    // 4. Script Variables
    if (context.variables && context.variables[key] !== undefined) {
      return { 
        value: String(context.variables[key]), 
        source: 'Script', 
        name: key, 
        scope: 'script' 
      };
    }

    // 3. Environment Variables
    if (context.activeEnvId) {
      const activeEnv = context.environments.find(e => e.id === context.activeEnvId);
      const v = activeEnv?.variables?.find(v => v.key === key && v.active);
      if (v) return { 
        value: v.value, 
        source: `Environment (${activeEnv?.name})`, 
        name: key, 
        scope: 'environment',
        sourceId: activeEnv?.id,
        masked: (v as any).masked 
      };
    }

    // 2. Collection Variables
    if (context.collection && context.collection.variables) {
      const v = context.collection.variables.find(v => v.key === key && v.active);
      if (v) return { 
        value: v.value, 
        source: 'Collection', 
        name: key, 
        scope: 'collection',
        masked: (v as any).masked
      };
    }

    // 1. Workspace Variables
    if (context.workspaceVariables) {
      const v = context.workspaceVariables.find(v => v.key === key && v.active);
      if (v) return { 
        value: v.value, 
        source: 'Workspace', 
        name: key, 
        scope: 'workspace',
        masked: (v as any).masked
      };
    }

    // 0. Global Variables
    if (context.globalVariables) {
      const v = context.globalVariables.find(v => v.key === key && v.active);
      if (v) return { 
        value: v.value, 
        source: 'Global', 
        name: key, 
        scope: 'global',
        masked: (v as any).masked
      };
    }

    return { 
      value: key, 
      source: 'Unresolved', 
      name: key, 
      scope: 'unresolved' 
    };
  }
}

import { createClient } from '@supabase/supabase-js';
import { fetchInitScriptFromDb } from './fetchInitScriptFromDb';
import { SQLScriptGenerator } from '../lib/SQLScriptGenerator';

type ProgressCallback = (label: string, pct: number) => void;

export type SchemaCompareResult = {
  success: boolean;
  upToDate: boolean;
  requiredTables: string[];
  missingTables: string[];
  script: string;
  error?: string;
};

const FALLBACK_REQUIRED_TABLES = [
  'profiles',
  'teams',
  'workspaces',
  'team_members',
  'collections',
  'folders',
  'requests',
  'environments',
  'scripts',
  'script_execution_logs',
  'request_history',
  'sync_logs',
];

function extractRequiredTablesFromScript(sql: string): string[] {
  const regex = /create\s+table\s+if\s+not\s+exists\s+(?:public\.)?([a-zA-Z_][a-zA-Z0-9_]*)/gi;
  const found = new Set<string>();
  let match: RegExpExecArray | null;

  while ((match = regex.exec(sql)) !== null) {
    found.add(match[1].toLowerCase());
  }

  return Array.from(found);
}

function splitSqlStatements(sql: string): string[] {
  const statements: string[] = [];
  let current = '';
  let i = 0;

  while (i < sql.length) {
    if (sql[i] === '$') {
      const tagEnd = sql.indexOf('$', i + 1);
      if (tagEnd !== -1) {
        const tag = sql.substring(i, tagEnd + 1);
        if (/^\$[a-zA-Z_0-9]*\$$/.test(tag)) {
          const closeIdx = sql.indexOf(tag, tagEnd + 1);
          if (closeIdx !== -1) {
            current += sql.substring(i, closeIdx + tag.length);
            i = closeIdx + tag.length;
            continue;
          }
        }
      }
    }

    if (sql[i] === ';') {
      const stmt = current.trim();
      if (stmt.length > 0) statements.push(stmt);
      current = '';
      i++;
      continue;
    }

    current += sql[i];
    i++;
  }

  const tail = current.trim();
  if (tail.length > 0) statements.push(tail);

  return statements;
}

async function tableExists(client: any, table: string): Promise<boolean> {
  const { error } = await client.from(table).select('*').limit(0);
  if (!error) return true;

  const msg = (error.message || '').toLowerCase();
  
  // High-priority: Handle schema cache stale errors (PGRST205)
  if (msg.includes('schema cache') || error.code === 'PGRST205') {
    console.warn(`[Schema Check] Schema cache stale for table "${table}". Tentatively assuming success.`);
    return true; 
  }

  // Permission errors imply the table exists but caller cannot read it.
  if (msg.includes('permission denied') || msg.includes('forbidden')) {
    return true;
  }

  if (msg.includes('does not exist') || msg.includes('not found') || msg.includes('relation')) {
    return false;
  }

  // Fallback
  return true;
}

export async function compareDatabaseStructure(
  supabaseUrl: string,
  anonOrServiceKey: string,
): Promise<SchemaCompareResult> {
  try {
    const { script: dbScript } = await fetchInitScriptFromDb(supabaseUrl, anonOrServiceKey);
    const script = dbScript || SQLScriptGenerator.generateInitializationScript();

    const parsedTables = extractRequiredTablesFromScript(script);
    const requiredTables = parsedTables.length > 0 ? parsedTables : FALLBACK_REQUIRED_TABLES;

    const client = createClient(supabaseUrl, anonOrServiceKey);
    const missingTables: string[] = [];

    for (const table of requiredTables) {
      const exists = await tableExists(client, table);
      if (!exists) missingTables.push(table);
    }

    return {
      success: true,
      upToDate: missingTables.length === 0,
      requiredTables,
      missingTables,
      script,
    };
  } catch (err: any) {
    return {
      success: false,
      upToDate: false,
      requiredTables: [],
      missingTables: [],
      script: SQLScriptGenerator.generateInitializationScript(),
      error: err?.message || 'Failed to compare database structure.',
    };
  }
}

/**
 * Fetches the latest script from init_scripts, compares current DB structure,
 * and auto-applies missing updates through execute_sql when needed.
 */
export async function ensureDatabaseSchema(
  supabaseUrl: string,
  anonOrServiceKey: string,
  onProgress?: ProgressCallback,
): Promise<{ success: boolean; updated?: boolean; missingTables?: string[]; error?: string }> {
  try {
    onProgress?.('Fetching initialization script from database', 20);

    const compare = await compareDatabaseStructure(supabaseUrl, anonOrServiceKey);
    if (!compare.success) {
      return { success: false, error: compare.error || 'Failed to compare database structure.' };
    }

    onProgress?.('Comparing current database structure', 40);

    // Even if upToDate is true (meaning all tables exist), 
    // we still execute the script to ensure ALL columns and constraints are correct 
    // (the "Repair" section of the script handles this IDEMPOTENTLY).
    if (compare.upToDate) {
      onProgress?.('Ensuring schema integrity and relationships', 60);
    } else {
      onProgress?.(`Applying schema updates (${compare.missingTables.length} missing tables)`, 55);
    }

    const client = createClient(supabaseUrl, anonOrServiceKey);
    const statements = splitSqlStatements(compare.script);

    for (let i = 0; i < statements.length; i++) {
      const stmt = statements[i];
      const pct = Math.round(55 + ((i + 1) / statements.length) * 40);
      onProgress?.('Executing update statements', pct);

      const { error } = await client.rpc('execute_sql', { sql: stmt });
      if (error) {
        const msg = error.message ?? '';
        
        // Handle missing RPC specially
        if (msg.includes('function') && msg.includes('execute_sql') && (msg.includes('not find') || msg.includes('does not exist'))) {
          return {
            success: false,
            missingTables: compare.missingTables,
            error: `Helper function 'execute_sql' is missing from your database.\n\nFIX: Run the initialization script in the Supabase SQL Editor manually first, or use the 'Smart Initialize' flow which includes it.`,
          };
        }

        const ignorable =
          msg.includes('already exists') ||
          msg.includes('duplicate_object') ||
          (msg.includes('does not exist') && msg.includes('constraint')) ||
          (msg.includes('policy') && msg.includes('does not exist'));

        if (!ignorable) {
          return {
            success: false,
            missingTables: compare.missingTables,
            error: msg,
          };
        }
      }
    }

    onProgress?.('Re-checking database structure', 97);
    const verify = await compareDatabaseStructure(supabaseUrl, anonOrServiceKey);

    if (!verify.success) {
      return { success: false, error: verify.error || 'Schema update verification failed.' };
    }

    if (!verify.upToDate) {
      return {
        success: false,
        missingTables: verify.missingTables,
        error: `Schema update incomplete. Missing tables: ${verify.missingTables.join(', ')}`,
      };
    }

    onProgress?.('Done', 100);
    return { success: true, updated: true, missingTables: [] };
  } catch (err: any) {
    return { success: false, error: err?.message || 'Schema initialization failed.' };
  }
}

import { createClient } from '@supabase/supabase-js';

/**
 * Fetch the latest initialization script from the init_scripts table in Supabase.
 * @param supabaseUrl Supabase project URL
 * @param anonKey Supabase anon or service key
 * @returns Promise<{ script: string | null; error?: string }>
 */
export async function fetchInitScriptFromDb(
  supabaseUrl: string,
  anonKey: string
): Promise<{ script: string | null; error?: string }> {
  try {
    const client = createClient(supabaseUrl, anonKey);
    const { data, error } = await client
      .from('init_scripts')
      .select('script')
      .order('created_at', { ascending: false })
      .limit(1)
      .maybeSingle();
    if (error) {
      return { script: null, error: error.message };
    }
    return { script: data?.script || null };
  } catch (err: any) {
    return { script: null, error: err.message };
  }
}

