          {
            label: `${ns}.request`,
            kind: monaco.languages.CompletionItemKind.Function,
            documentation: 'Execute an asynchronous network request.',
            insertText: `${ns}.request({\n  url: "\${1:https://api.example.com}",\n  method: "\${2:GET}",\n  headers: \${3:{}},\n  body: \${4:{}}\n})`,
