        },
        error: e.message
      });
    } finally {
      currentScriptState = null;
      logs = [];
      testResults = [];
      changedVariables = {};
      changedEnvironment = {};
      if (pendingResolvers) {
        pendingResolvers.clear();
        pendingResolvers = null;
      }
      vars = null;
      envVars = null;
      variableStore = null;
      environmentStore = null;
      sendToMain = null;
      requestHeaders = null;
      if (headersMap) {
        headersMap.clear();
        headersMap = null;
      }
      requestFunc = null;
      gmy = null;
      pm = null;
      gimay = null;
      putman = null;
      console = null;
      context = null;
    }
