                  } else {
                    throw new Error("Target is not include-compatible");
                  }
                  return assertion;
                },
                have: {
                  property: (prop: string) => {
                    if (!val || typeof val !== 'object' || !(prop in val)) {
                      throw new Error(`Expected object to have property "${  prop  }"`);
                    }
                    return assertion;
                  },
                  status: (code: number) => {
                    if (gmy.response.code !== code) throw new Error(`Expected status ${  code  } but got ${  gmy.response.code}`);
                    return assertion;
                  }
                }
              }
            };
            return assertion;
          }
        };

        const pm = gmy;
        const gimay = gmy;
        const putman = gmy;
        const console = consoleMock;

        class Script {
          public name: string;
          constructor(name: string) {
            this.name = name;
          }
          async Run() {
            const allScripts = useScriptStore.getState().scripts;
            const target = allScripts.find(s => s.id === this.name || s.name === this.name);
            if (!target) throw new Error(`Script "${this.name}" not found.`);
            let processedContent = target.content || '';
            processedContent = processedContent.replace(/new\s*\(\s*(['"`])(.*?)\1\s*\)/g, 'new Script("$2")');
            
            const fn = new Function('gmy', 'pm', 'gimay', 'putman', 'console', 'Script', 'CryptoJS', `
              return (async () => {
                ${processedContent}
              })();
            `);
            await fn(gmy, pm, gimay, putman, consoleMock, Script, typeof CryptoJS !== 'undefined' ? CryptoJS : undefined);
          }
        }

        let processedCode = code || '';
        processedCode = processedCode.replace(/new\s*\(\s*(['"`])(.*?)\1\s*\)/g, 'new Script("$2")');
        
        const fn = new Function('gmy', 'pm', 'gimay', 'putman', 'console', 'Script', 'CryptoJS', `
          return (async () => {
            ${processedCode}
          })();
        `);

        await fn(gmy, pm, gimay, putman, consoleMock, Script, typeof CryptoJS !== 'undefined' ? CryptoJS : undefined);

        // Wait for any async callbacks or pending gmy.sendRequest calls
        let waitTime = 0;
        while (activeAsyncRequests > 0 && waitTime < timeoutMs) {
          await new Promise((resolve) => setTimeout(resolve, 50));
          waitTime += 50;
        }

        // Resolve any async tests
        const resolvedTests = [];
        for (const t of testResults) {
          if (t instanceof Promise) {
            resolvedTests.push(await t);
          } else {
            resolvedTests.push(t);
          }
        }

        cleanUpAndResolve({
          logs,
          testResults: resolvedTests,
          changedVariables,
          changedEnvironment,
          changedRequest: {
            method: requestFunc.method,
            url: requestFunc.url,
            body: requestFunc.body.raw,
            headers: Array.from(headersMap.entries()).map(([k, v]) => ({ key: k, value: v, active: true }))
          }
        });

      } catch (e: any) {
        logs.push({ level: 'error', message: e.message });
        cleanUpAndResolve({
          logs,
          testResults: [],
          changedVariables,
          changedEnvironment,
          error: e.message
        });
      }
    });
  }

  static run(code: string, context: SandboxContext, timeoutMs = 5000, useWorker = false): Promise<SandboxResult> {
    if (!useWorker) {
      return this.runInThread(code, context, timeoutMs);
    }
    return new Promise<SandboxResult>((resolve) => {
      const worker = WorkerPool.acquire();
      const runtimeId = Math.random().toString(36).substring(2, 15);
      (worker as any).activeRuntimeId = runtimeId;
      
      let resolved = false;
      let timer: any = null;

      const onAbort = () => {
        cleanUpAndResolve({
          logs: [{ level: 'error', message: 'Execution aborted by user.' }],
          testResults: [],
          changedVariables: {},
          error: 'Aborted: Execution aborted by user.'
        }, true);
      };

      const cleanUpAndResolve = (result: SandboxResult, forceTerminate = false) => {
        if (resolved) return;
        resolved = true;
        clearTimeout(timer);
        delete (worker as any).onTerminate;
        
        if (context.signal) {
          context.signal.removeEventListener('abort', onAbort);
        }
        
        if (forceTerminate) {
          WorkerPool.terminateWorker(worker);
        } else {
          WorkerPool.release(worker);
        }
        resolve(result);
      };

      if (context.signal) {
        if (context.signal.aborted) {
          onAbort();
          return;
        }
        context.signal.addEventListener('abort', onAbort);
      }

      (worker as any).onTerminate = () => {
        cleanUpAndResolve({
          logs: [{ level: 'error', message: 'Sandbox Worker terminated during memory tuning or abort.' }],
          testResults: [],
          changedVariables: {},
          error: 'Execution terminated'
        }, true);
      };

      // Set up timeout safety
      timer = setTimeout(() => {
        cleanUpAndResolve({
          logs: [{ level: 'error', message: `Execution timed out after ${timeoutMs}ms.` }],
          testResults: [],
          changedVariables: {},
          error: `Timeout: Execution exceeded ${timeoutMs}ms limit.`
        }, true);
      }, timeoutMs);

      const safePostMessage = (msg: any) => {
        try {
          worker.postMessage(msg);
        } catch (postErr) {
          console.warn('[SandboxRunner] safePostMessage discarded message. Worker might be terminated.', postErr);
        }
      };

      // Register error handler
      worker.onerror = (errEvent) => {
        cleanUpAndResolve({
          logs: [{ level: 'error', message: `Sandbox Worker Error: ${errEvent.message || 'Unknown'}` }],
          testResults: [],
          changedVariables: {},
          error: errEvent.message || 'Worker runtime error'
        }, true);
      };

      // Set up communication channel
      worker.onmessage = async (e) => {
        const { type, action, id, data, logs, testResults, changedVariables, changedEnvironment, changedRequest, error, runtimeId: msgRuntimeId } = e.data;
        
        // Isolate stale execution events to prevent race-condition pollution of current run or subsequent suites
        if (msgRuntimeId && msgRuntimeId !== runtimeId) {
          return;
        }
        
        if (type === 'coordination') {
          if (action === 'request') {
            try {
              const requestOpts = typeof data === 'string' ? { url: data, method: 'GET' } : { ...data };
              
              if (requestOpts.header && typeof requestOpts.header === 'object') {
                requestOpts.headers = Object.entries(requestOpts.header).map(([key, value]) => ({
                  key,
                  value: String(value),
                  active: true
                }));
              }
              
              if (requestOpts.body && typeof requestOpts.body === 'object') {
                const mode = requestOpts.body.mode || requestOpts.body.type || 'raw';
                requestOpts.bodyType = mode;
                
                if (mode === 'urlencoded' && Array.isArray(requestOpts.body.urlencoded)) {
                  requestOpts.body.urlencoded = requestOpts.body.urlencoded.map((item: any) => ({
                    ...item,
                    active: item.active !== false
                  }));
                }
                if (mode === 'form-data' && Array.isArray(requestOpts.body.formData)) {
                  requestOpts.body.formData = requestOpts.body.formData.map((item: any) => ({
                    ...item,
                    active: item.active !== false
                  }));
                }
              }

              if (requestOpts.data !== undefined && requestOpts.body === undefined) {
                requestOpts.body = requestOpts.data;
                requestOpts.bodyType = requestOpts.bodyType || 'raw';
              }
              if (typeof requestOpts.body === 'string' && !requestOpts.bodyType) {
                requestOpts.bodyType = 'raw';
              }
              const state = useStore.getState();
              const response = await RequestService.execute(
                requestOpts as any,
                {
                  collections: state.collections || [],
                  environments: state.environments || [],
                  activeEnvId: state.activeEnvId,
                  variables: {}
                } as any
              );
              
              // Validate that worker is still dedicated to this run session before posting back response
              if ((worker as any).activeRuntimeId !== runtimeId) {
                return;
              }
              safePostMessage({
                type: 'coordination_response',
                id,
                runtimeId,
                data: {
                  status: response.status,
                  statusText: response.statusText,
                  body: response.body,
                  headers: response.headers
                }
              });
            } catch (err: any) {
              if ((worker as any).activeRuntimeId !== runtimeId) {
                return;
              }
              safePostMessage({
                type: 'coordination_response',
                id,
                runtimeId,
                error: err.message
              });
            }
          } else if (action === 'import') {
            try {
              const allScripts = useScriptStore.getState().scripts;
              const target = allScripts.find(s => s.id === data || s.name === data);
              if ((worker as any).activeRuntimeId !== runtimeId) {
                return;
              }
              if (!target) {
                safePostMessage({
                  type: 'coordination_response',
                  id,
                  runtimeId,
                  error: `Script "${data}" not found.`
                });
              } else {
                safePostMessage({
                  type: 'coordination_response',
                  id,
                  runtimeId,
                  data: target.content
                });
              }
            } catch (err: any) {
              if ((worker as any).activeRuntimeId !== runtimeId) {
                return;
              }
              safePostMessage({
                type: 'coordination_response',
                id,
                runtimeId,
                error: err.message
              });
            }
          }
        } else if (type === 'result') {
          cleanUpAndResolve({
            logs: logs || [],
            testResults: testResults || [],
            changedVariables: changedVariables || {},
            changedEnvironment: changedEnvironment || {},
            changedRequest,
            error
          }, false);
        }
      };

      // Start execution with session run runtimeId
      safePostMessage({
        code,
        context: {
          ...context,
          signal: undefined
        },
        runtimeId
      });
    });
  }
}

import { createClient } from '@supabase/supabase-js';

/**
 * Save the initialization script to the Supabase database for auditing/reference.
 * @param supabaseUrl Supabase project URL
 * @param serviceKey Supabase service role key
 * @param script The SQL script to save
 * @param userId The user who triggered the save
 * @returns Promise<{ success: boolean; error?: string }>
 */
export async function saveInitScriptToDb(
  supabaseUrl: string,
  serviceKey: string,
  script: string,
  userId: string | null
): Promise<{ success: boolean; error?: string }> {
  try {
    const client = createClient(supabaseUrl, serviceKey);
    const { error } = await client.from('init_scripts').insert([
      {
        script,
        created_by: userId,
        created_at: new Date().toISOString(),
      },
    ]);
    if (error) {
      return { success: false, error: error.message };
    }
    return { success: true };
  } catch (err: any) {
    return { success: false, error: err.message };
  }
}

import { useScriptStore } from '../store/scriptStore';
import { useStore } from '../store/useStore';
import { SandboxRunner } from './sandboxRunner';

export class ScriptEngine {
  static async execute(code: string) {
    const { addLog, setConsoleOpen } = useScriptStore.getState();
    const { environments, activeEnvId, globalVariables } = useStore.getState();

    setConsoleOpen(true);
    addLog({ level: 'info', message: 'Sandbox environment initializing...' });

    // 1. Gather variables from active environment or global fallback
    const activeEnv = environments.find(e => e.id === activeEnvId);
    const envVars = activeEnv ? [...(activeEnv.variables || [])] : [...globalVariables];
    
    const variablesMap: Record<string, any> = {};
    envVars.forEach(v => {
      if (v.active !== false && v.enabled !== false) {
        variablesMap[v.key] = v.value;
      }
    });

    // 2. Run in dynamic Web Worker sandbox
    addLog({ level: 'info', message: 'Starting asynchronous sandboxed execution thread...' });
    const result = await SandboxRunner.run(code, { variables: variablesMap });

    // 3. Process logs
    result.logs.forEach(log => {
      addLog({ level: log.level === 'log' ? 'info' : log.level, message: log.message });
    });

    // 4. Update modified variables
    const hasChanges = Object.keys(result.changedVariables).length > 0;
    if (hasChanges) {
      const activeVars = [...(activeEnv?.variables || [])];
      
      for (const [key, value] of Object.entries(result.changedVariables)) {
        if (value === null) {
          const index = activeVars.findIndex(v => v.key === key);
          if (index !== -1) activeVars.splice(index, 1);
        } else {
          const index = activeVars.findIndex(v => v.key === key);
          if (index !== -1) {
            activeVars[index] = { ...activeVars[index], value: String(value) };
          } else {
            activeVars.push({
              id: Math.random().toString(36).substr(2, 9),
              key,
              value: String(value),
              type: 'string',
              enabled: true,
              active: true
            });
          }
        }
      }

      if (activeEnvId) {
        useStore.getState().updateEnvironment(activeEnvId, { variables: activeVars });
        addLog({ level: 'info', message: `Variables in environment "${activeEnv?.name}" updated.` });
      } else {
        const globals = [...useStore.getState().globalVariables];
        for (const [key, value] of Object.entries(result.changedVariables)) {
          if (value === null) {
            const index = globals.findIndex(v => v.key === key);
            if (index !== -1) globals.splice(index, 1);
          } else {
            const index = globals.findIndex(v => v.key === key);
            if (index !== -1) {
              globals[index] = { ...globals[index], value: String(value) };
            } else {
              globals.push({
                id: Math.random().toString(36).substr(2, 9),
                key,
                value: String(value),
                active: true
              });
            }
          }
        }
        useStore.getState().setGlobalVariables(globals);
        addLog({ level: 'info', message: `Global variables updated.` });
      }
    }

    // 5. Assert final execution state
    if (result.error) {
      addLog({ level: 'error', message: `Execution failed: ${result.error}` });
    } else {
      addLog({ level: 'success', message: 'Execution thread finished successfully.' });
    }
  }
}

import { create } from 'zustand';
import { persist } from 'zustand/middleware';

export type OnboardingStep = 'idle' | 'welcome' | 'option-select' | 'create-setup' | 'join-team' | 'join-invite' | 'team-select' | 'complete';
export type SetupMode = 'create' | 'join' | 'join-invite' | 'select' | null;

interface OnboardingState {
  // State
  step: OnboardingStep;
  setupMode: SetupMode;
  isConfigured: boolean;
  isInitializing: boolean;
  error: string | null;
  
  // Credentials
  supabaseUrl: string;
  supabaseAnonKey: string;
  teamCode: string;
  teamSecretCode: string;
  
  // Metadata
  workspaceId: string | null;
  teamId: string | null;
  userId: string | null;
  hasHydrated: boolean;

  // Actions
  setStep: (step: OnboardingStep) => void;
  setSetupMode: (mode: SetupMode) => void;
  setIsConfigured: (configured: boolean) => void;
  setIsInitializing: (initializing: boolean) => void;
  setError: (error: string | null) => void;
  setSupabaseCredentials: (url: string, key: string) => void;
  setTeamCode: (code: string) => void;
  setTeamSecretCode: (code: string) => void;
  setWorkspaceId: (id: string) => void;
  setTeamId: (id: string) => void;
  setUserId: (id: string | null) => void;
  setHasHydrated: (hydrated: boolean) => void;
  resetOnboarding: () => void;
}

const initialState = {
  step: 'welcome' as OnboardingStep,
  setupMode: null as SetupMode,
  isConfigured: false,
  isInitializing: false,
  error: null as string | null,
  supabaseUrl: '',
  supabaseAnonKey: '',
  teamCode: '',
  teamSecretCode: '',
  workspaceId: null as string | null,
  teamId: null as string | null,
  userId: null as string | null,
  hasHydrated: false,
};

export const useOnboardingStore = create<OnboardingState>()(
  persist(
    (set) => ({
      ...initialState,

      setStep: (step) => set({ step }),
      setSetupMode: (mode) => set({ setupMode: mode }),
      setIsConfigured: (configured) => set({ isConfigured: configured }),
      setIsInitializing: (initializing) => set({ isInitializing: initializing }),
      setError: (error) => set({ error }),
      setSupabaseCredentials: (url, key) => set({ supabaseUrl: url, supabaseAnonKey: key }),
      setTeamCode: (code) => set({ teamCode: code }),
      setTeamSecretCode: (code) => set({ teamSecretCode: code }),
      setWorkspaceId: (id) => set({ workspaceId: id }),
      setTeamId: (id) => set({ teamId: id }),
      setUserId: (id) => set({ userId: id }),
      setHasHydrated: (hydrated) => set({ hasHydrated: hydrated }),
      resetOnboarding: () => {
        console.log('[OnboardingStore] resetOnboarding called');
        set({ ...initialState, step: 'welcome', hasHydrated: true });
      },
    }),
    {
      name: 'gimay-onboarding-storage',
      onRehydrateStorage: () => (state) => {
        state?.setHasHydrated(true);
      },
      partialize: (state) => ({
        step: state.step,
        setupMode: state.setupMode,
        isConfigured: state.isConfigured,
        workspaceId: state.workspaceId,
        teamId: state.teamId,
        userId: state.userId,
      }),
    }
  )
);

